#!/usr/bin/env python3
"""
Tableau → Power BI Migration Server
Watches a source folder for .twb/.twbx files, converts each to .pbit,
and streams progress to the browser UI via Server-Sent Events (SSE).

Usage:
    python tableau_pbi_server.py [--port 8765] [--source ./source] [--target ./target]
"""

import argparse
import json
import os
import queue
import sys
import threading
import time
import traceback
import uuid
import xml.etree.ElementTree as ET
import zipfile
from datetime import datetime, timezone
from http.server import BaseHTTPRequestHandler, HTTPServer, ThreadingHTTPServer
from pathlib import Path
from urllib.parse import urlparse, parse_qs


# ─────────────────────────────────────────────────────────────────────────────
# Auto-install optional dependencies
# openpyxl is required for the Excel analysis report feature.
# tableauhyperapi and pantab are used for Tier-1 exact data extraction from
# Tableau .hyper files embedded inside .twbx archives.
# All three are installed silently if missing rather than crashing at runtime.
# ─────────────────────────────────────────────────────────────────────────────
def _ensure_openpyxl():
    try:
        import openpyxl  # noqa: F401
    except ImportError:
        print("  [INFO] openpyxl not found — installing…", flush=True)
        import subprocess
        result = subprocess.run(
            [sys.executable, "-m", "pip", "install", "openpyxl", "--quiet"],
            capture_output=True, text=True
        )
        if result.returncode == 0:
            print("  [INFO] openpyxl installed successfully.", flush=True)
        else:
            print(f"  [WARN] openpyxl install failed: {result.stderr.strip()}", flush=True)


def _ensure_hyper_libs():
    """Auto-install tableauhyperapi and pantab if not present.

    tableauhyperapi — Tableau's official SDK; Tier-1a exact .hyper extraction.
    pantab          — open-source HyperAPI wrapper;   Tier-1b exact extraction.

    Both are optional: the server falls back to Tier-2 binary extraction or
    Tier-3 synthesis when neither is installed.  Installing either (or both)
    enables exact row data in the generated PBIT embedded dataset.
    """
    for pkg, import_name in [
        ('tableauhyperapi', 'tableauhyperapi'),
        ('pantab',          'pantab'),
    ]:
        try:
            __import__(import_name)
        except ImportError:
            print(f"  [INFO] {pkg} not found — installing…", flush=True)
            import subprocess
            result = subprocess.run(
                [sys.executable, "-m", "pip", "install", pkg, "--quiet"],
                capture_output=True, text=True
            )
            if result.returncode == 0:
                print(f"  [INFO] {pkg} installed successfully.", flush=True)
            else:
                print(f"  [WARN] {pkg} install failed (Tier-1 extraction unavailable): "
                      f"{result.stderr.strip()}", flush=True)


_ensure_openpyxl()
_ensure_hyper_libs()


# ─────────────────────────────────────────────────────────────────────────────
# Global event bus — all SSE clients subscribe to this
# ─────────────────────────────────────────────────────────────────────────────
_clients: list[queue.Queue] = []
_clients_lock = threading.Lock()

conversion_state = {
    "running": False,
    "source": "",
    "target": "",
    "jobs": {},          # filename -> {status, message, started, finished}
}


def broadcast(event: str, data: dict):
    """Push an SSE event to all connected browser clients."""
    payload = f"event: {event}\ndata: {json.dumps(data)}\n\n"
    with _clients_lock:
        dead = []
        for q in _clients:
            try:
                q.put_nowait(payload)
            except queue.Full:
                print(f"[DEBUG except] line ~107: exception caught")
                dead.append(q)
        for q in dead:
            _clients.remove(q)


def log(level: str, message: str, filename: str = ""):
    ts = datetime.now().strftime("%H:%M:%S")
    broadcast("log", {"ts": ts, "level": level, "message": message, "file": filename})
    print(f"[{ts}] [{level.upper():5s}] {('[' + filename + '] ') if filename else ''}{message}",
          flush=True)


# ─────────────────────────────────────────────────────────────────────────────
# PBIT Generator — everything learned from the debugging sessions
# ─────────────────────────────────────────────────────────────────────────────

def _jmin(obj) -> str:
    return json.dumps(obj, ensure_ascii=False, separators=(',', ':'))


def _jstr(obj, indent=2) -> str:
    return json.dumps(obj, ensure_ascii=False, indent=indent)


def _sanitise_json(text: str) -> str:
    """
    Remove XML-illegal control characters from a JSON string before
    encoding as UTF-16LE for PBIT/PBIX ZIP entries.

    Power BI Desktop's XMLA layer rejects code points 0x00–0x1F except
    TAB (0x09), LF (0x0A), CR (0x0D).  These enter through embedded CSV
    cell values, Tableau calc formulas, or hyper binary artefacts.

    Strategy: NUL → removed; other C0 controls → \\uXXXX JSON escape.
    """
    import re as _re_san
    text = text.replace('\x00', '')
    text = _re_san.sub(r'[\x01-\x08\x0b\x0c\x0e-\x1f]',
                       lambda m: f'\\u{ord(m.group(0)):04x}', text)
    return text


def _utf16(text: str) -> bytes:
    """Encode to UTF-16LE without BOM — required for all JSON entries in PBIT."""
    return text.encode('utf-16-le')


def _guid() -> str:
    return str(uuid.uuid4())


def _now_iso() -> str:
    return datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%S.%fZ")


def _add_period(base_date: datetime, period_type: str, n: int) -> datetime:
    """Shift base_date by n Tableau relative-date periods (stdlib only, no dateutil)."""
    from datetime import timedelta
    import calendar
    pt = (period_type or 'day').lower().replace('iso-', '')
    if pt == 'year':
        try:
            return base_date.replace(year=base_date.year + n)
        except ValueError:  # Feb 29 on a non-leap target year
            return base_date.replace(month=2, day=28, year=base_date.year + n)
    if pt == 'quarter':
        return _add_period(base_date, 'month', n * 3)
    if pt == 'month':
        total = base_date.month - 1 + n
        year = base_date.year + total // 12
        month = total % 12 + 1
        day = min(base_date.day, calendar.monthrange(year, month)[1])
        return base_date.replace(year=year, month=month, day=day)
    if pt == 'week':
        return base_date + timedelta(weeks=n)
    if pt == 'hour':
        return base_date + timedelta(hours=n)
    if pt == 'minute':
        return base_date + timedelta(minutes=n)
    if pt == 'second':
        return base_date + timedelta(seconds=n)
    return base_date + timedelta(days=n)  # day (default/fallback)


def _relative_date_window(period_type_v2: str, first_period, last_period, period_anchor: str):
    """Best-effort static snapshot of a Tableau relative-date filter window.

    Tableau recomputes this filter against "today" every time the view is
    opened; there's no verified Power BI internal filter shape for a live
    equivalent, so we resolve the window using the anchor date recorded in
    the workbook. Returns (start_iso, end_iso) date strings, or (None, None)
    if the anchor/periods can't be parsed (caller then skips the filter
    rather than emitting a bogus range).
    """
    try:
        anchor = datetime.strptime((period_anchor or '')[:19], '%Y-%m-%dT%H:%M:%S')
    except ValueError:
        try:
            anchor = datetime.strptime((period_anchor or '')[:10], '%Y-%m-%d')
        except ValueError:
            anchor = datetime.now()
    try:
        first_n, last_n = int(float(first_period)), int(float(last_period))
    except (TypeError, ValueError):
        return None, None
    start = _add_period(anchor, period_type_v2, first_n)
    end = _add_period(anchor, period_type_v2, last_n)
    if start > end:
        start, end = end, start
    return start.date().isoformat(), end.date().isoformat()


def _set_member_condition(gf, calc_caption_map: dict):
    """Build a Tableau-syntax boolean OR-condition for a member-defining
    <groupfilter>. Tableau's <group> element allows exactly ONE top-level
    <groupfilter> child (confirmed via the 2026.2 TWB XSD's Group-G /
    SetFunction-G definitions — not multiple flat siblings), so a Set with
    2+ included values nests one <groupfilter function="member" member="..">
    per value INSIDE a single outer element that carries the shared `level`
    (which may or may not itself carry a `member` value). Handles both that
    nested shape and the single-value shape where `gf` carries level+member
    directly. Returns None if there are no usable members.
    """
    if gf is None:
        return None
    level_raw = gf.get('level', '')
    members   = []
    if gf.get('member'):
        stripped = gf.get('member').strip('"').replace('"', '""')
        members.append(f'"{stripped}"')
    for child in gf.findall('.//groupfilter[@function="member"]'):
        if not level_raw and child.get('level'):
            level_raw = child.get('level')
        if child.get('member'):
            stripped = child.get('member').strip('"').replace('"', '""')
            members.append(f'"{stripped}"')
    level_raw = level_raw.strip('[').strip(']')
    if not level_raw or not members:
        return None
    level_display = calc_caption_map.get(level_raw, level_raw)
    if len(members) == 1:
        return f'[{level_display}] = {members[0]}'
    return '(' + ' OR '.join(f'[{level_display}] = {m}' for m in members) + ')'


def _resolve_set_groupfilter(gf, group_by_name: dict, calc_caption_map: dict, depth: int = 0):
    """Recursively translate a Tableau Set's defining <groupfilter> into a
    Tableau-SYNTAX boolean formula string (bracket field refs, AND/OR/NOT,
    RANK()) — NOT raw DAX. It is stored on the calc entry exactly like any
    user-authored calculated field's formula and runs through the same later
    _tableau_formula_to_dax translation pipeline, so no new internal-format
    guessing is introduced; a wrong translation here degrades to worse DAX,
    never a broken/unparseable file.

    Handles (schema-verified against the 2026.2 TWB XSD Function-ST /
    SetFunction-G): member, except, union, intersection, named-set (reference
    to another Set by name), filter (condition-based dynamic Set — its
    `expression` is already a normal Tableau formula, passed through as-is),
    order (Top/Bottom-N dynamic Set, 'records' unit only, via Tableau's own
    RANK() — already converted to RANKX() elsewhere in the pipeline), and
    range (a continuous-field domain restriction with numeric bounds).

    Returns None for anything unrecognised or structurally incomplete —
    caller falls back to the existing explicit FALSE()-with-comment rather
    than emit a guessed formula.
    """
    if gf is None or depth > 8:   # guard against cyclic/pathological named-set refs
        return None
    fn = gf.get('function', '')

    if fn == 'member':
        return _set_member_condition(gf, calc_caption_map)

    if fn == 'except':
        # "All members of the field EXCEPT the ones listed" — Tableau's
        # Exclude-mode Set. The excluded values live somewhere in the
        # subtree as function="member" elements (single-level or nested,
        # same ambiguity _set_member_condition already resolves); any
        # sibling domain/level-members child is the implicit "everything
        # else" and needs no separate handling.
        cond = _set_member_condition(gf, calc_caption_map)
        return f'NOT ({cond})' if cond else None

    if fn in ('union', 'intersection'):
        sub = [
            _resolve_set_groupfilter(c, group_by_name, calc_caption_map, depth + 1)
            for c in gf.findall('groupfilter')
        ]
        sub = [s for s in sub if s]
        if not sub:
            return None
        if len(sub) == 1:
            return sub[0]
        joiner = ' OR ' if fn == 'union' else ' AND '
        return '(' + joiner.join(sub) + ')'

    if fn == 'named-set':
        ref_raw = gf.get('name', '').strip('[').strip(']')
        ref_grp = group_by_name.get(ref_raw)
        if ref_grp is None:
            return None
        return _resolve_set_groupfilter(ref_grp.find('groupfilter'), group_by_name,
                                         calc_caption_map, depth + 1)

    if fn == 'filter':
        # Condition-based dynamic Set ("Condition" tab) — expression is a
        # normal Tableau calc formula referencing real fields/measures.
        expr = gf.get('expression', '')
        return expr if expr.strip() else None

    if fn == 'order':
        # Top/Bottom-N dynamic Set ("Top" tab). Only the plain-count
        # 'records' unit has a safe translation; percent/sample units would
        # need a different (COUNTROWS-cutoff) DAX shape not attempted here.
        if gf.get('units', 'records') != 'records':
            return None
        try:
            n = int(float(gf.get('count', '')))
        except (TypeError, ValueError):
            return None
        expr = gf.get('expression', '')
        if not expr.strip():
            return None
        # RANK() always ranks descending (Tableau's own default, already
        # mapped to RANKX(..., DESC, Dense) later in the pipeline); negate
        # the ranked expression to get "bottom N" out of the same DESC path.
        ranked = expr if gf.get('end', 'top') == 'top' else f'-({expr})'
        return f'RANK({ranked}) <= {n}'

    if fn == 'range':
        level_raw = gf.get('level', '').strip('[').strip(']')
        level_display = calc_caption_map.get(level_raw, level_raw)
        lo, hi = gf.get('from', ''), gf.get('to', '')
        if not level_display:
            return None
        try:
            float(lo)
            float(hi)
        except (TypeError, ValueError):
            return None   # non-numeric bounds (e.g. an encoded date token) — don't guess
        return f'[{level_display}] >= {lo} AND [{level_display}] <= {hi}'

    return None


