# ─────────────────────────────────────────────────────────────────────────────
# Hyper / TWBX data extraction
# ─────────────────────────────────────────────────────────────────────────────

def _extract_hyper_schemas(hyper_bytes: bytes) -> list:
    """Extract EVERY real table's schema from a .hyper file's embedded JSON
    catalog — not just the first one found.

    A single embedded .hyper can back MULTIPLE real Tableau physical tables
    joined together (e.g. a federated datasource's Orders/People/Returns all
    materialised into one superstore_data.hyper) — confirmed real on
    sales_dashboard_no_conn.twbx, where the catalog lists 3 separate
    type='block' relations (Orders_<hash>, People_<hash>, Returns_<hash>).
    The previous single-table version silently discarded every table but the
    first, which meant dimension-side row data (needed for relationship
    cardinality/uniqueness checks and dimension-table embedding) was never
    even attempted for a multi-table extract.

    Returns a list of:
        {
          'name':        table name  (e.g. 'Extract' or 'Orders_<hash>'),
          'schema_name': schema/namespace name (e.g. 'Extract' or 'public'),
          'columns':     [{name, type, nullCount}, ...]
        }
    in catalog order, deduplicated by table name. Empty list if nothing
    could be parsed.
    """
    import json as _json
    results = []
    seen_names: set = set()
    i, n = 0, len(hyper_bytes)
    while i < n:
        idx = hyper_bytes.find(b'"relations"', i)
        if idx == -1: break
        depth, js = 0, idx
        while js > 0:
            b = hyper_bytes[js]
            if b == ord('{'): depth += 1
            elif b == ord('}'): depth -= 1
            if depth == 1: break
            js -= 1
        depth, je = 0, js
        while je < n:
            b = hyper_bytes[je]
            if b == ord('{'): depth += 1
            elif b == ord('}'):
                depth -= 1
                if depth == 0: je += 1; break
            je += 1
        try:
            obj = _json.loads(hyper_bytes[js:je])
            # Build OID → namespace name map for schema resolution
            ns_map = {ns['oid']: ns['name']
                      for ns in obj.get('namespaces', [])
                      if 'oid' in ns and 'name' in ns}
            for rel in obj.get('relations', []):
                if rel.get('type') == 'block' and rel.get('attributes'):
                    tbl_name = rel.get('name', 'Extract')
                    if tbl_name in seen_names:
                        continue
                    seen_names.add(tbl_name)
                    schema_name = ns_map.get(rel.get('parent'), 'Extract')
                    results.append({
                        'name':        tbl_name,
                        'schema_name': schema_name,
                        'columns': [
                            {'name': a['name'],
                             'type': (a['type'][0] if isinstance(a['type'], list)
                                      else str(a['type'])),
                             'nullCount': rel.get('nullCounts', [0]*999)[idx2]}
                            for idx2, a in enumerate(rel['attributes'])
                        ]
                    })
        except Exception:
            print(f"[DEBUG except] line ~204: exception caught")
            pass
        i = idx + 1
    return results


def _extract_hyper_schema(hyper_bytes: bytes) -> dict:
    """Back-compat single-table wrapper around _extract_hyper_schemas —
    returns the first real table found, or {} if none. Prefer
    _extract_hyper_schemas directly for any .hyper that may contain more
    than one physical table (i.e. any real extract with relationships)."""
    _schemas = _extract_hyper_schemas(hyper_bytes)
    return _schemas[0] if _schemas else {}


def _extract_hyper_lp_strings(hyper_bytes: bytes) -> list:
    """
    Extract length-prefixed strings (4-byte LE length + ASCII content) from a
    .hyper binary. These are reliably stored in the string dictionary sections
    of the HyperDB page format and represent real categorical values.
    Returns a deduplicated list of clean ASCII strings.
    """
    import struct as _s
    SYSTEM = {
        'compressionMethod','encryptionSchemeId','databases','dropped','namespaces',
        'relations','attributes','externaltables','views','functions','types',
        'aggregates','sequences','partitionKey','partitionedRelation','nullCounts',
        'HyperDB','Extract','public','tableau','internal','user','block','table',
        'Varchar','BigInt','Double','Date','nullable','collate','description',
        'family-name','superuser','createdb','createrole','inherit','login',
        'validUntil','memberOf','adminOf','connlimit','replication','hasPassword',
        'password','encrypted','oid','name','owner','parent','dependencies',
        'reverseDependencies','false','true','lz4','Hyper','type','author-locale',
        'authentication','auth-none','schema','tablename','update-time','class',
    }
    found, seen = [], set()
    i = 0
    while i < len(hyper_bytes) - 5:
        length = _s.unpack_from('<I', hyper_bytes, i)[0]
        if 2 <= length <= 120 and i + 4 + length <= len(hyper_bytes):
            raw = hyper_bytes[i+4:i+4+length]
            if all(32 <= b <= 126 for b in raw):
                try:
                    text = raw.decode('ascii').strip()
                    if (text and len(text) >= 2
                            and text not in SYSTEM
                            and not text.startswith('{')
                            and not text.endswith('}')
                            and text not in seen
                            and sum(1 for c in text if c.isalpha()) >= 1):
                        found.append(text)
                        seen.add(text)
                    i += 4 + length
                    continue
                except Exception:
                    print(f"[DEBUG except] line ~249: exception caught")
                    pass
        i += 1
    return found


def _synth_value(col_name: str, col_type: str, row_idx: int):
    """
    Generate a realistic synthetic value based on column name and type.
    Returns a Python value (str, int, or float).
    Covers financial, telecom, HR, retail, and generic datasets.
    """
    name_l = col_name.lower().replace(' ', '').replace('_', '')

    if col_type in ('Varchar', 'string', 'text'):
        # ── Yes/No binary columns ─────────────────────────────────────────────
        YES_NO_COLS = ('churn','attrition','active','status','flag','indicator',
                       'partner','dependent','phone','service','billing','senior',
                       'paperless','streaming','security','backup','protection',
                       'support','online','multiple','wireless')
        if any(k in name_l for k in YES_NO_COLS):
            return ['Yes', 'No'][row_idx % 2]

        # ── Gender ────────────────────────────────────────────────────────────
        if 'gender' in name_l or name_l == 'sex':
            return ['Male', 'Female'][row_idx % 2]

        # ── Month ─────────────────────────────────────────────────────────────
        if 'month' in name_l:
            return ['January','February','March','April','May','June',
                    'July','August','September','October','November','December'][row_idx % 12]

        # ── Quarter ───────────────────────────────────────────────────────────
        if 'quarter' in name_l or name_l == 'qtr':
            return f'Q{(row_idx % 4) + 1}'

        # ── Year ──────────────────────────────────────────────────────────────
        if 'year' in name_l:
            return str(2019 + (row_idx % 5))

        # ── Date string ───────────────────────────────────────────────────────
        if 'date' in name_l:
            months = ['Jan','Feb','Mar','Apr','May','Jun',
                      'Jul','Aug','Sep','Oct','Nov','Dec']
            m = months[row_idx % 12]
            y = 13 + (row_idx // 12) % 5
            return f'{m}-{y:02d}'

        # ── Contract / plan ───────────────────────────────────────────────────
        if 'contract' in name_l or 'plan' in name_l or 'subscription' in name_l:
            return ['Month-to-month', 'One year', 'Two year'][row_idx % 3]

        # ── Payment method ────────────────────────────────────────────────────
        if 'payment' in name_l or 'paymethod' in name_l:
            return ['Electronic check', 'Mailed check',
                    'Bank transfer (automatic)', 'Credit card (automatic)'][row_idx % 4]

        # ── Internet service ──────────────────────────────────────────────────
        if 'internet' in name_l:
            return ['DSL', 'Fiber optic', 'No'][row_idx % 3]

        # ── Multiple lines ────────────────────────────────────────────────────
        if 'multipleline' in name_l:
            return ['Yes', 'No', 'No phone service'][row_idx % 3]

        # ── Services that can be No/Yes/No internet service ───────────────────
        NET_SERVICES = ('streamingtv','streamingmovies','onlinesecurity',
                        'onlinebackup','deviceprotection','techsupport')
        if any(k in name_l for k in NET_SERVICES):
            return ['Yes', 'No', 'No internet service'][row_idx % 3]

        # ── Customer / account ID ─────────────────────────────────────────────
        if any(k in name_l for k in ('customerid','custid','accountid','userid')):
            n = row_idx + 1
            letters = chr(65 + (n % 26)) * 5
            return f'{n:04d}-{letters}'

        # ── Country ───────────────────────────────────────────────────────────
        if 'country' in name_l or 'region' in name_l:
            return ['United States','Canada','United Kingdom','Germany',
                    'France','Australia','Japan','Brazil','India','Mexico'][row_idx % 10]

        # ── Department / division ─────────────────────────────────────────────
        if 'dept' in name_l or 'department' in name_l or 'division' in name_l:
            return ['Sales','Engineering','HR','Finance','Marketing'][row_idx % 5]

        # ── Job role / title ──────────────────────────────────────────────────
        if any(k in name_l for k in ('jobrole','role','title','position')):
            return ['Manager','Analyst','Director','Associate','Specialist'][row_idx % 5]

        # ── Education ────────────────────────────────────────────────────────
        if 'education' in name_l:
            return ['Bachelor','Master','PhD','Associate','High School'][row_idx % 5]

        # ── Marital / civil status ────────────────────────────────────────────
        if 'marital' in name_l or 'civil' in name_l:
            return ['Single','Married','Divorced','Widowed'][row_idx % 4]

        # ── Client / customer name ────────────────────────────────────────────
        if any(k in name_l for k in ('client','company','vendor','supplier')):
            COMPANIES = ['Acme Corp','Globex','Initech','Umbrella','Hooli',
                         'Pied Piper','Massive Dynamic','Dunder Mifflin',
                         'Cyberdyne','Soylent Corp']
            return COMPANIES[row_idx % len(COMPANIES)]

        # ── Financial type / category ─────────────────────────────────────────
        if any(k in name_l for k in ('type','category','segment','class')):
            return ['Revenue','Cost of Sales','Gross Profit',
                    'Operating Expenses','EBITDA','Net Income'][row_idx % 6]

        # ── Activity (cash flow) ──────────────────────────────────────────────
        if 'activity' in name_l:
            return ['Operating Activities','Investing Activities',
                    'Financing Activities'][row_idx % 3]

        # ── Percentage string ─────────────────────────────────────────────────
        if '%' in col_name or 'pct' in name_l or 'percent' in name_l:
            return f'{15 + (row_idx % 20):.1f}%'

        # ── Sub-category ──────────────────────────────────────────────────────
        if 'sub' in name_l:
            return f'Sub-category {(row_idx % 5) + 1}'

        # ── Generic string fallback using column name as prefix ───────────────
        import re as _re
        safe = _re.sub(r'[^A-Za-z0-9]', '', col_name)[:8] or 'Val'
        return f'{safe} {(row_idx % 10) + 1}'

    # ── Numeric columns ───────────────────────────────────────────────────────
    base = row_idx + 1
    name_l_full = col_name.lower()   # use the original (with spaces) for numeric

    if any(k in name_l for k in ('seniorcitizen','senior','flag','binary','bool')):
        return row_idx % 2

    if any(k in name_l for k in ('tenure','months','days','age','years')):
        return 1 + (row_idx % 72)   # 1-72 months typical for telecom

    if any(k in name_l for k in ('monthlycharge','monthly')):
        return round(18.25 + (row_idx % 100) * 1.01, 2)

    if any(k in name_l for k in ('totalcharge','total')):
        tenure = 1 + (row_idx % 72)
        monthly = round(18.25 + (row_idx % 100) * 1.01, 2)
        return round(tenure * monthly, 2)

    if any(k in name_l for k in ('revenue','sales','income')):
        scale = 100_000
    elif any(k in name_l for k in ('profit','gross','ebitda','operating')):
        scale = 50_000
    elif any(k in name_l for k in ('cost','expense','expenditure')):
        scale = 60_000
    elif any(k in name_l for k in ('payable','receivable','inventory',
                                    'assets','liabilit','capital','cash')):
        scale = 200_000
    elif any(k in name_l for k in ('ratio','rate','margin')):
        return round(0.1 + (row_idx % 90) * 0.01, 4)
    elif any(k in name_l for k in ('dpo','dso','cycle')):
        return 20 + (row_idx % 60)
    elif 'year' in name_l:
        return 2019 + (row_idx % 5)
    else:
        scale = 10_000

    val = base * scale + (base * 1337 % max(scale, 1))
    if col_type == 'Double':
        return round(val * 1.0 + (row_idx * 0.75), 2)
    return int(val)




def _classify_lp_string(s: str) -> set:
    """
    Return the set of column-type keywords this LP-string value could belong to.
    Used to match extracted strings to the right column without grabbing everything.
    """
    sl = s.lower().strip()
    tags = set()

    # Yes/No values → any binary column
    if sl in ('yes', 'no'):
        tags |= {'yesno', 'churn', 'partner', 'dependent', 'phoneservice',
                 'paperlessbilling', 'streaming', 'security', 'backup',
                 'protection', 'support', 'online', 'multiplelines'}

    # No phone service / No internet service → service columns
    if 'no phone' in sl:
        tags.add('multiplelines')
    if 'no internet' in sl:
        tags |= {'streamingtv', 'streamingmovies', 'onlinesecurity',
                 'onlinebackup', 'deviceprotection', 'techsupport'}

    # Gender
    if sl in ('male', 'female'):
        tags.add('gender')

    # Contract types
    if sl in ('month-to-month', 'one year', 'two year'):
        tags.add('contract')

    # Payment methods
    if any(k in sl for k in ('check', 'transfer', 'credit', 'electronic',
                              'mailed', 'bank', 'card', 'automatic')):
        tags.add('paymentmethod')

    # Internet service values
    if sl in ('dsl', 'fiber optic', 'fiber'):
        tags.add('internetservice')

    # Month names
    if any(m in sl for m in ('jan','feb','mar','apr','may','jun',
                               'jul','aug','sep','oct','nov','dec')):
        tags.add('month')

    # Quarter
    if sl.startswith('q') and any(c.isdigit() for c in sl):
        tags.add('quarter')

    # Year
    if sl.isdigit() and 1990 <= int(sl) <= 2035:
        tags.add('year')

    # Customer ID pattern XXXX-YYYYY
    import re as _re
    if _re.match(r'^\d{4}-[A-Z]{5}$', s):
        tags.add('customerid')

    # Client/company names (titlecase, multi-word, no special telecom patterns)
    if (s[0].isupper() and len(s) >= 4
            and not tags   # only if nothing else matched
            and ' ' in s or len(s) >= 6):
        tags.add('client')

    # Any string can be a generic category/type
    if not tags:
        tags.add('generic')

    return tags


def _extract_hyper_rows(hyper_bytes: bytes, schema_cols: list,
                         max_rows: int = 10000) -> list:
    """
    Extract or synthesize row data from a .hyper file.

    Three-tier strategy — no external files required:

      Tier 1  SDK extraction (best accuracy):
              a) tableauhyperapi — Tableau's official Python SDK
              b) pantab          — open-source HyperAPI wrapper
              The hyper bytes are written to a temp file, queried, then
              optionally exported to a temp CSV which is read back and
              deleted.  No files are left on disk after this call.

      Tier 2  Binary LP-string extraction + column-aware value classification
              Reads real categorical values (e.g. 'Female', 'Month-to-month',
              'Electronic check') directly from the HyperDB string dictionary
              pages.  Assigns them to the correct columns by value semantics,
              then synthesizes numeric/date columns with realistic ranges.

      Tier 3  Pure column-name-aware synthesis (_synth_value)
              Used when no binary values could be extracted.

    Returns list of row dicts: [{col_name: value, ...}, ...]
    """
    import tempfile as _tmp, os as _os

    col_names = [c['name'] for c in schema_cols]

    # ── Tier 1a: tableauhyperapi ──────────────────────────────────────────────
    try:
        from tableauhyperapi import (HyperProcess, Connection, Telemetry,
                                      SchemaName, TableName)
        tmp = _tmp.NamedTemporaryFile(suffix='.hyper', delete=False)
        tmp.write(hyper_bytes)
        tmp.close()
        try:
            with HyperProcess(Telemetry.DO_NOT_SEND_USAGE_DATA_TO_TABLEAU) as hp:
                with Connection(hp.endpoint, tmp.name) as conn:
                    quoted = ', '.join(f'"{n}"' for n in col_names)

                    # Build a prioritised list of (schema, table) name pairs to try.
                    # 1. Names discovered from the binary catalog (most reliable)
                    # 2. Classic Tableau default:  "Extract"."Extract"
                    # 3. Newer Tableau Desktop:    "public"."Extract"
                    # 4. Discover all tables via the HyperAPI catalog
                    schema_name = schema_cols[0].get('_schema', 'Extract') \
                                  if schema_cols else 'Extract'
                    table_name  = schema_cols[0].get('_table', 'Extract') \
                                  if schema_cols else 'Extract'
                    candidates = [
                        (schema_name, table_name),
                        ('Extract', 'Extract'),
                        ('public',  'Extract'),
                    ]
                    # Deduplicate while preserving order
                    seen_cands = set()
                    unique_cands = []
                    for c in candidates:
                        if c not in seen_cands:
                            seen_cands.add(c)
                            unique_cands.append(c)

                    # Also try autodiscovery via HyperAPI catalog if available
                    try:
                        catalog = conn.catalog
                        for sn in catalog.get_schema_names():
                            for tn in catalog.get_table_names(sn):
                                pair = (str(sn.unescaped), str(tn.unescaped))
                                if pair not in seen_cands:
                                    seen_cands.add(pair)
                                    unique_cands.append(pair)
                    except Exception:
                        print(f"[DEBUG except] line ~562: exception caught")
                        pass

                    rows_raw = None
                    used_pair = None
                    last_err  = None
                    for sch, tbl in unique_cands:
                        try:
                            rows_raw = conn.execute_list_query(
                                f'SELECT {quoted} FROM "{sch}"."{tbl}" '
                                f'LIMIT {max_rows}'
                            )
                            used_pair = (sch, tbl)
                            break
                        except Exception as _qe:
                            print(f"[DEBUG except] line ~576: {_qe}")
                            last_err = _qe
                            continue

                    if rows_raw is not None:
                        result = [dict(zip(col_names, row)) for row in rows_raw]
                        log('info', f'  [Tier 1a] tableauhyperapi: {len(result)} exact rows '
                            f'from "{used_pair[0]}"."{used_pair[1]}"')
                        return result
                    else:
                        log('warn', f'  [Tier 1a] tableauhyperapi: could not find table '
                            f'(tried {unique_cands}): {last_err}')
        finally:
            _os.unlink(tmp.name)
    except ImportError:
        print(f"[DEBUG except] line ~590: exception caught")
        pass  # SDK not installed – try next tier
    except Exception as _e:
        log('warn', f'  [Tier 1a] tableauhyperapi error: {_e}')

    # ── Tier 1b: pantab ───────────────────────────────────────────────────────
    try:
        import pantab as _pt
        tmp = _tmp.NamedTemporaryFile(suffix='.hyper', delete=False)
        tmp.write(hyper_bytes)
        tmp.close()
        try:
            frames = _pt.frames_from_hyper(tmp.name)
            if frames:
                df = next(iter(frames.values()))
                df = df.head(max_rows)
                df.columns = [str(c) for c in df.columns]
                rows = []
                for _, row_s in df.iterrows():
                    row = {}
                    for col in schema_cols:
                        val = row_s.get(col['name'])
                        if val is None or (hasattr(val, '__class__')
                                           and val.__class__.__name__ == 'NaT'):
                            row[col['name']] = None
                        else:
                            row[col['name']] = val
                    rows.append(row)
                log('info', f'  [Tier 1b] pantab: {len(rows)} exact rows extracted')
                return rows
        finally:
            _os.unlink(tmp.name)
    except ImportError:
        print(f"[DEBUG except] line ~622: exception caught")
        pass  # SDK not installed – try next tier
    except Exception as _e:
        log('warn', f'  [Tier 1b] pantab error: {_e}')

    # ── Tier 1c: subprocess export via any Python env with tableauhyperapi ────
    try:
        import subprocess as _sp
        tmp_hyper = _tmp.NamedTemporaryFile(suffix='.hyper', delete=False)
        tmp_hyper.write(hyper_bytes)
        tmp_hyper.close()
        tmp_csv = _tmp.NamedTemporaryFile(suffix='.csv', delete=False,
                                           mode='w', newline='')
        tmp_csv.close()
        try:
            # Build the candidate table list from schema_cols metadata
            # The subprocess tries each (schema, table) pair until one succeeds.
            sch = (schema_cols[0].get('_schema', 'Extract')
                   if schema_cols else 'Extract')
            tbl = (schema_cols[0].get('_table', 'Extract')
                   if schema_cols else 'Extract')
            candidates_str = repr([
                (sch, tbl), ('Extract', 'Extract'), ('public', 'Extract')
            ])
            script = (
                "import sys, csv;"
                "from tableauhyperapi import HyperProcess,Connection,Telemetry;"
                "hp=HyperProcess(Telemetry.DO_NOT_SEND_USAGE_DATA_TO_TABLEAU);"
                "conn=Connection(hp.endpoint,sys.argv[1]);"
                f"candidates={candidates_str};"
                "rows=None;"
                "["
                "  (setattr(sys.modules[__name__],'rows',"
                "    conn.execute_list_query('SELECT * FROM \"'+s+'\".\"'+t+'\"'))"
                "  ) for s,t in candidates"
                "  if rows is None"
                "  and not (setattr(sys.modules[__name__],'_e',None))"
                "];"
                "w=csv.writer(open(sys.argv[2],'w',newline=''));"
                "[w.writerow(r) for r in (rows or [])];"
                "conn.close();hp.close()"
            )
            result = _sp.run(
                ['python3', '-c', script, tmp_hyper.name, tmp_csv.name],
                capture_output=True, timeout=30
            )
            if result.returncode == 0 and _os.path.getsize(tmp_csv.name) > 0:
                rows = _read_csv_as_rows(tmp_csv.name, schema_cols, max_rows)
                if rows:
                    log('info', f'  [Tier 1c] subprocess export: {len(rows)} exact rows')
                    return rows
        except Exception:
            print(f"[DEBUG except] line ~673: exception caught")
            pass
        finally:
            for f in (tmp_hyper.name, tmp_csv.name):
                try: _os.unlink(f)
                except: pass
    except Exception:
        print(f"[DEBUG except] line ~679: exception caught")
        pass

    # ── Tier 2: LP-string + schema-aware synthesis ────────────────────────────
    # No SDK available.  Extract real categorical values from the HyperDB
    # string dictionary pages (they are stored uncompressed), assign them to
    # the correct columns by value semantics, then synthesise numeric/date
    # columns with realistic ranges.
    #
    # IMPORTANT: the row COUNT comes from _read_hyper_row_count (two-method
    # binary scanner).  The row ORDER and numeric VALUES are synthesised.
    # For exact data install:  pip install tableauhyperapi   OR   pip install pantab
    lp_strings = _extract_hyper_lp_strings(hyper_bytes)

    col_name_set = {c['name'] for c in schema_cols}
    SYSTEM = {'false', 'true', 'lz4', 'block', 'null', 'none', 'extract', 'public'}
    data_strings = [s for s in lp_strings
                    if s not in col_name_set
                    and s.lower() not in SYSTEM
                    and len(s) >= 2
                    and not all(ch.isdigit() or ch in '.-' for ch in s)]

    col_seeds: dict = {}

    def _norm_col(name: str) -> str:
        return name.lower().replace(' ', '').replace('_', '').replace('-', '')

    for s in data_strings:
        value_tags = _classify_lp_string(s)
        for col in schema_cols:
            if col['type'] not in ('Varchar',):
                continue
            cn = _norm_col(col['name'])
            assigned = False
            for tag in value_tags:
                if tag == 'yesno':
                    if any(k in cn for k in ('churn', 'attrition', 'partner',
                                              'dependent', 'phoneservice',
                                              'paperless', 'streaming', 'security',
                                              'backup', 'protection', 'support',
                                              'service', 'billing', 'active',
                                              'flag', 'indicator', 'wireless')):
                        assigned = True
                elif tag in cn or cn.startswith(tag) or cn.endswith(tag):
                    assigned = True
                elif tag == 'customerid' and any(k in cn for k in
                                                  ('customerid', 'custid',
                                                   'accountid', 'id')):
                    assigned = True
                elif tag == 'internetservice' and 'internet' in cn:
                    assigned = True
                elif tag == 'multiplelines' and 'multiple' in cn:
                    assigned = True
                elif tag == 'paymentmethod' and 'payment' in cn:
                    assigned = True
                if assigned:
                    break
            if assigned:
                if col['name'] not in col_seeds:
                    col_seeds[col['name']] = []
                if s not in col_seeds[col['name']]:
                    col_seeds[col['name']].append(s)

    # ── Row count detection ───────────────────────────────────────────────────
    # _read_hyper_row_count uses two binary-scan methods to read the row count
    # directly from the .hyper pages without the SDK.  Pass n_cols so the
    # method-2 upper-bound cap scales with the table width.
    n_cols   = max(len(schema_cols), 1)
    est_rows = _read_hyper_row_count(hyper_bytes, n_cols)
    row_src  = 'hyper_binary'

    if est_rows > 0:
        row_src = 'hyper_count'
    else:
        # SDK not installed and binary scan found nothing reliable.
        # Use a conservative file-size-tier estimate.
        # Values are intentionally small: Hyper compresses aggressively, so
        # physical file size tells us little.  Better to under-generate a few
        # rows and have a fast PBIT than to balloon it with thousands of
        # synthesised rows.  The user will see a WARN log pointing to the SDK.
        file_size = len(hyper_bytes)
        if   file_size <=  65_536:  est_rows = 100   # small Finance tables
        elif file_size <= 131_072:  est_rows = 300   # medium tables
        else:                       est_rows = 500   # large tables without SDK
        row_src = 'file_size_estimate'

    est_rows = min(est_rows, max_rows)

    # Emit one clear warning so the user knows exactly what happened
    sdk_hint = ('pip install tableauhyperapi  OR  pip install pantab')
    if row_src in ('file_size_estimate', 'hyper_count'):
        log('warn',
            f'  [Tier 2] No SDK — synthesised {est_rows} rows '
            f'(source: {row_src}). '
            f'For exact row data: {sdk_hint}')

    # ── Build synthesised rows ────────────────────────────────────────────────
    rows = []
    for row_idx in range(est_rows):
        row = {}
        for col in schema_cols:
            cname, ctype = col['name'], col['type']
            if ctype == 'Varchar':
                seeds = col_seeds.get(cname)
                row[cname] = seeds[row_idx % len(seeds)] if seeds else \
                              _synth_value(cname, ctype, row_idx)
            elif ctype == 'Date':
                import datetime as _dt
                row[cname] = (_dt.date(2013, 1, 1) +
                              _dt.timedelta(days=row_idx * 30)).isoformat()
            else:
                row[cname] = _synth_value(cname, ctype, row_idx)
        rows.append(row)

    return rows


def _read_hyper_row_count(hyper_bytes: bytes, n_cols: int = 3) -> int:
    """
    Estimate the row count from a .hyper file without the SDK.

    Two-method approach (falls back to 0 so the caller uses a conservative
    file-size estimate):

    Method 1 — Header page  (reliable for large datasets, e.g. Telco 7 043 rows)
        HyperDB stores the total row count as a u64 LE integer at byte 0 of a
        dedicated header page.  The immediately following u64 is a smaller
        positive value (page-count or chunk-count) that acts as a sanity check.

    Method 2 — Catalog double-entry  (reliable for small/medium Finance tables)
        The data-catalog JSON is written twice inside the .hyper file (primary +
        shadow copy).  Each copy embeds the row count as a u64 in the
        page-local offset range [2 000, 7 000].  We find every non-power-of-2
        integer ≤ max_rows_m2 = file_size ÷ (n_cols × 4) that appears at such
        offsets in exactly two different scan passes (i.e. appears in the catalog
        region across the whole file exactly twice).  The median of those
        candidates is returned as the row count.

        Why median?  The catalog contains a few structural integers alongside
        the actual row count.  Taking the median of the exact-pair candidates
        discards both the smallest structural constants and any outlier block
        sizes, leaving the true row count in the middle.

    Returns 0 when neither method finds a plausible value; the caller then
    falls back to a conservative file-size-based estimate.
    """
    import struct as _s, collections as _col
    PAGE_SIZE = 8192
    n_pages   = len(hyper_bytes) // PAGE_SIZE

    # ── Method 1: header page ─────────────────────────────────────────────────
    for pg in range(n_pages):
        page = hyper_bytes[pg * PAGE_SIZE: pg * PAGE_SIZE + PAGE_SIZE]
        if len(page) < 16:
            continue
        val = _s.unpack_from('<Q', page, 0)[0]
        if 1 <= val <= 10_000_000:
            v2 = _s.unpack_from('<Q', page, 8)[0]
            if 0 < v2 < val * 10:
                return int(val)

    # ── Method 2: catalog double-entry ────────────────────────────────────────
    # Upper bound: at ≥4 bytes per value per column we know the file cannot
    # store more than file_size ÷ (n_cols × 4) rows.
    max_rows_m2 = len(hyper_bytes) // max(n_cols * 4, 4)

    global_counts = _col.Counter()
    for pg in range(n_pages):
        page = hyper_bytes[pg * PAGE_SIZE: pg * PAGE_SIZE + PAGE_SIZE]
        for i in range(0, len(page) - 8, 8):
            if not (2000 <= i <= 7000):
                continue
            v = _s.unpack_from('<Q', page, i)[0]
            if (1 <= v <= max_rows_m2
                    and (v & (v - 1)) != 0   # not a power of 2
                    and v != 257):            # known catalog constant
                global_counts[v] += 1

    pairs = sorted([v for v, c in global_counts.items() if c == 2])
    if pairs:
        return pairs[len(pairs) // 2]   # median of exact-pair candidates

    return 0   # caller uses file-size fallback




def _read_csv_as_rows(csv_path: str, schema_cols: list,
                       max_rows: int = 10000) -> list:
    """
    Read a CSV file and return rows as dicts matching schema_cols.

    Handles:
    - BOM (utf-8-sig)
    - Column name normalisation (spaces ↔ camelCase ↔ underscores)
    - Type coercion: BigInt → int, Double → float, Varchar → str
    - Empty/null values → None
    """
    import csv as _csv

    def _norm(s):
        return s.lower().replace(' ', '').replace('_', '').replace('-', '')

    # Build normalised name → schema col mapping
    col_map = {_norm(c['name']): c for c in schema_cols}

    rows = []
    try:
        with open(csv_path, encoding='utf-8-sig', newline='') as f:
            reader = _csv.DictReader(f)
            for i, raw_row in enumerate(reader):
                if i >= max_rows:
                    break
                row = {}
                for csv_col, csv_val in raw_row.items():
                    schema_col = col_map.get(_norm(csv_col))
                    if schema_col is None:
                        continue
                    cname = schema_col['name']
                    ctype = schema_col['type']
                    val = csv_val.strip() if csv_val else ''
                    if val == '' or val.lower() in ('null', 'none', 'na', 'n/a'):
                        row[cname] = None
                    elif ctype == 'BigInt':
                        try:
                            row[cname] = int(float(val))
                        except (ValueError, TypeError):
                            print(f"[DEBUG except] line ~905: exception caught")
                            row[cname] = None
                    elif ctype == 'Double':
                        try:
                            row[cname] = float(val)
                        except (ValueError, TypeError):
                            print(f"[DEBUG except] line ~910: exception caught")
                            row[cname] = None
                    elif ctype == 'Date':
                        row[cname] = val
                    else:
                        row[cname] = val
                # Fill any schema cols not present in CSV with None
                for col in schema_cols:
                    if col['name'] not in row:
                        row[col['name']] = None
                rows.append(row)
    except Exception:
        print(f"[DEBUG except] line ~921: exception caught")
        pass
    return rows




def extract_twbx_data(twbx_path: 'Path') -> dict:
    """
    Extract embedded data from all .hyper extracts / CSV files in a .twbx.

    For federated datasources (multiple CSVs joined), each sub-table is
    extracted as a SEPARATE datasource entry so PBI gets a proper star-schema
    data model with relationships — not a single flat merged table.

    Returns:
        {'has_data': bool, 'datasources': {name: {'schema':..., 'rows':...}}}
    """
    import zipfile as _zf, xml.etree.ElementTree as _ET
    import csv as _csv, io as _io

    result = {'has_data': False, 'datasources': {}}

    try:
        with _zf.ZipFile(twbx_path) as z:
            names    = z.namelist()
            twb_name = next((n for n in names if n.endswith('.twb')), None)
            if not twb_name:
                return result

            twb_bytes = z.read(twb_name)
            hyper_map = {n.split('/')[-1].strip(): n
                         for n in names if n.endswith('.hyper')}

            try:
                root = _ET.fromstring(twb_bytes.decode('utf-8', 'replace'))
            except Exception:
                print("[DEBUG except] extract_twbx_data: XML parse failed")
                return result

            # ── Step 1: Extract raw CSV files from federated datasources ──────
            # Tableau stores the original CSV files inside the TWBX zip under
            # Data/xxx/ subdirectories. Read each directly — full fidelity data.
            _col_dtype: dict = {}  # field_name.lower() → datatype
            for ds in root.findall('.//datasource'):
                if 'Parameters' in ds.get('name', ''): continue
                for col in ds.findall('.//column'):
                    cname  = col.get('name','').strip('[]').lower()
                    dtype  = col.get('datatype','string')
                    if cname: _col_dtype[cname] = dtype

            def _infer_dtype(fn, sample_vals, known_dtype):
                """Infer the best datatype from sample values when known_dtype is generic."""
                if known_dtype and known_dtype != 'string':
                    return known_dtype
                for v in sample_vals:
                    if v is None or v == '': continue
                    try: int(v); return 'int64'
                    except ValueError: pass
                    try: float(v); return 'double'
                    except ValueError: pass
                    import re as _ire
                    if _ire.match(r'\d{4}-\d{2}-\d{2}', str(v)):
                        return 'date'
                return 'string'

            for n in names:
                if not n.lower().endswith('.csv'): continue
                base = n.split('/')[-1]
                tbl_name = base.replace('.csv','').replace('.CSV','').strip()
                try:
                    csv_bytes = z.read(n)
                    csv_text  = csv_bytes.decode('utf-8', 'replace')
                    reader    = _csv.DictReader(_io.StringIO(csv_text))
                    rows_raw  = list(reader)
                    fieldnames = reader.fieldnames or []
                    # Sample first 5 rows for type inference
                    _samples = {fn: [r.get(fn,'') for r in rows_raw[:5]]
                                for fn in fieldnames}
                    schema_cols = [{'name': fn,
                                    'datatype': _infer_dtype(
                                        fn, _samples.get(fn,[]),
                                        _col_dtype.get(fn.lower(), ''))}
                                   for fn in fieldnames]
                    rows = [{fn: r.get(fn,'') for fn in fieldnames}
                            for r in rows_raw]
                    result['datasources'][tbl_name] = {
                        'hyper_file': base,
                        'schema':     schema_cols,
                        'rows':       rows,
                    }
                    result['has_data'] = True
                    log('info', f"  ↳ {tbl_name!r}: {len(rows)} rows "
                        f"× {len(schema_cols)} cols from {base}")
                except Exception as _ce:
                    print(f"[DEBUG except] CSV read {base}: {_ce}")

            # ── Step 1b: Extract raw Excel files from datasources embedded ────
            # in the twbx package. Unlike CSV, a single embedded .xlsx workbook
            # can back SEVERAL Tableau physical tables — one per sheet (e.g.
            # 'Data/Data Sources/sample_super_store.xlsx' backs the Orders/
            # People/Returns sub-tables of a federated datasource via a shared
            # named-connection) — confirmed real on sales_dashboard.twbx, whose
            # generated Power BI query previously fell back to a fake
            # 'C:\path\to\...' placeholder path because embedded Excel data was
            # never extracted at all (only CSV/hyper were handled). Extracting
            # it here lets the normal embed_sample_data path take over, so no
            # file-path parameter (and therefore no placeholder) is needed.
            try:
                import openpyxl as _openpyxl
            except ImportError:
                _openpyxl = None

            if _openpyxl is not None:
                for ds in root.findall('.//datasource'):
                    if 'Parameters' in ds.get('name', ''):
                        continue
                    ds_cap = ds.get('caption', ds.get('name', ''))
                    # named-connection name -> embedded Excel filename (as
                    # stored in the twbx zip, e.g. 'Data/Data Sources/x.xlsx')
                    _nc_files: dict = {}
                    for _nc in ds.findall('.//named-connection'):
                        _inner = _nc.find('./connection')
                        if _inner is not None:
                            _fn = _inner.get('filename', '')
                            if _fn.lower().endswith(('.xlsx', '.xls', '.xlsm')):
                                _nc_files[_nc.get('name', '')] = _fn
                    if not _nc_files:
                        continue
                    # <relation type="table" name="Orders" table="[Orders$]">'s
                    # name IS the sheet name Tableau reads from that workbook.
                    _rel_to_file: dict = {}
                    for _rel in ds.findall('.//relation[@type="table"]'):
                        _fn = _nc_files.get(_rel.get('connection', ''))
                        if _fn:
                            _rel_to_file[_rel.get('name', '')] = _fn

                    def _find_zip_entry(fn):
                        if fn in names:
                            return fn
                        _base = fn.split('/')[-1]
                        return next((nm for nm in names if nm.split('/')[-1] == _base), None)

                    # Same reasoning as Step 2's identical single-vs-multi-
                    # table guard below: a datasource with only ONE relevant
                    # sheet is keyed by ds_cap directly (unique per
                    # datasource, so it can never collide with another
                    # datasource's identically-named sheet) rather than by
                    # the bare sheet/relation name, which multiple different
                    # embedded workbooks could plausibly share (e.g. two
                    # datasources each with their own 'Sheet1').
                    _single_sheet_ds = len(_rel_to_file) == 1
                    _wb_cache: dict = {}
                    _row_counts: dict = {}
                    for _rel_name, _zip_fn in _rel_to_file.items():
                        _dest_key = ds_cap if _single_sheet_ds else _rel_name
                        if not _rel_name or _dest_key in result['datasources']:
                            continue  # already loaded via CSV/hyper step above
                        _zpath = _find_zip_entry(_zip_fn)
                        if _zpath is None:
                            continue
                        if _zpath not in _wb_cache:
                            try:
                                _wb_cache[_zpath] = _openpyxl.load_workbook(
                                    _io.BytesIO(z.read(_zpath)),
                                    read_only=True, data_only=True)
                            except Exception as _xe:
                                log('warn', f'extract_twbx_data: could not open '
                                    f'embedded Excel {_zpath}: {_xe}')
                                _wb_cache[_zpath] = None
                        _wb = _wb_cache[_zpath]
                        if _wb is None or _rel_name not in _wb.sheetnames:
                            continue
                        try:
                            _ws = _wb[_rel_name]
                            _rows_iter = _ws.iter_rows(values_only=True)
                            _header = next(_rows_iter, None)
                            if not _header:
                                continue
                            _fieldnames = [str(h) if h is not None else f'Column{i}'
                                           for i, h in enumerate(_header)]
                            _raw_rows = []
                            for _i, _r in enumerate(_rows_iter):
                                if _i >= 10000:
                                    break
                                _raw_rows.append(dict(zip(_fieldnames, _r)))

                            def _cellstr(v):
                                import datetime as _dtm
                                if v is None:
                                    return ''
                                if isinstance(v, (_dtm.datetime, _dtm.date)):
                                    return v.isoformat()
                                return str(v)

                            _samples = {fn: [_cellstr(rr.get(fn)) for rr in _raw_rows[:5]]
                                        for fn in _fieldnames}
                            _schema_cols = [{'name': fn,
                                              'datatype': _infer_dtype(
                                                  fn, _samples.get(fn, []),
                                                  _col_dtype.get(fn.lower(), ''))}
                                             for fn in _fieldnames]
                            _out_rows = [{fn: _cellstr(rr.get(fn)) for fn in _fieldnames}
                                         for rr in _raw_rows]
                            result['datasources'][_dest_key] = {
                                'hyper_file': _zpath.split('/')[-1],
                                'schema':     _schema_cols,
                                'rows':       _out_rows,
                            }
                            result['has_data'] = True
                            _row_counts[_dest_key] = len(_out_rows)
                            log('info', f"  ↳ {_dest_key!r}: {len(_out_rows)} rows "
                                f"× {len(_schema_cols)} cols from embedded Excel "
                                f"{_zpath} (sheet {_rel_name!r})")
                        except Exception as _xe2:
                            log('warn', f'extract_twbx_data: sheet {_rel_name!r} '
                                f'read failed: {_xe2}')

                    # Alias the largest real sheet under the outer datasource
                    # caption too — the flat/fact table's embed lookup in
                    # build_data_model_schema is keyed by the Tableau
                    # datasource caption (e.g. 'superstore_data'), which never
                    # matches an individual sheet name directly.
                    if _row_counts and ds_cap not in result['datasources']:
                        _primary = max(_row_counts, key=_row_counts.get)
                        result['datasources'][ds_cap] = result['datasources'][_primary]

            # ── Step 2: Extract from hyper files for any remaining datasources ─
            ds_to_hyper: dict = {}
            for ds in root.findall('.//datasource'):
                cap = ds.get('caption', ds.get('name', ''))
                if 'Parameters' in ds.get('name', ''): continue
                ext = ds.find('extract')
                if ext is None: continue
                conn = (ext.find('.//connection[@class="dataengine"]')
                        or ext.find('.//connection[@class="hyper"]'))
                if conn is None:
                    conn = next(
                        (c for c in ext.findall('.//connection')
                         if c.get('dbname','').endswith('.hyper')),
                        None
                    )
                if conn is None: continue
                dbname   = conn.get('dbname','')
                basename = dbname.split('/')[-1].strip()
                if basename in hyper_map:
                    ds_to_hyper[cap] = basename

            for ds_cap, hyper_fname in ds_to_hyper.items():
                try:
                    hyper_bytes = z.read(hyper_map[hyper_fname])
                except Exception:
                    print(f"[DEBUG except] hyper read {hyper_fname}: exception")
                    continue

                # A single embedded .hyper can back MULTIPLE real Tableau
                # tables joined together (e.g. Orders/People/Returns) — see
                # _extract_hyper_schemas. Extract every one, not just the
                # first, keyed by its clean (hash-suffix-stripped) name so
                # dimension-table embedding / relationship-cardinality checks
                # can find real per-table data instead of falling back to
                # synthetic (and potentially duplicate-value) rows.
                #
                # IMPORTANT: Tableau gives every SIMPLE (non-relationship)
                # extract's single internal table the same generic name
                # 'Extract' regardless of which datasource it came from —
                # confirmed real on Finance Dashboard_v2026.1.twbx, which has
                # 9 separate single-table .hyper files (one per worksheet's
                # own datasource) that ALL name their table 'Extract'. Keying
                # by that shared clean name across DIFFERENT datasources
                # would make every one after the first look like an
                # already-seen duplicate and silently drop it — a real
                # regression caught by comparing against a known-good
                # pre-existing .pbit (only 2 of 9 datasources' data survived
                # instead of 9). So: a hyper file with exactly ONE table is
                # keyed by ds_cap directly (matches the original, proven-
                # correct single-table behaviour — ds_cap is unique per
                # datasource, so this can never collide). Only a hyper file
                # that genuinely contains MULTIPLE tables (a real
                # relationship-bearing extract) uses per-table clean-name
                # keying, since those names (e.g. 'Orders'/'People'/
                # 'Returns') are what dimension-table lookups need.
                table_schemas = _extract_hyper_schemas(hyper_bytes)
                if not table_schemas:
                    continue

                import re as _re_hs
                _row_counts2: dict = {}
                _single_table = len(table_schemas) == 1
                for schema_info in table_schemas:
                    raw_schema_cols = schema_info.get('columns', [])
                    tbl_name    = schema_info.get('name', 'Extract')
                    schema_name = schema_info.get('schema_name', 'Extract')
                    schema_cols = [
                        {**c, '_schema': schema_name, '_table': tbl_name}
                        for c in raw_schema_cols
                    ]
                    if _single_table:
                        key_name = ds_cap
                    else:
                        key_name = _re_hs.sub(r'_[A-Fa-f0-9]{32}$', '', tbl_name) or tbl_name
                    if key_name in result['datasources']:
                        continue  # already loaded via CSV/Excel step above
                    rows = _extract_hyper_rows(hyper_bytes, schema_cols)
                    result['datasources'][key_name] = {
                        'hyper_file': hyper_fname,
                        'schema':     schema_cols,
                        'rows':       rows,
                    }
                    result['has_data'] = True
                    _row_counts2[key_name] = len(rows)
                    log('info', f'  ↳ {key_name!r}: {len(rows)} rows '
                        f'× {len(schema_cols)} cols from {hyper_fname}')

                # Alias the largest real table under the outer datasource
                # caption too (see Step 1b's identical rationale). No-op in
                # the single-table case: key_name already IS ds_cap above.
                if _row_counts2 and ds_cap not in result['datasources']:
                    _primary2 = max(_row_counts2, key=_row_counts2.get)
                    result['datasources'][ds_cap] = result['datasources'][_primary2]

    except Exception as _e:
        log('warn', f'extract_twbx_data error: {_e}')

    return result


def _parse_dashboard_actions(root, dashboard_names: set, worksheet_names: set) -> list:
    """Parse the workbook-level <actions> block (a direct child of <workbook>,
    sibling to <worksheets>/<dashboards> — confirmed against a real workbook,
    not just the XSD) into a list of classified action dicts.

    Tableau XML structure confirmed from a real sample (Finance_Dashboard.twb)
    plus the official 2026.2 TWB XSD (github.com/tableau/tableau-document-schemas):
      <actions>
        <action name="[ActionN]" caption="...">
          <activation type="on-select|on-hover|explicit" auto-clear="true|false"/>
          <source type="all|datasource|sheet" dashboard="..." worksheet="...">
            <exclude-sheet name="..."/>*
          </source>
          <link caption="..." expression="tsl:...-or-http(s)://..." .../>   (optional)
          <command command="tsc:tsl-filter" >                              (optional)
            <param name="target" value="..."/>*
          </command>
        </action>
        <nav-action .../>*             — pure "go to sheet" navigation
        <edit-group-action .../>*      — "change set values" action
        <edit-parameter-action .../>*  — "change parameter" action
      </actions>

    IMPORTANT: a <link> element does NOT necessarily mean an external URL —
    Tableau reuses the same <link> element for its internal "Sheet Link"
    mechanism (expression starting with "tsl:") when a filter action also
    navigates to another sheet/dashboard. Only expressions starting with
    http:// or https:// are genuine external URL actions. Getting this wrong
    was the actual failure mode caught by checking a real workbook instead of
    only the abstract XSD.

    We deliberately do NOT attempt to auto-wire these into Power BI's
    page-level visual-interactions or button-action JSON — those internal
    Report.json shapes could not be verified with the same confidence as the
    per-visual filter format this engine already proves out elsewhere, and a
    wrong guess in page-level config is a needless risk for a feature that's
    reported clearly instead. Returned here for the audit report / migration
    quality score to surface as specific, actionable recommendations.
    """
    actions_el = root.find('actions')
    if actions_el is None:
        return []

    def _source_info(action_el):
        src = action_el.find('source')
        if src is None:
            return {'type': '', 'dashboard': '', 'worksheet': '', 'exclude_sheets': []}
        return {
            'type':      src.get('type', ''),
            'dashboard': src.get('dashboard', ''),
            'worksheet': src.get('worksheet', ''),
            'exclude_sheets': [e.get('name', '') for e in src.findall('exclude-sheet')],
        }

    def _activation_info(action_el):
        act = action_el.find('activation')
        if act is None:
            return {'type': 'on-select', 'auto_clear': True}
        return {
            'type':       act.get('type', 'on-select'),
            'auto_clear': act.get('auto-clear', 'true').lower() == 'true',
        }

    results = []

    for el in actions_el.findall('action'):
        source = _source_info(el)
        activation = _activation_info(el)
        link = el.find('link')
        command = el.find('command')
        target_sheet = ''
        command_name = ''
        if command is not None:
            command_name = command.get('command', '')
            for p in command.findall('param'):
                if p.get('name') == 'target':
                    target_sheet = p.get('value', '')

        link_expr = link.get('expression', '') if link is not None else ''
        if link is not None and (link_expr.startswith('http://') or link_expr.startswith('https://')):
            category = 'url'
        elif link is not None and link_expr.startswith('tsl:'):
            # Internal Tableau Sheet Link — filter action, possibly also
            # navigating cross-dashboard if target_sheet names a dashboard
            # rather than a worksheet on the same dashboard as the source.
            category = 'navigate_filter' if (target_sheet and target_sheet in dashboard_names) else 'filter'
        elif link is not None:
            category = 'other_link'
        elif command is not None:
            category = 'filter'
        else:
            category = 'unknown'

        results.append({
            'kind':         'action',
            'category':     category,
            'name':         el.get('name', ''),
            'caption':      el.get('caption', el.get('name', '')),
            'enabled':      el.get('enabled', 'true').lower() != 'false',
            'activation':   activation,
            'source':       source,
            'target_sheet': target_sheet,
            'command':      command_name,
            'url':          link_expr if category == 'url' else '',
            'link_caption': link.get('caption', '') if link is not None else '',
        })

    for tag, kind in (('nav-action', 'navigate'), ('edit-group-action', 'change_set'),
                      ('edit-parameter-action', 'change_parameter')):
        for el in actions_el.findall(tag):
            source = _source_info(el)
            activation = _activation_info(el)
            raw_params = {p.get('name', ''): p.get('value', '') for p in el.findall('.//param')}
            results.append({
                'kind':         kind,
                'category':     kind,
                'name':         el.get('name', ''),
                'caption':      el.get('caption', el.get('name', '')),
                'enabled':      el.get('enabled', 'true').lower() != 'false',
                'activation':   activation,
                'source':       source,
                'target_sheet': '',
                'command':      '',
                'url':          '',
                'link_caption': '',
                'params':       raw_params,
            })

    return results


def _zone_attr(z, name: str):
    """
    Read a <zone> (or similar) element's attribute, tolerating Tableau's
    "feature capability" attribute-gating convention where certain
    attributes are stored under a literal PREFIXED key name instead of the
    plain one — e.g. a real zone in HR Analytics.twbx has:

        _.fcp.SetMembershipControl.false...type='filter'
        _.fcp.SetMembershipControl.true...type-v2='filter'

    ElementTree parses these as two attribute keys with the fcp prefix baked
    directly into the key text (confirmed via a raw ET.fromstring().attrib
    test), so a plain z.get('type') returns None and the zone silently
    falls through to whatever branch handles an untyped zone — confirmed as
    a real bug: a Department filter-card zone in HR Analytics.twbx was
    misclassified as a plain chart zone instead of a filter zone because of
    exactly this.

    Scope-checked directly (grepped every <zone> tag across all 10 real
    fixtures, not guessed): only 'type' and 'type-v2' are ever fcp-gated on
    <zone> elements in practice (seen in AB_NYC Dashboard, HR Analytics,
    Sales Param — all saved by a newer Tableau version than the other 7
    fixtures). Other zone attributes (param, mode, show-title, layout) were
    never seen gated this way, so this fallback existing for any attribute
    name is a generalisation to keep the helper reusable, not evidence every
    attribute needs it.

    When both the '.false...' and '.true...' variants are present, prefers
    '.true...' (the newer-capability variant) since that's what a
    capability-aware reader is meant to honor.
    """
    v = z.get(name)
    if v is not None:
        return v
    suffix = '...' + name
    true_val, false_val = None, None
    for k, val in z.attrib.items():
        if not k.endswith(suffix):
            continue
        if k.endswith('true' + suffix):
            true_val = val
        elif k.endswith('false' + suffix):
            false_val = val
    return true_val if true_val is not None else false_val


def _zone_type(z):
    """
    Resolve a <zone>'s effective type, trying both real attribute names
    Tableau uses across save-format versions.

    Schema-verified across all 10 real fixtures (not guessed): 'type' is
    the older attribute name, 'type-v2' the newer one. Some saves emit
    BOTH (always with the same value, confirmed by direct comparison across
    every <zone> in all 10 fixtures — never a conflict), gated behind the
    fcp-prefix convention _zone_attr() already tolerates. But 6 of the 10
    real fixtures (House Sales Dashboard, Netfix Workbook, Amazon Sales
    Insights, LocBar, superstore_profits, superstore_profits_extract) emit
    ONLY 'type-v2', never 'type' at all — _zone_attr(z, 'type') alone
    silently resolves to '' for every typed zone in those files (filter
    zones, text zones, and layout containers all misread as untyped).
    'type' wins when present since it's checked first; 'type-v2' is a
    fallback, not a competing signal.
    """
    return _zone_attr(z, 'type') or _zone_attr(z, 'type-v2') or ''


def _collect_worksheet_style_font(ws_elem, element_name):
    """Scan every <style-rule element='{element_name}'> block under a
    <worksheet> for font-family/font-size/font-weight/font-style/color
    formatting (e.g. element='worksheet' for the general per-worksheet font
    that cascades to axis tick labels, 'legend' for legend text,
    'datalabel' for mark/data-label text — same real attribute names
    already schema-verified for element='title' by Increment 29).

    Tableau can carry multiple style-rule blocks for the same element per
    worksheet (e.g. one per pane); a value is only returned when every
    block that sets that attribute agrees. Real case found while surveying
    the 11 fixtures: Finance Dashboard's 'Revenue vs Profit Margin'
    worksheet has two element='datalabel' blocks with genuinely different
    colors (white and black, for two differently-colored series in one
    combo chart) — Power BI's single per-visual 'labels' color can't
    represent that per-series split, so silently picking one would
    misrepresent the worksheet rather than honestly skip a property PBI
    can't carry. Returns (font_family, font_size, bold, italic, color).
    """
    seen = {'font-family': set(), 'font-size': set(), 'font-weight': set(),
            'font-style': set(), 'color': set()}
    for sr in ws_elem.findall(f'.//style-rule[@element="{element_name}"]'):
        for fmt in sr.findall('format'):
            attr = fmt.get('attr', '')
            val  = (fmt.get('value') or '').strip()
            if val and attr in seen:
                seen[attr].add(val)

    def _agreed(attr):
        vals = seen[attr]
        return next(iter(vals)) if len(vals) == 1 else ''

    font_family = _agreed('font-family')
    weight      = _agreed('font-weight')
    style       = _agreed('font-style')
    color       = _agreed('color')
    font_size = 0
    _size_s = _agreed('font-size')
    if _size_s:
        try:
            font_size = int(float(_size_s))
            # PBI fontSize range is 6-45pt (schema-verified: Power BI Report
            # Theme JSON Schema, definitions.fontSize) — clamp rather than
            # emit an out-of-range value PBI Desktop would reject.
            if not (6 <= font_size <= 45):
                font_size = max(6, min(45, font_size))
        except ValueError:
            font_size = 0
    bold = weight.lower() == 'bold' if weight else False
    italic = style.lower() == 'italic' if style else False
    return font_family, font_size, bold, italic, color


# ── Physical join-tree parsing (classic <relation type='join'>) ─────────────
# Schema-verified against the official Tableau 2026.2 TWB XSD
# (github.com/tableau/tableau-document-schemas, RelationType-ST/
# JoinType-ST/Relation-G groups) — this is Tableau's OLDER datasource
# model (pre-dating the "Relationships" feature Increment 22 already
# handles), used when a datasource joins multiple physical tables into
# ONE flat logical table via an explicit SQL-style join:
#
#   <relation type='join' join='inner|left|right|full'>
#     <clause type='join'>
#       <expression op='='><expression op='[TableA].[Key]'/>
#                           <expression op='[TableB].[Key]'/></expression>
#     </clause>
#     <relation type='table' name='TableA' table='...' connection='...'/>
#     <relation type='table' name='TableB' table='...' connection='...'/>
#   </relation>
#
# Confirmed real in zero of the 11 regression fixtures (all use either a
# single physical table or the newer Relationships model) — this whole
# code path is additive and dormant for every current fixture, gated on
# a workbook actually containing this construct (see ds['_join_tree']
# below). Verified via synthetic ElementTree construction, not a real
# sample — see MIGRATION_ENGINE_PROGRESS.md for the verification method
# and the one specific parsing assumption (join-clause column-qualifier
# format) that could not be checked against a real Tableau export.
def _extract_join_keys(expr_elem):
    """Recursively extract (leftColumn, rightColumn) pairs from a join
    <clause>'s top-level <expression>. SQLExpression-G is fully recursive
    with only an 'op' attribute distinguishing operator vs. operand nodes
    (the same shape already proven for <relationship><expression> parsing
    above) — op='=' with 2 children is a single-column key, op='AND'
    wrapping N op='=' children is a composite key (both forms schema-legal
    per Op-ST, since Tableau join clauses support multi-column join keys).

    ASSUMPTION not verified against a real sample (flagged honestly, per
    this project's standing rule for schema-plausible-but-unconfirmed
    shapes): each operand is assumed to be table-qualified
    ('[TableName].[ColName]', consistent with how Tableau writes field
    references everywhere else in this XML), so only the last bracketed
    segment is kept as the column name. If a real sample ever shows this
    assumption wrong, the caller cross-validates each key against both
    sides' actual known columns and swaps/drops it rather than trusting
    this blindly (see _parse_relation_join_tree's key resolution).
    """
    if expr_elem is None:
        return []
    op = (expr_elem.get('op') or '').strip()
    op_upper = op.upper()
    if op_upper in ('AND', 'INTERSECT'):
        keys = []
        for child in expr_elem.findall('expression'):
            keys.extend(_extract_join_keys(child))
        return keys
    if op == '=':
        children = expr_elem.findall('expression')
        if len(children) != 2:
            return []
        def _col(raw):
            raw = (raw or '').strip()
            # '[TableName].[ColName]' → 'ColName'; bare '[ColName]' → 'ColName'
            return raw.split('.')[-1].strip('[]')
        left_raw  = children[0].get('op', '')
        right_raw = children[1].get('op', '')
        _l, _r = _col(left_raw), _col(right_raw)
        return [(_l, _r)] if _l and _r else []
    return []


def _resolve_join_leaf_connection(rel_elem, nc_map):
    """Build a conn-info-shaped dict for one <relation type='table'> leaf of
    a physical join tree, capturing every real XML attribute generically
    (not a fixed key list) via nc_map — the same named-connection lookup
    pattern already proven in Increment 22's dim-split code — so leaf
    tables can reuse this codebase's existing single-table M-query
    builders (_build_csv_m_query, _build_excel_m_query, every entry in
    _LIVE_DB_BUILDERS) with zero new per-connector code."""
    conn = dict(nc_map.get(rel_elem.get('connection', ''), {}))
    tbl_ref = rel_elem.get('table', '') or ''
    parts = [p.strip('[]') for p in tbl_ref.split('.') if p.strip('[]')]
    if parts:
        conn.setdefault('db_table', parts[-1])
        if len(parts) >= 2:
            conn.setdefault('schema', parts[-2])
        if len(parts) >= 3:
            conn.setdefault('dbname', parts[-3])
    rname = rel_elem.get('name', '') or ''
    import re as _re_jt
    sheet_tab = _re_jt.sub(r'\.(csv|xlsx?|txt|tsv)$', '', rname, flags=_re_jt.I) if rname else ''
    conn.setdefault('sheet_tab', sheet_tab)
    return conn


def _parse_relation_leaf(rel_elem, nc_map):
    """Parse a non-join <relation> (almost always type='table') into a
    join-tree leaf node: {'kind': 'table', 'name': <real table name>,
    'conn': <connection info dict>}. Table-name extraction mirrors the
    already-proven <relation type="table"> canonicalisation used
    elsewhere in this file (metadata-records / _obj_to_table)."""
    import re as _re_jt
    tbl_ref = rel_elem.get('table', '') or rel_elem.get('name', '') or ''
    m = _re_jt.search(r'\[([^\[\]]+?)(?:_[A-F0-9]{32})?\]$', tbl_ref)
    if m:
        name = m.group(1).replace('.csv', '').replace('.CSV', '')
        name = _re_jt.sub(r'[^a-zA-Z0-9 _]', '', name).strip()
    else:
        name = _re_jt.sub(r'[^a-zA-Z0-9 _]', '', rel_elem.get('name', '') or 'Table').strip()
    conn = _resolve_join_leaf_connection(rel_elem, nc_map)
    return {'kind': 'table', 'name': name or 'Table', 'conn': conn}


def _parse_relation_join_tree(rel_elem, nc_map):
    """Recursively parse a <relation type='join'> element into a nested
    dict: {'kind':'join', 'join_type':'inner'|'left'|'right'|'full',
    'keys':[(l,r),...], 'left':<node>, 'right':<node>} down to leaf
    {'kind':'table', 'name':, 'conn':}. Returns None when the shape can't
    be safely reconstructed (missing clause, fewer than 2 child relations,
    no resolvable keys) — callers fall back to today's existing flatten
    behavior rather than emit a guessed/broken join.
    """
    if rel_elem is None or rel_elem.get('type', '') != 'join':
        return _parse_relation_leaf(rel_elem, nc_map)

    join_kind = (rel_elem.get('join') or 'inner').strip().lower()
    if join_kind not in ('inner', 'left', 'right', 'full'):
        join_kind = 'inner'   # schema (JoinType-ST) only allows these 4; safety net only

    clause = rel_elem.find("clause[@type='join']")
    keys = _extract_join_keys(clause.find('expression')) if clause is not None else []

    children = rel_elem.findall('relation')
    if len(children) < 2 or not keys:
        return None
    if len(children) > 2:
        # Schema-atypical: Relation-G's binary shape means a 3+-table join
        # should already be encoded as nested binary <relation type='join'>
        # elements (A join B, then that joined against C), not one join
        # node with 3+ flat <relation> children. Using only the first two
        # is a defensive fallback, not a guess at a 3-way join's semantics.
        log('warn', "[DataModel] join-tree relation has "
                     f"{len(children)} child relations (expected 2) — "
                     "using only the first two; verify the join manually.")

    left  = _parse_relation_join_tree(children[0], nc_map)
    right = _parse_relation_join_tree(children[1], nc_map)
    if left is None or right is None:
        return None

    return {'kind': 'join', 'join_type': join_kind, 'keys': keys, 'left': left, 'right': right}


def parse_tableau_workbook(path: Path) -> dict:
    """
    Parse a .twb (XML) or .twbx (zip containing a .twb) and return a
    normalised description of the workbook's data sources, fields, and
    dashboard sheets that is enough to drive PBIT generation.
    """
    if path.suffix.lower() == '.twbx':
        with zipfile.ZipFile(path) as zf:
            twb_names = [n for n in zf.namelist() if n.endswith('.twb')]
            if not twb_names:
                raise ValueError("No .twb found inside .twbx archive")
            xml_bytes = zf.read(twb_names[0])
    else:
        xml_bytes = path.read_bytes()

    root = ET.fromstring(xml_bytes)
    workbook_name = path.stem

    # ── Data sources ──────────────────────────────────────────────────────────
    #
    # Pre-scan: build a global registry of column elements from every
    # <datasource-dependencies> block in every worksheet.
    #
    # Tableau's column storage has evolved across versions:
    #   • Modern workbooks (v10+): columns declared inside <datasource> at the
    #     top level — the parser's Pass 1/Pass 2 loops pick these up.
    #   • Older workbooks (v9 and below) and some edge cases (live connections,
    #     publish-to-server flows, Databricks TWBs): columns are declared ONLY
    #     inside <datasource-dependencies> blocks inside each <worksheet>.
    #     The datasource element itself has no <column> children.
    #
    # This pre-scan covers ALL datasource types (Excel, CSV, SQL, cloud, live)
    # because the pattern is independent of connection class.
    # We collect unique columns per datasource name; Pass 3 (below) uses this
    # to supplement datasources whose ds-level column list is empty or partial.
    import re as _re_prescan
    _dep_col_registry: dict = {}   # ds_name → {col_name_key: col_element}
    for _ws in root.findall('.//worksheet'):
        for _dep in _ws.findall('.//datasource-dependencies'):
            _ds_ref = _dep.get('datasource', '')
            if not _ds_ref:
                continue
            if _ds_ref not in _dep_col_registry:
                _dep_col_registry[_ds_ref] = {}
            for _col in _dep.findall('column'):
                _cname = _col.get('name', '')
                if _cname and _cname not in _dep_col_registry[_ds_ref]:
                    _dep_col_registry[_ds_ref][_cname] = _col

    datasources = []

    # ── Pre-extract Tableau parameter values ──────────────────────────────────
    # Tableau parameters (datasource name='Parameters') store scalar values used
    # in bin-size calculations, axis ranges, etc.  We extract them into a dict
    # {param_caption → float_value} so that bin calcs can resolve their size
    # without referencing a PBI measure that doesn't exist.
    import re as _re_param_ext
    _param_values: dict = {}   # e.g. {'Parameter 1': 8.0} — numeric only, kept for bin-size resolution (unchanged)
    # Full parameter definitions — schema-verified against the 2026.2 TWB XSD
    # (<column param-domain-type="any|list|range" ...> with a <range min max
    # granularity> child for 'range', or <members><member value alias>...
    # </members> for 'list'). 'range'/'list' domains are enumerable and become
    # real Power BI What-if parameters (table + SELECTEDVALUE measure) in
    # build_data_model_schema; 'any' domain has no enumerable set (e.g. a
    # free-form date parameter) and stays a best-effort inlined literal.
    _tableau_parameters: list = []
    for _pds in root.findall('.//datasource'):
        if 'Parameters' not in _pds.get('name', ''):
            continue
        for _pcol in _pds.findall('.//column'):
            _pcap = (_pcol.get('caption') or _pcol.get('name', '')).strip('[]')
            _pval = _pcol.get('value', '')
            if not _pcap:
                continue
            if _pval:
                try:
                    _param_values[_pcap] = float(_pval)
                except ValueError:
                    pass   # non-numeric current value — fine, captured below instead

            _domain = _pcol.get('param-domain-type', 'any')
            _pdef = {
                'name':        _pcol.get('name', '').strip('[]'),
                'caption':     _pcap,
                'datatype':    _pcol.get('datatype', 'string'),
                'domain_type': _domain,
                'value':       _pval,
                'range':       None,
                'members':     [],
            }
            _range_el = _pcol.find('range')
            if _domain == 'range' and _range_el is not None:
                _pdef['range'] = {
                    'min':         _range_el.get('min'),
                    'max':         _range_el.get('max'),
                    'granularity': _range_el.get('granularity'),
                    'period_type': _range_el.get('period-type-v2'),
                }
            _members_el = _pcol.find('members')
            if _domain == 'list' and _members_el is not None:
                _pdef['members'] = [
                    {'value': m.get('value', ''), 'alias': m.get('alias', '')}
                    for m in _members_el.findall('member')
                ]
            _tableau_parameters.append(_pdef)

    for ds in root.findall('.//datasource'):
        ds_name = ds.get('name', '')
        if ds_name in ('Parameters',):
            continue
        caption = ds.get('caption', ds_name)

        columns = []
        seen_col_names: set = set()   # deduplicate by internal name within this ds

        def _add_column(col):
            """Parse one <column> element and append to columns if not yet seen."""
            col_name = col.get('name', '').strip('[').strip(']')
            # Skip pseudo-columns, empty names, and columns that start with __
            if not col_name or col_name.startswith(':') or col_name.startswith('__'):
                return
            # Deduplicate by internal name
            if col_name.lower() in seen_col_names:
                return
            # Skip calculated fields — handled separately below
            if col.find('calculation') is not None:
                return

            col_caption = col.get('caption', col_name)
            datatype    = col.get('datatype', 'string')
            role        = col.get('role', 'dimension')
            col_type    = col.get('type', 'nominal')
            hidden      = col.get('hidden', 'false').lower() == 'true'

            pbi_type = {
                'integer': 'int64',
                'real':    'double',
                'string':  'string',
                'date':    'date',      # Kept as 'date'; PBI TOM converts to 'dateTime'
                                        # in build_data_model_schema, while _pbi_m_type
                                        # correctly emits 'date' in the M type table so
                                        # #date() literals load without a type mismatch.
                'datetime':'dateTime',
                'boolean': 'boolean',
            }.get(datatype, 'string')

            seen_col_names.add(col_name.lower())
            # ── Geographic data category from Tableau semantic-role ────────────
            # Tableau marks geographic dimension columns with a semantic-role
            # attribute, e.g. semantic-role="[Country].[ISO3166_2]".
            # We extract the bracket-prefix and map it to the PBI TOM
            # 'dataCategory' value so filledMap and map visuals can geocode.
            import re as _re_sr
            _semantic_role = col.get('semantic-role', '')
            _sr_prefix_m   = _re_sr.match(r'\[([^\]]+)\]', _semantic_role)
            _sr_prefix     = _sr_prefix_m.group(1) if _sr_prefix_m else ''
            _GEO_CATEGORY  = {
                'Country':     'Country',
                'State':       'StateOrProvince',
                'City':        'City',
                'ZipCode':     'PostalCode',
                'PostalCode':  'PostalCode',
                'Continent':   'Continent',
                'County':      'County',
                'NUTS Europe': 'StateOrProvince',
                'Latitude':    'Latitude',
                'Longitude':   'Longitude',
            }
            _geo_category = _GEO_CATEGORY.get(_sr_prefix, '')
            # Is this field genuinely referenced by some worksheet (present in
            # the datasource-dependencies pre-scan below), as opposed to only
            # being a raw physical-schema descriptor picked up by Pass 2's
            # recursive `.//column` scan (e.g. a <relation><columns><column>
            # entry describing a joined sub-table's own sheet layout, never
            # dragged onto any shelf)? Used later (build_data_model_schema)
            # to tell a genuinely-unused cross-table schema leak (safe to
            # drop from the flat/fact table — it can never be produced by
            # that table's own M query anyway) apart from a field a
            # worksheet actually uses (left alone, unchanged from prior
            # behaviour, to avoid creating a dangling visual reference).
            _ws_used = f'[{col_name}]' in _dep_col_registry.get(ds_name, {})
            columns.append({
                'name':        col_caption or col_name,
                'source_name': col_name,
                'datatype':    pbi_type,
                'role':        role,
                'hidden':      hidden,
                'measure':     col_type == 'quantitative' and role == 'measure',
                'tableau_format': col.get('default-format', ''),
                '_worksheet_used': _ws_used,
                **({'geo_category': _geo_category} if _geo_category else {}),
            })

        # Pass 1: direct child <column> elements — these carry the Tableau captions
        # (e.g. PaymentMethod → 'Payment Method') and must be processed FIRST so
        # their captions win over the raw CSV names in nested relation/columns.
        for col in ds:
            if col.tag == 'column':
                _add_column(col)

        # Pass 2: any remaining columns from nested elements (relation headers, etc.)
        # that weren't already added in pass 1.
        for col in ds.findall('.//column'):
            _add_column(col)

        # Pass 3: supplement from worksheet <datasource-dependencies> registry.
        # This handles workbooks (typically v9 or older, or certain live/cloud
        # datasource formats) where the real data columns are declared only inside
        # worksheet-level <datasource-dependencies> blocks and never appear as
        # <column> children of the <datasource> element itself.
        # We add any column from the registry whose internal name is not already
        # known, using _add_column so all existing guards (dedup, hidden, calc
        # skip) still apply.  Datasource-level columns always win (Pass 1/2
        # ran first), so this only fills genuine gaps.
        for _dep_cname, _dep_col in _dep_col_registry.get(ds_name, {}).items():
            _add_column(_dep_col)

        # Extract connection info
        # Tableau uses several connection structures:
        # Simple:    <datasource><connection class="excel-direct" filename="..." /></datasource>
        # Federated: <datasource><connection class="federated">
        #                <named-connections><named-connection>
        #                    <connection class="excel-direct" filename="..." />
        #                </named-connection></named-connections>
        #            </connection></datasource>
        # In both cases we want the innermost non-federated connection for filename etc.
        connection = ds.find('.//connection')
        conn_info = {}
        if connection is not None:
            conn_info = {
                'class':                  connection.get('class', ''),
                'filename':               connection.get('filename', ''),
                'server':                 connection.get('server', ''),
                'dbname':                 connection.get('dbname', ''),
                'schema':                 connection.get('schema', ''),
                # Live-DB / cloud connector fields
                'port':                   connection.get('port', ''),
                'username':               connection.get('username', ''),
                'authentication':         connection.get('authentication', ''),
                'authentication-type':    connection.get('authentication-type', ''),
                # Databricks-specific
                'v-http-path':            connection.get('v-http-path', ''),
                'odbc-connect-string-extras': connection.get('odbc-connect-string-extras', ''),
                'one-time-sql':           connection.get('one-time-sql', ''),
                'workgroup-auth-mode':    connection.get('workgroup-auth-mode', ''),
                # Snowflake-specific
                'warehouse':              connection.get('warehouse', ''),
                'role':                   connection.get('role', ''),
                # SQL Server / generic
                'sslmode':                connection.get('sslmode', ''),
            }
            # For federated datasources, pull the real connection from named-connections
            named = connection.find('named-connections/named-connection/connection')
            if named is not None:
                # Merge ALL XML attributes from the inner (non-federated) connection,
                # letting them override the outer federated-shell values where present.
                # Using named.attrib directly (instead of a fixed key list) ensures
                # that any connector-specific attribute — including future cloud
                # connectors and non-standard properties — is captured automatically.
                for attr_key, attr_val in named.attrib.items():
                    if attr_val:               # only override when attr is non-empty
                        conn_info[attr_key] = attr_val

        # Fix 2: Legacy non-federated connections (class='excel', 'csv', 'text-file',
        # 'mdb', etc.) do not store the filename as a connection attribute — they were
        # the original Tableau connection format before the federated wrapper was
        # introduced.  The datasource name attribute carries the filename in the form:
        #   "DatasetTitle (actual_filename.xlsx)"
        # When filename is still empty after processing the connection, extract it from
        # the datasource name.  This applies generically to any connection class that
        # lacks an explicit filename attribute (Excel, CSV, Access, OData, etc.).
        if not conn_info.get('filename'):
            import re as _re_fname
            _m_fname = _re_fname.search(
                r'\(([^()]+\.(xlsx?|xlsm|csv|tsv|txt|mdb|accdb|json|xml|odata))\)\s*$',
                ds_name, _re_fname.I
            )
            if _m_fname:
                conn_info['filename'] = _m_fname.group(1)

        # Capture custom SQL text from the <relation type="text"> child if present.
        # Custom SQL replaces the normal table navigation with a raw query.
        import re as _re_conn
        custom_sql = ''
        for rel in ds.findall('.//relation'):
            if rel.get('type') == 'text':
                custom_sql = (rel.text or '').strip()
                if custom_sql:
                    break
        conn_info['custom_sql'] = custom_sql

        # Capture the table name from a <relation type="table"> if available.
        # This is the physical fully-qualified table name: [catalog].[schema].[table]
        db_table = ''
        for rel in ds.findall('.//relation'):
            if rel.get('type') == 'table':
                raw_tbl = rel.get('table', '')   # e.g. [samples].[bakehouse].[sales_suppliers]
                # Strip square brackets and split into parts
                parts = [p.strip('[]') for p in raw_tbl.split('.') if p.strip('[]')]
                if parts:
                    db_table = parts[-1]          # physical table name
                    # Override schema/dbname from relation if not already set
                    if len(parts) >= 2 and not conn_info.get('schema'):
                        conn_info['schema'] = parts[-2]
                    if len(parts) >= 3 and not conn_info.get('dbname'):
                        conn_info['dbname'] = parts[-3]
                break
        conn_info['db_table'] = db_table

        # Extract sheet tab name from <relation> elements.
        # In federated workbooks <relation> is a DIRECT child of <datasource> (not
        # of <connection>), referencing the named-connection by @connection attr.
        # In simple workbooks it may be a direct child of <connection>.
        # We check all three locations and use the first non-empty match.
        import re as _re

        def _extract_sheet_tab(rel_el):
            """Pull the sheet name from a <relation> element, stripping $ suffix."""
            if rel_el is None:
                return ''
            rel_name  = rel_el.get('name', '')   # e.g. "HR data" or "Census Data$"
            rel_table = rel_el.get('table', '')  # e.g. "['HR data$']"
            raw = rel_name or _re.sub(r"[\[\]']", '', rel_table.split('$')[0])
            cleaned = _re.sub(r'\$_?$', '', raw).strip()
            return cleaned

        sheet_tab = ''
        # 1. <relation> as direct child of <datasource> (federated Tableau workbooks)
        for rel in ds.findall('relation'):
            sheet_tab = _extract_sheet_tab(rel)
            if sheet_tab:
                break
        # 2. <relation> under <connection> (simple / older workbooks)
        _named_conn = (connection.find('named-connections/named-connection/connection')
                       if connection is not None else None)
        if not sheet_tab and connection is not None:
            for conn_el in ([connection] +
                            ([] if _named_conn is None else [_named_conn])):
                rel = conn_el.find('relation')
                t = _extract_sheet_tab(rel)
                if t:
                    sheet_tab = t
                    break
        # 3. Recursive search anywhere in <datasource> as last resort
        if not sheet_tab:
            for rel in ds.findall('.//relation'):
                t = _extract_sheet_tab(rel)
                if t and t != 'Extract':   # skip Tableau extract placeholder
                    sheet_tab = t
                    break

        conn_info['sheet_tab'] = sheet_tab

        # Text-connection locale (schema-verified real signal, e.g.
        # <columns character-set='UTF-8' header='yes' locale='en_IN'
        # separator='\t'> — confirmed real on 3 of 11 fixtures: AB_NYC
        # Dashboard, HR Analytics, Netfix Workbook). Used generically (not
        # workbook-specific) to resolve ambiguous D/M-vs-M/D string dates
        # correctly instead of always assuming US month-first — see
        # _date_value_to_m_literal's day_first parameter. Locale absent
        # (the other 8 fixtures) preserves today's existing US-first
        # default exactly — this is additive, not a behavior change for
        # workbooks with no locale signal.
        _cols_el = ds.find('.//columns[@locale]')
        conn_info['locale'] = _cols_el.get('locale', '') if _cols_el is not None else ''

        # Calculated fields / measures.
        # Also build calc_caption_map: internal_name -> caption so that
        # formulas referencing [Calculation_XXXXXXXXX] get resolved to their
        # human-readable caption before DAX translation.
        calculations = []
        calc_caption_map = {}
        for col in ds.findall('.//column'):
            calc = col.find('calculation')
            if calc is not None:
                formula     = calc.get('formula', '')
                calc_class  = calc.get('class', '')
                col_name    = col.get('name', '').strip('[').strip(']')
                col_caption = col.get('caption', col_name)
                # Map internal name -> caption for ALL calc columns
                if col_caption and col_caption != col_name:
                    calc_caption_map[col_name] = col_caption
                # ── categorical-bin: Tableau string grouping ──────────────────
                # Tableau class="categorical-bin" groups distinct string values of
                # a dimension (or combined field) into named buckets. Unlike
                # numeric bins (class="bin"), these have NO formula attribute —
                # the grouping is in <bin> children. We handle this BEFORE the
                # 'if formula:' guard, which would silently drop these columns.
                if calc_class == 'categorical-bin' and not formula:
                    import re as _re_cb
                    raw_cap_cb     = col_caption or col_name
                    pbi_name_cb    = raw_cap_cb
                    src_col_cb     = calc.get('column', '').strip('[').strip(']')
                    src_display_cb = calc_caption_map.get(src_col_cb, src_col_cb)
                    default_cb     = calc.get('default', '"Other"').strip('"')
                    bins_cb = []
                    for bin_el in calc.findall('bin'):
                        bin_label = bin_el.get('value', '').strip('"')
                        members_cb = [(val_el.text or '').strip()
                                      for val_el in bin_el.findall('value')]
                        if bin_label and members_cb:
                            bins_cb.append({'label': bin_label, 'members': members_cb})
                    if bins_cb or default_cb:
                        calculations.append({
                            'name':               pbi_name_cb,
                            'formula':            '',
                            'is_categorical_bin': True,
                            'catbin_source':      src_col_cb,
                            'catbin_source_disp': src_display_cb,
                            'catbin_bins':        bins_cb,
                            'catbin_default':     default_cb,
                            'is_agg_calc':        False,
                        })
                        if pbi_name_cb.lower() not in seen_col_names:
                            seen_col_names.add(pbi_name_cb.lower())
                        calc_caption_map[col_name] = pbi_name_cb
                    continue   # handled — skip formula-based path below

                if formula:
                    # Normalize bin calc display name: 'Tenure (bin)' → 'Tenure (Bin)'
                    import re as _re_bname
                    raw_cap  = col_caption or col_name
                    # The entry name stays as-is for non-bin calcs.
                    # For bin calcs we normalise to PBI convention below.
                    norm_cap = raw_cap
                    entry = {
                        'name':    norm_cap,
                        'formula': formula,
                        'tableau_format': col.get('default-format', ''),
                    }
                    # The bin size comes from either:
                    #   a) size-parameter: a Tableau parameter (look up its value)
                    #   b) size attribute: a literal number on the <calculation> element
                    # We resolve the actual NUMERIC value here so the schema builder
                    # can embed it directly in DAX (avoids referencing a non-existent
                    # PBI measure named after the Tableau parameter).
                    if calc_class == 'bin':
                        import re as _re_bp
                        _bin_size_val = None
                        # Try size-parameter first (most common)
                        size_param = calc.get('size-parameter', '')
                        if size_param:
                            param_m = _re_bp.match(
                                r'\[Parameters\]\.\[(.+?)\]', size_param, _re_bp.I
                            )
                            param_name = (param_m.group(1) if param_m
                                          else size_param.strip('[').strip(']'))
                            # Look up the actual numeric value from _param_values
                            _bin_size_val = _param_values.get(param_name)
                            if _bin_size_val is None:
                                for k, v in _param_values.items():
                                    if k.lower() == param_name.lower():
                                        _bin_size_val = v
                                        break
                        # Fall back to direct 'size' attribute
                        if _bin_size_val is None:
                            _direct = calc.get('size', '').strip()
                            if _direct:
                                try:
                                    _bin_size_val = float(_direct)
                                except ValueError:
                                    print(f"[DEBUG except] line ~1445: exception caught")
                                    pass
                        if _bin_size_val is None or _bin_size_val <= 0:
                            _bin_size_val = 1.0

                        # PBI convention: bin columns are named "{source} (bins)".
                        # Normalise (bin)/(Bin) → (bins) so PBI recognises the group.
                        # ONLY apply this renaming for actual bin calcs.
                        bin_display_name = _re_bname.sub(
                            r'\(bin\)', '(bins)', raw_cap, flags=_re_bname.I
                        )
                        if '(bins)' not in bin_display_name.lower():
                            bin_display_name = bin_display_name.rstrip() + ' (bins)'
                        entry['name']             = bin_display_name
                        entry['is_bin_calc']      = True
                        entry['bin_source']       = col_caption or col_name
                        entry['bin_source_raw']   = formula.strip('[').strip(']')
                        entry['bin_size']         = float(_bin_size_val)
                        # Keep the original Tableau name so the layout builder can
                        # match it against shelf references (e.g. "Tenure (bin)").
                        entry['bin_tableau_name'] = raw_cap
                    # RC1: Mark Tableau set-action synthetic calculations.
                    # These are named "Action (Field)" or "Action (Field1,Field2)" and
                    # represent interactive filter/highlight states — they are never real
                    # data values and must not appear as chart Y-axis measures.
                    import re as _re_action
                    _raw_cap = col_caption or col_name
                    if _re_action.match(r'^Action\s*\(', _raw_cap, _re_action.I):
                        entry['is_action_calc'] = True
                    calculations.append(entry)

        # ── Two-pass classification: Measure vs Calculated Column ─────────────
        # Pass 1 — formula-level: does the formula itself use aggregation?
        for calc in calculations:
            if calc.get('is_bin_calc'):
                calc['is_agg_calc'] = False   # bins always become calc columns
                continue
            if calc.get('is_categorical_bin'):
                calc['is_agg_calc'] = False   # categorical bins → calc columns
                continue
            calc['is_agg_calc'] = _is_aggregating_formula(calc.get('formula', ''))

        # Pass 2 — dependency propagation: a row-level calc that references
        # another calc that IS a measure must also be a measure in DAX, because
        # DAX calculated columns cannot reference measures.
        # We iterate to fixpoint (handles chains: A→B→C where C is a measure).
        agg_names = {c['name'] for c in calculations if c.get('is_agg_calc')}
        changed = True
        while changed:
            changed = False
            for calc in calculations:
                if calc.get('is_agg_calc'):
                    continue   # already a measure
                formula = calc.get('formula', '')
                # Check if this formula references any known measure by name
                for mname in agg_names:
                    if (f'[{mname}]' in formula
                            or f'[{mname.strip()}]' in formula):
                        calc['is_agg_calc'] = True
                        agg_names.add(calc['name'])
                        changed = True
                        break
        # Tableau <group> elements represent two distinct constructs:
        #
        # A) COMBINED FIELD (crossjoin) — created by shift-clicking 2+ dimensions
        #    in the Fields pane: "Create Combined Field". The group uses
        #    function="crossjoin" with child function="level-members" groupfilters.
        #    This is NOT a boolean set — it is a new derived DIMENSION whose value
        #    is the concatenation of its component dimensions (e.g. "Region 1 - Arkansas").
        #    → Translate to a DAX calculated COLUMN: [Dim1] & " - " & [Dim2]
        #
        # B) BOOLEAN SET — created via right-click → Create Set. Uses
        #    function="member" groupfilters or complex groupfilter expressions.
        #    Referenced in formulas as a boolean condition: IF [SetName] THEN ...
        #    → Translate to a DAX MEASURE: [col] = "value" (or FALSE() for complex sets)
        #
        import re as _re_set
        _drill_paths_ds: list = []   # collect for this datasource

        # Name → <group> element, for resolving named-set references inside
        # combined (union/intersection) Sets regardless of XML source order.
        _group_by_name = {
            g.get('name', '').strip('[').strip(']'): g for g in ds.findall('./group')
        }

        for grp in ds.findall('./group'):
            grp_raw     = grp.get('name', '').strip('[').strip(']')
            grp_caption = grp.get('caption', grp_raw)
            if not grp_raw:
                continue
            # RC1: Skip set-action groups — named "Action (Field)", interactive only
            if _re_set.match(r'^Action\s*\(', grp_caption, _re_set.I):
                continue
            # Tableau also serializes the internal scaffolding for a
            # continuous-field Filter-card widget (e.g. a month/date slider)
            # as a <group> — never a real user-visible Set. Confirmed against
            # a real sample (House Sales Dashboard's "MY(Date) Set" group,
            # marked user:ui-builder="filter-group", never referenced anywhere
            # else in the workbook) rather than guessed from the XSD alone.
            if grp.get('{http://www.tableausoftware.com/xml/user}ui-builder') == 'filter-group':
                continue

            # ── Detect crossjoin (Combined Field) ─────────────────────────────
            # A crossjoin group has exactly one top-level groupfilter with
            # function="crossjoin", whose children have function="level-members".
            # These are NOT boolean sets — they define a new concatenated dimension.
            _top_gf = grp.find('groupfilter')
            _is_crossjoin = (_top_gf is not None
                             and _top_gf.get('function', '') == 'crossjoin')
            if _is_crossjoin:
                # Extract the component dimension names from level-members children
                _levels = []
                for _lgf in _top_gf.findall('groupfilter[@function="level-members"]'):
                    _lvl_raw = _lgf.get('level', '').strip('[').strip(']')
                    # Strip Tableau prefix like "[none:Field:nk]" → "Field"
                    import re as _re_lvl
                    _m_lvl = _re_lvl.match(
                        r'^(?:none|sum|avg|min|max|attr):\s*(.+?)\s*(?::[a-z]{2})?$',
                        _lvl_raw, _re_lvl.I
                    )
                    _lvl_clean = _m_lvl.group(1) if _m_lvl else _lvl_raw
                    # Resolve via caption map
                    _lvl_display = calc_caption_map.get(_lvl_clean, _lvl_clean)
                    if _lvl_display:
                        _levels.append(_lvl_display)

                if _levels:
                    # DAX: concatenate with " - " separator
                    # Use & operator matching PBI's native Combined Field behaviour
                    _concat_parts = [f"'{table_name_placeholder}'[{l}]"
                                     if False else f"[{l}]"
                                     for l in _levels]
                    _dax_concat = ' & " - " & '.join(f'[{l}]' for l in _levels)
                    # Register as a calculated column entry (not a measure)
                    calculations.append({
                        'name':             grp_raw,
                        'formula':          _dax_concat,
                        '_is_combined_field': True,
                        'is_agg_calc':      False,   # row-level, goes to calc columns
                        '_combined_levels': _levels,
                    })
                    if grp_raw.lower() not in seen_col_names:
                        seen_col_names.add(grp_raw.lower())
                    calc_caption_map[grp_raw] = grp_raw
                continue   # crossjoin group fully handled — don't fall through to set logic

            # ── Boolean Set ───────────────────────────────────────────────────
            # Register the name so formula references can resolve correctly.
            # (Bug fix: this used to map/emit the internal grp_raw name for
            # both the caption map AND the calc's display name. A Set renamed
            # after creation keeps its original internal `name` in the XML —
            # only `caption` updates — so this silently surfaced the stale
            # internal name in Power BI instead of what the user renamed it
            # to in Tableau's Sets pane. Every other calc kind in this file
            # already prefers caption; this branch just hadn't matched that.)
            if grp_raw.lower() not in seen_col_names:
                seen_col_names.add(grp_raw.lower())
            calc_caption_map[grp_raw] = grp_caption

            # Build a Tableau-syntax boolean formula for this set — recognises
            # member / except / union / intersection / named-set / filter
            # (condition-based) / order (Top-N) / range groupfilter shapes;
            # anything else falls back to the existing explicit FALSE().
            set_formula = _resolve_set_groupfilter(_top_gf, _group_by_name, calc_caption_map)
            if not set_formula:
                safe_cap = _re_set.sub(r'[^A-Za-z0-9 _-]', '', grp_caption)
                set_formula = (
                    f'FALSE() /* Tableau set "{safe_cap}" — '
                    'implement set membership logic manually */'
                )
            calculations.append({
                'name':    grp_caption,
                'formula': set_formula,
                '_is_set': True,
            })

        # ── Parse <drill-path> elements → PBI hierarchy definitions ───────────
        # A Tableau <drill-path> defines a named drill-down sequence (hierarchy).
        # Each <field> child is one level, ordered from coarsest to finest.
        # We store these on the datasource so the schema builder can emit a
        # "hierarchies" array in the TOM table object.
        import re as _re_dp
        for dp in ds.findall('.//drill-path'):
            dp_name   = dp.get('name', '').strip()
            dp_fields = []
            for field_el in dp.findall('field'):
                raw = (field_el.text or '').strip().strip('[').strip(']')
                if not raw:
                    continue
                # Strip datasource prefix [ds].[field] → field
                _m_dp = _re_dp.match(r'^[^.]+\.\[?(.+?)\]?$', raw)
                raw = _m_dp.group(1) if _m_dp else raw
                # Resolve via caption map
                display = calc_caption_map.get(raw, raw)
                if display:
                    dp_fields.append(display)
            if dp_name and len(dp_fields) >= 2:
                _drill_paths_ds.append({
                    'name':   dp_name,
                    'levels': dp_fields,   # ordered list of column display names
                })

        # Deduplicate: skip this datasource if we already have one with the same
        # underlying file/connection AND the same column fingerprint.
        # Tableau often creates one datasource per worksheet using the same file,
        # resulting in 10 identical entries that produce 10 ghost PBI tables.
        ds_file_key = (
            conn_info.get('filename', '').lower().strip(),
            conn_info.get('dbname', '').lower().strip(),
            conn_info.get('server', '').lower().strip(),
        )
        col_key = tuple(sorted(c['name'].lower() for c in columns))
        dedup_key = (ds_name.lower(), ds_file_key, col_key)
        if any(d.get('_dedup_key') == dedup_key for d in datasources):
            continue  # exact duplicate — skip

        # Also skip if we already have a datasource with the same raw_name
        # (Tableau sometimes emits both caption-named and internal-named entries
        # for the same connection; the later empty-columns one is the skeleton).
        if any(d.get('raw_name', '').lower() == ds_name.lower() for d in datasources):
            continue

        datasources.append({
            'name': caption,
            'raw_name': ds_name,
            'original_sheet': caption or ds_name,
            'connection': conn_info,
            'columns': columns,
            'calculations': calculations,
            'calc_caption_map': calc_caption_map,
            'drill_paths': _drill_paths_ds,   # list of {name, levels} for PBI hierarchies
            '_dedup_key': dedup_key,
        })

    # ── Dashboards / sheets ───────────────────────────────────────────────────
    dashboards = []
    stories = []
    for dash in root.findall('.//dashboard'):
        dash_name = dash.get('name', 'Dashboard')

        # Tableau represents a Story as a <dashboard type="storyboard"> whose
        # only real content is a nested <flipboard><story-points> sequence
        # (schema-verified via the 2026.2 TWB XSD: Dashboard-DashboardType-ST,
        # StoryPoint-G — each <story-point> has `captured-sheet`, pointing at
        # a worksheet name, and an optional `caption`). Previously this fell
        # through to the generic zone-collection code below, which has no
        # carve-out for the 'flipboard' zone type — its `name` doesn't
        # reference a real worksheet, so it would silently produce an empty
        # or broken visual instead of being recognised as a Story. Parsed
        # separately here and excluded from the regular dashboard-page list.
        if dash.get('type') == 'storyboard':
            _story_points = []
            for sp in dash.findall('.//story-point'):
                _sheet = sp.get('captured-sheet', '').strip('[').strip(']')
                if not _sheet:
                    continue
                try:
                    _sp_id = int(sp.get('id', '0'))
                except ValueError:
                    _sp_id = 0
                _story_points.append({
                    'id':      _sp_id,
                    'sheet':   _sheet,
                    'caption': sp.get('caption', '').strip(),
                })
            _story_points.sort(key=lambda p: p['id'])
            if _story_points:
                stories.append({'name': dash_name, 'points': _story_points})
            continue

        size_el = dash.find('size')

        def _szattr(el, *attrs, default=0):
            if el is None: return default
            for a in attrs:
                v = el.get(a)
                if v is not None:
                    try: return int(float(v))
                    except ValueError: pass
            return default

        actual_w = _szattr(size_el, 'maxwidth',  'maxw',  default=1280)
        actual_h = _szattr(size_el, 'maxheight', 'maxh',  default=720)
        COORD_MAX = 100_000  # Tableau zone coords: 0-100000 → actual pixels

        _skip_types = {'color','bitmap','empty','blank','tab-navigation',
                       'legend','highlighter'}
        chart_zones = []; filter_zones = []; parameter_zones = []; text_zones = []
        seen_chart  = set(); seen_filter = set(); seen_param = set()

        def _collect_zone(z):
            zn = z.get('name',''); zt = _zone_type(z)
            try:
                rx=int(float(z.get('x',0))); ry=int(float(z.get('y',0)))
                rw=int(float(z.get('w',0))); rh=int(float(z.get('h',0)))
            except (ValueError,TypeError): rx=ry=rw=rh=0
            # Dashboard Text Object zones (schema-verified <zone type='text'>,
            # real on Finance Dashboard — 6 real section-header captions).
            # Unlike every other zone kind, these NEVER carry a 'name'
            # attribute (confirmed across all 10 fixtures), so they can't
            # go through the zn-gated block below at all — handled here,
            # first, keyed by position/traversal order rather than name.
            if zt == 'text' and rw > 0 and rh > 0:
                px_tx=int(rx*actual_w/COORD_MAX); px_ty=int(ry*actual_h/COORD_MAX)
                px_tw=max(1,int(rw*actual_w/COORD_MAX))
                px_th=max(1,int(rh*actual_h/COORD_MAX))
                _runs = []
                _ft = z.find('formatted-text')
                if _ft is not None:
                    for _run in _ft.findall('run'):
                        _rtext = (_run.text or '').strip()
                        if not _rtext:
                            continue
                        _runs.append({
                            'text': _rtext,
                            'bold': _run.get('bold', 'false').lower() == 'true',
                            'italic': _run.get('italic', 'false').lower() == 'true',
                            'underline': _run.get('underline', 'false').lower() == 'true',
                            'fontname': _run.get('fontname', ''),
                            'fontsize': _run.get('fontsize', ''),
                            # fontalignment is xs:int in the schema with no
                            # documented enum (verified: 2026.2 TWB XSD only
                            # types it as a bare int) — every real occurrence
                            # across all 10 fixtures is '1'. Mapped using the
                            # ordinary left/center/right ordinal convention
                            # (0/1/2); not schema-proven, low-risk (a wrong
                            # guess just leaves text at PBI's default left
                            # alignment, no broken visual).
                            'fontalignment': _run.get('fontalignment', ''),
                            'fontcolor': _run.get('fontcolor', ''),
                        })
                _zs_bg = ''
                _zs = z.find('zone-style')
                if _zs is not None:
                    _bgfmt = _zs.find('format[@attr="background-color"]')
                    if _bgfmt is not None:
                        _bg = (_bgfmt.get('value') or '').strip()
                        if _bg and _bg.lower() not in ('#ffffff', '#fff', 'white') and not (
                                len(_bg) == 9 and _bg.lower().endswith('00')):
                            _zs_bg = _bg[:7] if len(_bg) == 9 else _bg
                if _runs:
                    text_zones.append({
                        'x': px_tx, 'y': px_ty, 'w': px_tw, 'h': px_th,
                        'runs': _runs, 'background_color': _zs_bg,
                    })
            if zn and rw>0 and rh>0 and zt not in _skip_types:
                px_x=int(rx*actual_w/COORD_MAX); px_y=int(ry*actual_h/COORD_MAX)
                px_w=max(1,int(rw*actual_w/COORD_MAX))
                px_h=max(1,int(rh*actual_h/COORD_MAX))
                # show-title: schema-verified Tableau zone attribute — a dashboard
                # author can hide a specific worksheet's title bar per zone
                # instance (common when a text zone already labels the area).
                # Previously ignored entirely — every zone always got a forced-on
                # title in the generated PBIT regardless of this setting.
                _show_title = z.get('show-title', 'true').strip().lower() != 'false'
                # Zone container border — schema-verified real signal
                # (<zone-style><format attr='border-style'/'border-color'/
                # 'border-width'>), confirmed real on HR Analytics (every
                # real chart/multiRowCard zone in the 'HR Analytics'
                # dashboard has an explicit 1px solid black border Tableau
                # would otherwise silently lose). Only emit when Tableau
                # explicitly declares a VISIBLE border (style != 'none') —
                # border-color defaults to '#000000' as inert placeholder
                # metadata even on invisible borders across every fixture,
                # so color/width alone are not a real signal, only style is.
                _zb_color, _zb_width = '', 1.0
                _zs_b = z.find('zone-style')
                if _zs_b is not None:
                    _bstyle_el = _zs_b.find('format[@attr="border-style"]')
                    if _bstyle_el is not None and (_bstyle_el.get('value') or '').strip().lower() not in ('', 'none'):
                        _bcolor_el = _zs_b.find('format[@attr="border-color"]')
                        _bwidth_el = _zs_b.find('format[@attr="border-width"]')
                        _zb_color = (_bcolor_el.get('value') or '#000000').strip() if _bcolor_el is not None else '#000000'
                        try:
                            _zb_width = float((_bwidth_el.get('value') or '1').strip()) if _bwidth_el is not None else 1.0
                        except ValueError:
                            _zb_width = 1.0
                entry={'name':zn,'type':zt,'x':px_x,'y':px_y,'w':px_w,'h':px_h,
                       'show_title':_show_title,
                       'border_color':_zb_color, 'border_width':_zb_width}
                if zt=='filter':
                    # Schema-verified: a filter zone's own 'param' attribute names
                    # the EXACT field being filtered (e.g.
                    # '[federated.xxx].[none:Department:nk]') and 'mode' names its
                    # display style ('dropdown' = single-select, 'checkdropdown' =
                    # multi-select checklist). Both were previously ignored — the
                    # renderer instead guessed the filtered field from the
                    # worksheet's x_field (often empty, e.g. for a card/KPI
                    # worksheet) or the first non-measure column in the
                    # datasource, which is unrelated to the real filtered field.
                    # Confirmed wrong on a real sample: HR Analytics' "KPI"
                    # dashboard filter zone has param=[...].[none:Department:nk]
                    # but the "KPI" worksheet (a multiRowCard, no rows/cols
                    # shelf) has an empty x_field, so the old guess fell through
                    # to the datasource's first non-measure column, 'Attrition'
                    # — a completely different field. Raw values captured here;
                    # resolved to a clean field name below once _clean_field_name
                    # and global_calc_caption_map exist (both defined after this
                    # per-dashboard loop finishes, not available yet in this scope).
                    entry['filter_param'] = z.get('param', '')
                    entry['filter_mode']  = z.get('mode', '')
                    if zn not in seen_filter: seen_filter.add(zn); filter_zones.append(entry)
                elif zt=='parameter':
                    # <zone type="parameter" param="[Parameter 1]" ...> — schema-verified
                    # (Zone-G's 'param' attribute) — names the Tableau parameter this
                    # control shows. Rendered as a slicer bound to the matching
                    # What-if parameter table built in build_data_model_schema.
                    _pname = z.get('param', '').strip('[]')
                    if zn not in seen_param:
                        seen_param.add(zn)
                        parameter_zones.append({**entry, 'param': _pname})
                elif zt=='':
                    if zn not in seen_chart: seen_chart.add(zn); chart_zones.append(entry)
            for child in z:
                if child.tag=='zone': _collect_zone(child)

        zones_root = dash.find('zones')
        if zones_root is not None:
            for z in zones_root: _collect_zone(z)

        # ── Stage 3 / Priority 2: Layout Tree Engine ──────────────────────────
        # Build a recursive layout tree preserving container hierarchy so the
        # rendering engine can distribute space per container type instead of
        # relying on raw Tableau absolute coordinates.
        #
        # 'layout-basic'/'layout-flow' are kept in the skip set DELIBERATELY,
        # not because they're rare — they are schema-verified as the ONLY
        # real container zone types across all 10 fixtures, universally
        # replacing the older <layout type='.../> child-element form this
        # function was originally written against (zero real fixtures use
        # that form). Investigated unlocking them (routing 'layout-flow'
        # through a real horizontal/vertical split via its own 'param'
        # attribute, and letting 'layout-basic' fall through to 'tiled')
        # and it's a real mixed bag, not a clean win: it measurably improved
        # House Sales Dashboard's left-side "Filters" panel (was a wrongly
        # squat 120x274 box; became a correctly tall 212x636 one) but
        # actively CORRUPTED Finance Dashboard's KPI card row (6 short/wide
        # 204x96 cards turned into 6 tall/narrow 120x1160 slivers). Root
        # cause traced to `_distribute()`'s 'tiled' fallback: it forces a
        # naive `cols=min(n,2)` 2-column grid, which happens to degenerate
        # correctly for containers with 1-2 children (the House Sales case)
        # but actively misarranges containers with many (Finance
        # Dashboard's dashboard root has 19) flat, non-flow-wrapped
        # children that are really meant to stack full-width down the page
        # — a common real authoring pattern (see MIGRATION_ENGINE_PROGRESS.md
        # "Framework Engineering Phase" for the full investigation). Fixing
        # THAT (most likely: treat large flat 'tiled' sibling groups like
        # the already-correct 'floating' branch — direct proportional
        # scaling of each child's own real recorded position, not a forced
        # grid) is real, scoped, next-increment work, not something to ship
        # half-verified in the same pass as the zone-type resolution fix
        # below. Left as-is here; only the type/type-v2 resolution used for
        # 'floating' detection and the skip-check itself changed.
        # 'layout-basic'/'layout-flow' are the ONLY real container zone
        # types across all 10 fixtures (schema-verified; the older <layout
        # type='.../> child-element form below is dead code — no real
        # fixture ever uses it) — unlocked here (Increment 18), now that
        # _distribute()'s 'tiled' fallback (below) uses real per-child
        # relative-position scaling instead of the naive 2-column grid that
        # made this unsafe to unlock in Increment 16.
        _LAYOUT_SKIP_TYPES = {
            'color', 'bitmap', 'text', 'empty', 'blank',
            'filter', 'legend', 'highlighter', 'parameter',
            'tab-navigation',
        }

        def _build_layout_tree(z_el, p_w=actual_w, p_h=actual_h):
            zn   = z_el.get('name', '')
            zt   = _zone_type(z_el)
            if zt in _LAYOUT_SKIP_TYPES:
                return None
            zlay = z_el.get('layout', '')
            lay_el = z_el.find('layout')
            if lay_el is not None:
                zlay = lay_el.get('type', zlay)
            # Real orientation signal for the modern 'layout-flow' container
            # (schema-verified, universal across all 10 fixtures — none of
            # them ever set the 'layout' attribute or a <layout> child
            # element): its own 'param' attribute is 'horz' or 'vert'.
            _zparam = z_el.get('param', '')
            if zt == 'floating':                            ctype = 'floating'
            elif zt == 'layout-flow' and _zparam == 'horz':  ctype = 'horizontal'
            elif zt == 'layout-flow' and _zparam == 'vert':  ctype = 'vertical'
            elif zlay == 'horizontal':                       ctype = 'horizontal'
            elif zlay == 'vertical':                         ctype = 'vertical'
            elif not zn and z_el.findall('zone'):            ctype = 'tiled'
            else:                                            ctype = 'leaf'
            try:
                rx=int(float(z_el.get('x',0))); ry=int(float(z_el.get('y',0)))
                rw=int(float(z_el.get('w',0))); rh=int(float(z_el.get('h',0)))
            except (ValueError, TypeError):
                rx=ry=rw=rh=0
            px_x=int(rx*actual_w/COORD_MAX); px_y=int(ry*actual_h/COORD_MAX)
            px_w=max(1,int(rw*actual_w/COORD_MAX)); px_h=max(1,int(rh*actual_h/COORD_MAX))
            node = {'name':zn,'type':zt,'layout':ctype,
                    'x':px_x,'y':px_y,'w':px_w,'h':px_h,'children':[]}
            for child in z_el:
                if child.tag == 'zone':
                    child_node = _build_layout_tree(child, px_w, px_h)
                    if child_node is not None:
                        node['children'].append(child_node)
            return node

        layout_tree = []
        if zones_root is not None:
            for z in zones_root:
                if z.tag == 'zone':
                    node = _build_layout_tree(z)
                    if node is not None:
                        layout_tree.append(node)

        dashboards.append({'name':dash_name,'width':actual_w,'height':actual_h,
                           'zones':chart_zones,'filter_zones':filter_zones,
                           'parameter_zones': parameter_zones,
                           'text_zones': text_zones,
                           'layout_tree': layout_tree})

    # ── Worksheets ────────────────────────────────────────────────────────────
    # Build a global calc_caption_map across all datasources so worksheet
    # field resolution can convert Calculation_XXXXX -> caption.
    global_calc_caption_map: dict = {}
    for ds_parsed in datasources:
        global_calc_caption_map.update(ds_parsed.get('calc_caption_map', {}))

    import re as _re

    def _is_utility_calc(name: str) -> bool:
        """
        Return True for Tableau-internal shelf-placement calcs that have no
        meaningful data role (e.g. MIN(1), SUM(0), AGG(1), 'Blank', empty string).
        These appear on shelves just to control bar sizing/position or as placeholders.
        """
        n = name.strip()
        if not n:
            return True
        # Pure numeric aggregation placeholders: MIN(1), SUM(0), AGG(1.0) etc.
        if _re.match(r'^(?:MIN|MAX|SUM|AVG|AGG|COUNT)\s*\([01](?:\.\d+)?\)$', n, _re.I):
            return True
        # 'Blank' is a Tableau calc that returns '' — used as an empty shelf placeholder
        if n.lower() in ('blank', 'blank (copy)', 'empty', 'null', 'placeholder'):
            return True
        return False

    def _clean_field_name(raw: str, local_map: dict = None) -> str:
        """
        Convert any Tableau field reference form to a plain display name.

        Handles:
          [federated.xxx].[none:CF_age band:nk]  → 'CF_age band'
          [sum:Calculation_3340896920146604032:qk] → resolved via caption map
          [none:Gender:nk]                         → 'Gender'
          [Age (bin)]                              → 'Age (bin)'
          Calculation_3340896920146604032          → resolved via caption map
        """
        # Handle multi-token refs like [datasource].[field]: extract last token
        tokens = _re.findall(r'\[([^\[\]]+)\]', raw)
        if len(tokens) >= 2:
            # Use the last token (the actual field name, not datasource prefix)
            raw = tokens[-1]
        elif len(tokens) == 1:
            raw = tokens[0]
        else:
            raw = raw.strip('[').strip(']')

        # Qualified form: "prefix:FieldName:suffix"
        # Covers all known Tableau field-reference prefixes including:
        #   Aggregation: none, sum, avg, min, max, usr, count, attr, pcto, pctm, clct
        #   Date-part / date-trunc derivations (DATEPART / DATETRUNC of a date column):
        #     yr=Year  qr=Quarter  mn=Month  wk=Week  dt=Day(trunc)  dy=Day(of-year)
        #     hr=Hour  mi=Minute   ss=Second
        # All of these follow the same shelf-token format:  prefix:FieldName:ok
        # and must be stripped to recover the base field name (e.g. dy:Date:ok → Date).
        qualified = _re.match(
            r'^(?:none|sum|avg|min|max|med|cnt|usr|count|attr|pcto|pctm|clct'
            r'|ctd|yr|qr|mn|wk|dt|dy|hr|mi|ss'
            r'|tmn|tyr|tqr|twk|tdt|thr|fval|cum|wtd|wd|bin'
            r')\s*:\s*(.+?)\s*:\s*\w+$',
            raw, _re.I
        )
        if qualified:
            raw = qualified.group(1)

        # Skip datasource identifiers (e.g. "federated.0ylbsu81...")
        if '.' in raw and ' ' not in raw and not raw.startswith('Calculation'):
            return ''

        # Skip Tableau pseudo-fields
        if raw.startswith(':') or raw in ('Measure Names', 'Measure Values'):
            return ''

        # Resolve internal calc name → caption (local map takes priority)
        combined = {**global_calc_caption_map, **(local_map or {})}
        resolved = combined.get(raw, raw)

        # Skip utility/anonymous calcs (MIN(1), SUM(0) etc.)
        if _is_utility_calc(resolved):
            return ''

        # Block Calculation_XXXXX IDs only if they remain UNRESOLVED.
        # If resolved != raw, the caption map found a display name → keep it.
        # (e.g. Calculation_14847816630190510 → 'Normalized Amount' → keep)
        if _re.match(r'^Calculation_\d+$', resolved) and resolved == raw:
            return ''

        return resolved.strip()

    # ── Resolve dashboard filter-zone 'param' → clean field name ──────────────
    # Deferred until here (rather than done inline in _collect_zone above)
    # because _clean_field_name and global_calc_caption_map don't exist until
    # after the dashboard loop finishes — this mutates the same filter_zones
    # dicts already stored on `dashboards` in place.
    for _dbrd in dashboards:
        for _fz in _dbrd.get('filter_zones', []):
            _raw_param = _fz.get('filter_param', '')
            if _raw_param:
                _cleaned = _clean_field_name(_raw_param, {})
                if _cleaned:
                    _fz['filter_field'] = _cleaned

    worksheets = []
    for ws in root.findall('.//worksheet'):
        ws_name = ws.get('name', '')

        # Which datasource(s) this worksheet uses
        ws_ds_names = []
        for ds_ref in ws.findall('.//datasource'):
            n = ds_ref.get('name', '')
            if n and n not in ws_ds_names:
                ws_ds_names.append(n)

        # ── FIX: Cross-datasource shelf resolution ────────────────────────────
        # Tableau worksheets often reference columns from a DIFFERENT datasource
        # than what appears in the <datasource> child element.  For example,
        # "Balance Trend" has primary dep = Dso_vs_Dpo but the rows/cols shelf
        # text references [excel-direct.42452...].[sum:Value:qk] which belongs
        # to the Balance_Sheet datasource.
        # We scan the shelf text for [ds_name].[field] prefixes and prepend any
        # discovered datasource names so the layout builder uses the correct table.
        import re as _re_shelf_ds
        _rows_el_pre = ws.find('.//rows')
        _cols_el_pre = ws.find('.//cols')
        _shelf_combined = (
            (_rows_el_pre.text or '') if _rows_el_pre is not None else ''
        ) + ' ' + (
            (_cols_el_pre.text or '') if _cols_el_pre is not None else ''
        )
        # Extract ds names from [ds_name].[field] patterns in shelf text
        _shelf_ds_refs = _re_shelf_ds.findall(r'\[([^\[\]]+)\]\.\[', _shelf_combined)
        _shelf_ds_prepend = []
        for _sds in _shelf_ds_refs:
            # Skip Measure Names pseudo-datasource
            if _sds and 'Measure Names' not in _sds and _sds not in _shelf_ds_prepend:
                _shelf_ds_prepend.append(_sds)
        # Prepend shelf-discovered DS names so they take priority in matching
        for _sds in reversed(_shelf_ds_prepend):
            if _sds not in ws_ds_names:
                ws_ds_names.insert(0, _sds)

        # Build a WORKSHEET-LOCAL caption map from its own datasource-dependencies.
        # Worksheet-level <column> elements can define captions for Calculation_XXXX
        # that may differ from or supplement the datasource-level map.
        local_caption_map: dict = {}
        for dep in ws.findall('.//datasource-dependencies'):
            for col in dep.findall('column'):
                internal = col.get('name', '').strip('[').strip(']')
                caption  = col.get('caption', '').strip()
                if internal and caption and caption != internal:
                    if not _is_utility_calc(caption):
                        local_caption_map[internal] = caption

        # Extract fields from datasource-dependencies:
        # - <column> elements: direct field refs (resolve via caption maps)
        # - <column-instance> elements: aggregated/derived refs (resolve @column attr)
        ws_fields = []

        def _add_field(name: str):
            cleaned = _clean_field_name(name, local_caption_map)
            if not cleaned: return
            # Skip Tableau alias columns — they duplicate real columns and
            # cause cyclic references in PBI when included as field references
            _cl = cleaned.lower().strip()
            if '(copy)' in _cl: return          # e.g. "Revenue (copy)"
            if cleaned != cleaned.strip(): return  # trailing-space aliases
            if _cl in ('number of records','back'): return
            if cleaned not in ws_fields:
                ws_fields.append(cleaned)

        for dep in ws.findall('.//datasource-dependencies'):
            if dep.get('datasource', '') == 'Parameters':
                continue
            for col in dep.findall('column'):
                _add_field(col.get('name', ''))
            for ci in dep.findall('column-instance'):
                # column-instance @column refers to the base column
                _add_field(ci.get('column', ''))

        # Rows/Cols shelves — extract field names respecting local caption map
        def _shelf_fields(el):
            if el is None or not el.text:
                return []
            tokens = _re.findall(r'\[([^\[\]]+)\]', el.text)
            result = []
            for tok in tokens:
                cleaned = _clean_field_name(tok, local_caption_map)
                if cleaned and cleaned not in result:
                    result.append(cleaned)
            return result

        row_fields = _shelf_fields(ws.find('.//rows'))
        col_fields = _shelf_fields(ws.find('.//cols'))

        # ── FIX: Parse Pages shelf → PBI Small Multiples ─────────────────────
        # Tableau's Pages shelf places a dimension on it to create "small multiples"
        # (one chart per value of that dimension, arranged as a grid).
        # In PBI this is called "Small Multiples" and is set via the
        # 'SmallMultiple' projection role.
        # We store the Pages shelf field so _make_chart_vc can emit it.
        pages_el = ws.find('.//pages')
        pages_fields = _shelf_fields(pages_el) if pages_el is not None else []

        # ── FIX: Multi-field column shelf → correct x_field handling ──────────
        # Tableau's Columns shelf can hold MULTIPLE dimensions
        # e.g. [Quarter], [Client], [Year] → creates grouped X-axis.
        # The old code only used col_fields[0] as x_field_name, dropping the rest.
        # Now we store all col_fields so the layout builder can use them all
        # as Category fields (for a grouped/nested X-axis).
        # PBI doesn't support true nested X-axis grouping, so we combine
        # all column shelf fields as separate category dimensions — which
        # PBI renders as a grouped clustered chart (one axis per combination).
        all_col_fields = col_fields   # full list preserved for layout builder

        # Final ordered list: shelf fields first (they define the primary axes),
        # then remaining dep fields
        ordered = []
        for f in col_fields + row_fields:   # cols shelf = X-axis (primary dimension)
            if f and f not in ordered:
                ordered.append(f)
        for f in ws_fields:
            if f and f not in ordered:
                ordered.append(f)

        # ── Infer chart type from shelves, mark class, and encodings ─────────
        # Detection priority order (first match wins):
        #   1. card        — rows=EMPTY, cols=EMPTY, has text encoding
        #   2. tableEx     — has text encoding (no chart marks), OR pure dim hierarchy
        #   3. pieChart    — mark class is 'Pie' or has <wedge-size> encoding
        #   4. lineChart   — mark class is 'Line' (single pane)
        #   5. lineClusteredColumnComboChart — multiple panes with mixed marks
        #   6. scatterChart — both axes are continuous measures
        #   7. clusteredColumnChart / clusteredBarChart — standard bar charts
        #   8. tableEx     — fallback

        rows_el_ws = ws.find('.//rows')
        cols_el_ws = ws.find('.//cols')
        rows_txt = (rows_el_ws.text or '').strip() if rows_el_ws is not None else ''
        cols_txt = (cols_el_ws.text or '').strip() if cols_el_ws is not None else ''

        def _shelf_type(txt):
            """Classify a shelf token as MEASURE, AGG_MEASURE, DIMENSION, EMPTY, or UNKNOWN."""
            if not txt:
                return 'EMPTY'
            # Strip outer Tableau forecast/cumulative prefixes before classification.
            # e.g. fVal:sum:Sale Amt:qk → sum:Sale Amt:qk (forecast measure)
            #      cum:sum:Sale Amt:qk  → sum:Sale Amt:qk (cumulative measure)
            _inner_txt = txt
            for _op in ('fVal:', 'fcon:', 'cum:', 'pcto:'):
                _lower = _inner_txt.split('[')[-1] if '[' in _inner_txt else _inner_txt
                if _lower.lower().startswith(_op.lower()):
                    _inner_txt = _inner_txt.replace(_op, '', 1) if '[' not in _inner_txt else \
                                 _inner_txt[:_inner_txt.rfind('[')+1] + _lower[len(_op):]
                    break
            if any(p in _inner_txt for p in ('ctd:', 'cnt:', 'sum:', 'avg:', 'min:', 'max:')):
                return 'AGG_MEASURE'
            _DATE_TRUNC_PFXS = (
                'tmn:', 'tyr:', 'tqr:', 'twk:', 'tdt:', 'tdy:',
                'yr:', 'qr:', 'mn:', 'wk:', 'dt:', 'dy:', 'hr:', 'mi:', 'ss:',
                'wd:', 'ok:',
            )
            if any(_inner_txt.split('[')[-1].startswith(p) if '[' in _inner_txt
                   else _inner_txt.startswith(p)
                   for p in _DATE_TRUNC_PFXS):
                return 'DIM_ORDINAL'
            _inner = _inner_txt.split('[')[-1] if '[' in _inner_txt else _inner_txt
            if _inner.startswith('none:') or _inner.startswith('attr:') or _inner.startswith('bin:'):
                return 'DIMENSION'
            if _inner_txt.endswith(':qk]') or _inner_txt.endswith(':ok]'):
                t = _inner_txt.split('[')[-1]
                if any(p in t for p in ('ctd:', 'cnt:', 'sum:', 'avg:')):
                    return 'AGG_MEASURE'
                return 'MEASURE' if ':qk]' in t else 'DIM_ORDINAL'
            if ':nk]' in _inner_txt or ':ok]' in _inner_txt:
                return 'DIMENSION'
            if '/' in _inner_txt and ':nk]' in _inner_txt:
                return 'DIMENSION'
            if ':qk]' in _inner_txt:
                if any(p in _inner_txt for p in ('usr:', 'sum:', 'cnt:', 'avg:')):
                    return 'AGG_MEASURE'
                return 'MEASURE'
            return 'UNKNOWN'

        row_type = _shelf_type(rows_txt)
        col_type = _shelf_type(cols_txt)

        # Collect all pane mark classes (there may be multiple for combo charts)
        # Also collect per-pane explicit mark-color / stroke-color from style rules.
        # Tableau stores per-series colors as pane-level style-rule format elements;
        # these are used when color_is_measure_names to override the default palette.
        # Reference lines / trend lines — schema-verified against the official
        # 2026.2 TWB XSD: both live inside <pane>, sibling to <mark>/<encodings>.
        # <reference-line formula="constant|average|median|sum|min|max|..."
        #                  value-column="..." axis-column="..." .../>
        # <trendline enabled="true" fit="linear|polynomial|log|exp|power" .../>
        ws_reference_lines = []
        ws_trendline = None
        for _pane_rl in ws.findall('.//pane'):
            for rl in _pane_rl.findall('reference-line'):
                ws_reference_lines.append({
                    'axis_column':  _clean_field_name(rl.get('axis-column', ''), local_caption_map),
                    'value_column': _clean_field_name(rl.get('value-column', ''), local_caption_map),
                    'scope':        rl.get('scope', 'per-table'),
                    'label_type':   rl.get('label-type', 'automatic'),
                    'label':        rl.get('label', ''),
                    'formula':      rl.get('formula', 'constant'),
                    'value':        rl.get('value'),
                    'show_lines':   rl.get('show-lines', 'both'),
                })
            _tl = _pane_rl.find('trendline')
            if _tl is not None and _tl.get('enabled', 'false').lower() == 'true' and ws_trendline is None:
                ws_trendline = {'fit': _tl.get('fit', 'linear'), 'degree': _tl.get('degree')}

        # Dual-axis "Synchronize Axis" flag — schema-verified location
        # (<style-rule element="axis"><encoding synchronized="true"/>), but
        # unlike reference-line/trendline this one has no real sample to
        # confirm against, and Power BI's combo chart has no verified,
        # stable "lock secondary axis to primary" property to wire it into
        # safely. Detected defensively (never raises) and only surfaced as a
        # quality-score note, not translated into any objects_cfg guess.
        ws_axis_synchronized = False
        try:
            for _sr in ws.findall('.//style-rule[@element="axis"]'):
                for _enc in _sr.findall('encoding'):
                    if _enc.get('synchronized', '').lower() == 'true':
                        ws_axis_synchronized = True
                        break
                if ws_axis_synchronized:
                    break
        except Exception:
            ws_axis_synchronized = False

        pane_marks = []
        pane_mark_colors = []   # one entry per pane: hex str or None
        for pane in ws.findall('.//pane'):
            m = pane.find('mark')
            if m is not None:
                pane_marks.append(m.get('class', 'Automatic'))
            _pc = None
            for _style in pane.findall('.//style'):
                for _sr in _style.findall('.//style-rule[@element="mark"]'):
                    _mc = _sr.find('.//format[@attr="mark-color"]')
                    _sc = _sr.find('.//format[@attr="stroke-color"]')
                    if _mc is not None:
                        _v = (_mc.get('value', '') or '').strip()
                        if _v.startswith('#'):
                            _pc = _v.lower()
                        break
                    if _sc is not None:
                        _v = (_sc.get('value', '') or '').strip()
                        if _v.startswith('#'):
                            _pc = _v.lower()
                        break
                if _pc:
                    break
            pane_mark_colors.append(_pc)
        mark_class = pane_marks[0] if pane_marks else 'Automatic'
        pane_count = len(ws.findall('.//pane'))

        # Distinct mark classes (ignoring 'Automatic' and 'Circle' which are generic)
        distinct_marks = set(m for m in pane_marks
                             if m not in ('Automatic', 'Circle', None))

        # Encoding checks
        has_text_enc    = ws.find('.//pane/encodings/text')      is not None
        has_color_enc   = ws.find('.//pane/encodings/color')     is not None
        has_wedge_enc   = ws.find('.//pane/encodings/wedge-size') is not None
        has_size_enc    = ws.find('.//pane/encodings/size')        is not None

        # Parse wedge-size (pie slice size) encoding column.
        # Tableau encodes the slice-size column as e.g.:
        #   pcto:sum:Total:qk  or  pcto:sum:Calculation_123:qk
        # We extract the raw column name and resolve it via the caption map
        # so the layout builder can emit an Aggregation(Column) for the Y value.
        import re as _re_wedge
        pie_size_field = None
        for enc in ws.findall('.//pane/encodings/wedge-size'):
            raw_wedge = enc.get('column', '')
            # Strip pcto: prefix — format is [ds].[pcto:sum:ColName:qk] or [ds].[sum:ColName:qk]
            m_wedge = _re_wedge.search(
                r'\[(?:pcto:)?(?:sum|cnt|avg|min|max):(.+?)(?::qk.*?)?\]$',
                raw_wedge, _re_wedge.I
            )
            if m_wedge:
                raw_field_ref = f'[none:{m_wedge.group(1)}:nk]'
                cleaned = _clean_field_name(raw_field_ref, local_caption_map)
                if not cleaned:
                    # Try direct sum: prefix
                    raw_field_ref2 = f'[sum:{m_wedge.group(1)}:qk]'
                    cleaned = _clean_field_name(raw_field_ref2, local_caption_map)
                if not cleaned:
                    cleaned = m_wedge.group(1)  # fallback: raw name
                pie_size_field = cleaned
            break  # use first wedge-size encoding

        # Parse size encoding field — used for Treemap rectangle area and Bubble size.
        # Format is the same as wedge-size: [ds].[sum:ColName:qk] or [ds].[none:Col:nk]
        import re as _re_size
        size_enc_field = None
        for enc in ws.findall('.//pane/encodings/size'):
            raw_size = enc.get('column', '')
            m_size = _re_size.search(
                r'\[(?:sum|cnt|avg|min|max|none):(.+?)(?::(?:qk|nk).*?)?\]$',
                raw_size, _re_size.I
            )
            if m_size:
                _sz_raw = f'[none:{m_size.group(1)}:nk]'
                _sz_cln = _clean_field_name(_sz_raw, local_caption_map)
                if not _sz_cln:
                    _sz_raw2 = f'[sum:{m_size.group(1)}:qk]'
                    _sz_cln = _clean_field_name(_sz_raw2, local_caption_map)
                size_enc_field = _sz_cln or m_size.group(1)
            break  # use first size encoding
        # e.g. pcto:cnt:Churn:qk → percent of total count of Churn
        pcto_field = None
        import re as _re_pcto
        for enc in ws.findall('.//pane/encodings/text'):
            col_attr = enc.get('column', '')
            m_pcto = _re_pcto.search(r'\[pcto:cnt:(.+?):qk\]', col_attr, _re_pcto.I)
            if m_pcto:
                pcto_field = _clean_field_name(
                    f'[none:{m_pcto.group(1)}:nk]', local_caption_map
                ) or m_pcto.group(1)
                break

        # Detect whether any color encoding is on a DIMENSION column (:nk = nominal/discrete).
        # In Tableau: Bar mark + dimension color → STACKED bar chart.
        # Bar mark + measure color or no color → clustered/side-by-side.
        has_dim_color_enc = False
        for enc in ws.findall('.//pane/encodings/color'):
            col_attr = enc.get('column', '')
            if ':nk]' in col_attr or col_attr.startswith('[none:'):
                has_dim_color_enc = True
                break

        # Scatter: explicit filled-circle shape style
        has_scatter_shape = any(
            'circle' in (fmt.get('value', '')).lower()
            for sr in ws.findall('.//style-rule[@element="mark"]')
            for fmt in sr.findall('.//format[@attr="shape"]')
        )

        # Data labels: Tableau 'mark-labels-show' style rule → PBI labels.show.
        # 'true'  → add labels object to chart visual objects_cfg
        # 'false' or absent → no labels (PBI default = hidden)
        show_data_labels = any(
            fmt.get('value', '').lower() == 'true'
            for sr in ws.findall('.//style-rule[@element="mark"]')
            for fmt in sr.findall('format[@attr="mark-labels-show"]')
        )

        # Data label number format: Tableau 'text-format' attribute on
        # label / cell / datalabel style-rules.  Stored so PBI charts
        # can set labelFormatString instead of using auto-abbreviation.
        label_format = ''
        for _sr_el in ('label', 'cell', 'datalabel'):
            for sr in ws.findall(f'.//style-rule[@element="{_sr_el}"]'):
                for fmt in sr.findall('format[@attr="text-format"]'):
                    _tf = fmt.get('value', '').strip()
                    if _tf:
                        label_format = _tf
                        break
                if label_format:
                    break
            if label_format:
                break

        # Worksheet plot-area background color: real, schema-verified signal
        # (<style-rule element='table'><format attr='background-color'
        # value='#000000'/></style-rule>, direct child of <worksheet>) —
        # e.g. Netfix Workbook's Netflix-themed dashboard sets every
        # worksheet's background to black; rendering that in Power BI with
        # the default white background would look completely wrong.
        # Skip meaningless "no override" cases: empty, pure white (PBI's own
        # default), and fully-transparent 8-digit hex (alpha byte '00').
        background_color = ''
        for sr in ws.findall('.//style-rule[@element="table"]'):
            fmt = sr.find('format[@attr="background-color"]')
            if fmt is None:
                continue
            _bg = (fmt.get('value') or '').strip()
            if not _bg or _bg.lower() in ('#ffffff', '#fff', 'white'):
                continue
            if len(_bg) == 9 and _bg.lower().endswith('00'):
                continue   # fully transparent (#RRGGBB00) — no visible override
            background_color = _bg[:7] if len(_bg) == 9 else _bg  # drop alpha byte
            break

        # Worksheet title font — real, schema-verified signal
        # (<style-rule element='title'><format attr='font-size'/'font-family'/
        # 'font-weight'/'color'/'background-color'>, direct child of
        # <worksheet>) — confirmed real and genuinely varied (not an ambient
        # Tableau default — the trap Increments 14/20/25 all had to check
        # for) across Finance Dashboard's real worksheets: most use 10pt
        # bold Calibri on a light-green title bar, but its 6 "_Count" KPI
        # worksheets use 14pt normal white text instead — a real, deliberate
        # per-worksheet distinction that was being silently dropped.
        title_font_family = ''
        title_font_size   = 0
        title_bold        = False
        title_italic      = False
        title_color       = ''
        title_bg_color    = ''
        for sr in ws.findall('.//style-rule[@element="title"]'):
            for fmt in sr.findall('format'):
                attr = fmt.get('attr', '')
                val  = (fmt.get('value') or '').strip()
                if not val:
                    continue
                if attr == 'font-family':
                    title_font_family = val
                elif attr == 'font-size':
                    try:
                        title_font_size = int(float(val))
                    except ValueError:
                        pass
                elif attr == 'font-weight':
                    title_bold = val.lower() == 'bold'
                elif attr == 'font-style':
                    title_italic = val.lower() == 'italic'
                elif attr == 'color':
                    title_color = val
                elif attr == 'background-color':
                    title_bg_color = val
            if title_font_family or title_font_size or title_color:
                break
        # Same "no meaningful override" filtering as background_color above.
        if title_bg_color and (title_bg_color.lower() in ('#ffffff', '#fff', 'white')
                                or (len(title_bg_color) == 9 and title_bg_color.lower().endswith('00'))):
            title_bg_color = ''
        elif title_bg_color and len(title_bg_color) == 9:
            title_bg_color = title_bg_color[:7]
        # PBI fontSize range is 6-45pt (schema-verified: Power BI Report
        # Theme JSON Schema, definitions.fontSize) — clamp rather than emit
        # an out-of-range value PBI Desktop would reject.
        if title_font_size and not (6 <= title_font_size <= 45):
            title_font_size = max(6, min(45, title_font_size))

        # Axis-label / legend / data-label fonts — real, schema-verified
        # signals (<style-rule element='worksheet'|'legend'|'datalabel'>),
        # same discipline as title_font_family above (see
        # _collect_worksheet_style_font's docstring for the exact real
        # cases found: Finance Dashboard, Netfix Workbook, Amazon Sales
        # Insights). element='worksheet' is Tableau's general per-worksheet
        # default text font (no rows/cols scope on these attrs), which
        # cascades to axis tick labels absent a more specific override —
        # the closest real PBI equivalent for a worksheet-wide font signal,
        # same judgment call already made for background_color above.
        (axis_label_font_family, axis_label_font_size, axis_label_bold,
         axis_label_italic, axis_label_color) = _collect_worksheet_style_font(ws, 'worksheet')
        (legend_font_family, legend_font_size, legend_bold,
         legend_italic, legend_color) = _collect_worksheet_style_font(ws, 'legend')
        (datalabel_font_family, datalabel_font_size, datalabel_bold,
         datalabel_italic, datalabel_color) = _collect_worksheet_style_font(ws, 'datalabel')

        # Check whether a large-font style is set (card KPI indicator)
        large_font = False
        for sr in ws.findall('.//style-rule'):
            for fmt in sr.findall('format[@attr="font-size"]'):
                try:
                    if int(fmt.get('value', '0')) >= 12:
                        large_font = True
                except ValueError:
                    print(f"[DEBUG except] line ~2113: exception caught")
                    pass

        # ── Detect chart type ─────────────────────────────────────────────────
        is_measure_rows = row_type in ('AGG_MEASURE', 'MEASURE')
        is_measure_cols = col_type in ('AGG_MEASURE', 'MEASURE')
        is_dim_rows     = row_type in ('DIMENSION', 'DIM_ORDINAL')
        is_dim_cols     = col_type in ('DIMENSION', 'DIM_ORDINAL')

        # Custom axis titles: real, schema-verified signal
        # (<style-rule element='axis'><format attr='title' scope='rows'|'cols'
        # value='...'/></style-rule>) — confirmed real on Finance Dashboard
        # (e.g. 'DSO vs DPO' worksheet's value axis titled 'Amount($)'/'DSO
        # vs DPO', not the raw field name it would otherwise show) and
        # AB_NYC's 'Availability and Price' (value axis titled
        # 'availability'). 'scope' names the SHELF (rows/cols), not the
        # visual axis directly, so it's mapped through the already-computed
        # is_measure_rows/is_measure_cols/is_dim_rows/is_dim_cols flags
        # (verified correct for both real cases above, both non-hbar). A
        # dual-axis worksheet can carry TWO rows-scope title overrides (one
        # per axis, e.g. DSO vs DPO's 'DSO vs DPO' + 'Gap') — first is the
        # primary/value axis, second (if present) the secondary (Y2) axis,
        # matching the one real multi-override sample found.
        _axis_titles_rows, _axis_titles_cols = [], []
        for _asr in ws.findall('.//style-rule[@element="axis"]'):
            for _afmt in _asr.findall('format[@attr="title"]'):
                _aval = (_afmt.get('value') or '').strip()
                if not _aval:
                    continue
                (_axis_titles_rows if _afmt.get('scope') == 'rows'
                 else _axis_titles_cols if _afmt.get('scope') == 'cols'
                 else []).append(_aval)
        # Real gap found verifying this against Finance Dashboard: 2 of its
        # 4 real title overrides sit on a worksheet whose rows shelf is a
        # composite '[Multiple Values]' token (a Tableau placeholder for
        # "several distinct field references combined," e.g. a dashboard
        # ratio calc) — row_type can't classify that as a clean MEASURE
        # token and falls back to 'UNKNOWN', so is_measure_rows alone
        # missed them. Both real cases have a confidently-classified
        # DIMENSION on the OTHER shelf though (col_type == 'DIMENSION'), so
        # treat an 'UNKNOWN' shelf as the value shelf when its counterpart
        # is confidently a dimension — a worksheet needs a measure
        # somewhere, and the classifier's inability to name a composite
        # token doesn't mean it isn't one.
        _rows_is_value = is_measure_rows or (row_type == 'UNKNOWN' and is_dim_cols)
        _cols_is_value = is_measure_cols or (col_type == 'UNKNOWN' and is_dim_rows)
        axis_title_value = axis_title_value2 = axis_title_category = ''
        if _rows_is_value and _axis_titles_rows:
            axis_title_value  = _axis_titles_rows[0]
            axis_title_value2 = _axis_titles_rows[1] if len(_axis_titles_rows) > 1 else ''
        elif _cols_is_value and _axis_titles_cols:
            axis_title_value  = _axis_titles_cols[0]
            axis_title_value2 = _axis_titles_cols[1] if len(_axis_titles_cols) > 1 else ''
        if is_dim_cols and _axis_titles_cols:
            axis_title_category = _axis_titles_cols[0]
        elif is_dim_rows and _axis_titles_rows:
            axis_title_category = _axis_titles_rows[0]

        # Gridlines explicitly hidden: real, schema-verified signal
        # (<style-rule element='axis'><format attr='stroke-size' value='0'/>)
        # — surveyed real 'stroke-color'/'stroke-size' usage across all 10
        # fixtures before implementing anything: stroke-color is almost
        # always Tableau's own uniform cached default ('#c0c0c0' appears on
        # 10+ unrelated Finance Dashboard worksheets, clearly not a
        # deliberate per-worksheet customization — replicating it would be
        # cargo-culting a default, the exact mistake this engagement's
        # background-color work already learned to filter out). stroke-
        # size='0' is different: it never appears as an ambient default
        # anywhere in the 10 fixtures, only on Sales Param's 'Line graph'
        # worksheet — a real, deliberate, unambiguous "gridlines off"
        # signal, schema-confirmed via the 2026.2 TWB XSD's
        # StyleAttribute-ST enum (stroke-size is a real attribute name).
        gridlines_hidden = any(
            (_gfmt.get('value') or '').strip() == '0'
            for _gsr in ws.findall('.//style-rule[@element="axis"]')
            for _gfmt in _gsr.findall('format[@attr="stroke-size"]')
        )

        # Tableau mark classes that signify a text table (not a chart):
        #   'Square' = text table cell, 'Text' = text/BAN mark
        # Chart marks (Circle, Bar, Line, Area, Shape, GanttBar, Multipolygon) →
        # override any text-encoding and must be handled as charts.
        all_square_marks = bool(pane_marks) and all(m == 'Square' for m in pane_marks)
        is_text_mark     = bool(pane_marks) and all(m in ('Text', 'Square') for m in pane_marks)

        # Detect donut chart: Tableau donut = Pie marks + Circle mark on the same chart.
        # Pure Pie without Circle = regular pie chart.
        has_pie_mark    = 'Pie'    in pane_marks
        has_circle_mark = 'Circle' in pane_marks
        is_donut        = has_pie_mark and has_circle_mark

        # For stacked vs clustered: detect when the color encoding is the SAME column
        # as the category (rows) dimension. In that case Tableau is only color-coding
        # each bar, NOT stacking — treat as clustered.
        color_dim_cols = []
        for enc in ws.findall('.//pane/encodings/color'):
            col_attr = enc.get('column', '')
            cleaned  = _clean_field_name(col_attr, local_caption_map)
            if cleaned:
                color_dim_cols.append(cleaned)

        # The primary category field (rows shelf first token)
        # ── Collect ctd: (COUNT DISTINCT) referenced column base-names ─────────
        # Tableau uses ctd:<col>:qk on shelves/encodings for COUNTD([col]).
        # After _clean_field_name strips the prefix the col name looks the same
        # as any plain dimension reference.  We capture the intent here by
        # scanning column-instance elements with derivation='CountD', plus any
        # raw shelf/encoding tokens that match the ctd: prefix pattern.
        # This drives DISTINCTCOUNT DAX measure generation in build_data_model_schema.
        import re as _re_ctd_p
        _ctd_fields_ws: set = set()   # caption-resolved base column names
        for _dep in ws.findall('.//datasource-dependencies'):
            for _ci in _dep.findall('column-instance'):
                if _ci.get('derivation', '').lower() == 'countd':
                    _base_raw = _ci.get('column', '')
                    _cleaned_ctd = _clean_field_name(_base_raw, local_caption_map)
                    if _cleaned_ctd:
                        _ctd_fields_ws.add(_cleaned_ctd)
        # Also scan shelf text and encoding attributes for raw ctd: tokens
        for _shelf_text in (rows_txt, cols_txt):
            for _tok in _re_ctd_p.findall(r'\[([^\[\]]+)\]', _shelf_text):
                _mc = _re_ctd_p.match(r'^ctd:(.+?):qk$', _tok, _re_ctd_p.I)
                if _mc:
                    _cn = local_caption_map.get(_mc.group(1), _mc.group(1)).strip()
                    if _cn: _ctd_fields_ws.add(_cn)
        for _enc in ws.findall('.//pane/encodings/'):
            _raw_col = _enc.get('column', '')
            _mc = _re_ctd_p.search(r'\[ctd:([^\]]+):qk\]', _raw_col, _re_ctd_p.I)
            if _mc:
                _cn = local_caption_map.get(_mc.group(1), _mc.group(1)).strip()
                if _cn: _ctd_fields_ws.add(_cn)
        _rows_first_field = _clean_field_name(
            rows_txt.strip().split('+')[0].strip() if rows_txt else '',
            local_caption_map
        )
        # Color = same as category → just colouring each bar, not stacking
        def _norm_match(a, b):
            def _n(s): return s.strip().lower().replace(' ','').replace('-','').replace('_','')
            return _n(a) == _n(b)
        color_same_as_category = bool(
            color_dim_cols and _rows_first_field
            and any(_norm_match(c, _rows_first_field) for c in color_dim_cols)
        )

        # Detect whether the text encoding is a MEASURE aggregation (sum:, cnt:, etc.)
        # vs a plain dimension (none:, attr:).  Only measure text encodings on empty
        # shelves indicate a KPI/card visual — dimension text encodings (e.g. Country)
        # are tooltip/detail labels and should fall through to the tableEx path.
        import re as _re_textkind
        _text_enc_is_measure = False
        for _enc in ws.findall('.//pane/encodings/text'):
            _raw = _enc.get('column', '')
            if _re_textkind.search(r'\[(sum|cnt|avg|min|max|pct|pcto):', _raw, _re_textkind.I):
                _text_enc_is_measure = True
            break  # only check first text encoding

        # Tableau's canonical multi-KPI "strip": :Measure Names dropped on a
        # shelf (usually Columns) + Measure Values shown as text, filtered
        # down to N specific measures (the ":Measure Names" categorical
        # filter's <groupfilter> member list, extracted later into
        # ws['measure_names_filter_fields'] and threaded through to the
        # renderer). Power BI's Multi-row Card is the direct visual
        # equivalent — previously this had no dedicated detection at all and
        # fell through every other branch to a generic tableEx table
        # (confirmed against a real sample: HR Analytics' worksheet named,
        # literally, "KPI").
        _has_measure_names_shelf = (
            ':Measure Names' in rows_txt or ':Measure Names' in cols_txt)
        _text_enc_is_multiple_values = any(
            'Multiple Values' in (enc.get('column', '') or '')
            for enc in ws.findall('.//pane/encodings/text')
        )
        if row_type == 'EMPTY' and _has_measure_names_shelf and _text_enc_is_multiple_values:
            chart_type = 'multiRowCard'

        elif row_type == 'EMPTY' and col_type == 'EMPTY' and has_text_enc and is_text_mark:
            # No shelves + explicit Text/Square mark → KPI card
            chart_type = 'card'

        elif (row_type == 'EMPTY' and col_type == 'EMPTY'
              and has_text_enc and _text_enc_is_measure):
            # No shelves + MEASURE text encoding (sum:col:qk) with Automatic mark →
            # KPI-style card showing a single aggregated value.
            # (e.g. EBITDA_Count: enc.text = sum:Value:qk, mark=Automatic)
            # Dimension text encodings (none:Country:nk) fall through to tableEx.
            chart_type = 'card'

        elif (row_type == 'EMPTY' and col_type == 'DIM_ORDINAL'
              and not has_text_enc or
              (row_type == 'EMPTY' and col_type == 'DIM_ORDINAL'
               and has_text_enc and not _text_enc_is_measure)):
            # Date dimension on cols only, no measure rows, no measure text enc.
            # Pattern: Tableau date-part/filter indicator sheets (Month, Year pickers).
            # Examples: cols=mn:cy_date:ok (Month), cols=yr:cy_date:ok (Year)
            # These are used as timeline filters/indicators → PBI slicer is the
            # closest equivalent (allows the user to filter by date part).
            chart_type = 'slicer'

        elif all_square_marks and not has_size_enc:
            # All marks are 'Square' → Tableau text table → PBI table visual
            chart_type = 'tableEx'

        elif has_text_enc and not has_color_enc and not has_wedge_enc and is_text_mark:
            # Text encoding with table marks (no chart marks present) → table
            chart_type = 'tableEx'

        elif row_type == 'EMPTY' and has_text_enc and is_dim_cols:
            # No rows shelf + text encoding + dimension on cols = pivot/percentage table
            # (e.g. Payment Method with pcto:cnt:Churn label — shows percentages per
            # dimension value). Use 'pivotTable' to match PBI Desktop's visual type
            # for cross-tab / matrix visuals, which is what the reference PBIT uses.
            chart_type = 'pivotTable'

        elif (rows_txt and '/' in rows_txt and col_type == 'EMPTY'
              and not is_measure_rows):
            # Nested dimension hierarchy on rows only
            chart_type = 'tableEx'

        elif ('Latitude' in rows_txt or 'Longitude' in rows_txt
              or 'Latitude' in cols_txt or 'Longitude' in cols_txt):
            # Tableau geographic map: Latitude (generated) / Longitude (generated)
            # are placed on the rows/cols shelves.
            #
            # Two Tableau map types map to different PBI visuals:
            #   Filled Map  — mark class 'Multipolygon' → PBI 'filledMap' (choropleth)
            #                 Colors polygons by a dimension/measure; region name is
            #                 the category (e.g. State, Country).
            #   Bubble/Point Map — any other mark class → PBI 'map' (Bing bubble map)
            #                 Plots a circle at each geocoded location, sized by measure.
            if 'Multipolygon' in pane_marks:
                chart_type = 'filledMap'
            else:
                chart_type = 'mapChart'

        elif is_donut or (has_wedge_enc and has_pie_mark):
            # Tableau donut (Pie+Circle) → PBI donutChart
            # Pure pie with wedge encoding → pieChart
            chart_type = 'donutChart' if is_donut else 'pieChart'

        elif has_wedge_enc or mark_class == 'Pie':
            chart_type = 'pieChart'

        elif (len(distinct_marks) >= 2
              and any(m in distinct_marks for m in ('Line', 'Bar', 'GanttBar'))
              and any(m in distinct_marks for m in ('Line', 'Bar', 'GanttBar'))
              and not is_dim_rows):
            # Combo chart: multiple distinct mark types (Line+Bar etc.) with
            # measure-based rows and a dimension on cols.
            # MUST be checked BEFORE the lineChart branch so charts like
            # DSO vs DPO (marks=Line+Line+Bar, cols=Month) are correctly detected.
            chart_type = 'lineClusteredColumnComboChart'

        elif 'Area' in distinct_marks and (is_measure_cols or is_measure_rows):
            # Area/sparkline — Tableau 'Area' mark class with a measure axis.
            # Maps to PBI 'areaChart' (filled area under the line), NOT lineChart.
            chart_type = 'areaChart'

        elif (pane_count >= 2 and is_measure_rows and not is_dim_rows
              and len(distinct_marks) <= 1):
            # True Tableau "Dual Axis" with the SAME mark type on both panes
            # (e.g. two Line measures combined on Rows via Analysis > Dual
            # Axis — as opposed to the mixed-mark combo case above, e.g.
            # Line+Bar, which already routes here). Previously this fell
            # through to the single-measure lineChart branch below and
            # silently dropped the second measure/axis entirely.
            # Power BI's only built-in visual with genuine independent-
            # secondary-axis semantics is the line+column combo chart, so we
            # reuse the exact same mapping and Y2-axis wiring already proven
            # for the mixed-mark case — the second measure renders as a
            # column rather than a matching mark, flagged in the per-
            # worksheet quality score rather than silently presented as exact.
            #
            # NOTE: a different Tableau technique also lands here — duplicating
            # the SAME measure across panes to give it a second independent
            # mark-type LAYER sharing one axis (e.g. a Line pane + a
            # Shape-marker pane coloured by a threshold calc; confirmed via a
            # real sample's `y-index="1"` pane attribute, Tableau's own marker
            # for "layered on the same axis," not a genuine second axis). A
            # guard requiring 2+ DISTINCT measures on Rows was tried to route
            # that case to a plain line chart instead, but a real sample
            # (Sales Param's "Line graph") showed it then falls into a WORSE
            # branch: its continuous month-truncation column (Tableau
            # `tmn:Field:qk` — a continuous date-part, ':qk' suffixed like a
            # real measure) gets misclassified as a second measure by this
            # cascade's is_measure_cols check, routing to scatterChart with a
            # non-numeric categorical field as Y. That misclassification is a
            # separate, deeper gap (continuous date-truncation shelf tokens
            # aren't distinguished from real measures anywhere in this
            # cascade) that needs its own fix, not a one-line guard here — so
            # this branch is reverted to the original always-combo behavior
            # (a merely cosmetic duplicated second line in the same-measure
            # case) until that's addressed properly.
            chart_type = 'lineClusteredColumnComboChart'

        elif mark_class == 'Line' and (is_measure_rows or row_type in ('UNKNOWN', 'AGG_MEASURE')):
            chart_type = 'lineChart'

        elif is_dim_rows and is_measure_cols:
            # Dimension on rows, measure on cols → horizontal bar.
            # Stacking rule: a separate color DIMENSION (different from the category
            # column) means Tableau stacks the bars — regardless of whether the mark
            # class is 'Automatic' or explicitly 'Bar'.  'Automatic' is Tableau's
            # default and always produces stacked bars when a color dimension is present.
            # Side-by-side (Clustered) applies when there is no separate color dimension.
            if has_dim_color_enc and not color_same_as_category:
                chart_type = 'barChart'
            else:
                chart_type = 'clusteredBarChart'

        elif (pane_count >= 2 and len(distinct_marks) >= 2
              and any(m in distinct_marks for m in ('Line', 'Bar'))
              and any(m in distinct_marks for m in ('Line', 'Bar', 'GanttBar'))
              and not is_dim_rows):
            # Combo: multiple panes with line+bar marks, measure-based shelves
            chart_type = 'lineClusteredColumnComboChart'

        elif has_scatter_shape or (is_measure_rows and is_measure_cols and not is_dim_cols):
            chart_type = 'scatterChart'

        elif is_measure_rows and is_measure_cols and is_dim_cols:
            # Both rows and cols have measures but cols also has a dim →
            # treat as column chart with the dim as category.
            if has_dim_color_enc and not color_same_as_category:
                chart_type = 'columnChart'
            else:
                chart_type = 'clusteredColumnChart'

        elif (pane_marks and all(m == 'GanttBar' for m in pane_marks)):
            # GanttBar MUST be checked before is_measure_rows+is_dim_cols.
            # GanttBar rows are cumulative measures (cum:sum:...) which are
            # AGG_MEASURE — without this early check they fall into columnChart.
            #
            # A true Tableau Gantt timeline requires a DATE-typed field on one
            # of the position axes (rows/cols) — the bars' horizontal extent
            # IS the date range. Without one, GanttBar is just Tableau's mark
            # class for a plain measure-vs-dimension bar view (confirmed
            # against a real sample: AB_NYC Dashboard's "Neighnourhood group
            # vs Price" — rows=avg:price (measure), cols=neighbourhood_group
            # (dimension), size=avg:price, no date field anywhere in the
            # worksheet). Routing that case to Area was a real visual-fidelity
            # bug: discrete bars and a continuous filled area are very
            # different shapes, and a plain Bar/Column chart is the far
            # closer — and still schema-safe, since it reuses the exact same
            # proven bar/column branches below — approximation. Genuine
            # date-anchored Gantt worksheets keep the existing Area
            # approximation (still no verified native waterfall/Gantt
            # role-map exists — see roadmap item #5b).
            _gantt_ds_cols = []
            try:
                for _ds_obj in datasources:
                    if _ds_obj.get('name', '') in ws_ds_names or not ws_ds_names:
                        _gantt_ds_cols = _ds_obj.get('columns', [])
                        break
                if not _gantt_ds_cols and datasources:
                    _gantt_ds_cols = datasources[0].get('columns', [])
            except Exception:
                _gantt_ds_cols = []

            def _gantt_field_is_date(fname):
                if not fname:
                    return False
                return any(
                    c.get('datatype', '') in ('date', 'dateTime', 'datetime', 'timestamp')
                    for c in _gantt_ds_cols
                    if c.get('name', '').strip('[]').lower() == fname.lower()
                    or c.get('caption', '').strip('[]').lower() == fname.lower()
                )

            _gantt_cols_first_field = _clean_field_name(
                cols_txt.strip().split('+')[0].strip() if cols_txt else '',
                local_caption_map
            )
            if (_gantt_field_is_date(_rows_first_field)
                    or _gantt_field_is_date(_gantt_cols_first_field)):
                chart_type = 'areaChart'
            elif is_dim_rows and is_measure_cols:
                if has_dim_color_enc and not color_same_as_category:
                    chart_type = 'barChart'
                else:
                    chart_type = 'clusteredBarChart'
            else:
                if has_dim_color_enc and not color_same_as_category:
                    chart_type = 'columnChart'
                else:
                    chart_type = 'clusteredColumnChart'

        elif is_measure_rows and is_dim_cols:
            # Measure on rows, dimension on cols → vertical column chart.
            # Exception: when the dim is date/time AND mark is Line or Automatic
            # → lineChart (trend over time).
            # Look up columns from the first matching datasource for this worksheet.
            _ws_ds_cols = []
            try:
                _x_field_now = x_field_ws if 'x_field_ws' in dir() else ''
                for _ds_obj in datasources:
                    if _ds_obj.get('name','') in ws_ds_names or not ws_ds_names:
                        _ws_ds_cols = _ds_obj.get('columns', [])
                        break
                if not _ws_ds_cols and datasources:
                    _ws_ds_cols = datasources[0].get('columns', [])
            except Exception:
                print(f"[DEBUG except] line ~2327: could not resolve datasource columns for date check")
                _x_field_now = ''
                _ws_ds_cols  = []
            _x_field_now = x_field_ws if 'x_field_ws' in dir() and x_field_ws else ''
            _x_is_date = _x_field_now and any(
                c.get('datatype','') in ('date','dateTime','datetime','timestamp')
                for c in _ws_ds_cols
                if c.get('name','').strip('[]').lower() == _x_field_now.lower()
                or c.get('caption','').strip('[]').lower() == _x_field_now.lower()
            )
            if mark_class in ('Automatic','Line') and _x_is_date:
                chart_type = 'lineChart'
            elif has_dim_color_enc and not color_same_as_category:
                chart_type = 'columnChart'
            else:
                chart_type = 'clusteredColumnChart'

        elif row_type in ('AGG_MEASURE', 'MEASURE', 'UNKNOWN') and is_dim_cols:
            # Compound/unknown measure on rows, dimension on cols → column chart.
            # Special case: bin dimension + count measure = histogram → column chart.
            if has_dim_color_enc and not color_same_as_category:
                chart_type = 'columnChart'
            else:
                chart_type = 'clusteredColumnChart'

        elif is_measure_rows and col_type == 'UNKNOWN' and cols_tokens:
            # Bin field on cols (e.g. [Price (bin)]) — 'bin' prefix is in _AGG_PFXS
            # so it parses as measure, but it IS a dimension (histogram bucket).
            # Treat as clusteredColumnChart: bin field → X, count/sum → Y.
            _bin_tok = next((t for t in cols_tokens if t.get('agg') == 'bin'), None)
            if _bin_tok:
                _bin_name = _clean_field_name(_bin_tok['name'], local_caption_map)
                if _bin_name and not x_field_ws:
                    x_field_ws = _bin_name
                chart_type = 'clusteredColumnChart'
            else:
                chart_type = 'clusteredColumnChart'

        elif row_type == 'EMPTY' and is_dim_cols:
            if has_dim_color_enc and not color_same_as_category:
                chart_type = 'barChart'
            else:
                chart_type = 'clusteredBarChart'

        elif (pane_marks
              # Heatmap mark type: Tableau 'Square'/'Rect'/'Polygon' with color
              # encoding -> PBI matrix (pivotTable). Defined inline here (pre-
              # existing bug: the module previously only defined this set
              # further down in the same function, after this first use,
              # raising "cannot access free variable '_HEATMAP_MARKS'" for
              # any worksheet whose chart-type resolution actually reaches
              # this branch — confirmed real on input/sales_dashboard.twbx).
              and all(m in {'Square', 'Rect', 'Polygon'} for m in pane_marks)
              and color_fields_ws
              and (rows_tokens or cols_tokens)):
            # Heatmap: Square/Rect/Polygon marks with color encoding and axes
            # → PBI matrix (pivotTable) is the closest equivalent
            chart_type = 'pivotTable'

        elif (row_type == 'EMPTY' and col_type == 'EMPTY'
              and bool(pane_marks)
              and all(m in ('Shape', 'Automatic') for m in pane_marks)
              and ws.find('.//pane/encodings/shape') is not None
              and not has_text_enc):
            # Tableau Shape mark with empty shelves = icon/indicator visual
            # (e.g. up/down arrow KPI).  No direct PBI equivalent — render as a
            # card showing the underlying measure so the page is not an empty table.
            chart_type = 'card'

        elif (row_type == 'EMPTY' and col_type == 'EMPTY'
              and has_size_enc
              and not has_wedge_enc
              and all(m in ('Automatic', 'Square') for m in pane_marks if m)):
            # Tableau Treemap: empty shelves + size encoding + Automatic/Square marks.
            # PBI visual type is 'treemap'. The size field drives rectangle area;
            # a color/dimension field defines the hierarchy.
            chart_type = 'treemap'

        elif (row_type == 'EMPTY' and col_type == 'EMPTY'
              and has_size_enc
              and not has_wedge_enc
              and any(m == 'Circle' for m in pane_marks)):
            # Tableau Packed Bubble chart: Circle marks on empty shelves with a
            # size encoding. PBI maps this to a scatter chart using the size field
            # as the bubble-size axis and a dimension for the category/label.
            chart_type = 'bubbleChart'

        else:
            chart_type = 'tableEx'

        # Extract color/legend encoding field name
        color_fields_ws = []
        for enc in ws.findall('.//encodings/color'):
            raw_col = enc.get('column', '')
            cleaned = _clean_field_name(raw_col, local_caption_map)
            if cleaned and cleaned not in color_fields_ws:
                color_fields_ws.append(cleaned)

        # Level-of-detail (lod) encodings define the mark granularity in Tableau.
        # For scatter charts: lod columns (e.g. "Contract") give each mark its
        # identity and map to the PBI scatter chart "Details" role.
        detail_fields_ws = []
        for enc in ws.findall('.//encodings/lod'):
            raw_col = enc.get('column', '')
            cleaned = _clean_field_name(raw_col, local_caption_map)
            if cleaned and cleaned not in detail_fields_ws:
                detail_fields_ws.append(cleaned)

        # Extract X/Y axis fields from shelf text generically.
        import re as _re_psf
        _AGG_PFXS = {'sum','avg','min','max','ctd','cnt','usr','pcto','trunc',
                     'bin','year','qr','mn','wk','dt','dy',
                     'fval','cum','pctm','wtd',         # forecast, running total, % max
                     'tmn','tyr','tqr','twk','tdt',     # DATETRUNC prefixes
                     'wd',                              # week-day DATEPART
                     'attr',                            # attribute aggregation
                     'none',                            # explicit dimension (no aggregation)
                     'ok',                              # ordinal key suffix (Tableau internal)
                     'nk',                              # natural key (Tableau internal dim)
                     'qk',                              # quick key (Tableau internal)
                     }
        _DIM_PFXS = {'none','attr','bin'}
        _DATE_DIM_PFXS = {
            'tmn','tyr','tqr','twk','tdt','tdy',
            'yr','qr','mn','wk','dt','dy','hr','mi','ss','wd',
        }
        # Tableau forecast prefix: fVal:agg:field:kind (e.g. fVal:sum:Sale Amt:qk)
        # Strip the leading 'fVal:' so the underlying aggregation is used correctly.
        # Also handle cumulative: cum:sum:field:qk → treat as sum:field:qk
        _STRIP_OUTER_PFXS = ('fVal:', 'fcon:', 'cum:', 'pcto:')
        # Heatmap mark type: Tableau 'Square' or 'Rect' with color encoding
        # → PBI tableEx (closest equivalent)
        _HEATMAP_MARKS = {'Square', 'Rect', 'Polygon'}

        def _parse_shelf_tokens(txt):
            if not txt: return []
            result = []
            for _ds_tok, fld in _re_psf.findall(
                    r'\[([^\[\]]+)\]\.\[([^\[\]]+)\]', txt):
                # Strip outer Tableau prefixes (forecast fVal:, cumulative cum:)
                # e.g. fVal:sum:Sale Amt:qk → sum:Sale Amt:qk
                _fld_stripped = fld
                for _op in _STRIP_OUTER_PFXS:
                    if _fld_stripped.lower().startswith(_op.lower()):
                        _fld_stripped = _fld_stripped[len(_op):]
                        break
                fld = _fld_stripped
                parts = fld.split(':')
                agg   = parts[0].lower() if len(parts)>=2 else ''
                name  = parts[1]         if len(parts)>=2 else fld
                kind  = parts[2]         if len(parts)>=3 else ''
                is_mv = 'Multiple Values' in fld or 'Measure Names' in fld
                _is_date_dim = agg in _DATE_DIM_PFXS
                is_m  = agg in _AGG_PFXS and kind in ('qk','ok','') and not _is_date_dim
                is_d  = agg in _DIM_PFXS or _is_date_dim
                result.append({'name':name,'agg':agg,'kind':kind,
                               'is_measure':is_m and not is_d,
                               'is_dim':is_d,'is_mv':is_mv})
            return result

        cols_tokens = _parse_shelf_tokens(cols_txt)
        rows_tokens = _parse_shelf_tokens(rows_txt)
        has_mv_rows = any(t['is_mv'] for t in rows_tokens)

        def _first_dim(tokens):
            for t in tokens:
                if t['is_dim'] and not t['is_mv']:
                    c = _clean_field_name(t['name'], local_caption_map)
                    if c: return c
            return ''

        def _first_measure(tokens):
            for t in tokens:
                if t['is_measure'] and not t['is_mv']:
                    c = _clean_field_name(t['name'], local_caption_map)
                    if c: return c
            return ''

        x_field_ws = _first_dim(cols_tokens)
        y_field_ws = _first_measure(rows_tokens)

        # All measure fields — handles [Multiple Values] shelves generically.
        # When rows=[Multiple Values], ALL col-instances in datasource-dependencies
        # are the Y series (this covers DSO vs DPO, Quick Ratio, Op Cycle, etc.)
        all_row_measure_fields = []
        _dim_words = {'month','quarter','year','date','week','day','period',
                      'fiscal','fy','country','region','state','city','type',
                      'category','client','name','id','code','flag','icon',
                      'number of records','measure names','number of record',
                      'count','back'}
        # Also exclude the x_field (dimension on X axis) and alias columns
        _x_field_low = x_field_ws.lower().strip() if x_field_ws else ''

        def _is_alias_or_dim(name):
            """Return True if field should NOT be used as a Y-axis measure."""
            low = name.lower().strip()
            # Exclude (copy) alias columns — they duplicate real columns
            if '(copy)' in low: return True
            # Exclude trailing-space aliases (e.g. "Actual " = [Actual])
            if name != name.strip(): return True
            # Exclude the X-axis field itself
            if _x_field_low and low == _x_field_low: return True
            # Exclude known dimension words
            if any(d in low for d in _dim_words): return True
            return False

        if has_mv_rows or (rows_tokens and not y_field_ws):
            for dep in ws.findall('.//datasource-dependencies'):
                if dep.get('datasource','') == 'Parameters': continue
                for ci in dep.findall('column-instance'):
                    raw = ci.get('column','').strip('[]')
                    cleaned = _clean_field_name(raw, local_caption_map)
                    if not cleaned: continue
                    if _is_alias_or_dim(cleaned): continue
                    if cleaned not in all_row_measure_fields:
                        all_row_measure_fields.append(cleaned)
        else:
            for t in rows_tokens:
                if t['is_measure'] and not t['is_mv']:
                    c = _clean_field_name(t['name'], local_caption_map)
                    if c and not _is_alias_or_dim(c) and c not in all_row_measure_fields:
                        all_row_measure_fields.append(c)
        if not all_row_measure_fields and y_field_ws and not _is_alias_or_dim(y_field_ws):
            all_row_measure_fields = [y_field_ws]

        # Extra dimension fields from COLS (multi-dim X axis)
        all_col_dim_fields = []
        for t in cols_tokens:
            if t['is_dim'] and not t['is_mv']:
                c = _clean_field_name(t['name'], local_caption_map)
                if c and c != x_field_ws and c not in all_col_dim_fields:
                    all_col_dim_fields.append(c)

        # ── Horizontal bar chart axis correction ──────────────────────────────
        # Tableau hbar: COLS shelf = measures (Sale Amt, Cost Amt…) → PBI Y-axis
        #               ROWS shelf = dimension hierarchy (Region/City…) → PBI X-axis
        # When x_field_ws is empty (no dim on cols), capture ALL col-shelf measures
        # and promote the first rows-shelf dim to x_field_ws.
        _rows_dim_for_hbar = _first_dim(rows_tokens)
        if not x_field_ws:
            # Add ALL col-shelf measures to all_row_measure_fields
            for _ct in cols_tokens:
                if _ct.get('is_measure') and not _ct.get('is_mv'):
                    _cm = _clean_field_name(_ct['name'], local_caption_map)
                    if _cm and not _is_alias_or_dim(_cm) and _cm not in all_row_measure_fields:
                        all_row_measure_fields.append(_cm)
            # Use the rows-shelf dim as the X category
            if _rows_dim_for_hbar:
                x_field_ws = _rows_dim_for_hbar

        # ── Parse DATEPART groupings from shelf text ──────────────────────────
        # Tableau encodes DATEPART(year/quarter/month/…, [Field]) on the shelf as:
        #   [datasource].[yr:Order Date:ok]   → Year grouping of Order Date
        #   [datasource].[qr:Order Date:ok]   → Quarter grouping
        #   [datasource].[mn:Order Date:ok]   → Month grouping
        #   [datasource].[wk:Order Date:ok]   → Week grouping
        #   [datasource].[dt:Order Date:ok]   → Day grouping
        # In PBI these map to HierarchyLevel expressions referencing the built-in
        # "Date Hierarchy" variation on the date column.
        # We collect (col_name, pbi_level) pairs so the layout builder can emit
        # HierarchyLevel selects and projections instead of plain Column refs.
        import re as _re_dg
        # Full Tableau date-derivation prefix → PBI Date Hierarchy level mapping.
        # Tableau shelf tokens use these prefixes for DATEPART / DATETRUNC groupings:
        #   yr = Year,   qr = Quarter,  mn = Month,   wk = Week
        #   dt = Day (DATETRUNC to day), dy = Day (day-of-year, same PBI level)
        #   hr = Hour,   mi = Minute,   ss = Second
        # PBI's built-in Date Hierarchy supports Year/Quarter/Month/Day.
        # Hour/Minute/Second have no Date Hierarchy level — map to 'Day' as closest.
        _DG_LEVEL_MAP = {
            'yr': 'Year',  'qr': 'Quarter', 'mn': 'Month',
            'wk': 'Week',  'dt': 'Day',     'dy': 'Day',
            'hr': 'Hour',  'mi': 'Minute',  'ss': 'Second',
        }
        date_shelf_groupings = []   # list of {'col': col_name, 'level': 'Year'/…}
        for _shelf_txt in (cols_txt, rows_txt):
            for _tok in _re_dg.findall(r'\[([^\[\]]+)\]', _shelf_txt):
                _m_dg = _re_dg.match(
                    r'^(yr|qr|mn|wk|dt|dy|hr|mi|ss):(.+?):ok$', _tok, _re_dg.I
                )
                if _m_dg:
                    _prefix   = _m_dg.group(1).lower()
                    _col_raw  = _m_dg.group(2)
                    _col_name = local_caption_map.get(_col_raw, _col_raw).strip()
                    _level    = _DG_LEVEL_MAP[_prefix]
                    _entry    = {'col': _col_name, 'level': _level}
                    if _entry not in date_shelf_groupings:
                        date_shelf_groupings.append(_entry)

        # ── Extract shelf fields in order (for table column ordering) ─────────
        # These are all field names that appear on the rows shelf in their
        # original nested order — used to populate tableEx Rows exactly.
        shelf_row_fields = []
        if rows_txt:
            import re as _re_shelf
            # Extract all [ds].[col] pairs in order of appearance
            refs = _re_shelf.findall(
                r'\[[^\[\]]*\]\.\[([^\[\]]+)\]', rows_txt
            )
            for col_ref in refs:
                # Strip derivation prefix: none:name:nk → name, dy:Date:ok → Date, etc.
                # Covers all Tableau aggregation AND date-derivation prefixes so that
                # any shelf token resolves to the underlying base field name.
                m2 = _re_shelf.match(
                    r'^(?:none|sum|cnt|ctd|avg|min|max|attr|usr|pcto|bin'
                    r'|yr|qr|mn|wk|dt|dy|hr|mi|ss):(.+?)(?::(?:nk|ok|qk))?$',
                    col_ref, _re_shelf.I
                )
                fn = m2.group(1) if m2 else _re_shelf.sub(r':(?:nk|ok|qk)$', '', col_ref)
                # Apply caption map
                fn = local_caption_map.get(fn, fn).strip()
                if fn and fn not in shelf_row_fields:
                    shelf_row_fields.append(fn)

        # ── Parse Tableau filters for this worksheet ──────────────────────────
        ws_filter_fields  = []
        ws_filter_specs   = []   # [{field, values}] for specific-value filters
        measure_names_filter_fields = []  # measures from :Measure Names filter
        # Issue 5: Capture default filter selections for slicer initialisation
        _filter_defaults: dict = {}  # field_caption → [selected_values]
        for _fv in ws.findall('.//filter'):
            _fvf  = _fv.get('column','').strip('[]')
            # Only capture categorical (include-only) selections
            _incl = [v.get('value','') for v in _fv.findall('.//member[@member-is-included="true"]')]
            if _fvf and _incl:
                _filter_defaults[_fvf] = _incl
        for flt in ws.findall('.//view/filter'):
            col_ref = flt.get('column', '')
            if 'Action (' in col_ref or 'ui-action-filter' in col_ref:
                continue
            # Skip Tableau date-part grouping tokens: yr:Field:ok, mn:Field:ok, etc.
            # These are internal DATEPART/DATETRUNC shelf references — they have no
            # direct PBI filter equivalent and produce spurious filter entries on the
            # visual if emitted.  Covers all date-derivation prefixes generically.
            import re as _re_dg_flt
            if _re_dg_flt.search(
                r'\[(yr|qr|mn|wk|dt|dy|hr|mi|ss):[^\]]+:ok\]', col_ref, _re_dg_flt.I
            ):
                continue
            # Capture measures from the :Measure Names filter
            # (used on Tableau "Multiple Values" / measure-names grouped charts)
            if ':Measure Names' in col_ref or '[:Measure Names]' in col_ref:
                for gf in flt.findall('.//groupfilter[@function="member"]'):
                    raw_member = gf.get('member', '').strip('"')
                    # raw_member looks like "[ds_name].[sum:Accounts Payable:qk]"
                    cleaned_m = _clean_field_name(raw_member, local_caption_map)
                    if cleaned_m and cleaned_m not in measure_names_filter_fields:
                        measure_names_filter_fields.append(cleaned_m)
                continue   # :Measure Names is not a real filterable column
            fn = _clean_field_name(col_ref, local_caption_map)
            if not fn:
                continue
            if fn not in ws_filter_fields:
                ws_filter_fields.append(fn)
            # Collect any specific member values (e.g. Year = "FY-16").
            #
            # Direction detection:
            #   Tableau <groupfilter function="except"> → EXCLUDE the listed members.
            #   All other wrapper functions (union, intersect, level-members, or none)
            #   → INCLUDE the listed members (standard "In" filter).
            #
            # Null sentinel: Tableau uses '%null%' and '%empty%' as internal tokens
            # for null/empty values — they are not real data values.  Strip them from
            # the values list; PBI already hides nulls in most visuals by default.
            _top_gf  = flt.find('groupfilter')
            _is_excl = (_top_gf is not None and
                        _top_gf.get('function', '') == 'except')
            _null_sentinels = {'%null%', '%empty%', '%all%', ''}
            member_vals = [
                gf.get('member', '').strip('"')
                for gf in flt.findall('.//groupfilter[@function="member"]')
                if gf.get('member', '').strip('"') not in _null_sentinels
            ]
            if member_vals:
                ws_filter_specs.append({
                    'field':   fn,
                    'values':  member_vals,
                    'exclude': _is_excl,   # True → build NOT IN filter in PBI
                })

            # ── Context filter (Tableau <filter context="true">) ──────────────
            # Tableau computes context filters first; all other filters on the
            # sheet are then evaluated relative to that reduced dataset. Power BI
            # has no identical "compute this filter first" primitive, so the
            # closest approximation is ordering it ahead of the sheet's other
            # filters in the Filters pane (build_report_layout's shared filter
            # builder sorts on this flag). Flagged here rather than silently
            # dropped so the audit/log trail records the approximation.
            if flt.get('context', 'false').lower() == 'true':
                ws_filter_specs.append({'field': fn, 'context': True})

            # ── Quantitative (range) filter — <min>/<max> bounds ───────────────
            # Previously only captured as an unrestricted "field visible in
            # filter pane" entry (member_vals stays empty for range filters,
            # since there is no <groupfilter> — the bounds live in <min>/<max>
            # child elements instead). That silently dropped the actual
            # restriction, so a Tableau "Price between 100 and 500" filter
            # rendered the visual UNFILTERED in Power BI. Extract real bounds
            # when present and translate to a native Advanced (Between) filter.
            if flt.get('class', '') == 'quantitative':
                _min_el, _max_el = flt.find('min'), flt.find('max')
                if _min_el is not None or _max_el is not None:
                    ws_filter_specs.append({
                        'field': fn,
                        'kind':  'quantitative',
                        'min':   _min_el.text if _min_el is not None else None,
                        'max':   _max_el.text if _max_el is not None else None,
                    })

            # ── Relative-date filter — <filter class="relative-date" ...> ─────
            # Tableau recomputes this window against "today" every time the
            # view opens. Power BI's internal Report.json filter format has no
            # publicly verified equivalent we can safely emit (a wrong shape
            # risks an unopenable filter/report), so we take the closest safe
            # approximation: snapshot the concrete date window using the
            # anchor date recorded in the workbook, emit it as a native
            # Advanced (Between) date filter, and log clearly that it is a
            # static snapshot needing reconfiguration as a live Power BI
            # relative-date filter for ongoing use.
            elif flt.get('class', '') == 'relative-date':
                _rel_start, _rel_end = _relative_date_window(
                    flt.get('period-type-v2', 'month'),
                    flt.get('first-period', '0'),
                    flt.get('last-period', '0'),
                    flt.get('period-anchor', ''),
                )
                if _rel_start and _rel_end:
                    ws_filter_specs.append({
                        'field':     fn,
                        'kind':      'relative-date',
                        'rel_start': _rel_start,
                        'rel_end':   _rel_end,
                    })
                    log('warn',
                        f"Relative-date filter on '{fn}' converted to a static "
                        f"snapshot [{_rel_start} .. {_rel_end}] — reconfigure as a "
                        f"live Power BI relative-date filter for ongoing use.",
                        filename=ws_name)

            # ── Top-N filter — <groupfilter function="order" end=".." count=".."> ──
            # Tableau's Top/Bottom-N quick filter nests an "order" groupfilter
            # (end='top'/'bottom', count=N, expression=<ranking measure>) inside
            # the sheet's <filter>. Previously undetected entirely — the field
            # rendered completely unfiltered. Map to Power BI's native TopN
            # SQE filter condition (same query-language family already used
            # for the 'In'/'Not' categorical filters below).
            _topn_gf = next(
                (gf for gf in flt.findall('.//groupfilter')
                 if gf.get('end') in ('top', 'bottom') and gf.get('count')),
                None
            )
            if _topn_gf is not None:
                _topn_measure = None
                _topn_expr = _topn_gf.get('expression', '')
                _m_ref = _re_dg_flt.search(r'\[([^\[\]]+)\]', _topn_expr)
                if _m_ref:
                    _topn_measure = _clean_field_name(f'[{_m_ref.group(1)}]', local_caption_map)
                try:
                    _topn_count = int(float(_topn_gf.get('count')))
                except (TypeError, ValueError):
                    _topn_count = None
                if _topn_count:
                    ws_filter_specs.append({
                        'field':          fn,
                        'kind':           'topn',
                        'topn_count':     _topn_count,
                        'topn_direction': _topn_gf.get('end', 'top'),
                        'topn_measure':   _topn_measure,
                    })

        # ── Parse sort spec for PBI OrderBy ───────────────────────────────────
        # Tableau <sort> elements specify how dimension members are ordered.
        # We translate ASC→Direction=1, DESC→Direction=2 and store the first
        # non-Measure-Names sort field so the layout builder can emit OrderBy.
        #
        # For time-series axes (Month, Quarter, Year on the cols shelf) we also
        # detect and force an ascending sort even if no <sort> element is present,
        # because PBI defaults to alphabetical which breaks chronological order.
        import re as _re_sort

        sort_field   = None
        sort_dir     = 1
        sort_is_col  = True

        for sort_el in ws.findall('.//sort'):
            raw_col = sort_el.get('column', '')
            direction = sort_el.get('direction', 'ASC').upper()
            sort_class = sort_el.get('class', '').lower()
            # Skip Measure-Names sorts (multi-measure shelf artifact)
            if ':Measure Names' in raw_col or '[:Measure Names]' in raw_col:
                continue
            # Skip Tableau "natural" sorts — these are the default chronological
            # ordering for date/time dimensions (Month, Quarter, Year). Power BI
            # line and combo charts with date axes already render in natural data
            # order, so adding an explicit Column OrderBy is unnecessary and wrong.
            if sort_class == 'natural':
                continue
            cleaned = _clean_field_name(raw_col, local_caption_map)
            if cleaned:
                sort_field  = cleaned
                sort_dir    = 1 if direction == 'ASC' else 2
                sort_is_col = ':nk' in raw_col or ':ok' in raw_col or ':dk' in raw_col
                break

        # NOTE: We intentionally do NOT force a Column sort on date/time axes.
        # Line and combo charts with Month/Quarter/Year on the X-axis render
        # in natural data order (which is already chronological from the extract).
        # Forcing an alphabetical Column sort would break charts like "Apr-13,
        # Feb-13, Jan-13, …" (alphabetical ≠ chronological).
        # Column/bar charts get a default measure-descending sort added later at
        # the build_report_layout call site instead.

        # ── Detect single-measure text/shape worksheets (KPI cards) ─────────────
        # Worksheets with EMPTY rows+cols shelves and a MEASURE text encoding
        # (sum:col:qk, cnt:col:qk etc.) are KPI-style single-number displays.
        # Only activate for measure encodings — dimension text encodings (none:col:nk,
        # e.g. 'Income - ' showing Country) still need the full datasource columns.
        # Also handle Shape-mark indicator pages: use the shape encoding field.
        text_enc_field = None
        if row_type == 'EMPTY' and col_type == 'EMPTY':
            import re as _re_text
            # Try pane-level text encodings first
            for enc in (ws.findall('.//pane/encodings/text')
                        + ws.findall('.//encodings/text')):
                raw_col = enc.get('column', '')
                if not raw_col: continue
                # Accept any aggregation prefix (extended list)
                m_text = _re_text.search(
                    r'\[(sum|cnt|ctd|avg|min|max|attr|pct|pcto|usr|fval|cum'
                    r'|yr|qr|mn|wk|tmn|tyr|tqr):(.+?):\w+\]',
                    raw_col, _re_text.I
                )
                if m_text:
                    cleaned = _clean_field_name(raw_col, local_caption_map)
                    if cleaned:
                        text_enc_field = cleaned
                        break
                # Fallback: even without a recognised prefix, try to clean the ref
                if not text_enc_field:
                    cleaned = _clean_field_name(raw_col, local_caption_map)
                    if cleaned and cleaned not in ('Measure Names', 'Measure Values'):
                        text_enc_field = cleaned
                        break

            # If still empty and we have only measure tokens on rows/cols,
            # use the first measure token from any shelf as the KPI value.
            if not text_enc_field:
                for t in rows_tokens + cols_tokens:
                    if t.get('is_measure') and not t.get('is_mv'):
                        cleaned = _clean_field_name(t['name'], local_caption_map)
                        if cleaned:
                            text_enc_field = cleaned
                            break

            # For Shape-mark card pages, derive the measure from shape encoding.
            if not text_enc_field and chart_type == 'card':
                for enc in ws.findall('.//pane/encodings/shape'):
                    raw_col = enc.get('column', '')
                    if not raw_col:
                        continue
                    cleaned = _clean_field_name(raw_col, local_caption_map)
                    if cleaned:
                        text_enc_field = cleaned
                    break

        # ── For map worksheets: extract location and size encoding fields ─────
        # Tableau geographic maps use Latitude/Longitude (generated) on shelves
        # and put the actual entity dimension in color or detail (lod) encoding,
        # with a measure on size encoding.  We capture those here for use in the
        # PBI map visual generator.
        map_location_field = ''
        map_size_field     = ''
        if chart_type in ('mapChart', 'filledMap'):
            # Location: for filledMap Tableau puts the geo dim in lod encoding;
            # for mapChart it's also lod or color. Check lod first, then color.
            for enc in (ws.findall('.//pane/encodings/lod')
                        + ws.findall('.//encodings/lod')
                        + ws.findall('.//pane/encodings/color')
                        + ws.findall('.//encodings/color')):
                raw_col = enc.get('column', '')
                if not raw_col:
                    continue
                cleaned = _clean_field_name(raw_col, local_caption_map)
                # Skip measure encodings (aggregated) — we want the dimension
                if cleaned and (':nk]' in raw_col or not any(
                        agg in raw_col for agg in ('sum:','avg:','min:','max:','cnt:','ctd:'))):
                    map_location_field = cleaned
                    break
            # Size/color measure: size encoding, then color encoding (measure)
            for enc in (ws.findall('.//pane/encodings/size')
                        + ws.findall('.//encodings/size')
                        + ws.findall('.//pane/encodings/color')
                        + ws.findall('.//encodings/color')):
                raw_col = enc.get('column', '')
                if not raw_col: continue
                cleaned = _clean_field_name(raw_col, local_caption_map)
                if cleaned and any(agg in raw_col for agg in
                                   ('sum:','avg:','ctd:','cnt:','min:','max:')):
                    map_size_field = cleaned
                    break
            # Fallback location: first detail_fields or color_fields
            if not map_location_field and detail_fields_ws:
                map_location_field = detail_fields_ws[0]
            if not map_location_field and color_fields_ws:
                map_location_field = color_fields_ws[0]
            # Fallback size: first measure in fields
            if not map_size_field:
                for f in ordered:
                    if isinstance(f, dict) and f.get('is_measure'):
                        map_size_field = f.get('name', '')
                        break
                    elif isinstance(f, str) and f:
                        map_size_field = f
                        break

        # ── For treemap/bubble worksheets: move encoding fields to front of 'ordered' ─
        # Tableau treemaps and bubble charts have EMPTY shelves — the Category
        # (color enc), Details (lod enc), and Size (size enc) fields are carried
        # exclusively in the pane encodings, NOT on rows/cols.
        # Without this, 'ordered' has datasource-dependency columns in arbitrary
        # order, so filtered_cols is wrong and the treemap builder may pick the
        # wrong first non-measure dimension as the Category.
        # We move these fields to the front so filtered_cols[0] is the color field
        # (i.e. the intended Category).  The layout builder also reads color_names[0]
        # directly, so this is belt-and-suspenders correctness.
        if chart_type in ('treemap', 'bubbleChart'):
            _enc_ordered = []
            for _ef in color_fields_ws:       # color enc → Category
                if _ef: _enc_ordered.append(_ef)
            for _ef in detail_fields_ws:      # lod enc → Details
                if _ef and _ef not in _enc_ordered: _enc_ordered.append(_ef)
            if size_enc_field and size_enc_field not in _enc_ordered:
                _enc_ordered.append(size_enc_field)  # size enc → Values/Y
            # Rebuild ordered: encoding fields first (in enc order), then remaining
            _rest = [f for f in ordered if f not in _enc_ordered]
            ordered = _enc_ordered + _rest

        worksheets.append({
            'name':             ws_name,
            'ds_names':         ws_ds_names,
            'fields':           ordered,
            'chart_type':       chart_type,
            'color_fields':     color_fields_ws,
            'detail_fields':    detail_fields_ws,
            'pcto_field':       pcto_field,
            'show_data_labels': show_data_labels,
            'label_format':     label_format,
            'background_color': background_color,
            'title_font_family': title_font_family,
            'title_font_size':   title_font_size,
            'title_bold':        title_bold,
            'title_italic':      title_italic,
            'title_color':       title_color,
            'title_bg_color':    title_bg_color,
            'axis_label_font_family': axis_label_font_family,
            'axis_label_font_size':   axis_label_font_size,
            'axis_label_bold':        axis_label_bold,
            'axis_label_italic':      axis_label_italic,
            'axis_label_color':       axis_label_color,
            'legend_font_family': legend_font_family,
            'legend_font_size':   legend_font_size,
            'legend_bold':        legend_bold,
            'legend_italic':      legend_italic,
            'legend_color':       legend_color,
            'datalabel_font_family': datalabel_font_family,
            'datalabel_font_size':   datalabel_font_size,
            'datalabel_bold':        datalabel_bold,
            'datalabel_italic':      datalabel_italic,
            'datalabel_color':       datalabel_color,
            'axis_title_value':    axis_title_value,
            'axis_title_value2':   axis_title_value2,
            'axis_title_category': axis_title_category,
            'gridlines_hidden':    gridlines_hidden,
            'x_field':          x_field_ws,
            'y_field':          y_field_ws,
            'all_row_measure_fields': all_row_measure_fields,
            'all_col_dim_fields':    all_col_dim_fields,
            'all_col_fields':   all_col_fields,
            # FIX: store Pages shelf fields → PBI Small Multiples
            'pages_fields':     pages_fields,
            'pane_marks':       pane_marks,
            'reference_lines':  ws_reference_lines,   # [{axis_column,value_column,scope,formula,value,label,...}]
            'trendline':        ws_trendline,         # {fit, degree} or None
            'axis_synchronized': ws_axis_synchronized,  # dual-axis "Synchronize Axis" flag (report-only)
            'pane_mark_colors': pane_mark_colors,    # per-pane explicit hex or None (all panes)
            # Filtered colors: one entry per real chart-measure pane (Automatic/Circle skipped).
            # Aligns with value_fields in _make_chart_vc for color_is_measure_names charts.
            'chart_pane_colors': [
                c for m, c in zip(pane_marks, pane_mark_colors)
                if m not in ('Automatic', 'Circle')
            ],
            'row_type':         row_type,
            'col_type':         col_type,
            'shelf_row_fields': shelf_row_fields,
            'filter_fields':    ws_filter_fields,
            'filter_specs':     ws_filter_specs,     # [{field,values}] specific-value filters
            'filter_defaults':  _filter_defaults,    # Issue 5: default selections per filter
            'measure_names_filter_fields': measure_names_filter_fields,
            'sort_field':       sort_field,          # field to sort by in OrderBy
            'sort_dir':         sort_dir,            # 1=ASC, 2=DESC
            'sort_is_col':      sort_is_col,         # True=Column, False=Measure
            'text_enc_field':   text_enc_field,      # single text-enc measure (KPI display)
            'pie_size_field':   pie_size_field,      # wedge-size column → pie/donut Aggregation value
            'size_enc_field':   size_enc_field,      # size encoding column → treemap/bubble size
            'date_shelf_groupings': date_shelf_groupings,  # [{col, level}] DATEPART shelf refs
            'map_location_field': map_location_field, # mapChart: geocoded location dimension
            'map_size_field':     map_size_field,     # mapChart: bubble-size measure
            'ctd_fields':         list(_ctd_fields_ws), # columns used with COUNT DISTINCT (ctd:)
        })

    # ── Extract embedded data from .hyper if this is a .twbx ─────────────────
    extracted_data = {}
    if path.suffix.lower() == '.twbx':
        extracted_data = extract_twbx_data(path)
        if extracted_data.get('has_data'):
            n_ds = len(extracted_data.get('datasources', {}))
            log("info", f"  ↳ Embedded data found in {n_ds} datasource(s)")

    # ── Extract color palette from TWB styling ────────────────────────────────
    TABLEAU_10 = [
        '#4e79a7', '#f28e2b', '#59a14f', '#e15759',
        '#76b7b2', '#edc948', '#b07aa1', '#ff9da7',
        '#9c755f', '#bab0ac',
    ]

    def _extract_workbook_palette(xml_root):
        for pal in xml_root.findall('.//color-palette'):
            if pal.get('type', '') not in ('regular', 'ordered-sequential',
                                           'ordered-diverging', ''):
                continue
            colors = []
            for c in pal.findall('color'):
                val = (c.text or '').strip()
                if val:
                    colors.append(val if val.startswith('#') else '#' + val)
            if len(colors) >= 2:
                return colors
        return None

    custom_palette = _extract_workbook_palette(root)
    data_colors = custom_palette if custom_palette else TABLEAU_10

    # ── Parse explicit value→color mappings from datasource columns ───────────
    # Tableau stores these in <color-map><bucket value="'v'" color="#hex"/></color-map>
    # inside <column> definitions.  When present they override the default palette
    # and alphabetical assignment — the author deliberately chose those colors.
    #
    # Also handle the worksheet-level <encoding type="color"><map><bucket .../> pattern.
    #
    # Result: explicit_color_map = {field_caption: {'value_string': '#hexcolor', ...}}
    explicit_color_map: dict = {}   # field_name → {value → hex}

    import re as _re_color

    def _norm_color(hex_str):
        """Normalize a Tableau color value to lowercase 7-char hex."""
        h = (hex_str or '').strip().lstrip('#')
        return '#' + h.lower() if h else ''

    def _strip_quotes(v):
        """Strip surrounding single-quotes that Tableau adds to string values."""
        if v.startswith("'") and v.endswith("'"):
            return v[1:-1]
        return v

    for ds in root.findall('.//datasource'):
        if 'Parameters' in ds.get('name', ''):
            continue
        for col in ds.findall('.//column'):
            col_caption = col.get('caption', '') or _re_color.sub(
                r'^\[|\]$', '', col.get('name', ''))
            col_caption = col_caption.strip()

            color_map_el = col.find('color-map')
            if color_map_el is not None:
                val_to_color = {}
                for bucket in color_map_el.findall('bucket'):
                    raw_val = bucket.get('value', '')
                    raw_hex = bucket.get('color', '')
                    val = _strip_quotes(raw_val)
                    hex_c = _norm_color(raw_hex)
                    if val and hex_c:
                        val_to_color[val] = hex_c
                if val_to_color and col_caption:
                    explicit_color_map[col_caption] = val_to_color

    # Also tag each worksheet: does its color encoding use ':Measure Names'?
    # When it does, we use metadata selectors (one per measure) instead of
    # value-based In-expression selectors.
    for ws_dict in worksheets:
        ws_el = next(
            (w for w in root.findall('.//worksheet')
             if w.get('name') == ws_dict['name']),
            None
        )
        uses_measure_names_color = False
        if ws_el is not None:
            for enc in ws_el.findall('.//encodings/color'):
                col_ref = enc.get('column', '')
                if ':Measure Names' in col_ref or col_ref.endswith('.[:Measure Names]'):
                    uses_measure_names_color = True
                    break
        ws_dict['color_is_measure_names'] = uses_measure_names_color

    # ── Reorder worksheets and mark hidden ones from <windows> ───────────────
    # The <windows> section is Tableau's tab bar.  It lists every tab that is
    # visible in the workbook UI, in display order.  Rules:
    #
    #   • A <window class="worksheet"> entry WITHOUT a <hidden> child → visible
    #   • A <window class="worksheet"> entry WITH <hidden value="true"> → hidden
    #   • A worksheet whose name never appears in <windows> at all     → hidden
    #     (Tableau omits worksheet windows when a dashboard hides them)
    #   • A <window class="dashboard"> entry → visible dashboard tab
    #
    # We store hidden=True on each worksheet dict so build_report_layout can
    # skip hidden worksheets and fall back to dashboards when appropriate.
    windows_el = root.find('.//windows')
    if windows_el is not None:
        # Build: name → is_explicitly_hidden (True/False)
        _win_map: dict = {}
        for w in windows_el:
            wname  = w.get('name', '')
            wclass = w.get('class', '')
            if not wname:
                continue
            hidden_child = w.find('hidden')
            is_hidden = (hidden_child is not None and
                         hidden_child.get('value', '').lower() == 'true')
            if wclass in ('worksheet', 'dashboard'):
                _win_map[wname] = is_hidden

        # Determine whether any dashboard tabs exist
        _has_dashboard_tabs = any(
            w.get('class') == 'dashboard' and not _win_map.get(w.get('name',''), True)
            for w in windows_el
        )

        # Build ordered visible worksheet list from <windows>
        _win_order = [w.get('name', '') for w in windows_el
                      if w.get('class') == 'worksheet' and w.get('name')]

        if _win_order:
            _ws_by_name = {ws['name']: ws for ws in worksheets}
            _ordered = [_ws_by_name[n] for n in _win_order if n in _ws_by_name]
            _ordered_names = {ws['name'] for ws in _ordered}
            for ws in worksheets:
                if ws['name'] not in _ordered_names:
                    _ordered.append(ws)
            worksheets = _ordered

        # Mark hidden status on each worksheet:
        # Hidden if: (a) explicitly flagged in <windows>, or
        #            (b) absent from <windows> entirely while a dashboard exists
        for ws in worksheets:
            wn = ws['name']
            if wn in _win_map:
                ws['hidden'] = _win_map[wn]          # explicit flag from XML
            elif _has_dashboard_tabs:
                ws['hidden'] = True                   # absent from windows + has dashboards
            else:
                ws['hidden'] = False                  # no dashboard context → visible

    # ── Parse Tableau relationships for the PBI data model ───────────────────
    # Tableau federated datasources use <relationships> XML to define joins.
    # We convert these to PBI model relationships (fromTable/fromColumn/toTable/toColumn).
    # Key: table_object_id → canonical table name (last segment after '.' in filename)
    import re as _re_rel
    _obj_to_table: dict = {}
    # Primary source: <metadata-records><metadata-record class="column">'s own
    # object-id attribute (plain "object-id", or a version-prefixed key
    # ending "...object-id", e.g. "_.fcp.ObjectModelEncapsulateLegacy.true
    # ...object-id" — both forms confirmed real) paired with parent-name.
    # More reliable than the <relation type="table"> name attribute below:
    # confirmed real (sales_dashboard.twb, superstore_profits.twbx) that a
    # relationship's <first-end-point object-id="Orders_HASH"> can reference
    # a hash-suffixed id that never appears as any <relation name=...> at
    # all — only in metadata-records — so relying on <relation> alone left
    # these two fixtures' relationships unresolved (fromTable/toTable fell
    # back to the raw, un-canonicalised object-id string).
    for _ds in root.findall('.//datasource'):
        for _mr in _ds.findall('.//metadata-records/metadata-record[@class="column"]'):
            _pn = _mr.findtext('parent-name', '') or ''
            _m_pn = _re_rel.search(r'\[([^\[\]]+?)(?:_[A-F0-9]{32})?\]$', _pn)
            if not _m_pn:
                continue
            _tbl = _m_pn.group(1).replace('.csv', '').replace('.CSV', '')
            _tbl = _re_rel.sub(r'[^a-zA-Z0-9 _]', '', _tbl).strip()
            if not _tbl:
                continue
            # object-id can appear as an attribute OR as a child element (tag
            # possibly version-prefixed, e.g. "_.fcp.ObjectModelEncapsulate
            # Legacy.true...object-id") — both confirmed real across
            # different fixtures (Sales Param uses the attribute form,
            # sales_dashboard/superstore_profits use a plain <object-id>
            # child element).
            _oid_val = ''
            for _ak, _av in _mr.attrib.items():
                if _ak == 'object-id' or _ak.endswith('...object-id'):
                    _oid_val = _av.strip('[]')
                    break
            if not _oid_val:
                for _child in _mr:
                    if _child.tag == 'object-id' or _child.tag.endswith('...object-id'):
                        _oid_val = (_child.text or '').strip('[]')
                        break
            if _oid_val:
                _obj_to_table.setdefault(_oid_val, _tbl)
            _pn_clean = _pn.strip('[]')
            if _pn_clean:
                _obj_to_table.setdefault(_pn_clean, _tbl)
    # Fallback for datasources with no <metadata-records> at all: the
    # <relation type="table"> name attribute (only reliable when it happens
    # to carry the same hash-suffixed form the relationship endpoints use —
    # true for some workbooks, e.g. Amazon Sales Insights, not others).
    for _ds in root.findall('.//datasource'):
        for _rel_elem in _ds.findall('.//relation[@type="table"]'):
            _obj_id  = _rel_elem.get('name', '')
            if not _obj_id or _obj_id in _obj_to_table:
                continue
            _tbl_ref = _rel_elem.get('table', '')    # e.g. [Extract].[transactions.csv_XXX]
            _m = _re_rel.search(r'\[([^\[\]]+?)(?:_[A-F0-9]{32})?\]$', _tbl_ref)
            if _m:
                _base = _m.group(1).replace('.csv','').replace('.CSV','')
                _base = _re_rel.sub(r'[^a-zA-Z0-9 _]', '', _base).strip()
                if _base:
                    _obj_to_table[_obj_id] = _base

    _pbi_relationships: list = []
    _ds_relationships: dict = {}   # ds raw name -> this ds's own relationship dicts
    for _ds in root.findall('.//datasource'):
        _ds_name_rel = _ds.get('name', '')
        for _rel_block in _ds.findall('.//relationships'):
            for _rel in _rel_block.findall('relationship'):
                _expr = _rel.find('expression')
                if _expr is None: continue
                # expression has two child expressions: left=from, right=to
                _children = list(_expr.findall('expression'))
                if len(_children) < 2: continue
                _from_col_raw = _children[0].get('op','').strip('[]')
                _to_col_raw   = _children[1].get('op','').strip('[]')
                # Map via caption map
                _from_col = global_calc_caption_map.get(
                    f'[{_from_col_raw}]', _from_col_raw).strip()
                _to_col   = global_calc_caption_map.get(
                    f'[{_to_col_raw}]', _to_col_raw).strip()
                # Resolve table names via endpoint object-ids
                _ep1 = _rel.find('first-end-point')
                _ep2 = _rel.find('second-end-point')
                if _ep1 is None or _ep2 is None: continue
                _from_tbl_obj = _ep1.get('object-id','')
                _to_tbl_obj   = _ep2.get('object-id','')
                _from_tbl = _obj_to_table.get(_from_tbl_obj, _from_tbl_obj)
                _to_tbl   = _obj_to_table.get(_to_tbl_obj, _to_tbl_obj)
                if _from_tbl and _to_tbl and _from_col and _to_col:
                    _rel_entry_rel = {
                        'fromTable':  _from_tbl,
                        'fromColumn': _from_col,
                        'toTable':    _to_tbl,
                        'toColumn':   _to_col,
                    }
                    _pbi_relationships.append(_rel_entry_rel)
                    _ds_relationships.setdefault(_ds_name_rel, []).append(_rel_entry_rel)

    # ── Real per-table split info for datasources with genuine relationships ──
    # Increment 22: build_data_model_schema used to flatten every Tableau
    # datasource — including federated ones with real declared relationships
    # — into ONE merged PBI table, then still emit relationship objects
    # pointing at the original (now nonexistent) sub-table names. Every such
    # relationship was dangling — Power BI Desktop would refuse to open the
    # file cleanly ("Relationship object doesn't exist"). Confirmed against
    # all 5 real fixtures that declare relationships (Amazon Sales Insights,
    # Sales Param, sales_dashboard, superstore_profits(_extract)): 100% of
    # emitted relationships were dangling.
    #
    # Fix (additive, zero risk to the existing single-merged-table visual
    # pipeline every worksheet/chart resolver depends on): keep the merged
    # "fact" table exactly as before (every existing column stays, so every
    # already-verified visual/DAX binding keeps working unchanged), and ALSO
    # generate genuine standalone dimension tables — one per real Tableau
    # sub-table on the "one" side of a relationship — wired with real,
    # schema-verified relationship objects (fromCardinality/toCardinality per
    # the TMSL Relationship schema: learn.microsoft.com/analysis-services/
    # tmsl/relationships-object-tmsl). This gives a genuine, non-dangling
    # Logical layer (relationships) + Physical layer (real imported tables)
    # without touching any existing chart-resolution code.
    #
    # Column→real-table membership comes from Tableau's own schema-verified
    # <metadata-records><metadata-record class="column"><local-name>/
    # <parent-name> (confirmed real in all fixtures with relationships) —
    # not guessed from column-name heuristics.
    def _infer_relationships_from_cols_map(_ds_el):
        """Infer join relationships for a datasource that declares NO
        <object-graph><relationships> block at all — the older
        <relation type='collection'> physical style (a flat list of
        type='table' sub-relations plus a <cols> map assigning every field
        to its owning physical table), used by standalone .twb exports that
        never went through Tableau's newer Relationships (logical layer) UI.

        Confirmed real on sales_dashboard_new.twb: no <object-graph>
        anywhere, but its <cols> map contains both a plain '[Region]' ->
        '[Orders].[Region]' entry and a disambiguated '[Region (People)]' ->
        '[People].[Region]' entry — Tableau's own standing convention for
        "this field collides with one on another table" (the SAME suffix
        convention _strip_dim_disambig_suffix already strips when building
        dimension tables below). Without this, such a datasource never gets
        a _dim_split at all: every sub-table's columns (e.g. Regional
        Manager, a People-only field) leak into the single flat/fact table's
        column list via Pass 2's recursive `.//column` scan, so Power BI's
        TOM declares a column the fact table's own M query (which only ever
        reads ONE physical sheet) never produces — "The column '...' of the
        table wasn't found."

        Returns relationship dicts shaped identically to the <object-graph>
        parsing above (fromTable/fromColumn/toTable/toColumn, using
        col_table-space keys — i.e. the disambiguated bracket-stripped name,
        not the bare physical column name) so every downstream consumer
        (_ds_dim_table_info, the dimension-table builder, the relationship-
        emission loop) works unchanged regardless of which XML shape the
        relationship was discovered in.
        """
        _cols_map_el = _ds_el.find('.//cols')
        if _cols_map_el is None:
            return []
        _field_table: dict = {}   # col_table-space key -> (table, physical_col)
        for _m in _cols_map_el.findall('map'):
            _key = (_m.get('key') or '').strip('[]')
            _val = _m.get('value') or ''
            _vm = _re_rel.match(r'^\[([^\[\]]+)\]\.\[([^\[\]]+)\]$', _val)
            if _key and _vm:
                _field_table[_key] = (_vm.group(1), _vm.group(2))
        if len(_field_table) < 2:
            return []
        _tables_used = {_t for _t, _c in _field_table.values()}
        if len(_tables_used) < 2:
            return []
        from collections import Counter as _Counter_cm
        _fact_tbl = _Counter_cm(_t for _t, _c in _field_table.values()).most_common(1)[0][0]
        _rels_out = []
        for _key, (_tbl, _col) in _field_table.items():
            if _tbl == _fact_tbl:
                continue
            _suffix_m = _re_rel.match(r'^(.+) \(' + _re_rel.escape(_tbl) + r'\)$', _key)
            if not _suffix_m:
                continue
            _base = _suffix_m.group(1)
            _fact_side = _field_table.get(_base)
            if _fact_side and _fact_side[0] == _fact_tbl:
                _rels_out.append({
                    'fromTable':  _fact_tbl,
                    'fromColumn': _base,
                    'toTable':    _tbl,
                    'toColumn':   _key,
                })
        return _rels_out

    _ds_dim_table_info: dict = {}   # ds raw name -> {fact_table, col_table, dim_tables, relationships}
    for _ds in root.findall('.//datasource'):
        _ds_name_rel = _ds.get('name', '')
        _rels_here = _ds_relationships.get(_ds_name_rel, [])
        if not _rels_here:
            # Fallback: no <object-graph> relationships declared — a
            # type='collection' multi-table datasource may still encode the
            # same join intent via its <cols> map. Mutually exclusive with
            # the block above (only fires when that found nothing).
            _rels_here = _infer_relationships_from_cols_map(_ds)
            if _rels_here:
                _ds_relationships[_ds_name_rel] = _rels_here
                _pbi_relationships.extend(_rels_here)
        if not _rels_here:
            continue   # no real relationships on this datasource — nothing to split out

        # internal column name -> {'table':, 'remote_name':, 'local_type':}.
        # remote_name/local_type let build_data_model_schema synthesize a
        # relationship's FK/PK column when Tableau never emitted a <column>
        # element for it at all — confirmed real (Sales Param: the
        # relationship's own <expression op='[Region (People)]'> and this
        # exact metadata-record both reference it, but there is no matching
        # <column> anywhere in the datasource — Tableau only emits <column>
        # elements for fields actually dragged into a worksheet, while
        # <metadata-records> records every physical column regardless).
        import re as _re_mdr
        _col_table: dict = {}
        for _mr in _ds.findall('.//metadata-records/metadata-record[@class="column"]'):
            _ln = (_mr.findtext('local-name', '') or '').strip('[]')
            _pn = (_mr.findtext('parent-name', '') or '')
            if not _ln or not _pn:
                continue
            _m_pn = _re_mdr.search(r'\[([^\[\]]+?)(?:_[A-F0-9]{32})?\]$', _pn)
            if not _m_pn:
                continue
            _tbl = _m_pn.group(1).replace('.csv', '').replace('.CSV', '')
            _tbl = _re_mdr.sub(r'[^a-zA-Z0-9 _]', '', _tbl).strip()
            if _tbl and _ln not in _col_table:
                _col_table[_ln] = {
                    'table':       _tbl,
                    'remote_name': _mr.findtext('remote-name', '') or _ln,
                    'local_type':  _mr.findtext('local-type', '') or 'string',
                }
        if not _col_table:
            continue

        _real_tables = ({r['fromTable'] for r in _rels_here}
                        | {r['toTable'] for r in _rels_here})
        if len(_real_tables) < 2:
            continue   # relationship endpoints didn't resolve to 2+ distinct tables

        # Fact table = the side Tableau lists as first-end-point most often.
        # Confirmed across every real relationship in every fixture: the
        # detail/many side is always first-end-point, the dimension/one side
        # always second-end-point (Amazon Sales Insights' 4 relationships all
        # originate from 'transactions'; Sales Param/sales_dashboard/
        # superstore_profits(_extract)'s 2 each originate from 'Orders').
        from collections import Counter as _Counter_rel
        _fact_table = _Counter_rel(r['fromTable'] for r in _rels_here).most_common(1)[0][0]

        # Per real sub-table connection info, for the new dimension tables'
        # own M query (file-path-parameter mode; embed_sample_data mode uses
        # extracted_data instead and doesn't need this).
        _nc_map_rel: dict = {}
        for _nc in _ds.findall('.//named-connection'):
            _inner = _nc.find('./connection')
            if _inner is not None:
                _nc_map_rel[_nc.get('name', '')] = {
                    'filename': _inner.get('filename', '') or _inner.get('dbname', ''),
                    'class':    _inner.get('class', ''),
                }

        _dim_tables: dict = {}   # real table name -> {filename, class, sheet_tab}
        for _rel_elem in _ds.findall('.//relation[@type="table"]'):
            _tbl_ref = _rel_elem.get('table', '')
            _m_rt = _re_mdr.search(r'\[([^\[\]]+?)(?:_[A-F0-9]{32})?\]$', _tbl_ref)
            if not _m_rt:
                continue
            _tname = _m_rt.group(1).replace('.csv', '').replace('.CSV', '')
            _tname = _re_mdr.sub(r'[^a-zA-Z0-9 _]', '', _tname).strip()
            if _tname not in _real_tables or _tname == _fact_table or _tname in _dim_tables:
                continue
            _conn_meta = _nc_map_rel.get(_rel_elem.get('connection', ''), {})
            _rname = _rel_elem.get('name', '')
            _sheet_tab = _re_mdr.sub(r'\.(csv|xlsx?|txt|tsv)$', '', _rname, flags=_re_mdr.I) if _rname else ''
            _dim_tables[_tname] = {
                'filename':  _conn_meta.get('filename', '') or _tbl_ref.strip('[]'),
                'class':     _conn_meta.get('class', ''),
                'sheet_tab': _sheet_tab,
            }

        if _dim_tables:
            _ds_dim_table_info[_ds_name_rel] = {
                'fact_table':    _fact_table,
                'col_table':     _col_table,
                'dim_tables':    _dim_tables,
                'relationships': _rels_here,
            }

    # Attach the split info onto the matching already-built datasource dict
    # (matched by raw_name — the same Tableau <datasource name=…> attribute
    # used as the key above) so build_data_model_schema can use it without
    # re-parsing the XML.
    for _d in datasources:
        _info = _ds_dim_table_info.get(_d.get('raw_name', ''))
        if _info:
            _d['_dim_split'] = _info

    # ── Physical join-tree detection (classic <relation type='join'>) ────────
    # Mutually exclusive with the Relationships model just above (a Tableau
    # datasource uses either <relationships> or a type='join' physical
    # relation, never both) — this only fires for datasources that have
    # neither a single plain table nor a declared Relationships block.
    # See _parse_relation_join_tree's docstring for the schema citation.
    for _ds_jt in root.findall('.//datasource'):
        _ds_raw_name = _ds_jt.get('name', '')
        _d_match = next((d for d in datasources if d.get('raw_name') == _ds_raw_name), None)
        if _d_match is None or _d_match.get('_dim_split'):
            continue   # already has a real Relationships-based split — skip

        # Top-level relation: direct child of <datasource> (federated) or of
        # <connection> (older/simple workbooks) — same dual-path check
        # already used for sheet_tab extraction earlier in this function.
        _top_rel = None
        for _r in _ds_jt.findall('relation'):
            _top_rel = _r
            break
        if _top_rel is None:
            _conn_el = _ds_jt.find('.//connection')
            if _conn_el is not None:
                _top_rel = _conn_el.find('relation')
        if _top_rel is None or _top_rel.get('type', '') != 'join':
            continue

        _nc_map_jt: dict = {}
        for _nc in _ds_jt.findall('.//named-connection'):
            _inner = _nc.find('./connection')
            if _inner is not None:
                _nc_map_jt[_nc.get('name', '')] = dict(_inner.attrib)

        _tree = _parse_relation_join_tree(_top_rel, _nc_map_jt)
        if _tree is None:
            continue   # unsupported/unresolvable shape — fall back to today's flatten behavior

        # Per-leaf-table column membership, via the same metadata-records
        # <parent-name> technique already proven for the Relationships-based
        # dim-split above — attributes each of this datasource's already-
        # collected columns (ds['columns'], correctly typed/named) to its
        # real physical table, so join leaves reuse exactly the columns the
        # rest of the pipeline already depends on rather than re-deriving a
        # second, possibly-inconsistent column set from raw metadata-records.
        import re as _re_jtcol
        _col_table_jt: dict = {}
        for _mr in _ds_jt.findall('.//metadata-records/metadata-record[@class="column"]'):
            _ln = (_mr.findtext('local-name', '') or '').strip('[]')
            _pn = (_mr.findtext('parent-name', '') or '')
            if not _ln or not _pn:
                continue
            _m_pn = _re_jtcol.search(r'\[([^\[\]]+?)(?:_[A-F0-9]{32})?\]$', _pn)
            if not _m_pn:
                continue
            _tbl = _m_pn.group(1).replace('.csv', '').replace('.CSV', '')
            _tbl = _re_jtcol.sub(r'[^a-zA-Z0-9 _]', '', _tbl).strip()
            if _tbl and _ln not in _col_table_jt:
                _col_table_jt[_ln] = _tbl

        _leaf_columns: dict = {}
        for _c in _d_match.get('columns', []):
            _key = _c.get('source_name') or _c['name']
            _tbl = _col_table_jt.get(_key)
            if not _tbl:
                continue
            _leaf_columns.setdefault(_tbl, []).append({
                'name': _c['name'], 'source_name': _key, 'datatype': _c.get('datatype', 'string'),
            })

        _d_match['_join_tree'] = _tree
        _d_match['_join_leaf_columns'] = _leaf_columns
        log('info', f"[DataModel] '{_ds_raw_name}' uses a physical join-tree "
                     f"datasource (join reconstruction verified via synthetic "
                     f"test, not a real fixture — see MIGRATION_ENGINE_PROGRESS.md)")

    # ── Stage 2 / Priority 3: WorkbookModel — semantic intermediate layer ─────
    # ── Stage 2 / Priority 3: WorkbookModel — semantic intermediate layer ─────
    # Build the semantic model BEFORE returning so all downstream phases
    # (data modeling, DAX generation, visual creation) share a single
    # pre-computed semantic view rather than re-parsing XML repeatedly.
    #
    # Uses CalcRegistry: generic dependency resolution engine that:
    #   • collects ALL calcs globally (not per-worksheet)
    #   • extracts deps generically via bracket-token scanning
    #   • builds a directed dependency graph with per-node metadata
    #   • performs Kahn's topological sort for safe DAX generation order
    #   • detects and isolates cycles so they never corrupt the output model
    #   • classifies each calc as measure/calc_col/dimension/aggregation/parameter

    _calc_registry = CalcRegistry()
    _calc_registry.register_datasources(datasources)
    _calc_registry.register_parameters(_param_values)   # scalar param nodes

    _calc_gen_order = _calc_registry.generation_order()
    _all_calcs      = {n: _calc_registry.get(n) for n in _calc_registry.names()}
    _cycle_sets     = _calc_registry.cycles()

    _log_sample = ', '.join(_calc_gen_order[:6])
    _cycle_warn  = (f" | {len(_cycle_sets)} cycle(s) isolated"
                    if _cycle_sets else '')
    log('info',
        f"[CalcRegistry] {len(_all_calcs)} calcs registered, "        f"{len(_calc_gen_order)} in gen order{_cycle_warn}. "        f"First: {_log_sample}{'…' if len(_calc_gen_order) > 6 else ''}")

    # ── Dashboard actions (filter/highlight/navigate/URL/parameter/set) ──────
    _dashboard_actions = _parse_dashboard_actions(
        root,
        dashboard_names={d['name'] for d in dashboards},
        worksheet_names={ws['name'] for ws in worksheets},
    )
    if _dashboard_actions:
        log('info', f"[Actions] {len(_dashboard_actions)} dashboard action(s) detected "
                     f"— see migration audit report for Power BI equivalents")

    semantic_model = {
        # Stage 2 fields (WorkbookModel)
        'calculations':         _all_calcs,
        'calc_gen_order':       _calc_gen_order,   # topological order for DAX gen
        'calc_registry':        _calc_registry,    # full registry (graph + cache)
        'cycle_sets':           _cycle_sets,        # frozensets of cyclic names
        'dimensions': {
            ds['name']: [{'name':c['name'],'datatype':c.get('datatype','string')}
                         for c in ds.get('columns',[]) if not c.get('measure')]
            for ds in datasources
        },
        'measures': {
            ds['name']: [{'name':c['name'],'datatype':c.get('datatype','double')}
                         for c in ds.get('columns',[]) if c.get('measure')]
            for ds in datasources
        },
        'relationships': _pbi_relationships,
        'visual_intent': {
            ws['name']: {
                'chart_type':  ws.get('chart_type','tableEx'),
                'x_field':     ws.get('x_field',''),
                'y_fields':    ws.get('shelf_row_fields',[]),
                'color':       ws.get('color_fields',[]),
                'is_kpi':      ws.get('chart_type') == 'card',
                'is_map':      ws.get('chart_type') in ('mapChart','filledMap'),
                'is_dual':     ws.get('chart_type') == 'lineClusteredColumnComboChart',
            }
            for ws in worksheets
        },
    }

    return {
        'name':                  workbook_name,
        'extracted_data':        extracted_data,
        'datasources':           datasources,
        'dashboards':            dashboards,
        'stories':               stories,
        'worksheets':            worksheets,
        'data_colors':           data_colors,
        'explicit_color_map':    explicit_color_map,
        'pbi_relationships':     _pbi_relationships,
        'semantic':              semantic_model,     # Stage 2: WorkbookModel
        'dashboard_actions':     _dashboard_actions,
        'tableau_parameters':    _tableau_parameters,
    }


# ── M Query builders ──────────────────────────────────────────────────────────

def _m_str(s: str) -> str:
    """Escape a string for use inside an M double-quoted string literal."""
    return s.replace('"', '""')


def _m_col_types(columns: list, cols_per_line: int = 3) -> str:
    """Build column-type list for Table.TransformColumnTypes.

    Uses each column's ``source_name`` (the actual header in the source file)
    as the key — NOT the Tableau caption.  When a Tableau author renames a
    column (e.g. source header "payment_method" → caption "Payment Method"),
    TransformColumnTypes must reference the *source* name so Power Query can
    locate the column in the loaded data.  A Table.RenameColumns step (built
    by _m_rename_columns) then applies the Tableau display names.

    Matches the gold-standard PBI format: 3 entries per line, 8-space indent,
    closing }} on the last entry line.
    """
    entries = [
        '{{"{}", type {}}}'.format(
            _m_str(c.get("source_name") or c["name"]),
            _pbi_m_type(c["datatype"])
        )
        for c in columns
    ]
    if not entries:
        return ''
    rows = []
    for i in range(0, len(entries), cols_per_line):
        rows.append(', '.join(entries[i:i + cols_per_line]))
    joined = (',\n' + ' ' * 8).join(rows)
    return joined + '})'


def _m_rename_columns(columns: list) -> str:
    """Return a Table.RenameColumns second argument for columns whose
    Tableau caption differs from the actual source column header.

    Returns an empty string when no renaming is needed so callers can
    skip the step entirely.  Format:
        {{"source_name", "Caption"}, {"src2", "Cap2"}}
    """
    pairs = [
        '{{"{}", "{}"}}'.format(
            _m_str(c.get("source_name") or c["name"]),
            _m_str(c["name"])
        )
        for c in columns
        if (c.get("source_name") or c["name"]) != c["name"]
    ]
    if not pairs:
        return ''
    return '{' + ', '.join(pairs) + '}'


def _m_col_name_type(col_name: str, col_datatype: str) -> str:
    """Format one column entry for an M `type table [...]` declaration.

    M type-record syntax: bare name or #"name" for names with special chars.
    No surrounding [brackets] — those cause "Invalid identifier".
    """
    import re as _re
    needs_quoting = bool(_re.search(r'[^A-Za-z0-9_]', col_name))
    identifier = ('#"' + col_name.replace('"', '""') + '"') if needs_quoting else col_name
    return f"{identifier} = {_pbi_m_type(col_datatype)}"


def _build_excel_m_query(table_name: str, sheet_name: str,
                          param_name: str, columns: list) -> str:
    """Build the M query for an Excel-backed table.

    Uses try...otherwise null on File.Contents so the query compiles and
    runs cleanly even when the file path parameter has not been set yet.

    Column renaming strategy (Fix 2):
        1. TransformColumnTypes  — keys on source_name (actual file header)
        2. RenameColumns         — renames source_name → caption for columns
                                   where Tableau gave the column an alias
    The TOM sourceColumn = caption (the M output name after renaming).
    The TOM name = caption (display name used by visuals and DAX).
    """
    col_types  = _m_col_types(columns)
    rename_arg = _m_rename_columns(columns)
    sheet_esc  = _m_str(sheet_name)
    NL = "\n"

    fallback_schema = ", ".join(
        _m_col_name_type(c["name"], c["datatype"])
        for c in columns
    )
    fallback = "#table(type table [" + fallback_schema + "], {})"

    if col_types:
        indented_types = col_types.replace("\n" + " " * 8, "\n" + " " * 20)
        typed_step = (
            "    Typed     = if Promoted = null then " + fallback + "\n"
            "                else Table.TransformColumnTypes(Promoted,{\n"
            "                    " + indented_types
        )
    else:
        typed_step = "    Typed     = if Promoted = null then " + fallback + " else Promoted"

    # M `let` expressions: every step except the last needs a trailing comma.
    # When rename_arg is non-empty, Typed gets a trailing comma and Renamed
    # becomes the last step (no comma).  The `in` block returns whichever
    # is last — Renamed when aliases exist, Typed otherwise.
    if rename_arg:
        typed_step_with_comma = typed_step + ","
        renamed_step = "    Renamed   = Table.RenameColumns(Typed, " + rename_arg + ")"
        steps = [
            "let",
            "    FileBytes = try File.Contents(" + param_name + ") otherwise null,",
            "    Wb        = if FileBytes = null then null",
            "                else Excel.Workbook(FileBytes, null, true),",
            "    Sheet     = if Wb = null then null",
            "                else Wb{[Item=\"" + sheet_esc + "\",Kind=\"Sheet\"]}[Data],",
            "    Promoted  = if Sheet = null then null",
            "                else Table.PromoteHeaders(Sheet, [PromoteAllScalars=true]),",
            typed_step_with_comma,
            renamed_step,
            "in",
            "    Renamed",
        ]
    else:
        steps = [
            "let",
            "    FileBytes = try File.Contents(" + param_name + ") otherwise null,",
            "    Wb        = if FileBytes = null then null",
            "                else Excel.Workbook(FileBytes, null, true),",
            "    Sheet     = if Wb = null then null",
            "                else Wb{[Item=\"" + sheet_esc + "\",Kind=\"Sheet\"]}[Data],",
            "    Promoted  = if Sheet = null then null",
            "                else Table.PromoteHeaders(Sheet, [PromoteAllScalars=true]),",
            typed_step,
            "in",
            "    Typed",
        ]
    return NL.join(steps)



def _build_csv_m_query(table_name: str, param_name: str, columns: list,
                        delimiter: str = ',') -> str:
    """Build the M query for a CSV / TSV / plain-text file.

    Column renaming strategy (Fix 2):
        1. TransformColumnTypes  — keys on source_name (actual file header)
        2. RenameColumns         — renames source_name → caption for columns
                                   where Tableau gave the column an alias
    The TOM sourceColumn = caption (the M output name after renaming).
    The TOM name = caption (display name used by visuals and DAX).
    """
    col_types  = _m_col_types(columns)
    rename_arg = _m_rename_columns(columns)
    delim_m    = delimiter.replace('"', '""')
    NL         = "\n"

    fallback_schema = ", ".join(
        _m_col_name_type(c["name"], c["datatype"])
        for c in columns
    )
    fallback = "#table(type table [" + fallback_schema + "], {})"

    if col_types:
        indented_types = col_types.replace("\n" + " " * 8, "\n" + " " * 20)
        typed_step = (
            "    Typed     = if Promoted = null then " + fallback + "\n"
            "                else Table.TransformColumnTypes(Promoted,{\n"
            "                    " + indented_types
        )
    else:
        typed_step = (
            "    Typed     = if Promoted = null then " + fallback
            + " else Promoted"
        )

    # When rename_arg is non-empty, Typed gets a trailing comma and Renamed
    # becomes the last step.  `in` returns Renamed when aliases exist, else Typed.
    if rename_arg:
        typed_step_with_comma = typed_step + ","
        renamed_step = "    Renamed   = Table.RenameColumns(Typed, " + rename_arg + ")"
        steps = [
            "let",
            "    FileBytes = try File.Contents(" + param_name + ") otherwise null,",
            "    Csv       = if FileBytes = null then null",
            "                else Csv.Document(FileBytes, [Delimiter=\"" + delim_m + "\","
            " Encoding=65001, QuoteStyle=QuoteStyle.Csv]),",
            "    Promoted  = if Csv = null then null",
            "                else Table.PromoteHeaders(Csv, [PromoteAllScalars=true]),",
            typed_step_with_comma,
            renamed_step,
            "in",
            "    Renamed",
        ]
    else:
        steps = [
            "let",
            "    FileBytes = try File.Contents(" + param_name + ") otherwise null,",
            "    Csv       = if FileBytes = null then null",
            "                else Csv.Document(FileBytes, [Delimiter=\"" + delim_m + "\","
            " Encoding=65001, QuoteStyle=QuoteStyle.Csv]),",
            "    Promoted  = if Csv = null then null",
            "                else Table.PromoteHeaders(Csv, [PromoteAllScalars=true]),",
            typed_step,
            "in",
            "    Typed",
        ]
    return NL.join(steps)


def _safe_m_name(name: str) -> str:
    """
    Convert a database object name (catalog / schema / table) into a valid
    M step identifier.  M step names must not start with a digit and must
    not clash with M keywords.  Names with special characters are wrapped
    in #"..." notation.

    Examples:
        'samples'       → 'samples'
        'sales_suppliers' → 'sales_suppliers'
        '2024_data'     → '#"2024_data"'
        'my schema'     → '#"my schema"'
    """
    import re as _re
    # Simple identifier: starts with letter/underscore, only word chars
    if _re.match(r'^[A-Za-z_]\w*$', name):
        return name
    # Needs quoting
    escaped = name.replace('"', '""')
    return f'#"{escaped}"'


def _build_databricks_m_query(conn: dict, columns: list) -> str:
    """
    Build a Power BI M query for Databricks SQL Warehouse or Cluster.

    Verified from a working PBIT created by PBI Desktop 2026.03 connecting to
    Databricks with a Personal Access Token.

    EXACT function signature used by PBI Desktop:
        DatabricksMultiCloud.Catalogs(
            "dbc-724907c1-f588.cloud.databricks.com",       ← server (no https://)
            "/sql/1.0/warehouses/cb5e0a954129eaf1",          ← httpPath as 2nd positional arg
            [Catalog=null, Database=null, QueryTags=null,    ← options with null defaults
             EnableAutomaticProxyDiscovery=null,
             Implementation="2.0",
             MetricViewBiCompatibilityMode=null]
        )

    Navigation uses {[Name="...", Kind="Database/Schema/Table"]}[Data].
    Step names follow PBI Desktop convention: {name}_Database, {name}_Schema, {name}_Table.

    Custom SQL uses Value.NativeQuery with backtick-quoted 3-part table name.

    Tableau attrs → PBI M:
        server      → strip any leading https:// and trailing /
        v-http-path → 2nd positional arg (NOT inside options record)
        dbname      → {catalog}_Database navigation step
        schema      → {schema}_Schema navigation step
        db_table    → {table}_Table navigation step
        custom_sql  → Value.NativeQuery fallback
    """
    server     = conn.get('server', '').strip()
    # Strip protocol prefix — PBI uses hostname only
    server     = server.lstrip('https://').lstrip('http://').rstrip('/')
    http_path  = conn.get('v-http-path', '').strip()
    catalog    = conn.get('dbname', '').strip()
    schema     = conn.get('schema', '').strip()
    table      = conn.get('db_table', '').strip()
    custom_sql = conn.get('custom_sql', '').strip()

    def _mq(s):   # escape for M double-quoted string
        return s.replace('"', '""')

    # Exact options record PBI Desktop generates — keep null defaults so PBI
    # can identify the data source URL for credential store lookup (PAT prompt).
    opts = (
        '[Catalog=null, Database=null, QueryTags=null, '
        'EnableAutomaticProxyDiscovery=null, '
        'Implementation="2.0", '
        'MetricViewBiCompatibilityMode=null]'
    )

    if custom_sql:
        # Custom SQL — use Value.NativeQuery with 3-part backtick-quoted name
        sql_mq = custom_sql.replace('"', '""')
        lines = [
            'let',
            f'    Source = DatabricksMultiCloud.Catalogs("{_mq(server)}", "{_mq(http_path)}", {opts}),',
            f'    Result = Value.NativeQuery(',
            f'                 Source,',
            f'                 "{sql_mq}",',
            '                 null,',
            '                 [EnableFolding=true]',
            '             )',
            'in',
            '    Result',
        ]
        return '\n'.join(lines)

    # Table navigation — matches PBI Desktop exactly
    lines = [
        'let',
        f'    Source = DatabricksMultiCloud.Catalogs("{_mq(server)}", "{_mq(http_path)}", {opts}),',
    ]
    nav_var = 'Source'

    if catalog:
        step = f'{_safe_m_name(catalog)}_Database'
        lines.append(f'    {step} = {nav_var}{{[Name="{_mq(catalog)}",Kind="Database"]}}[Data],')
        nav_var = step
    if schema:
        step = f'{_safe_m_name(schema)}_Schema'
        lines.append(f'    {step} = {nav_var}{{[Name="{_mq(schema)}",Kind="Schema"]}}[Data],')
        nav_var = step
    if table:
        step = f'{_safe_m_name(table)}_Table'
        lines.append(f'    {step} = {nav_var}{{[Name="{_mq(table)}",Kind="Table"]}}[Data]')
        nav_var = step

    # Strip trailing comma from last let-binding
    if lines[-1].endswith(','):
        lines[-1] = lines[-1][:-1]

    lines += ['in', f'    {nav_var}']
    return '\n'.join(lines)


def _build_snowflake_m_query(conn: dict, columns: list) -> str:
    """
    Build a Power BI M query for Snowflake.

    Uses Snowflake.Databases() with Value.NativeQuery for reliable table access.

    Signature: Snowflake.Databases(server, warehouse, options)
    The warehouse is the SECOND positional argument (not inside the options record).

    Tableau attrs:
        server    → 1st arg
        warehouse → 2nd arg
        role      → [Role="..."] option
        dbname + schema + db_table → "catalog"."schema"."table" in SQL
    """
    server   = conn.get('server', '').strip()
    db       = conn.get('dbname', '').strip()
    schema   = conn.get('schema', '').strip()
    table    = conn.get('db_table', '').strip()
    wh       = conn.get('warehouse', '').strip()
    role     = conn.get('role', '').strip()
    custom_sql = conn.get('custom_sql', '').strip()

    def _mq(s): return s.replace('"', '""')
    def _sq(s): return f'"{s}"'  # SQL double-quote identifier

    opts = []
    if role: opts.append(f'Role="{_mq(role)}"')
    opts_str = f'[{", ".join(opts)}]' if opts else 'null'
    wh_arg   = f'"{_mq(wh)}"' if wh else '""'

    if custom_sql:
        sql = custom_sql
    elif db and schema and table:
        sql = f'SELECT * FROM {_sq(db)}.{_sq(schema)}.{_sq(table)}'
    elif schema and table:
        sql = f'SELECT * FROM {_sq(schema)}.{_sq(table)}'
    elif table:
        sql = f'SELECT * FROM {_sq(table)}'
    else:
        sql = 'SELECT 1'

    sql_mq = sql.replace('"', '""')
    return (
        'let\n'
        f'    Source = Snowflake.Databases("{_mq(server)}", {wh_arg}, {opts_str}),\n'
        f'    Result = Value.NativeQuery(\n'
        '                 Source,\n'
        f'                 "{sql_mq}",\n'
        '                 null,\n'
        '                 [EnableFolding=true]\n'
        '             )\n'
        'in\n'
        '    Result'
    )


def _build_sqlserver_m_query(conn: dict, columns: list) -> str:
    """
    Build a Power BI M query for SQL Server / Azure SQL Database.

    Uses Sql.Database() with {[Schema=..., Item=...]} for simple tables,
    or Value.NativeQuery for custom SQL.

    Tableau class: 'sqlserver', 'mssqlserver'
    """
    server = conn.get('server', '').strip()
    db     = conn.get('dbname', '').strip()
    schema = (conn.get('schema', '') or 'dbo').strip()
    table  = conn.get('db_table', '').strip()
    custom_sql = conn.get('custom_sql', '').strip()

    def _mq(s): return s.replace('"', '""')

    if custom_sql:
        sql_mq = custom_sql.replace('"', '""')
        return (
            f'let\n'
            f'    Source = Sql.Database("{_mq(server)}", "{_mq(db)}"),\n'
            f'    Result = Value.NativeQuery(\n'
            '                 Source,\n'
            f'                 "{sql_mq}",\n'
            '                 null,\n'
            '                 [EnableFolding=true]\n'
            '             )\n'
            'in\n'
            '    Result'
        )

    lines = ['let', f'    Source = Sql.Database("{_mq(server)}", "{_mq(db)}"),']
    if schema and table:
        step = f'{_safe_m_name(schema)}_{_safe_m_name(table)}'
        lines.append(f'    {step} = Source{{[Schema="{_mq(schema)}", Item="{_mq(table)}"]}}[Data]')
        lines += ['in', f'    {step}']
    else:
        lines[-1] = lines[-1].rstrip(',')
        lines += ['in', '    Source']
    return '\n'.join(lines)


