def _build_mysql_m_query(conn: dict, columns: list) -> str:
    """
    Build a Power BI M query for MySQL.

    Uses MySQL.Database() with {[Schema=..., Item=...]} navigation.
    In MySQL, the schema name equals the database name.

    Tableau class: 'mysql'
    """
    server = conn.get('server', '').strip()
    db     = conn.get('dbname', '').strip()
    table  = conn.get('db_table', '').strip()
    port   = conn.get('port', '').strip()
    custom_sql = conn.get('custom_sql', '').strip()

    def _mq(s): return s.replace('"', '""')

    server_str = f'{server}:{port}' if port and port not in ('3306', '') else server

    if custom_sql:
        sql_mq = custom_sql.replace('"', '""')
        return (
            f'let\n'
            f'    Source = MySQL.Database("{_mq(server_str)}", "{_mq(db)}"),\n'
            f'    Result = Value.NativeQuery(\n'
            '                 Source,\n'
            f'                 "{sql_mq}",\n'
            '                 null,\n'
            '                 [EnableFolding=true]\n'
            '             )\n'
            'in\n'
            '    Result'
        )

    lines = ['let', f'    Source = MySQL.Database("{_mq(server_str)}", "{_mq(db)}"),']
    if table:
        step = f'{_safe_m_name(db)}_{_safe_m_name(table)}'
        lines.append(f'    {step} = Source{{[Schema="{_mq(db)}", Item="{_mq(table)}"]}}[Data]')
        lines += ['in', f'    {step}']
    else:
        lines[-1] = lines[-1].rstrip(',')
        lines += ['in', '    Source']
    return '\n'.join(lines)


def _build_bigquery_m_query(conn: dict, columns: list) -> str:
    """
    Build a Power BI M query for Google BigQuery.

    Uses GoogleBigQuery.Database() with {[Name=..., Kind=...]} navigation.

    Tableau class: 'bigquery'
    Tableau attrs: server or dbname = project-id, schema = dataset, db_table = table
    """
    project  = (conn.get('server', '') or conn.get('dbname', '')).strip()
    dataset  = conn.get('schema', '').strip()
    table    = conn.get('db_table', '').strip()
    custom_sql = conn.get('custom_sql', '').strip()

    def _mq(s): return s.replace('"', '""')

    if custom_sql:
        sql_mq = custom_sql.replace('"', '""')
        return (
            f'let\n'
            f'    Source = GoogleBigQuery.Database([BillingProject="{_mq(project)}"]),\n'
            f'    Result = Value.NativeQuery(Source, "{sql_mq}")\n'
            f'in\n'
            f'    Result'
        )

    proj_step = _safe_m_name(project) + '_Database'
    lines = [
        'let',
        f'    Source = GoogleBigQuery.Database([BillingProject="{_mq(project)}"]),',
        f'    {proj_step} = Source{{[Name="{_mq(project)}", Kind="Database"]}}[Data],',
    ]
    nav_var = proj_step
    if dataset:
        step = f'{_safe_m_name(dataset)}_Schema'
        lines.append(f'    {step} = {nav_var}{{[Name="{_mq(dataset)}", Kind="Schema"]}}[Data],')
        nav_var = step
    if table:
        step = f'{_safe_m_name(table)}_Table'
        lines.append(f'    {step} = {nav_var}{{[Name="{_mq(table)}", Kind="Table"]}}[Data]')
        nav_var = step
    if lines[-1].endswith(','):
        lines[-1] = lines[-1][:-1]
    lines += ['in', f'    {nav_var}']
    return '\n'.join(lines)


