def _build_oracle_m_query(conn: dict, columns: list) -> str:
    """
    Build a Power BI M query for Oracle Database.

    Tableau class: 'oracle'
    PBI function:  Oracle.Database("server:port/SID")
    """
    server = conn.get('server', '').strip()
    port   = conn.get('port', '1521').strip()
    db     = conn.get('dbname', '').strip()    # SID or service name in Tableau
    schema = conn.get('schema', '').strip()
    table  = conn.get('db_table', '').strip()
    custom_sql = conn.get('custom_sql', '').strip()

    def _mq(s): return s.replace('"', '""')

    # Oracle connection string: "host:port/SID"
    host_str = server
    if port and port != '1521':
        host_str = f"{server}:{port}"
    if db:
        host_str = f"{host_str}/{db}"

    if custom_sql:
        sql_mq = custom_sql.replace('"', '""')
        return (
            f'let\n'
            f'    Source = Oracle.Database("{_mq(host_str)}", [HierarchicalNavigation=true]),\n'
            f'    Result = Value.NativeQuery(\n'
            '                 Source,\n'
            f'                 "{sql_mq}",\n'
            '                 null,\n'
            '                 [EnableFolding=true]\n'
            '             )\n'
            'in\n'
            '    Result'
        )

    lines = ['let', f'    Source = Oracle.Database("{_mq(host_str)}", [HierarchicalNavigation=true]),']
    if schema and table:
        step = f'{_safe_m_name(schema)}_{_safe_m_name(table)}'
        lines.append(f'    schema_Data = Source{{[Schema="{_mq(schema)}", Kind="Schema"]}}[Data],')
        lines.append(f'    {step} = schema_Data{{[Name="{_mq(table)}", Kind="Table"]}}[Data]')
        lines += ['in', f'    {step}']
    else:
        lines[-1] = lines[-1].rstrip(',')
        lines += ['in', '    Source']
    return '\n'.join(lines)


