def _build_hive_m_query(conn: dict, columns: list) -> str:
    """
    Build a Power BI M query for Apache Hive (Cloudera / Hortonworks).

    Tableau classes: 'hive', 'impala'
    PBI function:    Odbc.DataSource() using the Hive / Impala ODBC DSN.
    Power BI does not ship a native Hive connector; the recommended path
    is the generic ODBC connector pointed at the vendor ODBC driver.
    """
    server = conn.get('server', '').strip()
    port   = conn.get('port', '10000').strip()
    db     = conn.get('dbname', '').strip()
    table  = conn.get('db_table', '').strip()

    def _mq(s): return s.replace('"', '""')

    # Build an ODBC connection string; user will need the Hive ODBC driver installed.
    odbc_str = f"Driver={{Cloudera ODBC Driver for Apache Hive}};Host={server};Port={port};Schema={db}"

    lines = [
        'let',
        f'    Source = Odbc.DataSource("{_mq(odbc_str)}", [HierarchicalNavigation=true]),'
    ]
    if db and table:
        step = f'{_safe_m_name(db)}_{_safe_m_name(table)}'
        lines.append(f'    db_Data = Source{{[Name="{_mq(db)}", Kind="Schema"]}}[Data],')
        lines.append(f'    {step} = db_Data{{[Name="{_mq(table)}", Kind="Table"]}}[Data]')
        lines += ['in', f'    {step}']
    else:
        lines[-1] = lines[-1].rstrip(',')
        lines += ['in', '    Source']
    return '\n'.join(lines)


def _build_athena_m_query(conn: dict, columns: list) -> str:
    """
    Build a Power BI M query for Amazon Athena.

    Tableau class: 'athena'
    PBI uses the Amazon Athena ODBC driver (requires it to be installed).
    The ODBC DSN name defaults to 'AthenaODBC' — user configures the DSN.
    """
    server = conn.get('server', '').strip()
    db     = conn.get('dbname', '').strip()
    table  = conn.get('db_table', '').strip()

    def _mq(s): return s.replace('"', '""')

    # Region is often embedded in the server string (e.g. athena.us-east-1.amazonaws.com)
    odbc_str = f"Driver={{Amazon Athena ODBC Driver}};AwsRegion=us-east-1;S3OutputLocation=s3://aws-athena-results/;Schema={db}"
    if server:
        odbc_str = f"Driver={{Amazon Athena ODBC Driver}};Host={server};Schema={db}"

    lines = [
        'let',
        f'    Source = Odbc.DataSource("{_mq(odbc_str)}", [HierarchicalNavigation=true]),'
    ]
    if db and table:
        step = f'{_safe_m_name(db)}_{_safe_m_name(table)}'
        lines.append(f'    db_Data = Source{{[Name="{_mq(db)}"]}}[Data],')
        lines.append(f'    {step} = db_Data{{[Name="{_mq(table)}"]}}[Data]')
        lines += ['in', f'    {step}']
    else:
        lines[-1] = lines[-1].rstrip(',')
        lines += ['in', '    Source']
    return '\n'.join(lines)


