def _detect_functions(formula: str) -> list:
    """
    Return a list of dicts, one per unique Tableau function/LOD keyword used
    in *formula*.  Each dict has keys: function, support, note.

    Detection strategy:
      1. Scan WORD( patterns for function calls.
      2. Scan { FIXED|INCLUDE|EXCLUDE } for LOD expressions (no parens).
      3. Scan TABLE-CALC keywords that may appear without parens (INDEX, FIRST, etc.).
    Generic — no hardcoded field names.
    """
    found = []
    seen  = set()

    # 1. Function-call patterns:  WORD(
    for fn in _aud_re.findall(r'\b([A-Z_][A-Z0-9_]*)\s*\(', formula, _aud_re.I):
        fn_up = fn.upper()
        if fn_up in seen:
            continue
        seen.add(fn_up)
        # A function absent from the catalogue has an UNVERIFIED translation —
        # defaulting it to 'supported' would silently claim full confidence
        # for something never actually reviewed, which is exactly the kind of
        # audit inaccuracy this catalogue exists to prevent. Score it like
        # 'partial' (mild deduction, not zeroed out) until someone adds a
        # real entry.
        support, note = _TAB_FN_SUPPORT.get(
            fn_up, ('partial', 'Not in the function-support catalogue — verify DAX output manually'))
        found.append({'function': fn_up, 'support': support, 'note': note})

    # 2. LOD braces: { FIXED ... }, { INCLUDE ... }, { EXCLUDE ... }
    for lod in _aud_re.findall(r'\{\s*(FIXED|INCLUDE|EXCLUDE)\b', formula, _aud_re.I):
        lod_up = lod.upper()
        if lod_up in seen:
            continue
        seen.add(lod_up)
        support, note = _TAB_FN_SUPPORT.get(lod_up, ('partial', 'LOD expression'))
        found.append({'function': lod_up, 'support': support, 'note': note})

    # 3. Bare-keyword detection for constructs that use no parentheses:
    #    a) Tableau flow-control: IF...THEN...ELSEIF...ELSE...END, CASE...WHEN...END
    #    b) Table-calc identifiers: INDEX, FIRST, LAST, SIZE, PREVIOUS_VALUE
    _bare_keywords = {
        # Flow-control (Tableau keyword-based, no parens)
        'IF':             'logic',
        'ELSEIF':         'logic',
        'CASE':           'logic',
        # Table-calc identifiers
        'INDEX':          'table_calc',
        'FIRST':          'table_calc',
        'LAST':           'table_calc',
        'SIZE':           'table_calc',
        'PREVIOUS_VALUE': 'table_calc',
    }
    for kw in _bare_keywords:
        if kw in seen:
            continue
        if _aud_re.search(r'\b' + kw + r'\b', formula, _aud_re.I):
            seen.add(kw)
            support, note = _TAB_FN_SUPPORT.get(
                kw, ('partial', 'Not in the function-support catalogue — verify DAX output manually'))
            found.append({'function': kw, 'support': support, 'note': note})

    return found


def _dax_validate(dax: str, calc_name: str, all_names: set) -> dict:
    """
    Structural DAX validation.  Returns:
        {'valid': bool, 'issues': [str], 'warnings': [str]}

    Checks performed (generic — no workbook-specific logic):
      1. Self-reference: measure references itself by name inside its own expression.
      2. Fallback constant: whole expression is '0' or empty.
      3. Bare bracket references: [FieldName] not preceded by a table name — these
         are unresolved column references that will fail in Power BI.
      4. Nested CALCULATE depth — deep nesting signals complex LOD approximations.
      5. Cross-measure references: [Name] tokens matched against known measure names
         to surface potential recursive or invalid cross-measure chains.
      6. DIVIDE by zero pattern: DIVIDE(expr, 0, ...) constant denominator.
      7. ERROR() token: formula uses Tableau ERROR() — no DAX equivalent.
      8. Unbalanced parentheses: basic structural check.
    """
    issues   = []
    warnings = []

    if not dax or not dax.strip():
        warnings.append('No DAX generated — formula may be unsupported')
        return {'valid': True, 'issues': issues, 'warnings': warnings}

    dax_stripped = dax.strip()

    # 1. Fallback constant
    if dax_stripped in ('0', "'0'", '"0"', 'BLANK()', '""'):
        warnings.append(
            f'Formula translated to constant fallback ({dax_stripped!r}) '
            '— original Tableau formula likely unsupported'
        )

    # 2. Self-reference check — measure/col name appears inside its own DAX
    nm_norm = calc_name.strip().lower()
    _self_seen = False
    for ref_tuple in _aud_re.findall(r"'[^']+'\s*\[([^\]]+)\]|(?<![\w'])\[([^\]]+)\]", dax):
        ref_name = (ref_tuple[0] or ref_tuple[1]).strip().lower()
        if ref_name == nm_norm and not _self_seen:
            issues.append(
                f'Possible self-reference: [{calc_name}] appears inside its own '
                'DAX expression — check for circular dependency'
            )
            _self_seen = True

    # 3. Bare bracket references (not preceded by table/quote context)
    _bare = []
    for m in _aud_re.finditer(r"(?<![\]\w'])\[([^\[\]]+)\]", dax):
        # Check that the char before '[' is not a quote or closing bracket
        start = m.start()
        preceding = dax[max(0, start-2):start].strip()
        if not preceding or preceding[-1] not in ("'", ']', ')'):
            _bare.append(m.group(1))
    if _bare:
        warnings.append(
            f'Possibly unresolved bare column reference(s): '
            + ', '.join(f'[{b}]' for b in _bare[:5])
            + (' …' if len(_bare) > 5 else '')
            + ' — verify table prefix in generated DAX'
        )

    # 4. Nested CALCULATE depth
    _calc_count = dax.upper().count('CALCULATE(')
    if _calc_count > 3:
        warnings.append(
            f'Deeply nested CALCULATE ({_calc_count} occurrences) — '
            'complex LOD approximation; verify filter-context semantics'
        )
    elif _calc_count > 1:
        warnings.append(
            f'Multiple CALCULATE calls ({_calc_count}) — verify LOD/context semantics'
        )

    # 5. Cross-measure reference check against known measure names
    if all_names:
        nm_set = {n.lower() for n in all_names} - {nm_norm}
        for ref_tuple in _aud_re.findall(
                r"'[^']+'\s*\[([^\]]+)\]|(?<![\w'])\[([^\]]+)\]", dax):
            ref_name = (ref_tuple[0] or ref_tuple[1]).strip().lower()
            if ref_name in nm_set:
                warnings.append(
                    f'Cross-measure reference to [{ref_name}] — '
                    'ensure dependency ordering is correct'
                )

    # 6. DIVIDE with constant 0 denominator
    if _aud_re.search(r'\bDIVIDE\s*\([^,]+,\s*0\s*[,)]', dax, _aud_re.I):
        warnings.append('DIVIDE(expr, 0) detected — denominator is always zero')

    # 7. ERROR() usage
    if _aud_re.search(r'\bERROR\s*\(', dax, _aud_re.I):
        issues.append('ERROR() function has no DAX equivalent — will fail at runtime')

    # 8. Unbalanced parentheses
    _open  = dax.count('(')
    _close = dax.count(')')
    if _open != _close:
        issues.append(
            f'Unbalanced parentheses in generated DAX: {_open} open, {_close} close'
        )

    return {'valid': len(issues) == 0, 'issues': issues, 'warnings': warnings}


def _translation_confidence(formula: str, dax: str, functions: list,
                             dax_valid: dict, sem_class: str) -> int:
    """
    Score 0–100 for translation confidence.  Starts at 100 and deducts for
    each risk signal.  Signals are additive — multiple issues compound.

    Deduction table:
      -25  per unsupported function
      -10  per partial-support function
      -20  per DAX validation issue (structural error)
       -5  per DAX validation warning
      -10  suspicious or unknown semantic class
      -40  whole expression is a constant fallback (0, BLANK(), etc.)
      -15  formula much longer than DAX (possible truncation/simplification)
      -10  formula contains RAWSQL pass-through
      -10  formula contains unresolved field references (bare brackets in DAX)
       -5  deeply nested IF / CASE (>3 levels) — approximate translation risk
      -30  DAX contains ERROR() call
    """
    score = 100

    if not formula or not formula.strip():
        return 10
    # Intentional literal formulas (formula='0','1',etc.) → correct DAX='0' → SUCCESS
    _fs = formula.strip()
    if (_fs and _fs not in ('BLANK()', '""', "''")
            and (_fs.lstrip('-').replace('.','',1).isdigit()
                 or (_fs.startswith('"') and _fs.endswith('"'))
                 or (_fs.startswith("'") and _fs.endswith("'")))):
        return 100
    if not dax or dax.strip() in ('0', '', 'BLANK()', '""'):
        return 0

    # Deduct for unsupported / partial functions
    for fn in functions:
        if fn['support'] == 'unsupported':
            score -= 25
        elif fn['support'] == 'partial':
            score -= 10

    # Deduct for DAX validation issues and warnings
    score -= len(dax_valid.get('issues', [])) * 20
    score -= len(dax_valid.get('warnings', [])) * 5

    # Suspicious semantic class
    if sem_class in ('unknown', 'skipped'):
        score -= 10

    # Constant-fallback DAX
    if dax.strip() in ('0', 'BLANK()', '""', "''"):
        score -= 40

    # Formula length >> DAX length suggests truncation or simplification
    if formula and dax and len(formula) > 50 and len(dax) < len(formula) * 0.4:
        score -= 15

    # RAWSQL pass-through in formula
    if _aud_re.search(r'\bRAWSQL', formula, _aud_re.I):
        score -= 10

    # Bare bracket references remaining in DAX (unresolved column refs)
    _bare_in_dax = len(_aud_re.findall(r"(?<![\]\w'])\[[^\[\]]+\]", dax))
    if _bare_in_dax > 0:
        score -= 10

    # Deeply nested IF/CASE in formula — approximate translation risk
    _if_depth = len(_aud_re.findall(r'\b(?:IF|ELSEIF|CASE)\b', formula, _aud_re.I))
    if _if_depth > 3:
        score -= 5

    # ERROR() in generated DAX
    if _aud_re.search(r'\bERROR\s*\(', dax, _aud_re.I):
        score -= 30

    return max(0, min(100, score))


def _translation_status(score: int, functions: list, dax_valid: dict) -> str:
    """
    Map score + signals to a status string.
    SUCCESS / PARTIAL / FALLBACK / UNSUPPORTED / FAILED
    """
    has_unsupported = any(f['support'] == 'unsupported' for f in functions)
    has_issues      = bool(dax_valid.get('issues'))

    if has_issues:
        return 'FAILED'
    if has_unsupported:
        return 'UNSUPPORTED'
    if score >= 85:
        return 'SUCCESS'
    if score >= 50:
        return 'PARTIAL'
    if score >= 20:
        return 'FALLBACK'
    return 'FAILED'


class MigrationAudit:
    """
    Collect audit records during build_data_model_schema, then produce
    migration_audit.json and migration_audit.md alongside the .pbit.

    Usage
    -----
    audit = MigrationAudit(workbook_name)
    # Inside the DAX generation loop:
    audit.record(
        calc_name, formula, sem_class, deps, dax, ds_name, worksheet_names
    )
    # After generation:
    audit.write(output_dir)          # writes JSON + MD
    audit.log_summary()              # logs to the main log stream
    """

    def __init__(self, workbook_name: str, calc_registry=None):
        self.workbook_name = workbook_name
        self._records: list = []          # one dict per calculation
        self._ws_calc_map: dict = {}      # worksheet_name → set of calc names
        self._all_fn_names: set = set()   # global function inventory
        self.worksheet_scores: list = []  # one dict per worksheet — set via set_worksheet_scores()
        self.dashboard_actions: list = []  # from workbook['dashboard_actions'] — set via set_dashboard_actions()
        self.parameter_notes: list = []    # (caption, status, detail) — set via set_parameter_notes()
        self.story_notes: list = []        # from workbook['_story_notes'] — set via set_story_notes()
        self.data_model_tables: list = []          # set via set_data_model()
        self.data_model_relationships: list = []   # set via set_data_model()
        self.data_model_notes: list = []           # set via set_data_model()
        self.datasource_notes: list = []           # set via record_unsupported_datasource()
        # Snapshot of all known calc names for cross-reference validation.
        # Populated from CalcRegistry when available so _dax_validate can
        # check measure-to-measure reference chains at record() time.
        self._nodes_snapshot: set = (
            set(calc_registry.names()) if calc_registry is not None else set()
        )

    # ── Public API ────────────────────────────────────────────────────────────

    def record(self,
               calc_name:       str,
               formula:         str,
               sem_class:       str,
               deps:            list,
               dax:             str,
               ds_name:         str = '',
               worksheets:      list = None,
               fallback_reason: str = '',
               loss_stage:      str = '',
               failure_reason:  str = '',
               parsed_formula:          str = '',
               post_processing_warning: str = '') -> None:
        """
        Add one audit record.  Call once per calculation, after DAX generation.
        *worksheets*               — worksheet names that reference this calc.
        *fallback_reason*          — why a constant fallback was emitted.
        *loss_stage*               — pipeline stage: 'none'|'empty_formula'|'translator'|
                                     'col_ref_fix'|'agg_fix'|'reuse_cache'
        *post_processing_warning*  — non-fatal warning from col_ref_fix/agg_fix.
        *failure_reason*  — human-readable explanation.
        *parsed_formula*  — formula after caption expansion, before DAX.
        """
        functions   = _detect_functions(formula or '')
        dax_valid   = _dax_validate(dax or '', calc_name, set())
        confidence  = _translation_confidence(formula or '', dax or '',
                                               functions, dax_valid, sem_class)
        status      = _translation_status(confidence, functions, dax_valid)

        # Accumulate function inventory
        for fn in functions:
            self._all_fn_names.add(fn['function'])

        # Track which worksheets are affected
        affected_ws = list(worksheets or [])
        for ws in affected_ws:
            self._ws_calc_map.setdefault(ws, set()).add(calc_name)

        # Auto-detect fallback pattern when caller did not set reason
        _dax_stripped = (dax or '').strip()
        _orig_formula_stripped = (formula or '').strip()
        _formula_is_literal = bool(
            _orig_formula_stripped
            and _orig_formula_stripped not in ('BLANK()', '""', "''")
            and (
                _orig_formula_stripped.lstrip('-').replace('.', '', 1).isdigit()
                or (_orig_formula_stripped.startswith('"')
                    and _orig_formula_stripped.endswith('"'))
                or (_orig_formula_stripped.startswith("'")
                    and _orig_formula_stripped.endswith("'"))
            )
        )
        _is_fallback  = (
            not _formula_is_literal
            and (
                _dax_stripped in ('0', 'BLANK()', '""', "''", '')
                or _dax_stripped.startswith('BLANK() /*')
            )
        )
        _auto_reason = fallback_reason
        if _is_fallback and not _auto_reason:
            if not _dax_stripped:
                _auto_reason = 'No DAX generated — formula may be empty or unsupported'
            elif _dax_stripped.startswith('BLANK() /*'):
                _auto_reason = _dax_stripped[len('BLANK() /*'):].rstrip('*/').strip()
            else:
                _auto_reason = 'Constant fallback — likely unsupported Tableau construct'

        rec = {
            'calc_name':        calc_name,
            'datasource':       ds_name,
            'formula':          formula or '',
            'sem_class':        sem_class,
            'dependencies':     list(deps or []),
            'dep_count':        len(deps or []),
            'generated_dax':    dax or '',
            'status':           status,
            'confidence':       confidence,
            'functions':        functions,
            'dax_valid':        dax_valid,
            'affected_visuals': affected_ws,
            'fallback_reason':  _auto_reason,
            'loss_stage':       loss_stage or ('translator' if _is_fallback else 'none'),
            'failure_reason':   failure_reason or _auto_reason,
            'original_formula': formula or '',
            'parsed_formula':            parsed_formula or formula or '',
            'post_processing_warning':   post_processing_warning,
        }
        self._records.append(rec)

        # Per-calculation log line
        _fn_summary = (', '.join(f["function"] for f in functions)
                       if functions else '—')
        _fr_tag = f' | fallback: {_auto_reason[:50]}' if _auto_reason else ''
        log('info',
            f'[Audit] {calc_name!r:40s} | {sem_class:12s} | '
            f'{status:11s} | conf={confidence:3d} | fns=[{_fn_summary}]{_fr_tag}')

    def record_parameter(self, param_name: str, param_value, ds_name: str = '') -> None:
        """Record a Tableau parameter (scalar value, no formula)."""
        rec = {
            'calc_name':        param_name,
            'datasource':       ds_name,
            'formula':          f'[Parameter] value={param_value}',
            'sem_class':        'parameter',
            'dependencies':     [],
            'dep_count':        0,
            'generated_dax':    '',
            'status':           'SUCCESS',
            'confidence':       100,
            'functions':        [],
            'dax_valid':        {'valid': True, 'issues': [], 'warnings': []},
            'affected_visuals': [],
            'fallback_reason':  '',
            'loss_stage':       'none',
            'failure_reason':   '',
            'original_formula': f'[Parameter] value={param_value}',
            'parsed_formula':   '',
        }
        self._records.append(rec)

    def record_skipped(self, calc_name: str, reason: str,
                       formula: str = '', ds_name: str = '') -> None:
        """Record a calculation that was intentionally skipped."""
        rec = {
            'calc_name':        calc_name,
            'datasource':       ds_name,
            'formula':          formula,
            'sem_class':        'skipped',
            'dependencies':     [],
            'dep_count':        0,
            'generated_dax':    '',
            'status':           'FAILED',
            'confidence':       0,
            'functions':        [],
            'dax_valid':        {'valid': False,
                                 'issues': [f'Skipped: {reason}'],
                                 'warnings': []},
            'affected_visuals': [],
            'fallback_reason':  reason,
            'loss_stage':       'skipped',
            'failure_reason':   reason,
            'original_formula': formula,
            'parsed_formula':   formula,
        }
        self._records.append(rec)

    def calc_confidence_for(self, calc_names) -> int:
        """Average confidence (0-100) across the given calc names, using
        whatever records exist for them. Returns 100 when none are recorded
        (nothing to lose fidelity on)."""
        confidences = [r['confidence'] for r in self._records if r['calc_name'] in calc_names]
        return int(sum(confidences) / len(confidences)) if confidences else 100

    def calcs_for_worksheet(self, ws_name: str) -> set:
        return self._ws_calc_map.get(ws_name, set())

    def set_worksheet_scores(self, scores: list) -> None:
        """Attach the per-worksheet Migration Quality Score list — see
        _compute_worksheet_quality_scores() for how each entry is built."""
        self.worksheet_scores = scores or []

    def set_dashboard_actions(self, actions: list) -> None:
        """Attach workbook['dashboard_actions'] (from _parse_dashboard_actions)
        so the Markdown report can list them with recommendations."""
        self.dashboard_actions = actions or []

    def set_story_notes(self, notes: list) -> None:
        """Attach workbook['_story_notes'] (built in build_report_layout) so
        the Markdown report can explain the Story → sequential-pages conversion."""
        self.story_notes = notes or []

    def set_parameter_notes(self, notes: list) -> None:
        """Attach the (caption, status, detail) list built in
        build_data_model_schema for every Tableau parameter — status is
        'whatif_parameter' (got a real table+measure), 'inlined_literal'
        ('any'-domain, no enumerable set), or 'unresolved' (no usable value)."""
        self.parameter_notes = notes or []

    def set_data_model(self, table_names: list, relationships: list, notes: list) -> None:
        """Attach the final generated table list, validated relationship
        list, and (description, status, detail) notes built in
        build_data_model_schema (Increment 22) — 'created' relationships,
        'skipped' ones that couldn't resolve a real column, and 'repaired
        (dropped)' ones that failed the pre-write validation pass."""
        self.data_model_tables = table_names or []
        self.data_model_relationships = relationships or []
        self.data_model_notes = notes or []

    def record_unsupported_datasource(self, table_name: str, conn_class: str,
                                       raw_name: str) -> None:
        """Record a datasource whose Tableau connection class has no known
        M-query builder (Increment 27) — e.g. a live-database connector this
        engine has never seen, with no cached extract data to fall back on
        either. The generated table still gets its real, correctly-typed
        column schema (preserving every downstream visual/DAX binding), but
        has zero rows and an empty M query — this must be surfaced, not
        left for the user to discover as an unexplained blank report."""
        self.datasource_notes.append((table_name, conn_class, raw_name))

    # ── Aggregate statistics ──────────────────────────────────────────────────

    def summary(self) -> dict:
        """Return the workbook-level summary statistics dict."""
        total    = len(self._records)
        by_status = {}
        for r in self._records:
            by_status[r['status']] = by_status.get(r['status'], 0) + 1

        by_sem = {}
        for r in self._records:
            by_sem[r['sem_class']] = by_sem.get(r['sem_class'], 0) + 1

        # Collect all unique functions seen across the workbook
        fn_inventory = {}
        for r in self._records:
            for fn in r.get('functions', []):
                if fn['function'] not in fn_inventory:
                    fn_inventory[fn['function']] = fn

        # Visual impact: worksheets with at least one non-SUCCESS calc
        impacted_visuals = set()
        accuracy_risks   = set()
        for r in self._records:
            if r['status'] not in ('SUCCESS', 'skipped'):
                for ws in r.get('affected_visuals', []):
                    impacted_visuals.add(ws)
            if r['status'] in ('UNSUPPORTED', 'FAILED'):
                for ws in r.get('affected_visuals', []):
                    accuracy_risks.add(ws)

        # Overall confidence: weighted average
        if total:
            overall_confidence = int(
                sum(r['confidence'] for r in self._records) / total
            )
        else:
            overall_confidence = 100

        return {
            'workbook_name':            self.workbook_name,
            'total_calculations':       total,
            'by_status': {
                'SUCCESS':     by_status.get('SUCCESS',     0),
                'PARTIAL':     by_status.get('PARTIAL',     0),
                'FALLBACK':    by_status.get('FALLBACK',    0),
                'UNSUPPORTED': by_status.get('UNSUPPORTED', 0),
                'FAILED':      by_status.get('FAILED',      0),
            },
            'by_semantic_class':        by_sem,
            'total_measures':           by_sem.get('measure',      0)
                                        + by_sem.get('aggregation', 0),
            'total_lod_calculations':   sum(
                1 for r in self._records
                if r['sem_class'] == 'aggregation'
                and any(f['function'] in ('FIXED', 'INCLUDE', 'EXCLUDE')
                        for f in r.get('functions', []))
            ),
            'total_table_calculations': sum(
                1 for r in self._records
                if any(f['function'].startswith(('WINDOW_', 'RUNNING_', 'LOOKUP',
                                                  'INDEX', 'RANK', 'FIRST', 'LAST'))
                        for f in r.get('functions', []))
            ),
            'potential_visual_issues':  len(impacted_visuals),
            'potential_accuracy_risks': len(accuracy_risks),
            'overall_confidence_score': overall_confidence,
            'function_inventory':       fn_inventory,
            'impacted_visual_names':    sorted(impacted_visuals),
            'accuracy_risk_visuals':    sorted(accuracy_risks),
            # ── Loss-stage breakdown ─────────────────────────────────────
            'failed_by_empty_formula':  sum(
                1 for r in self._records
                if r.get('loss_stage') == 'empty_formula'
                and r.get('status') in ('FAILED','FALLBACK','PARTIAL','UNSUPPORTED')
            ),
            'failed_by_translator':     sum(
                1 for r in self._records
                if r.get('loss_stage') == 'translator'
                and r.get('status') in ('FAILED','FALLBACK','PARTIAL','UNSUPPORTED')
            ),
            'failed_by_col_ref_fix':    sum(
                1 for r in self._records
                if r.get('loss_stage') == 'col_ref_fix'
                and r.get('status') in ('FAILED','FALLBACK','PARTIAL','UNSUPPORTED')
            ),
            'failed_by_agg_fix':        sum(
                1 for r in self._records
                if r.get('loss_stage') == 'agg_fix'
                and r.get('status') in ('FAILED','FALLBACK','PARTIAL','UNSUPPORTED')
            ),
            'failed_by_reuse_cache':    sum(
                1 for r in self._records
                if r.get('loss_stage') == 'reuse_cache'
                and r.get('status') in ('FAILED','FALLBACK','PARTIAL','UNSUPPORTED')
            ),
            'failed_by_cycle':          sum(
                1 for r in self._records
                if r.get('sem_class') == 'skipped'
                and ('cyclic' in (r.get('failure_reason') or r.get('fallback_reason','') or '').lower()
                     or 'cycle' in (r.get('failure_reason') or r.get('fallback_reason','') or '').lower())
            ),
            'failed_by_dependency':      sum(
                1 for r in self._records
                if r.get('sem_class') == 'skipped'
                and 'dep' in (r.get('failure_reason') or r.get('fallback_reason','') or '').lower()
                and 'cyclic' not in (r.get('failure_reason') or r.get('fallback_reason','') or '').lower()
            ),
            # Calculations where post-processing raised an exception but DAX
            # was PRESERVED (not failed) — these are data-accuracy warnings,
            # not outright failures.
            'failed_by_post_processing': sum(
                1 for r in self._records if r.get('post_processing_warning')
            ),
            'worksheet_scores': self.worksheet_scores,
            'avg_overall_match_pct': (
                int(sum(w['overall_pct'] for w in self.worksheet_scores) / len(self.worksheet_scores))
                if self.worksheet_scores else None
            ),
            'dashboard_actions': self.dashboard_actions,
            'parameter_notes':   self.parameter_notes,
            'story_notes':       self.story_notes,
            'data_model_tables':        self.data_model_tables,
            'data_model_relationships': self.data_model_relationships,
            'data_model_notes':         self.data_model_notes,
            'datasource_notes':         self.datasource_notes,
        }

    # ── Output writers ────────────────────────────────────────────────────────

    def write(self, output_dir: 'Path') -> None:
        """Write migration_audit.json and migration_audit.md to *output_dir*."""
        import pathlib as _pl
        out = _pl.Path(output_dir)
        out.mkdir(parents=True, exist_ok=True)

        smry = self.summary()
        full_report = {
            'summary':  smry,
            'records':  self._records,
        }

        # JSON
        json_path = out / 'migration_audit.json'
        with open(json_path, 'w', encoding='utf-8') as fh:
            json.dump(full_report, fh, indent=2, ensure_ascii=False,
                      default=lambda o: list(o) if isinstance(o, (set, frozenset)) else str(o))
        log('info', f'[Audit] JSON report → {json_path}')

        # Markdown
        md_path = out / 'migration_audit.md'
        with open(md_path, 'w', encoding='utf-8') as fh:
            fh.write(self._render_md(smry))
        log('info', f'[Audit] Markdown report → {md_path}')

    def log_summary(self) -> None:
        """Emit a concise summary to the main log stream."""
        smry = self.summary()
        b    = smry['by_status']
        log('info',
            f"[Audit] {self.workbook_name} — "
            f"total={smry['total_calculations']} "
            f"SUCCESS={b['SUCCESS']} PARTIAL={b['PARTIAL']} "
            f"FALLBACK={b['FALLBACK']} UNSUPPORTED={b['UNSUPPORTED']} "
            f"FAILED={b['FAILED']} "
            f"confidence={smry['overall_confidence_score']}/100 "
            f"visual_risks={smry['potential_visual_issues']}")

    # ── Markdown renderer ─────────────────────────────────────────────────────

    def _render_md(self, smry: dict) -> str:
        b  = smry['by_status']
        sc = smry['overall_confidence_score']
        lines = [
            f"# Migration Audit: {smry['workbook_name']}",
            '',
            '## Workbook Summary',
            '',
            f"| Metric | Value |",
            f"|--------|-------|",
            f"| Total Calculations | {smry['total_calculations']} |",
            f"| ✅ SUCCESS | {b['SUCCESS']} |",
            f"| ⚠️ PARTIAL | {b['PARTIAL']} |",
            f"| 🔄 FALLBACK | {b['FALLBACK']} |",
            f"| ❌ UNSUPPORTED | {b['UNSUPPORTED']} |",
            f"| 💥 FAILED | {b['FAILED']} |",
            f"| Total Measures | {smry['total_measures']} |",
            f"| LOD Calculations | {smry['total_lod_calculations']} |",
            f"| Table Calculations | {smry['total_table_calculations']} |",
            f"| Potential Visual Issues | {smry['potential_visual_issues']} |",
            f"| Potential Accuracy Risks | {smry['potential_accuracy_risks']} |",
            f"| **Overall Confidence** | **{sc}/100** |",
            f"| Failed: Empty Formula  | {smry.get('failed_by_empty_formula', 0)} |",
            f"| Failed: Translator     | {smry.get('failed_by_translator', 0)} |",
            f"| Failed: Col Ref Fix    | {smry.get('failed_by_col_ref_fix', 0)} |",
            f"| Failed: Agg Fix        | {smry.get('failed_by_agg_fix', 0)} |",
            f"| Failed: Cyclic Dep     | {smry.get('failed_by_cycle', 0)} |",
            f"| Failed: Missing Dep    | {smry.get('failed_by_dependency', 0)} |",
            f"| Post-proc recovered    | {smry.get('failed_by_post_processing', 0)} |",
            '',
        ]

        # ── Per-worksheet Migration Quality Score ─────────────────────────────
        ws_scores = smry.get('worksheet_scores') or []
        if ws_scores:
            avg = smry.get('avg_overall_match_pct')
            lines += [
                '## Per-Worksheet Migration Quality Score',
                '',
                f"**Average Overall Match: {avg}/100** across {len(ws_scores)} worksheet(s).",
                '',
                '_Visual/Layout/Formatting % are heuristic estimates from known mapping '
                'quality and detected signals — not a pixel-level comparison against the '
                'original Tableau render. Calculation % and Filter % are measured directly '
                'from this workbook\'s translation results._',
                '',
                '| Worksheet | Detected (Tableau) | Power BI Visual | Calc % | Visual % | '
                'Layout % | Format % | Filter % | Overall % |',
                '|-----------|---------------------|------------------|--------|----------|'
                '----------|----------|----------|-----------|',
            ]
            for w in sorted(ws_scores, key=lambda x: x['overall_pct']):
                lines.append(
                    f"| {w['worksheet']} | {w['detected_visual']} | {w['pbi_visual']} | "
                    f"{w['calc_pct']} | {w['visual_pct']} | {w['layout_pct']} | "
                    f"{w['format_pct']} | {w['filter_pct']} | **{w['overall_pct']}** |"
                )
            lines.append('')

            _flagged = [w for w in ws_scores if w.get('notes')]
            if _flagged:
                lines += ['### Unsupported Features / Warnings / Recommendations', '']
                for w in _flagged:
                    lines.append(f"- **{w['worksheet']}**")
                    for note in w['notes']:
                        lines.append(f"  - {note}")
                lines.append('')

        # ── Dashboard Actions ──────────────────────────────────────────────
        actions = smry.get('dashboard_actions') or []
        if actions:
            lines += [
                '## Dashboard Actions',
                '',
                f"**{len(actions)} action(s) detected.** Power BI has no direct import path for "
                "Tableau dashboard actions, so each is listed here with a specific recommendation "
                "rather than silently dropped or guessed at with unverified internal Power BI JSON.",
                '',
                '| Action | Type | Source | Target | Recommendation |',
                '|--------|------|--------|--------|-----------------|',
            ]
            for a in actions:
                src = a.get('source', {})
                src_desc = src.get('worksheet') or src.get('dashboard') or '—'
                target = a.get('target_sheet') or a.get('url') or '—'
                lines.append(
                    f"| {a.get('caption', a.get('name',''))} | {a.get('category','')} | "
                    f"{src_desc} | {target} | {_action_recommendation(a)} |"
                )
            lines.append('')

        # ── Unsupported datasource connections (Increment 27) ──────────────────
        ds_notes = smry.get('datasource_notes') or []
        if ds_notes:
            lines += [
                '## ⚠️ Unsupported Data Source Connections',
                '',
                f"**{len(ds_notes)} table(s)** use a Tableau connection type this engine has no "
                "native Power BI query builder for, and no cached extract data was available to "
                "embed instead. The table and every column were still created with the correct "
                "name/type — every visual and calculation referencing them will bind correctly — "
                "but the table itself has **zero rows** until you manually configure its data "
                "source in Power BI Desktop (Transform Data → this query's `Source` step).",
                '',
                '| Table | Tableau Connection Type | Datasource |',
                '|-------|--------------------------|------------|',
            ]
            for tbl, conn_cls, raw in ds_notes:
                lines.append(f"| {tbl} | `{conn_cls or 'unknown'}` | {raw} |")
            lines.append('')

        # ── Data Model (tables, relationships, cardinality, validation) ────────
        dm_tables = smry.get('data_model_tables') or []
        dm_rels   = smry.get('data_model_relationships') or []
        dm_notes  = smry.get('data_model_notes') or []
        if dm_tables:
            lines += [
                '## Data Model',
                '',
                f"**{len(dm_tables)} table(s)**, **{len(dm_rels)} relationship(s)** in the "
                "generated Power BI semantic model. Every relationship below was validated "
                "against the actual generated tables/columns before the .pbit was written — "
                "none reference a table or column that doesn't exist.",
                '',
                '### Tables',
                '',
            ]
            for tn in dm_tables:
                lines.append(f"- {tn}")
            lines.append('')
            if dm_rels:
                lines += [
                    '### Relationships',
                    '',
                    '| From | To | Cardinality | Cross-Filter | Active |',
                    '|------|-----|-------------|--------------|--------|',
                ]
                for r in dm_rels:
                    lines.append(
                        f"| {r['fromTable']}.{r['fromColumn']} | {r['toTable']}.{r['toColumn']} | "
                        f"{r.get('fromCardinality','?')}:{r.get('toCardinality','?')} | "
                        f"{r.get('crossFilteringBehavior','')} | {r.get('isActive', True)} |"
                    )
                lines.append('')
            _dm_flagged = [n for n in dm_notes if n[1] != 'created']
            if _dm_flagged:
                lines += ['### Data Model Notes / Repairs', '']
                for desc, status, detail in _dm_flagged:
                    lines.append(f"- **{status}** — {desc}: {detail}")
                lines.append('')

        # ── Stories ──────────────────────────────────────────────────────────
        snotes = smry.get('story_notes') or []
        if snotes:
            lines += ['## Stories', '']
            for note in snotes:
                lines.append(f"- {note}")
            lines.append('')

        # ── Parameters ───────────────────────────────────────────────────────
        pnotes = smry.get('parameter_notes') or []
        if pnotes:
            _status_icon = {'whatif_parameter': '✅', 'inlined_literal': '⚠️', 'unresolved': '❌'}
            lines += [
                '## Parameters',
                '',
                f"**{len(pnotes)} Tableau parameter(s) detected.**",
                '',
                '| Parameter | Status | Detail |',
                '|-----------|--------|--------|',
            ]
            for _cap, _status, _detail in pnotes:
                lines.append(f"| {_cap} | {_status_icon.get(_status, '')} {_status} | {_detail} |")
            lines.append('')

        # Semantic class breakdown
        lines += ['## Semantic Classification Breakdown', '']
        lines += ['| Semantic Class | Count |', '|----------------|-------|']
        for cls, cnt in sorted(smry['by_semantic_class'].items(), key=lambda x: -x[1]):
            lines.append(f'| {cls} | {cnt} |')
        lines.append('')

        # Function inventory
        fn_inv = smry.get('function_inventory', {})
        if fn_inv:
            lines += ['## Tableau Function Support', '']
            lines += ['| Function | Support Level | Notes |',
                      '|----------|---------------|-------|']
            for fn_name, fn_info in sorted(fn_inv.items()):
                icon = {'supported': '✅', 'partial': '⚠️', 'unsupported': '❌'}.get(
                    fn_info['support'], '❓')
                lines.append(
                    f"| `{fn_name}` | {icon} {fn_info['support']} | {fn_info.get('note','')} |"
                )
            lines.append('')

        # Impacted visuals
        if smry['impacted_visual_names']:
            lines += ['## Potentially Impacted Visuals', '']
            for ws in smry['impacted_visual_names']:
                lines.append(f'- {ws}')
            lines.append('')

        # Accuracy risk visuals
        if smry['accuracy_risk_visuals']:
            lines += ['## Accuracy Risk Visuals (UNSUPPORTED/FAILED calcs)', '']
            for ws in smry['accuracy_risk_visuals']:
                lines.append(f'- ⚠️ {ws}')
            lines.append('')

        # Per-calculation table (only non-SUCCESS)
        non_success = [r for r in self._records if r['status'] != 'SUCCESS']
        if non_success:
            lines += ['## Non-Successful Calculations', '']
            lines += ['| Calculation | Status | Confidence | Semantic Class | '
                      'Affected Visuals | Fallback Reason | Warnings |',
                      '|-------------|--------|------------|----------------|'
                      '-----------------|-----------------|----------|']
            for r in non_success:
                status_icon = {
                    'PARTIAL':     '⚠️',
                    'FALLBACK':    '🔄',
                    'UNSUPPORTED': '❌',
                    'FAILED':      '💥',
                }.get(r['status'], '')
                ws_list = ', '.join(r['affected_visuals'][:3])
                if len(r['affected_visuals']) > 3:
                    ws_list += f" +{len(r['affected_visuals'])-3} more"
                warns = '; '.join(
                    r['dax_valid'].get('warnings', [])[:2]
                    + r['dax_valid'].get('issues', [])[:2]
                )
                fb_reason = r.get('fallback_reason', '')[:60]
                lines.append(
                    f"| `{r['calc_name']}` | {status_icon} {r['status']} | "
                    f"{r['confidence']}/100 | {r['sem_class']} | "
                    f"{ws_list} | {fb_reason} | {warns[:60]} |"
                )
            lines.append('')

        # Full calculation detail
        lines += ['## Full Calculation Detail', '']
        for r in self._records:
            status_icon = {
                'SUCCESS':     '✅',
                'PARTIAL':     '⚠️',
                'FALLBACK':    '🔄',
                'UNSUPPORTED': '❌',
                'FAILED':      '💥',
            }.get(r['status'], '❓')
            _orig_f = r.get('original_formula', r['formula'])
            _pars_f = r.get('parsed_formula', '')
            _ls     = r.get('loss_stage', '')
            _fr     = r.get('failure_reason') or r.get('fallback_reason', '')
            _detail = [
                f"### {status_icon} `{r['calc_name']}`",
                '',
                f"- **Datasource:** {r['datasource']}",
                f"- **Semantic Class:** {r['sem_class']}",
                f"- **Status:** {r['status']} ({r['confidence']}/100)",
            ]
            if _ls and _ls not in ('none', ''):
                _detail.append(f'- **Loss Stage:** `{_ls}`')
            if _fr:
                _detail.append(f'- **Failure Reason:** {_fr}')
            _detail += [
                f"- **Dependencies ({r['dep_count']}):** "
                + (', '.join(f'`{d}`' for d in r['dependencies']) or '—'),
                '',
                '**Original Tableau Formula:**',
                '```',
                _orig_f[:500] + ('…' if len(_orig_f) > 500 else ''),
                '```',
            ]
            if _pars_f and _pars_f != _orig_f:
                _detail += [
                    '',
                    '**Parsed Formula (after caption expansion):**',
                    '```',
                    _pars_f[:500] + ('…' if len(_pars_f) > 500 else ''),
                    '```',
                ]
            _detail += [
                '',
                '**Generated DAX:**',
                '```dax',
                r['generated_dax'][:500] + ('…' if len(r['generated_dax']) > 500 else ''),
                '```',
                '',
            ]
            lines += _detail
            _ppw = r.get('post_processing_warning', '')
            if _ppw:
                lines += [
                    '**⚠ Post-Processing Warning (DAX preserved):**',
                    f'> {_ppw}',
                    '',
                ]
            if r['functions']:
                lines.append('**Functions used:**')
                for fn in r['functions']:
                    icon = {'supported': '✅', 'partial': '⚠️', 'unsupported': '❌'}.get(
                        fn['support'], '❓')
                    lines.append(f'  - {icon} `{fn["function"]}` — {fn.get("note","")}')
                lines.append('')
            issues  = r['dax_valid'].get('issues', [])
            warns   = r['dax_valid'].get('warnings', [])
            if issues or warns:
                lines.append('**Validation:**')
                for iss in issues:
                    lines.append(f'  - 🔴 {iss}')
                for w in warns:
                    lines.append(f'  - 🟡 {w}')
                lines.append('')

        return '\n'.join(lines) + '\n'


# ── Per-worksheet Migration Quality Score ─────────────────────────────────────
# Visual-mapping-quality heuristic, keyed by the PBI visual type this engine's
# detection engine assigns (see the chart_type decision cascade in
# parse_tableau_workbook). Scores are a considered estimate of how faithfully
# that PBI visual reproduces the *kind* of Tableau chart it's standing in for,
# not a measurement of any specific worksheet's actual pixels.
_VISUAL_MATCH_SCORE = {
    # Exact / near-exact native Power BI equivalents.
    'clusteredColumnChart': 95, 'columnChart': 95, 'clusteredBarChart': 95,
    'barChart': 95, 'lineChart': 95, 'card': 95, 'slicer': 95, 'textbox': 100,
    'treemap': 90, 'pieChart': 90, 'donutChart': 90, 'scatterChart': 90,
    # Reasonable but approximate mappings.
    'areaChart': 85,                       # also stands in for Tableau Gantt bars on some
                                            # worksheets (flagged separately below) — a real
                                            # area chart scores higher than this in practice,
                                            # a Gantt-as-area one lower; 85 is a fair blend
                                            # given no per-worksheet signal distinguishes them.
    'lineClusteredColumnComboChart': 85,    # dual-axis combo approximation
    'mapChart': 85, 'filledMap': 85,        # PBI's generic 'map' visual, not true choropleth/symbol
    # Generic fallbacks — also double as the Heat Map / Highlight Table /
    # unrecognised-chart-type catch-all, hence the lower score and the note
    # attached in _compute_worksheet_quality_scores.
    'tableEx': 75, 'pivotTable': 75,
}
_DEFAULT_VISUAL_MATCH_SCORE = 70


def _compute_worksheet_quality_scores(workbook: dict, audit: 'MigrationAudit') -> list:
    """Build the per-worksheet Migration Quality Score: one entry per visible
    worksheet with Calculation / Visual / Layout / Format / Filter / Overall
    Match %, plus unsupported-feature notes. Call after build_report_layout()
    (needs workbook['_layout_fidelity']) and before audit.write().

    Calculation % and Filter % are measured from this workbook's actual
    translation/filter results. Visual / Layout / Format % are heuristics
    from known mapping quality and detected signals — not a pixel-level
    comparison against the original Tableau render. The Markdown report
    states this plainly so the score isn't mistaken for more than it is.
    """
    fidelity   = workbook.get('_layout_fidelity', {})
    referenced = set(fidelity.get('referenced', []))
    orphaned   = set(fidelity.get('orphaned', []))
    excluded   = set(fidelity.get('hidden_or_helper', []))
    has_dashboards = bool(workbook.get('dashboards'))

    # Fields that carry a real Tableau default-format successfully converted
    # to a PBI FormatString AND actually get that FormatString applied to the
    # generated model — see _tableau_default_format_to_pbi. Used below as a
    # 4th Format Match signal. Restricted to measure columns (the
    # measure_cols loop applies the real conversion) and calculations (every
    # calc becomes either a measure or calculated column, both of which apply
    # it) — deliberately EXCLUDES dimension/date columns: their default-format
    # (e.g. a date column's '*mmmm yyyy') is captured but not yet wired into
    # the model (date columns still get a hardcoded "General Date"), so
    # crediting it here would have the audit claim more than the generated
    # PBIT actually delivers.
    _real_fmt_field_norms = set()
    for _fds in workbook.get('datasources', []):
        for _fc in _fds.get('columns', []):
            if not _fc.get('measure'):
                continue
            if _tableau_default_format_to_pbi(_fc.get('tableau_format', '')):
                _real_fmt_field_norms.add(_field_norm_key(_fc.get('name', '')))
        for _fc in _fds.get('calculations', []):
            if _tableau_default_format_to_pbi(_fc.get('tableau_format', '')):
                _real_fmt_field_norms.add(_field_norm_key(_fc.get('name', '')))

    scores = []
    for ws in workbook.get('worksheets', []):
        name = ws.get('name', '')
        if not name or name in excluded:
            continue

        notes = []

        # ── Calculation Match % — measured, not estimated ─────────────────
        calc_pct = audit.calc_confidence_for(audit.calcs_for_worksheet(name))

        # ── Visual Match % — mapping-quality heuristic ────────────────────
        chart_type = ws.get('chart_type', 'tableEx')
        visual_pct = _VISUAL_MATCH_SCORE.get(chart_type, _DEFAULT_VISUAL_MATCH_SCORE)
        if chart_type in ('tableEx', 'pivotTable'):
            if ws.get('color_fields'):
                # A color encoding on a table/matrix is the Heat Map / Highlight
                # Table signature. Power BI's table/matrix conditional-formatting
                # (background color by rule/gradient) is a real feature, but this
                # engine doesn't have a verified-safe internal JSON shape for it
                # to write automatically (unlike the per-visual objects_cfg keys
                # used for reference lines/constant lines — this would be a
                # structurally novel nested property this codebase has never
                # proven out against a real reference PBIT), so it's reported
                # here as a specific, actionable step instead of guessed at.
                notes.append(
                    f"Detected as a Heat Map / Highlight Table ('{chart_type}' with a color "
                    f"encoding on {', '.join(ws['color_fields'][:2])}) — rendered as a plain "
                    "table/matrix. In Power BI, select the affected column(s) → Format → "
                    "Conditional formatting → Background color → Format by Gradient (or Rules) "
                    "to restore the color-scale visualization."
                )
            else:
                notes.append(
                    f"Rendered as a generic table/matrix ('{chart_type}') — verify this wasn't "
                    "meant to be a Heat Map or Highlight Table."
                )
        if (chart_type in ('barChart', 'clusteredBarChart', 'columnChart', 'clusteredColumnChart')
                and any(rl.get('formula') == 'constant' for rl in ws.get('reference_lines', []))):
            notes.append(
                "Bar/column chart with a fixed-value reference line — consistent with a "
                "Tableau Bullet Graph. Approximated as a bar chart with a target reference "
                "line (see Increment 3); qualitative performance bands (poor/satisfactory/"
                "good zones), if present in the original, are not replicated — only the "
                "single target value."
            )
        if (chart_type in ('clusteredColumnChart', 'columnChart')
                and any('(bin' in (f or '').lower() for f in
                        [ws.get('x_field', '')] + ws.get('shelf_row_fields', []))):
            notes.append(
                "Histogram (binned column chart) — Power BI's built-in column chart has no "
                "gap-width control to replicate Tableau's touching-bar histogram look; bars "
                "render with the standard column spacing instead. Bin boundaries and sort "
                "order are otherwise exact (the bin column is numeric, so it sorts correctly)."
            )
        if chart_type == 'areaChart' and any(m == 'GanttBar' for m in ws.get('pane_marks', [])):
            notes.append(
                "Tableau Gantt chart approximated as an Area Chart — no native Gantt "
                "visual mapping yet."
            )
        if (chart_type == 'lineClusteredColumnComboChart'
                and len(set(ws.get('pane_marks', []))) <= 1):
            notes.append(
                "True dual-axis chart (both measures share the same Tableau mark type) "
                "approximated with Power BI's line+column combo visual — the second "
                "measure renders as a column rather than matching the original mark, "
                "since that combo chart is PBI's only built-in visual with genuine "
                "independent-secondary-axis semantics."
            )
        if chart_type == 'lineClusteredColumnComboChart' and ws.get('axis_synchronized'):
            notes.append(
                "Tableau's dual axes were synchronized (shared scale) — Power BI's combo "
                "chart has no verified equivalent toggle; compare the primary/secondary "
                "axis ranges manually and adjust if they should match."
            )

        # ── Reference lines / trend lines — flag the cases left untranslated
        # (see _make_chart_vc: only formula='constant' and fit='linear' are
        # wired to real Power BI Analytics-pane objects; everything else needs
        # PBI's own dynamic line features configured manually).
        for _rl in ws.get('reference_lines', []):
            if _rl.get('formula') != 'constant':
                notes.append(
                    f"Reference line ({_rl.get('formula')}) on '{_rl.get('value_column')}' not "
                    f"translated — recreate using Power BI's Analytics pane "
                    f"'{_rl.get('formula')}' line feature manually."
                )
        _tl = ws.get('trendline')
        if _tl and (_tl.get('fit') or 'linear').lower() != 'linear':
            notes.append(
                f"Trend line (fit={_tl.get('fit')}) not translated — Power BI's native trend "
                "line is linear-regression only; no equivalent for this fit type."
            )

        # ── Layout Match % — did this worksheet keep its real dashboard
        # position, or land on the auto-arranged orphan grid page? ────────
        if name in referenced:
            layout_pct = 100
        elif not has_dashboards:
            layout_pct = 90   # no Tableau dashboard existed for this worksheet to begin with
        elif name in orphaned:
            layout_pct = 65
            notes.append(
                "Not referenced by any Tableau dashboard — placed on the auto-generated "
                "'Worksheets' grid page instead of its original position."
            )
        else:
            layout_pct = 80

        # ── Filter Match % — measured from this worksheet's actual filters.
        # Categorical/quantitative-range/Top-N/relative-date/context filters
        # are now converted; Measure Names filters remain a known partial case.
        filter_pct = 100
        if ws.get('measure_names_filter_fields'):
            filter_pct -= 15
            notes.append(
                "Measure Names filter captured as a field list only — approximated, not a "
                "fully equivalent Power BI filter."
            )

        # ── Formatting Match % — heuristic from captured formatting signals
        _ws_fmt_fields = (
            [ws.get('x_field', ''), ws.get('y_field', '')]
            + ws.get('shelf_row_fields', [])
            + ws.get('all_row_measure_fields', [])
        )
        has_real_number_format = any(
            _field_norm_key(f) in _real_fmt_field_norms for f in _ws_fmt_fields if f
        )
        fmt_signals = sum([
            bool(ws.get('label_format')),
            bool(ws.get('chart_pane_colors') or workbook.get('explicit_color_map')),
            bool(ws.get('sort_field')),
            has_real_number_format,
        ])
        format_pct = min(80 + 7 * fmt_signals, 100)

        overall_pct = round(
            visual_pct * 0.30 + calc_pct * 0.30 + filter_pct * 0.20
            + layout_pct * 0.10 + format_pct * 0.10
        )

        scores.append({
            'worksheet':       name,
            'detected_visual': ', '.join(sorted(set(ws.get('pane_marks', [])))) or '—',
            'pbi_visual':      chart_type,
            'calc_pct':        calc_pct,
            'visual_pct':      visual_pct,
            'layout_pct':      layout_pct,
            'format_pct':      format_pct,
            'filter_pct':      filter_pct,
            'overall_pct':     overall_pct,
            'notes':           notes,
        })
    return scores


def _action_recommendation(action: dict) -> str:
    """Human-readable Power BI equivalent/recommendation for one parsed
    Tableau dashboard action. See _parse_dashboard_actions() for why these
    are reported rather than auto-wired: the internal Report.json shape for
    page-level visual interactions and button actions couldn't be verified
    with the same confidence as this engine's per-visual filter format.
    """
    src = action.get('source', {})
    src_desc = src.get('worksheet') or src.get('dashboard') or 'workbook'
    excl = src.get('exclude_sheets') or []
    excl_note = (f" (Tableau excludes {', '.join(excl)} from being affected)"
                 if excl else '')

    cat = action.get('category')
    if cat == 'filter':
        return (
            f"Filter action from '{src_desc}' → '{action.get('target_sheet') or 'target sheet'}'. "
            f"If both are visuals on the same Power BI page, Power BI's default cross-filtering "
            f"already approximates this{excl_note} — verify the affected-visuals set matches via "
            f"Edit Interactions. If the target is on a different page, this isn't auto-replicated: "
            f"add a Bookmark + button, or a Drillthrough page, configured manually."
        )
    if cat == 'navigate_filter':
        return (
            f"Filter action from '{src_desc}' that also navigates to the dashboard "
            f"'{action.get('target_sheet')}'. Not auto-replicated — recommend a Bookmark + button "
            f"(or Drillthrough page) that jumps to that page filtered by the clicked value."
        )
    if cat == 'url':
        return (
            f"URL action: opens {action.get('url')!r}. Add a Power BI button or image with a "
            f"Web URL action manually. If the URL embeds a field value per selection, bind the "
            f"button's URL to a DAX measure built with SELECTEDVALUE() instead of a fixed string."
        )
    if cat == 'navigate':
        return (
            f"'Go to sheet' navigation action from '{src_desc}'. Add a Bookmark + button "
            f"(Action type: Page navigation) manually."
        )
    if cat == 'change_parameter':
        return (
            f"'Change parameter' action from '{src_desc}'. Requires the target parameter to exist "
            f"as a Power BI What-if parameter, then a button/bookmark or field-driven sync to "
            f"update it — not auto-replicated."
        )
    if cat == 'change_set':
        return (
            f"'Change set values' action from '{src_desc}'. Power BI has no direct Set equivalent; "
            f"requires a manually-built bookmark-driven selection or a DAX-based flag column."
        )
    if cat == 'other_link':
        return f"Action with an unrecognised link target ({action.get('url') or 'see workbook'}) — review manually."
    return f"Action '{action.get('caption')}' detected but its type couldn't be classified — review manually."


# ══════════════════════════════════════════════════════════════════════════════
# _translate_with_trace — loss-stage tracking wrapper for DAX translation
#
# Wraps _tableau_formula_to_dax + _fix_dax_col_refs + _fix_dax_aggregations
# and records exactly which stage produced the fallback.
#
# Returns a dict:
#   dax             : str   — final DAX string
#   loss_stage      : str   — 'none' | 'translator' | 'col_ref_fix' |
#                             'agg_fix' | 'empty_formula' | 'reuse_cache'
#   failure_reason  : str   — human-readable explanation (empty on success)
#   original_formula: str   — the raw Tableau formula before caption expansion
# ══════════════════════════════════════════════════════════════════════════════

def _translate_with_trace(
    original_formula: str,
    raw_formula:      str,
    table_name:       str,
    col_name_map:     dict,
    col_type_map:     dict,
    all_measure_names: set,
    cached_dax:       str = '',
    from_cache:       bool = False,
    param_ref_map:    dict = None,
) -> dict:
    """
    Thin tracing wrapper around the three-stage DAX translation pipeline.
    Does NOT modify any translation logic — only observes inputs and outputs
    to determine which stage introduced a fallback constant.

    Stages:
      empty_formula   — formula is blank at entry (parser lost it)
      reuse_cache     — DAX came from CalcRegistry cache (not retranslated)
      translator      — _tableau_formula_to_dax produced fallback
      col_ref_fix     — _fix_dax_col_refs degraded the DAX
      agg_fix         — _fix_dax_aggregations degraded the DAX
      none            — all stages produced valid non-fallback DAX
    """
    _FALLBACK_VALS = frozenset({'0', 'BLANK()', '""', "''", ''})

    def _is_fallback(d: str) -> bool:
        s = (d or '').strip()
        return s in _FALLBACK_VALS or s.startswith('BLANK() /*')

    result = {
        'dax':              '',
        'loss_stage':       'none',
        'failure_reason':   '',
        'original_formula': original_formula,
    }

    # Stage 0: empty formula
    if not (raw_formula or '').strip():
        result['dax']            = 'BLANK() /* empty Tableau formula */'
        result['loss_stage']     = 'empty_formula'
        result['failure_reason'] = (
            'Formula was empty or blank after parser/caption expansion. '
            'Check if the Tableau XML calculation element has no formula attribute, '
            'or if caption expansion removed the content.'
        )
        return result

    # Stage 1: reuse cache
    if from_cache:
        result['dax']        = cached_dax
        result['loss_stage'] = 'none' if not _is_fallback(cached_dax) else 'reuse_cache'
        if result['loss_stage'] == 'reuse_cache':
            result['failure_reason'] = (
                'Cached DAX from a previous translation is a constant fallback. '
                'The original translation (possibly for a different datasource) '
                'failed and the fallback was cached and reused.'
            )
        return result

    # Stage 2: _tableau_formula_to_dax
    try:
        dax_after_t2d = _tableau_formula_to_dax(raw_formula, table_name)
    except Exception as e:
        result['dax']            = 'BLANK() /* translation exception */'
        result['loss_stage']     = 'translator'
        result['failure_reason'] = f'_tableau_formula_to_dax raised exception: {e}'
        return result

    if _is_fallback(dax_after_t2d):
        # Already a fallback after translation — attempt recovery before giving up
        recovery = _attempt_recovery(raw_formula, table_name, col_name_map)
        if recovery and not _is_fallback(recovery):
            result['dax']            = recovery
            result['loss_stage']     = 'none'
            result['failure_reason'] = ''
            return result
        result['dax']            = dax_after_t2d
        result['loss_stage']     = 'translator'
        result['failure_reason'] = _infer_failure_reason(raw_formula, dax_after_t2d)
        return result

    # Stage 3: _fix_dax_col_refs
    # On ANY exception: preserve the pre-fix DAX rather than destroying the
    # calculation. A column-name remapping failure is cosmetic; the DAX is
    # still syntactically valid.
    try:
        dax_after_colfix = _fix_dax_col_refs(dax_after_t2d, table_name, col_name_map)
    except NameError as e:
        import warnings as _w
        _w.warn(f'[_translate_with_trace] _fix_dax_col_refs not in scope: {e}. '
                f'Using pre-fix DAX — column refs may retain Tableau names.',
                stacklevel=2)
        dax_after_colfix = dax_after_t2d
        result['post_processing_warning'] = f'col_ref_fix skipped (NameError): {e}'
    except Exception as e:
        import warnings as _w
        _w.warn(f'[_translate_with_trace] _fix_dax_col_refs error ({type(e).__name__}): {e}. '
                f'Preserving pre-fix DAX.',
                stacklevel=2)
        dax_after_colfix = dax_after_t2d
        result['post_processing_warning'] = f'col_ref_fix error ({type(e).__name__}): {e}'

    # Stage 4: _fix_dax_aggregations
    # Same policy: exception → preserve col-fix result, record warning, continue.
    try:
        dax_after_aggfix = _fix_dax_aggregations(
            dax_after_colfix, col_type_map, table_name,
            measure_names=all_measure_names, param_ref_map=param_ref_map
        )
    except NameError as e:
        import warnings as _w
        _w.warn(f'[_translate_with_trace] _fix_dax_aggregations not in scope: {e}. '
                f'Using post-colfix DAX — aggregation context may be wrong.',
                stacklevel=2)
        dax_after_aggfix = dax_after_colfix
        _prev = result.get('post_processing_warning', '')
        result['post_processing_warning'] = (
            (_prev + ' | ' if _prev else '') + f'agg_fix skipped (NameError): {e}'
        )
    except Exception as e:
        import warnings as _w
        _w.warn(f'[_translate_with_trace] _fix_dax_aggregations error ({type(e).__name__}): {e}. '
                f'Preserving post-colfix DAX.',
                stacklevel=2)
        dax_after_aggfix = dax_after_colfix
        _prev = result.get('post_processing_warning', '')
        result['post_processing_warning'] = (
            (_prev + ' | ' if _prev else '') + f'agg_fix error ({type(e).__name__}): {e}'
        )

    # Stage 5: final fallback detection — prefer less-processed intermediates
    result['dax'] = dax_after_aggfix
    if _is_fallback(dax_after_aggfix):
        if not _is_fallback(dax_after_colfix):
            result['dax']            = dax_after_colfix
            result['loss_stage']     = 'agg_fix'
            result['failure_reason'] = (
                '_fix_dax_aggregations degraded DAX to constant. '
                'Recovered col-fix intermediate: ' + dax_after_colfix[:120]
            )
        elif not _is_fallback(dax_after_t2d):
            result['dax']            = dax_after_t2d
            result['loss_stage']     = 'col_ref_fix'
            result['failure_reason'] = (
                '_fix_dax_col_refs degraded DAX to constant. '
                'Recovered translator intermediate: ' + dax_after_t2d[:120]
            )
        else:
            result['loss_stage']     = 'agg_fix'
            result['failure_reason'] = (
                'All post-processing stages degraded DAX to constant. '
                'Translator intermediate: ' + dax_after_t2d[:120]
            )
    return result


def _attempt_recovery(formula: str, table_name: str, col_name_map: dict) -> str:
    """
    Targeted recovery for common patterns that _tableau_formula_to_dax
    currently mishandles.  Returns a non-empty DAX string or '' if recovery
    is not possible.

    Handles:
      1. Icon/shape string calcs:  IF [x] THEN "▲" ELSE "▼" END
      2. Boolean / flag calcs:     [Dim] = "value"  (bare comparison)
      3. String concat patterns:   [A] + " " + [B]  (should be & not +)
      4. Numeric literal constants: 1, 0, 3.14  (no translation needed)
      5. MIN(literal) / MAX(literal): synthetic placeholder aggregates
    """
    import re as _rv

    f = formula.strip()
    if not f:
        return ''

    # Recovery 1: numeric literal constant (no translation needed)
    if _rv.match(r'^-?[\d.]+$', f):
        return f

    # Recovery 2: string literal constant
    if _rv.match(r'^"[^"]*"$', f) or _rv.match(r"^'[^']*'$", f):
        return f

    # Recovery 3: bare boolean comparison  [Col] = "val" / [Col] > 0
    _bare_cmp = _rv.match(r'^\[([^\]]+)\]\s*([=<>!]+)\s*(.+)$', f)
    if _bare_cmp:
        col_raw, op, rhs = _bare_cmp.groups()
        pbi_col = col_name_map.get(col_raw, col_raw)
        dax_col = f"'{table_name}'[{pbi_col}]"
        return f"{dax_col} {op} {rhs.strip()}"

    # Recovery 4: string concatenation — + between string fields → &
    # Pattern: "text" + [Col] or [Col] + "text"
    if '"' in f or "'" in f:
        candidate = _rv.sub(
            r'(?<=["\w\]])\s*[+]\s*(?=["\[])',
            ' & ', f
        )
        if '&' in candidate and '+' not in candidate.replace('&', ''):
            # Expand column refs
            def _expand_ref(m):
                col = m.group(1)
                pbi = col_name_map.get(col, col)
                return f"'{table_name}'[{pbi}]"
            candidate = _rv.sub(r'\[([^\]]+)\]', _expand_ref, candidate)
            return candidate

    # Recovery 5: MIN/MAX with literal (synthetic donut/icon placeholders)
    _lit = _rv.match(
        r'^(?:MIN|MAX|COUNT|SUM)\s*\(\s*(-?[\d.]+|TRUE|FALSE|NULL|"[^"]*")\s*\)$',
        f, _rv.I
    )
    if _lit:
        inner = _lit.group(1).strip()
        if inner.upper() == 'NULL': return 'BLANK()'
        if inner.upper() == 'TRUE': return 'TRUE()'
        if inner.upper() == 'FALSE': return 'FALSE()'
        return inner

    return ''


def _infer_failure_reason(formula: str, dax: str) -> str:
    """
    Infer a human-readable failure reason from the original formula and the
    generated (fallback) DAX.  Used in the audit record failure_reason field.
    """
    import re as _if_re
    f = formula.strip().upper()

    if not formula.strip():
        return 'Original formula is empty — check parser XML extraction'

    dax_s = (dax or '').strip()
    if dax_s.startswith('BLANK() /*'):
        return dax_s[len('BLANK() /*'):].rstrip(' */').strip()

    # Check for known unsupported patterns
    _checks = [
        (r'\bRAWSQLL?',                    'RAWSQL pass-through has no DAX equivalent'),
        (r'\bCOLLECT\s*\(',              'COLLECT() is a spatial aggregate with no DAX equivalent'),
        (r'\bMAKEPOINT\s*\(',            'MAKEPOINT() is spatial with no DAX equivalent'),
        (r'\bMAKELINE\s*\(',             'MAKELINE() is spatial with no DAX equivalent'),
        (r'\bDISTANCE\s*\(',             'DISTANCE() is spatial with no DAX equivalent'),
        (r'\bSCRIPT_',                     'SCRIPT_* analytics extension has no DAX equivalent'),
        (r'\bSIZE\s*\(\)',              'SIZE() is a table calculation — approximated but may not be accurate'),
        (r'\bPREVIOUS_VALUE\s*\(',       'PREVIOUS_VALUE() is a table calculation with no DAX equivalent'),
        (r'\bHEXBIN[XY]\s*\(',          'HEXBIN spatial binning has no DAX equivalent'),
        (r'\{\s*(?:INCLUDE|EXCLUDE)',     'INCLUDE/EXCLUDE LOD expression — approximated as CALCULATE'),
    ]
    for pat, reason in _checks:
        if _if_re.search(pat, formula, _if_re.I):
            return reason

    return (
        f'Translation produced constant fallback. '
        f'Formula uses constructs not yet fully supported. '
        f'First 100 chars: {formula[:100]}'
    )


def _param_literal(raw_value, datatype: str):
    """Format a raw Tableau parameter value (XML attribute string) as a DAX
    literal, dispatched by Tableau datatype. Returns None when the value is
    missing or doesn't parse — callers must treat that as 'can't build this'
    rather than emit a guessed literal."""
    if raw_value is None or str(raw_value).strip() == '':
        return None
    v = str(raw_value).strip()
    dt = (datatype or '').lower()
    if dt in ('integer', 'int'):
        try:
            return str(int(float(v)))
        except ValueError:
            return None
    if dt in ('real', 'float', 'double', 'decimal', 'number'):
        try:
            return str(float(v))
        except ValueError:
            return None
    if dt in ('date', 'datetime'):
        # Tableau stores dates as #YYYY-MM-DD# or #YYYY-MM-DD HH:MM:SS#
        m = __import__('re').match(r'#(\d{4})-(\d{2})-(\d{2})', v)
        if m:
            y, mo, d = m.groups()
            return f'DATE({y},{int(mo)},{int(d)})'
        return None
    if dt in ('boolean', 'bool'):
        return 'TRUE()' if v.lower() in ('true', '1') else 'FALSE()'
    return '"' + v.strip('"').replace('"', '""') + '"'   # string / default


def _build_whatif_parameter_table(pdef: dict, seen_table_names: set, seen_model_measure_names: set):
    """Build a real Power BI What-if parameter (table + SELECTEDVALUE measure)
    from an enumerable Tableau parameter (param-domain-type 'range' or
    'list' — schema-verified against the 2026.2 TWB XSD's <range min max
    granularity> and <members><member value alias>). Mirrors the standard,
    publicly-documented structure Power BI Desktop's own 'New Parameter' UI
    generates: GENERATESERIES (or a DAX table constructor for a fixed list)
    wrapped in SELECTCOLUMNS to name the value column, plus a SELECTEDVALUE
    measure — mainstream DAX, not an internal-format guess.

    Returns (table_dict, table_name, column_name, measure_name, measure_dax)
    or None when the parameter isn't enumerable or is missing the data
    needed to build one (caller falls back to inlining the literal value,
    same as an 'any'-domain parameter, and should log why).
    """
    caption  = pdef.get('caption') or pdef.get('name') or 'Parameter'
    datatype = pdef.get('datatype', 'string')
    col_name = caption
    col_esc  = col_name.replace('"', '""')

    default_lit = None
    if pdef.get('domain_type') == 'range' and pdef.get('range'):
        rng = pdef['range']
        min_lit = _param_literal(rng.get('min'), datatype)
        max_lit = _param_literal(rng.get('max'), datatype)
        if min_lit is None or max_lit is None:
            return None
        try:
            step = float(rng.get('granularity')) if rng.get('granularity') else 1.0
        except (TypeError, ValueError):
            step = 1.0
        step_lit = str(int(step)) if datatype.lower() in ('date', 'datetime') or step == int(step) else str(step)
        table_expr = (
            f'SELECTCOLUMNS(GENERATESERIES({min_lit}, {max_lit}, {step_lit}), '
            f'"{col_esc}", [Value])'
        )
        default_lit = _param_literal(pdef.get('value'), datatype) or min_lit
    elif pdef.get('domain_type') == 'list' and pdef.get('members'):
        literals = [l for l in (_param_literal(m['value'], datatype) for m in pdef['members'])
                    if l is not None]
        if not literals:
            return None
        table_expr = f'SELECTCOLUMNS({{{", ".join(literals)}}}, "{col_esc}", [Value1])'
        default_lit = _param_literal(pdef.get('value'), datatype) or literals[0]
    else:
        return None

    table_name = _unique_name(_safe_pbi_name(caption), seen_table_names)
    pbi_datatype = {
        'integer': 'int64', 'real': 'double', 'date': 'dateTime',
        'datetime': 'dateTime', 'boolean': 'boolean',
    }.get(datatype.lower(), 'string')

    table_dict = {
        "name": table_name,
        "lineageTag": _guid(),
        "columns": [{
            "name": col_name,
            "lineageTag": _guid(),
            "dataType": pbi_datatype,
            "sourceColumn": col_name,
            "summarizeBy": "none",
            "annotations": [{"name": "SummarizationSetBy", "value": "Automatic"}],
        }],
        "partitions": [{
            "name": table_name,
            "mode": "import",
            "source": {"type": "calculated", "expression": [table_expr]},
        }],
        "annotations": [{"name": "PBI_ResultType", "value": '"Table"'}],
    }

    measure_name = _unique_name(f"{caption} Value", seen_model_measure_names, case_insensitive=True)
    measure_dax  = f"SELECTEDVALUE('{table_name}'[{col_name}], {default_lit})"

    return table_dict, table_name, col_name, measure_name, measure_dax


def _strip_dim_disambig_suffix(raw: str, dim_table_name: str) -> str:
    """Strip Tableau's own cross-table name-collision suffix, e.g.
    'Customer Code (Customers.Csv)' -> 'Customer Code' when building the
    standalone 'customers' dimension table. Tableau only adds this suffix
    because the same-named column also lives in the fact table's merged
    column list; on its own dimension table it's unambiguous. Confirmed
    against real XML (Amazon Sales Insights' 'customer_code (customers.csv)')
    — see Increment 22."""
    import re as _re_sdd
    cleaned = _re_sdd.sub(
        r'\s*\(' + _re_sdd.escape(dim_table_name) + r'(\.csv)?\)\s*$',
        '', raw, flags=_re_sdd.I
    ).strip()
    return cleaned or raw


def _build_dimension_table(dim_table_name: str, dim_cols: list, conn_info: dict,
                            seen_table_names: set, embed_sample_data: bool,
                            extracted_data: dict, day_first: bool = False):
    """Build a standalone, real PBI dimension table for one physical Tableau
    sub-table that participates in a schema-verified <relationships>
    (logical-layer) join — see Increment 22 in MIGRATION_ENGINE_PROGRESS.md.

    dim_cols: the subset of the parent (merged/fact) datasource's own
    already-typed column dicts belonging to this real table (resolved via
    <metadata-records> at parse time — see parse_tableau_workbook).

    This is intentionally a smaller, self-contained rebuild of the per-column
    TOM-entry logic in the main per-datasource loop below rather than a
    refactor of that already-hardened ~1400-line block — dimension tables
    here don't need geo map-columns, drill-path hierarchies, or measures
    beyond their own numeric columns, so duplicating the small relevant
    subset carries far less regression risk than extracting a shared helper
    out of code every existing chart/DAX path already depends on.

    Returns (pbi_table_dict, param_table_or_None, col_name_map, table_name).
    col_name_map maps each source column's original name/source_name (as it
    appears on the FACT table, i.e. still carrying any disambiguation suffix)
    to this dimension table's own final PBI column name — used by the caller
    to resolve the relationship's toColumn.
    """
    table_name = _unique_name(_safe_pbi_name(dim_table_name), seen_table_names)
    param_name = _unique_name(_safe_pbi_name(dim_table_name + "FilePath"), seen_table_names)

    seen_field_names: set = set()
    col_name_map: dict = {}
    pbi_columns = []
    _mq_cols = []
    for col in dim_cols:
        _clean_name = _strip_dim_disambig_suffix(col['name'], dim_table_name)
        _clean_src  = _strip_dim_disambig_suffix(col.get('source_name') or col['name'], dim_table_name)
        col_name = _unique_name(_clean_name, seen_field_names, case_insensitive=True)
        col_name_map[col['name']] = col_name
        if col.get('source_name') and col['source_name'] != col['name']:
            col_name_map.setdefault(col['source_name'], col_name)

        _pbi_tom_dtype = 'dateTime' if col['datatype'] in ('date', 'datetime', 'timestamp') else col['datatype']
        _tom_col_entry = {
            "name": col_name,
            "lineageTag": _guid(),
            "dataType": _pbi_tom_dtype,
            "sourceColumn": _clean_name,
            "summarizeBy": "sum" if col.get('measure') else "none",
            "annotations": [{"name": "SummarizationSetBy", "value": "Automatic"}]
        }
        _real_fmt = _tableau_default_format_to_pbi(col.get('tableau_format', ''))
        if _real_fmt:
            _tom_col_entry["formatString"] = _real_fmt
        elif _pbi_tom_dtype == 'dateTime':
            _tom_col_entry["formatString"] = "General Date"
        if col.get('geo_category'):
            _tom_col_entry["dataCategory"] = col['geo_category']
        pbi_columns.append(_tom_col_entry)

        _mq_cols.append({'name': _clean_name, 'source_name': _clean_src, 'datatype': col['datatype']})

    param_table = None
    if embed_sample_data:
        m_query = _build_sample_m_query(table_name, _mq_cols,
                                         extracted_data=extracted_data,
                                         ds_caption=dim_table_name,
                                         day_first=day_first)
    else:
        filename = conn_info.get('filename', '')
        fl = filename.lower()
        if fl.endswith(('.csv', '.tsv', '.txt')) or conn_info.get('class') in ('csv', 'text-file', 'staticcsv', 'textscan'):
            delim = '\t' if fl.endswith('.tsv') else ','
            m_query = _build_csv_m_query(table_name, param_name, _mq_cols, delimiter=delim)
        elif fl.endswith(('.xlsx', '.xls', '.xlsm')) or conn_info.get('class') in ('excel', 'excel-direct'):
            m_query = _build_excel_m_query(table_name, conn_info.get('sheet_tab', '') or dim_table_name,
                                            param_name, _mq_cols)
        else:
            m_query = _build_generic_m_query(table_name, param_name, _mq_cols)
        param_table = {
            "name": param_name,
            "lineageTag": _guid(),
            "columns": [{
                "name": param_name, "lineageTag": _guid(), "dataType": "string",
                "sourceColumn": param_name, "summarizeBy": "none",
                "annotations": [{"name": "SummarizationSetBy", "value": "User"}]
            }],
            "partitions": [{
                "name": param_name, "mode": "import",
                "source": {"type": "m", "expression": _build_filepath_expression(
                    filename, conn_info.get('sheet_tab', ''), '')}
            }],
            "annotations": [
                {"name": "PBI_ResultType", "value": '"Text"'},
                {"name": "PBI_NavigationStepName", "value": "Navigation"}
            ]
        }

    data_table = {
        "name": table_name,
        "lineageTag": _guid(),
        "columns": pbi_columns,
        "partitions": [{
            "name": table_name,
            "mode": "import",
            "source": {"type": "m", "expression": m_query.splitlines()}
        }],
        "annotations": [
            {"name": "PBI_ResultType", "value": "Table"},
            {"name": "PBIDesktopVersion", "value": "2.128.952.0 (24.04)"}
        ],
    }
    return data_table, param_table, col_name_map, table_name


def build_data_model_schema(workbook: dict, filename: str = "", embed_sample_data: bool = False, extracted_data: dict = None) -> dict:
    wb_name = workbook['name']
    tables = []
    seen_table_names: set = set()
    seen_model_measure_names: set = set()
    seen_dedup_keys: set = set()

    # ── Tableau parameters → real Power BI What-if parameters ─────────────────
    # Built first (before any datasource table) so the resulting table/measure
    # names are reserved in seen_table_names/seen_model_measure_names, and so
    # param_ref_map is available to every calc's DAX generation below — a
    # calc referencing [Parameters].[Field] needs to resolve to the right
    # thing (a real measure for an enumerable range/list parameter, or an
    # inlined literal for an 'any'-domain one) no matter which datasource it
    # belongs to.
    # param_ref_map: Tableau parameter caption → DAX expression to substitute
    # in place of a bare [Field] reference — either '[Measure Name]' for a
    # parameter that got a real What-if table, or a literal DAX value
    # (DATE(...), "string", 123) for one that didn't.
    param_ref_map: dict = {}
    _param_tables: dict = {}  # caption → {'table':, 'column':} — for parameter-control slicers
    _param_notes: list = []   # (caption, status, detail) for the audit report
    for _pdef in workbook.get('tableau_parameters', []):
        _cap = _pdef.get('caption') or _pdef.get('name') or ''
        if not _cap:
            continue
        _built = _build_whatif_parameter_table(_pdef, seen_table_names, seen_model_measure_names)
        if _built:
            _ptable, _ptable_name, _pcol_name, _pmeasure_name, _pmeasure_dax = _built
            _ptable['measures'] = [{
                "name": _pmeasure_name,
                "lineageTag": _guid(),
                "expression": _pmeasure_dax,
                "annotations": [{"name": "PBI_FormatHint", "value": '{"isGeneralNumber":true}'}],
            }]
            tables.append(_ptable)
            param_ref_map[_cap] = f'[{_pmeasure_name}]'
            _param_tables[_cap] = {'table': _ptable_name, 'column': _pcol_name}
            _param_notes.append((_cap, 'whatif_parameter',
                                  f"Table '{_ptable_name}' + measure '[{_pmeasure_name}]'"))
        else:
            _lit = _param_literal(_pdef.get('value'), _pdef.get('datatype', 'string'))
            if _lit is not None:
                param_ref_map[_cap] = _lit
                _param_notes.append((_cap, 'inlined_literal',
                                      f"domain='{_pdef.get('domain_type')}' — no enumerable set, "
                                      f"inlined current value {_lit} wherever referenced"))
            else:
                _param_notes.append((_cap, 'unresolved',
                                      "no usable current value or domain — any reference to this "
                                      "parameter in a calculation will be left as a dangling field "
                                      "reference; set it manually in Power BI"))

    # ── Audit framework ───────────────────────────────────────────────────────
    # MigrationAudit collects one record per calculation after DAX generation.
    # It is a read-only observer — does NOT affect any generation logic.
    _audit = MigrationAudit(wb_name)
    _audit.set_parameter_notes(_param_notes)
    # Record Tableau parameters now (they come from the semantic model)
    for _pn_init, _pnd_init in workbook.get('semantic', {}).get('calculations', {}).items():
        if _pnd_init.get('is_param'):
            _audit.record_parameter(
                _pn_init, _pnd_init.get('_param_value', ''), ds_name='Parameters'
            )


    # ── Priority 3: Consume global calc generation order from semantic model ──
    # The semantic model was built in parse_tableau_workbook and contains the
    # topological sort order for ALL calcs across ALL datasources.  Use it here
    # so cross-datasource measure dependencies are resolved before any table loop
    # generates DAX — matching the Enterprise Guide §4.4 algorithm exactly.
    _semantic         = workbook.get('semantic', {})
    _global_all_calcs = _semantic.get('calculations', {})    # name → {formula, …}
    _global_gen_order = _semantic.get('calc_gen_order', [])  # topological order
    # CalcRegistry: full dependency graph, reuse cache, cycle information.
    # Falls back gracefully to None when converting older workbook dicts that
    # pre-date the registry (e.g. in unit tests).
    _global_registry: 'CalcRegistry | None' = _semantic.get('calc_registry')
    _global_cycles                           = _semantic.get('cycle_sets', [])
    # Names in any detected cycle — skip DAX generation for these to avoid
    # recursive measure errors in the Power BI semantic model.
    _cyclic_names: set = set()
    for _cs in _global_cycles:
        _cyclic_names.update(_cs)

    if _global_gen_order:
        _cycle_info = (f", {len(_global_cycles)} cycle(s) isolated"
                       if _global_cycles else '')
        log('info',
            f"[CalcRegistry] Using pre-built global calc order "            f"({len(_global_gen_order)} calcs{_cycle_info}). "            f"First: {', '.join(_global_gen_order[:5])}")

    for ds_idx, ds in enumerate(workbook['datasources']):
        # Skip exact duplicate datasources (same ds_name + file + columns).
        # The parse step already removed true duplicates; this catches any that
        # slip through (e.g. the same raw_name registered twice).
        dedup_key = ds.get('_dedup_key')
        if dedup_key is not None:
            frozen = (dedup_key[0], dedup_key[1], dedup_key[2])
            if frozen in seen_dedup_keys:
                continue
            seen_dedup_keys.add(frozen)
        # NOTE: We intentionally do NOT apply a secondary "same file + same columns"
        # check here.  Tableau workbooks legitimately contain multiple datasources
        # backed by different sheets of the same Excel file, producing the same
        # column names (e.g. 'Revenue' and 'Gross Profit' both from the same .xlsx).
        # A file+column fingerprint check would incorrectly drop one of them.

        raw_name = ds['name'] or ds['raw_name'] or f"Table{ds_idx}"

        # Skip datasources that carry no usable source columns at all.
        # These are typically Tableau metadata-only or parameter datasources
        # that produce empty ghost tables.
        visible_cols = [c for c in ds.get('columns', []) if not c.get('hidden')]
        if not visible_cols and not ds.get('calculations'):
            continue

        table_name = _unique_name(_safe_pbi_name(raw_name), seen_table_names)
        conn = ds['connection']
        conn_class = conn.get('class', '').lower()

        # ── Check whether this is a live database connection ───────────────
        # Live connections (Databricks, Snowflake, SQL Server, etc.) do NOT
        # need a FilePath parameter table — they carry all connection info
        # directly in the M query.  File-backed connections (Excel, CSV)
        # still need the parameter so the user can set the file path.
        live_builder, _needs_param = _LIVE_DB_BUILDERS.get(conn_class, (None, True))
        is_live_connection = live_builder is not None

        # ── Parameter table for file path (file-backed connections only) ───
        # param_name also goes into seen_table_names because TOM checks
        # uniqueness across the entire tables collection.
        param_name = _unique_name(_safe_pbi_name(raw_name + "FilePath"), seen_table_names)
        if not embed_sample_data and not is_live_connection:
            param_table = {
                "name": param_name,
                "lineageTag": _guid(),
                "columns": [{
                    "name": param_name,
                    "lineageTag": _guid(),
                    "dataType": "string",
                    "sourceColumn": param_name,
                    "summarizeBy": "none",
                    "annotations": [{"name": "SummarizationSetBy", "value": "User"}]
                }],
                "partitions": [{
                    "name": param_name,
                    "mode": "import",
                    "source": {
                        "type": "m",
                        "expression": _build_filepath_expression(
                            conn.get('filename', ''),
                            ds.get('original_sheet', '') or ds.get('name', ''),
                            conn.get('directory', '')   # folder from textscan/excel-direct connection
                        )
                    }
                }],
                "annotations": [
                    {"name": "PBI_ResultType", "value": '"Text"'},
                    {"name": "PBI_NavigationStepName", "value": "Navigation"}
                ]
            }
            tables.append(param_table)

        # ── Build columns for data table ───────────────────────────────────
        # FIX: Temporal fields (Year, Quarter, Month, Day, etc.) should ALWAYS be
        # dimensions, never measures — even if marked as numeric/measure in Tableau.
        # These are date-part grouping fields, not KPIs to be summed.
        dimension_cols = []
        measure_cols   = []
        _temporal_keywords = {'year', 'quarter', 'month', 'week', 'day', 'date', 'time', 'hour', 'minute'}
        # Increment 22: Tableau hides the raw join-key columns by convention
        # once a datasource uses its Relationships (logical layer) data model
        # — confirmed real on all 4 FK columns in Amazon Sales Insights
        # (hidden="true" in the XML). A relationship's fromColumn must
        # reference a real column, so keep exactly the FK columns real
        # relationships use (never a broad change to hidden-column handling)
        # — marked hidden in the TOM model too, respecting Tableau's intent
        # that they're join plumbing, not user-facing fields.
        _relationship_fk_names = ({r['fromColumn'] for r in ds['_dim_split']['relationships']}
                                   if ds.get('_dim_split') else set())
        if ds.get('_dim_split'):
            # Some FK columns have no <column> element anywhere in the
            # datasource at all (not even hidden) — confirmed real on Sales
            # Param's 'Region'/'Order ID' on the People/Returns side (see the
            # parse-time _col_table comment). Synthesize from the schema-
            # verified <metadata-records> entry so the relationship still has
            # a real backing column instead of being silently dropped.
            _existing_fk_keys = {(c.get('source_name') or c['name']) for c in ds['columns']}
            _col_table_meta = ds['_dim_split']['col_table']
            for _fk_name in _relationship_fk_names:
                if _fk_name in _existing_fk_keys:
                    continue
                _meta = _col_table_meta.get(_fk_name)
                if not isinstance(_meta, dict):
                    continue
                _dtype = {
                    'integer': 'int64', 'real': 'double', 'string': 'string',
                    'date': 'date', 'datetime': 'dateTime', 'boolean': 'boolean',
                }.get(_meta.get('local_type', 'string'), 'string')
                ds['columns'].append({
                    'name': _fk_name, 'source_name': _meta.get('remote_name') or _fk_name,
                    'datatype': _dtype, 'role': 'dimension', 'measure': False,
                    'hidden': True, 'tableau_format': '',
                })
                _existing_fk_keys.add(_fk_name)

        # A datasource with a real _dim_split has genuine per-table column
        # ownership known via col_table (metadata-records-derived). Pass 2's
        # column collection (parse_tableau_workbook) recursively scans every
        # <relation><columns> block regardless of which table it belongs to,
        # so a dimension-only field (e.g. 'Regional Manager', which lives
        # only on the People sub-table) can leak into ds['columns'] even
        # though the flat/fact table's own M query only ever reads the fact
        # table's physical sheet. Declaring it as a TOM column when the M
        # query can never produce it is exactly Power BI's "The column '...'
        # of the table wasn't found" error — confirmed real on
        # sales_dashboard_new.twb. Columns whose col_table-declared owner is
        # a DIFFERENT real table than this datasource's fact table are
        # dropped from the flat table here; they still reach the model via
        # their own dedicated dimension table (built further down from this
        # same ds['columns'] list, unaffected since this filter is local to
        # this loop only).
        _dim_split_ct = ds['_dim_split']['col_table'] if ds.get('_dim_split') else {}
        _dim_split_fact = ds['_dim_split']['fact_table'] if ds.get('_dim_split') else None

        for c in ds['columns']:
            if _dim_split_fact:
                _owner = _dim_split_ct.get(c.get('source_name') or c['name'])
                if (isinstance(_owner, dict) and _owner.get('table')
                        and _owner['table'] != _dim_split_fact
                        and (c.get('source_name') or c['name']) not in _relationship_fk_names
                        and not c.get('_worksheet_used')):
                    continue
            if c.get('hidden'):
                _fk_key = c.get('source_name') or c['name']
                if _fk_key not in _relationship_fk_names:
                    continue
                c = dict(c)
                c['_force_hidden_tom'] = True
            _col_name_lower = c.get('name', '').lower().replace(' ', '').replace('_', '')
            _is_temporal = any(k in _col_name_lower for k in _temporal_keywords)
            if _is_temporal:
                # Force temporal fields to dimension bucket
                dimension_cols.append(c)
            elif c.get('measure'):
                measure_cols.append(c)
            else:
                dimension_cols.append(c)

        # Within a single PBI table, columns AND measures share one name namespace.
        # Track every name used so we can deduplicate before adding anything.
        seen_field_names: set = set()

        # Pending geographic "(map)" calculated columns — collected during the
        # dimension-column loop and merged into pbi_calc_columns after that list
        # is declared (it is initialised in the pending_measures pass below).
        _pending_geo_map_cols: list = []
        # Initialise the map-column mapping dict on the datasource dict now so the
        # dim-col loop can populate it without an existence check each iteration.
        ds['_map_col_map'] = {}

        # col_name_map: original Tableau caption -> final PBI column name.
        # Used to fix up DAX expressions after _unique_name() may rename a column
        # (e.g. 'Emp No' -> 'Emp No_2' due to case-insensitive collision).
        col_name_map: dict = {}
        # col_type_map: final PBI column name -> PBI datatype string.
        # Used by _fix_dax_aggregations to determine SUM vs SELECTEDVALUE wrapping.
        col_type_map: dict = {}

        pbi_columns = []
        for col in dimension_cols:
            col_name = _unique_name(col['name'], seen_field_names, case_insensitive=True)
            # Map caption → pbi_col_name (used when formula text references the display alias)
            col_name_map[col['name']] = col_name
            # Also map source_name → pbi_col_name.
            # Tableau formula text always references columns by their internal source
            # name (e.g. [date_added]), not the display caption ("Date Added").
            # Without this entry _fix_dax_col_refs cannot resolve source-name refs
            # and they pass through unchanged, causing DAX errors like:
            #   Column 'date_added' in table 'T' cannot be found
            src_nm = col.get('source_name') or ''
            if src_nm and src_nm != col['name']:
                col_name_map.setdefault(src_nm, col_name)
            col_type_map[col_name]    = col['datatype']
            # PBI TOM column dataType vocabulary:
            #   'string', 'int64', 'double', 'dateTime', 'boolean', 'binary'
            # Tableau 'date' has no direct PBI equivalent — all date-only
            # columns must be stored as 'dateTime' in the TOM column definition.
            # The M query type table uses 'date' (via _pbi_m_type) and
            # data rows use #date() literals, which M correctly loads as
            # date values before the column-type coercion to dateTime.
            _pbi_tom_dtype = 'dateTime' if col['datatype'] in ('date','datetime','timestamp') else col['datatype']
            _tom_col_entry = {
                "name": col_name,
                "lineageTag": _guid(),
                "dataType": _pbi_tom_dtype,
                "sourceColumn": col['name'],
                "summarizeBy": "none",
                "annotations": [{"name": "SummarizationSetBy", "value": "Automatic"}]
            }
            # Date/time columns need UniqueMembersPerParent=false annotation
            # so PBI treats them as a continuous date axis (enabling year/quarter/month
            # drill-down and preventing mathematical operations on the date itself).
            # Prefer the column's own real Tableau default-format (e.g. a date
            # column's '*mmmm yyyy', or — just as real a fix — a zip/postal
            # code column's '*00000', without which PBI would drop the
            # leading zero and show '2134' instead of '02134') over the
            # generic "General Date"/no-formatString default.
            _dim_real_fmt = _tableau_default_format_to_pbi(col.get('tableau_format', ''))
            if _dim_real_fmt:
                _tom_col_entry["formatString"] = _dim_real_fmt
            elif _pbi_tom_dtype == 'dateTime':
                _tom_col_entry["formatString"] = "General Date"
            if _pbi_tom_dtype == 'dateTime':
                _tom_col_entry["annotations"] = [
                    {"name": "SummarizationSetBy", "value": "Automatic"},
                    {"name": "UniqueMembersPerParent", "value": "false"},
                ]
            # Emit dataCategory for geographic columns (parsed from Tableau
            # semantic-role attribute, e.g. "[Country].[ISO3166_2]" → "Country").
            # PBI's filledMap and map visuals require this to geocode the column;
            # without it, the map renderer reads 'kind' from undefined → JS TypeError.
            if col.get('geo_category'):
                _tom_col_entry["dataCategory"] = col['geo_category']
            if col.get('_force_hidden_tom'):
                _tom_col_entry["isHidden"] = True
            pbi_columns.append(_tom_col_entry)

            # ── Auto-generate a sanitised "{col} (map)" calculated column ──────
            # Problem: geographic source columns (e.g. Netflix 'Country') can contain:
            #   • Multi-value comma strings: "Argentina, Brazil, France"
            #   • Blank / empty strings: ""
            # Tableau's geo-engine silently drops both — it only draws polygons for
            # distinct values that match its internal geo-database.
            # PBI's filledMap/map sends EVERY distinct Location value to Bing Maps.
            # Blank and multi-value strings produce malformed geocode responses,
            # causing the JS error "Cannot read properties of undefined (reading 'kind')".
            #
            # Fix (Option B): create a calculated column that returns BLANK() for any
            # value that is empty or contains a comma, and the original value otherwise.
            # The map visual uses this cleaned column as its Location — it silently
            # skips BLANK() marks, exactly replicating Tableau's behaviour.
            # All other visuals continue to reference the original source column.
            #
            # NOTE: pbi_calc_columns is declared later in this function (after the
            # pending_measures/pending_calc_cols pass).  We collect these entries in
            # _pending_geo_map_cols and merge them into pbi_calc_columns after it exists.
            if col.get('geo_category'):
                _map_col_name = _unique_name(
                    f"{col_name} (map)", seen_field_names, case_insensitive=True
                )
                # DAX expression:
                #   BLANK()  when the value is empty OR contains a comma (multi-country)
                #   original value otherwise
                _map_dax = (
                    f"IF("
                    f"'{table_name}'[{col_name}] = \"\" "
                    f"|| CONTAINSSTRING('{table_name}'[{col_name}], \",\"), "
                    f"BLANK(), "
                    f"'{table_name}'[{col_name}]"
                    f")"
                )
                _pending_geo_map_cols.append({
                    "type":        "calculated",
                    "name":        _map_col_name,
                    "dataType":    "string",
                    "isDataTypeInferred": False,
                    "expression":  [_map_dax],
                    "dataCategory": col['geo_category'],   # geocoding still applies
                    "lineageTag":  _guid(),
                    "summarizeBy": "none",
                    "annotations": [
                        {"name": "SummarizationSetBy", "value": "Automatic"}
                    ]
                })
                seen_field_names.add(_map_col_name.lower())
                # Store mapping so the layout builder can redirect map visuals
                # from the raw column to the cleaned calculated column.
                ds['_map_col_map'][col_name] = _map_col_name

        # Numeric source columns (Tableau role="measure") must also be PBI columns
        # so they appear in the data model and data preview.
        # summarizeBy="sum" means PBI auto-aggregates them in visuals (Sum, Avg, Min…
        # all become available in the field well — not just the default Sum).
        # Issue 4 fix: PBI only shows Sum/Avg/etc. on fields with summarizeBy!="none".
        for col in measure_cols:
            col_name = _unique_name(col['name'], seen_field_names, case_insensitive=True)
            col_name_map[col['name']] = col_name
            src_nm = col.get('source_name') or ''
            if src_nm and src_nm != col['name']:
                col_name_map.setdefault(src_nm, col_name)
            col_type_map[col_name] = col['datatype']
            _pbi_tom_dtype2 = 'dateTime' if col['datatype'] == 'date' else col['datatype']
            # Format string: prefer Tableau's own real per-column default-format
            # (currency symbol, decimals, thousands/millions scaling, percentage
            # — see _tableau_default_format_to_pbi) over guessing from the
            # column's name. The name-keyword guess is now only a fallback for
            # columns with no captured default-format at all.
            _real_fmt = _tableau_default_format_to_pbi(col.get('tableau_format', ''))
            if _real_fmt:
                _fmt_str = _real_fmt
            else:
                _fmt_col = col['name'].lower()
                _fmt_str = ("\\$#,0.00;(\\$#,0.00)" if any(k in _fmt_col for k in
                            ('price','cost','revenue','sales','profit','amount','amt','value','salary','wage'))
                            else "#,##0")
            _meas_col_entry = {
                "name": col_name,
                "lineageTag": _guid(),
                "dataType": _pbi_tom_dtype2,
                "sourceColumn": col['name'],
                "summarizeBy": "sum",
                "formatString": _fmt_str,
                "annotations": [
                    {"name": "SummarizationSetBy", "value": "Automatic"},
                    {"name": "PBI_FormatHint", "value": '{"isGeneralNumber":true}'},
                ]
            }
            if col.get('_force_hidden_tom'):
                _meas_col_entry["isHidden"] = True
            pbi_columns.append(_meas_col_entry)

        # _fix_dax_col_refs has been promoted to module level so
        # _translate_with_trace can call it without a NameError.
        # Existing call sites inside this function continue to work via the
        # module-level name (no local alias needed; Python resolves it in
        # the enclosing module scope at call time).

        # ── Build measures ─────────────────────────────────────────────────
        # First pass: determine all measure names (needed to avoid wrapping
        # measure refs in SUM() during _fix_dax_aggregations).
        import re as _re_util
        # Utility/shelf-positioning calcs from Tableau (e.g. AVG(0), SUM(0),
        # MIN(1)) have no meaning in PBI and translate to invalid DAX such as
        # AVERAGE(0).  Filter them out before building any measures.
        _utility_calc_re = _re_util.compile(
            r'^(?:MIN|MAX|SUM|AVG|AGG|COUNT)\s*\([01](?:\.\d+)?\)$',
            _re_util.I
        )
        pending_measures  = []   # aggregating calcs → PBI Measures
        pending_calc_cols = []   # row-level calcs   → PBI Calculated Columns
        for calc in ds['calculations']:
            # Resolve the field name for this calc.
            # Prefer the stripped name (no leading/trailing whitespace).
            # If the stripped name collides with an existing column/measure,
            # try the ORIGINAL unstripped name — PBI treats 'Actual ' and
            # 'Actual' as distinct names even within the same table.
            raw_calc_name   = calc['name']           # e.g. 'Actual '
            clean_calc_name = raw_calc_name.strip()  # e.g. 'Actual'
            # Skip Tableau shelf-position utility calcs — they have no data role.
            if _utility_calc_re.match(clean_calc_name):
                continue
            if clean_calc_name.lower() in seen_field_names:
                # Stripped name taken — try original (unstripped) as fallback
                if (raw_calc_name != clean_calc_name
                        and raw_calc_name.lower() not in seen_field_names):
                    effective_name = raw_calc_name  # 'Actual ' is safe
                else:
                    continue   # genuinely duplicate, skip
            else:
                effective_name = clean_calc_name
            field_name = _unique_name(effective_name, seen_field_names,
                                      case_insensitive=True)
            # Route: aggregating formula (is_agg_calc=True) → Measure
            #        row-level formula (is_agg_calc=False)  → Calculated Column
            if calc.get('is_agg_calc', True):
                pending_measures.append((field_name, calc))
            else:
                pending_calc_cols.append((field_name, calc))

        # ── Issue 3: Topological sort — resolve calc dependencies ──────────────
        # Build dependency graph: calc_name → set of calc names it references.
        # Sort pending_measures so upstream calcs are emitted before downstream ones.
        import re as _dep_re
        def _extract_calc_refs(formula, known_names):
            """Return set of known calc names referenced in a formula."""
            refs = set()
            for _ref in _dep_re.findall(r'\[([^\]]+)\]', formula or ''):
                if _ref in known_names:
                    refs.add(_ref)
            return refs

        _all_pm_names = {pm[0] for pm in pending_measures}
        # Build adjacency: name → deps (other measures it depends on)
        _pm_deps = {}
        for _pmn, _pmc in pending_measures:
            _raw_f = _pmc.get('formula','')
            # Resolve captions in formula first
            for _int, _cap in ds.get('calc_caption_map',{}).items():
                _raw_f = _raw_f.replace(f'[{_int}]', f'[{_cap}]')
            _pm_deps[_pmn] = _extract_calc_refs(_raw_f, _all_pm_names) - {_pmn}

        # Kahn's algorithm topological sort
        def _topo_sort(items, deps):
            from collections import deque
            in_degree = {n: 0 for n in items}
            for n in items:
                for dep in deps.get(n, set()):
                    if dep in in_degree:
                        in_degree[n] += 1
            queue = deque(n for n in items if in_degree[n] == 0)
            order = []
            while queue:
                node = queue.popleft()
                order.append(node)
                for other in items:
                    if node in deps.get(other, set()):
                        in_degree[other] -= 1
                        if in_degree[other] == 0:
                            queue.append(other)
            # Append any remaining (cyclic) nodes at the end
            for n in items:
                if n not in order:
                    order.append(n)
            return order

        _pm_name_list = [pm[0] for pm in pending_measures]
        _pm_order     = _topo_sort(_pm_name_list, _pm_deps)
        _pm_dict      = {pm[0]: pm[1] for pm in pending_measures}
        pending_measures = [(_n, _pm_dict[_n]) for _n in _pm_order if _n in _pm_dict]

        # ── Registry-driven final sort + cycle/duplicate guard ─────────────────
        # If the CalcRegistry has been built, use its authoritative topological
        # order (which spans ALL datasources, not just the current one) to give
        # cross-datasource dependencies the correct generation sequence.
        # Also drop any calc whose name falls inside a detected cycle — generating
        # recursive DAX measures would corrupt the Power BI semantic model.
        if _global_registry is not None:
            # Sort by the registry's global generation order index
            _reg_order_idx = {n: i
                              for i, n in enumerate(_global_registry.generation_order())}
            _fallback_idx  = len(_reg_order_idx)
            pending_measures.sort(
                key=lambda x: _reg_order_idx.get(x[0], _fallback_idx)
            )
            # Remove cyclic calcs — they cannot be safely expressed as DAX measures
            # ── Audit: record cyclic calculations as FAILED ───────────────────
            if _cyclic_names:
                for _cyc_nm, _cyc_calc in pending_measures:
                    if _cyc_nm in _cyclic_names:
                        _audit.record_skipped(
                            _cyc_nm,
                            'Cyclic dependency — would cause recursive DAX measure',
                            formula=_cyc_calc.get('formula', ''),
                            ds_name=ds.get('name', ''),
                        )
            if _cyclic_names:
                pending_measures = [
                    (nm, calc) for nm, calc in pending_measures
                    if nm not in _cyclic_names
                ]
        elif _global_gen_order:
            # Fallback: older path without registry object
            _go_idx = {n: i for i, n in enumerate(_global_gen_order)}
            pending_measures.sort(
                key=lambda x: _go_idx.get(x[0], len(_global_gen_order))
            )

        # The set of names that will be DAX Measures in this table.
        # Used by _fix_dax_aggregations to strip table qualifiers off measure refs.
        all_measure_names = {pm[0] for pm in pending_measures}

        # Second pass: translate each formula now that we know all measure names.
        import re as _fre
        pbi_measures = []
        pbi_calc_columns = []   # Tableau bin calcs → PBI calculated columns
        # Merge the geographic "(map)" cleaned calculated columns that were collected
        # during the dimension-column loop above.  They go first so they appear
        # adjacent to their source columns in the TOM column list.
        pbi_calc_columns.extend(_pending_geo_map_cols)

        # ── FIX: Month Number as real M-query columns (not DAX calc-cols) ────
        # For every string dimension column whose name contains "month" we:
        #   1. Add a hidden integer "Month Number" column backed by a
        #      Table.AddColumn step in the M query (NOT a DAX calculated column).
        #      This means the column holds data the moment the PBIT opens —
        #      no manual refresh or recalculation is ever required.
        #   2. Set sortByColumn on the string month column so PBI sorts
        #      Jan→Feb→...→Dec instead of alphabetical Apr→Aug→Dec.
        _month_num_pairs: list = []   # [(str_col_name, int_col_name)]
        _month_num_lookup: dict = {}  # str_col_name → int_col_name

        def _is_month_str_col(name: str, dtype: str) -> bool:
            if dtype not in ('string',):
                return False
            nl = name.lower().replace(' ', '').replace('_', '')
            return 'month' in nl or nl == 'mon'

        for _pc_entry in pbi_columns:
            _pc_nm  = _pc_entry.get('name', '')
            _pc_dt  = _pc_entry.get('dataType', '')
            if _is_month_str_col(_pc_nm, _pc_dt):
                _int_col = _unique_name(
                    f"{_pc_nm} Number", seen_field_names, case_insensitive=True
                )
                seen_field_names.add(_int_col.lower())
                _month_num_pairs.append((_pc_nm, _int_col))
                _month_num_lookup[_pc_nm] = _int_col
                # Wire sortByColumn onto the string column entry
                _pc_entry['sortByColumn'] = _int_col

        # Add the hidden Month Number columns as real sourceColumn entries
        # (they are backed by M Table.AddColumn — see _build_sample_m_query call below)
        for _str_c, _int_c in _month_num_pairs:
            pbi_columns.append({
                "name": _int_c,
                "lineageTag": _guid(),
                "dataType": "int64",
                "sourceColumn": _int_c,
                "isHidden": True,
                "summarizeBy": "none",
                "annotations": [
                    {"name": "SummarizationSetBy", "value": "User"},
                    {"name": "PBI_FormatHint",
                     "value": '{"isGeneralNumber":true}'},
                ]
            })
        for measure_name, calc in pending_measures:
            # Resolve internal calc names to captions BEFORE translation.
            raw_formula = calc['formula']
            for internal, display in ds.get('calc_caption_map', {}).items():
                raw_formula = _fre.sub(
                    r'\[' + _fre.escape(internal) + r'\]',
                    '[' + display + ']',
                    raw_formula
                )
            # Pre-scan: find any [FieldRef] not yet in col_name_map.
            # e.g. Margin = [Sale Amt] - [Cost Amt] where [Cost Amt] is a real
            # data column — it must be registered so _fix_dax_col_refs can
            # resolve it to 'Table'[Cost Amt] instead of leaving an unqualified ref.
            import re as _psre
            for _ref in _psre.findall(r'\[([^\]]+)\]', raw_formula):
                if _ref in col_name_map:
                    continue
                _rn = _ref.strip().lower().replace(' ','').replace('-','')
                _fc2 = next(
                    (c for c in measure_cols + dimension_cols
                     if c.get('name','').strip().lower().replace(' ','').replace('-','') == _rn),
                    None
                )
                if _fc2 and _fc2['name'] not in col_name_map:
                    col_name_map[_fc2['name']] = _fc2['name']
            # ── DAX reuse cache: if this calc was already translated (e.g. it
            # is shared across datasources), retrieve the cached DAX directly
            # rather than re-translating.  This prevents formula drift where two
            # datasources produce subtly different DAX for the same calc.
            # Use _translate_with_trace for loss-stage tracing.
            # It calls the same three pipeline stages but records which
            # stage produced a fallback for the audit record.
            if _global_registry is not None and _global_registry.has_dax(measure_name):
                _tr = _translate_with_trace(
                    original_formula = calc.get('formula', ''),
                    raw_formula      = raw_formula,
                    table_name       = table_name,
                    col_name_map     = col_name_map,
                    col_type_map     = col_type_map,
                    all_measure_names= all_measure_names,
                    cached_dax       = _global_registry.get_dax(measure_name),
                    from_cache       = True,
                    param_ref_map    = param_ref_map,
                )
            else:
                _tr = _translate_with_trace(
                    original_formula = calc.get('formula', ''),
                    raw_formula      = raw_formula,
                    table_name       = table_name,
                    col_name_map     = col_name_map,
                    col_type_map     = col_type_map,
                    all_measure_names= all_measure_names,
                    param_ref_map    = param_ref_map,
                )
                if _global_registry is not None:
                    _global_registry.set_dax(measure_name, _tr['dax'])
            dax = _tr['dax']
            _tr_loss_stage   = _tr['loss_stage']
            _tr_fail_reason  = _tr['failure_reason']
            pbi_measures.append({
                "name": measure_name,
                "lineageTag": _guid(),
                "expression": dax,
                "formatString": (_tableau_default_format_to_pbi(calc.get('tableau_format', ''))
                                  or "#,0")
            })
            # ── Audit record for this measure ─────────────────────────────────
            _a_sem  = (_global_registry.get(measure_name).get('sem_class', 'measure')
                       if _global_registry else 'measure')
            _a_deps = sorted(_global_registry.deps_of(measure_name)
                             if _global_registry else set())
            _a_ws   = [_ws['name'] for _ws in workbook.get('worksheets', [])
                       if measure_name in (
                           _ws.get('shelf_row_fields', []) +
                           _ws.get('all_row_measure_fields', []) +
                           [_ws.get('x_field',''), _ws.get('y_field','')]
                       )]
            _audit.record(
                calc_name               = measure_name,
                formula                 = calc.get('formula', ''),
                sem_class               = _a_sem,
                deps                    = _a_deps,
                dax                     = dax,
                ds_name                 = ds.get('name', ''),
                worksheets              = _a_ws,
                fallback_reason         = _tr_fail_reason,
                loss_stage              = _tr_loss_stage,
                failure_reason          = _tr_fail_reason,
                parsed_formula          = raw_formula,
                post_processing_warning = _tr.get('post_processing_warning', ''),
            )

        # ── Row-level calcs → PBI Calculated Columns ─────────────────────────
        # These formulas contain no aggregation functions and operate row-by-row.
        # In DAX a calculated column evaluates in row context, so:
        #   • 'Table'[Col] references are valid directly (no SUM/SELECTEDVALUE)
        #   • We call _tableau_formula_to_dax + _fix_dax_col_refs as usual
        #   • We do NOT call _fix_dax_aggregations (that would wrongly wrap
        #     bare column refs in SUM() or SELECTEDVALUE())
        #   • The TOM entry uses "type": "calculated" in the columns array
        for col_name, calc in pending_calc_cols:
            if calc.get('is_bin_calc'):
                # ── Numeric bin → PBI 'New Group' calculated column (handled above) ──
                # (inserted into pbi_calc_columns; see pending_calc_cols handler below)
                pass   # fallthrough to the full bin block below

            if calc.get('is_categorical_bin'):
                # ── Categorical bin → SWITCH() calculated column ──────────────
                # Tableau "New Group" on a string/combined-field dimension.
                # Maps named groups to SWITCH(TRUE(), conditions..., default).
                #
                # Source column may be:
                #   A) A plain dimension column → match single column value
                #   B) A combined field (crossjoin) → match component columns
                #      by looking up the combined field's _combined_levels
                import re as _re_catbin, json as _jcb

                src_col_raw  = calc.get('catbin_source', '')
                default_lbl  = calc.get('catbin_default', 'Other')
                bins_list    = calc.get('catbin_bins', [])

                # Look up whether the source is a combined field
                _combined    = next(
                    (c for c in pending_calc_cols + [(n, c) for n, c in [] if False]
                     if False),   # placeholder — see below
                    None
                )
                # Find combined-field calc by matching catbin_source to combined name
                _cf_levels   = None
                for _other_name, _other_calc in pending_calc_cols:
                    if (_other_calc.get('_is_combined_field')
                            and _re_catbin.sub(r'[^a-z0-9]', '',
                                               _other_name.lower())
                                == _re_catbin.sub(r'[^a-z0-9]', '',
                                                  src_col_raw.lower())):
                        _cf_levels = _other_calc.get('_combined_levels', [])
                        break
                # Also search in ds calculations list directly
                if _cf_levels is None:
                    for _dc in ds.get('calculations', []):
                        if (_dc.get('_is_combined_field')
                                and _re_catbin.sub(r'[^a-z0-9]', '',
                                                   _dc['name'].lower())
                                    == _re_catbin.sub(r'[^a-z0-9]', '',
                                                      src_col_raw.lower())):
                            _cf_levels = _dc.get('_combined_levels', [])
                            break

                def _catbin_member_to_dax(member_str, levels, tname):
                    """Convert one member tuple/value to a DAX boolean condition."""
                    member_str = member_str.strip()
                    if levels and member_str.startswith('(') and member_str.endswith(')'):
                        # Tuple member: ("val1", val2) → component-column conditions
                        inner = member_str[1:-1]
                        # Tokenise: respect quoted strings
                        tokens = _re_catbin.findall(r'"[^"]*"|-?\d+(?:\.\d+)?', inner)
                        if len(tokens) == len(levels):
                            conditions = []
                            for tok, lvl in zip(tokens, levels):
                                pbi_lvl = col_name_map.get(lvl, lvl)
                                tok_clean = tok.strip()
                                # Numeric token → no quotes
                                if _re_catbin.match(r'^-?\d', tok_clean):
                                    conditions.append(
                                        f"'{table_name}'[{pbi_lvl}] = {tok_clean}")
                                else:
                                    val = tok_clean.strip('"').replace('"', '""')
                                    conditions.append(
                                        f"'{table_name}'[{pbi_lvl}] = \"{val}\"")
                            return '(' + ' && '.join(conditions) + ')'
                    # Scalar: plain quoted string or number
                    m_clean = member_str.strip('"').replace('"', '""')
                    src_pbi = col_name_map.get(src_col_raw, src_col_raw)
                    return f"'{tname}'[{src_pbi}] = \"{m_clean}\""

                # Build SWITCH(TRUE(), ...) expression
                switch_arms = []
                for b in bins_list:
                    label    = b['label'].replace('"', '""')
                    members  = b['members']
                    if not members:
                        continue
                    cond_parts = [_catbin_member_to_dax(m, _cf_levels, table_name)
                                  for m in members]
                    combined_cond = ' || '.join(cond_parts)
                    switch_arms.append(f"    {combined_cond},\n    \"{label}\"")

                if switch_arms:
                    dax_catbin = (
                        "SWITCH(\n    TRUE(),\n"
                        + ',\n'.join(switch_arms)
                        + f',\n    "{default_lbl}"\n)'
                    )
                else:
                    dax_catbin = f'"{default_lbl}"'

                pbi_calc_columns.append({
                    "type":               "calculated",
                    "name":               col_name,
                    "dataType":           "string",
                    "isDataTypeInferred": False,
                    "expression":         [dax_catbin],
                    "lineageTag":         _guid(),
                    "summarizeBy":        "none",
                    "annotations":        [
                        {"name": "SummarizationSetBy", "value": "Automatic"}
                    ]
                })
                seen_field_names.add(col_name.lower())
                # ── Audit this categorical-bin calc (Increment 23) ─────────────
                # Root cause of a gap flagged since MIGRATION_TEST_SUITE.md was
                # first built (Increment 21): this branch built its PBI column
                # and `continue`d without ever calling _audit.record(), unlike
                # every other calc-column path — so Calculation Match % was
                # silently computed over an incomplete subset on any workbook
                # with real bin/group calcs (confirmed real: House Sales
                # Dashboard tracked 0 of 3 real calcs before this fix).
                _catbin_ws = [_ws['name'] for _ws in workbook.get('worksheets', [])
                              if col_name in set(
                                  _ws.get('shelf_row_fields', []) + _ws.get('shelf_col_fields', []) +
                                  _ws.get('all_row_measure_fields', []) +
                                  [_ws.get('x_field',''), _ws.get('y_field',''),
                                   _ws.get('color_field',''), _ws.get('detail_field','')]
                              )]
                _audit.record(
                    calc_name  = col_name,
                    formula    = f"[New Group] on [{calc.get('catbin_source_disp', src_col_raw)}]",
                    sem_class  = 'calc_col',
                    deps       = [calc.get('catbin_source_disp', src_col_raw)] if src_col_raw else [],
                    dax        = dax_catbin,
                    ds_name    = ds.get('name', ''),
                    worksheets = _catbin_ws,
                )
                continue

            if calc.get('is_bin_calc'):
                # ── Bin calculations → PBI 'New Group' calculated column ──────
                # Bins have is_agg_calc=False so they arrive here, not in the
                # pending_measures loop above.
                _bin_alias = table_name[0].lower()   # source alias used in queries
                src_raw_clean = calc.get('bin_source_raw', '').strip('[').strip(']')
                pbi_src = next(
                    (c['name'] for c in ds.get('columns', [])
                     if (c.get('source_name', '').lower() == src_raw_clean.lower()
                         or c['name'].lower() == src_raw_clean.lower())),
                    calc.get('bin_source', src_raw_clean)
                )

                bin_size = float(calc.get('bin_size') or 1.0)
                size_literal = str(int(bin_size)) if bin_size == int(bin_size) else str(bin_size)

                # PBI 'New Group' bin formula (verified from reference PBIT):
                #   ROUNDDOWN/ROUNDUP × bin_size replicates Tableau's floor-division
                #   behaviour while safely handling nulls and negative values.
                dax_expr = [
                    f"IF(",
                    f"\tISBLANK('{table_name}'[{pbi_src}]),",
                    f"\tBLANK(),",
                    f"\tIF(",
                    f"\t\t'{table_name}'[{pbi_src}] >= 0,",
                    f"\t\tROUNDDOWN('{table_name}'[{pbi_src}] / {size_literal}, 0) * {size_literal},",
                    f"\t\tROUNDUP('{table_name}'[{pbi_src}] / {size_literal}, 0) * {size_literal}",
                    f"\t)",
                    f")",
                ]

                grouping_metadata = {
                    "version": 0,
                    "groupedColumns": [{"Column": {
                        "Expression": {"SourceRef": {"Entity": table_name}},
                        "Property": pbi_src
                    }}],
                    "binningMetadata": {"binSize": {"value": bin_size, "unit": 0}}
                }
                grouping_design_state = json.dumps({
                    "Version": 0,
                    "Sources": [{"Name": _bin_alias, "Entity": table_name}],
                    "GroupedColumns": [{"Column": {
                        "Expression": {"SourceRef": {"Source": _bin_alias}},
                        "Property": pbi_src
                    }}],
                    "BinItem": {"Expression": {"Floor": {
                        "Expression": {"Column": {
                            "Expression": {"SourceRef": {"Source": _bin_alias}},
                            "Property": pbi_src
                        }},
                        "Size": bin_size
                    }}}
                }, separators=(',', ':'))

                import json as _json_bin
                pbi_calc_columns.append({
                    "type":               "calculated",
                    "name":               col_name,
                    "dataType":           "double",
                    "isDataTypeInferred": True,
                    "expression":         dax_expr,
                    "lineageTag":         _guid(),
                    "summarizeBy":        "none",
                    "extendedProperties": [{"type": "json", "name": "GroupingMetadata",
                                            "value": grouping_metadata}],
                    "annotations": [
                        {"name": "GroupingDesignState", "value": grouping_design_state},
                        {"name": "SummarizationSetBy",  "value": "Automatic"},
                        {"name": "PBI_FormatHint",      "value": "{\"isGeneralNumber\":true}"}
                    ]
                })
                seen_field_names.add(col_name.lower())

                # Add __PBI_SemanticLinks to source column so PBI Desktop shows
                # the 'grouped by' indicator in the Fields pane.
                _sem_link = _json_bin.dumps([{
                    "LinkTarget": {"TableName": table_name, "TableItemName": col_name,
                                   "ObjectType": 4},
                    "LinkType": "UsedInGroup"
                }], separators=(',', ':'))
                for _pc in pbi_columns:
                    if _pc.get('name', '') == pbi_src:
                        _anns = _pc.setdefault('annotations', [])
                        if not any(a.get('name') == '__PBI_SemanticLinks' for a in _anns):
                            _anns.append({"name": "__PBI_SemanticLinks", "value": _sem_link})
                        break
                # ── Audit this numeric-bin calc (Increment 23) ─────────────────
                # Same gap as the categorical-bin branch above — this path also
                # `continue`d without ever calling _audit.record().
                _bin_ws = [_ws['name'] for _ws in workbook.get('worksheets', [])
                           if col_name in set(
                               _ws.get('shelf_row_fields', []) + _ws.get('shelf_col_fields', []) +
                               _ws.get('all_row_measure_fields', []) +
                               [_ws.get('x_field',''), _ws.get('y_field',''),
                                _ws.get('color_field',''), _ws.get('detail_field','')]
                           )]
                _audit.record(
                    calc_name  = col_name,
                    formula    = calc.get('formula', '') or f"BIN([{pbi_src}], {size_literal})",
                    sem_class  = 'calc_col',
                    deps       = [pbi_src] if pbi_src else [],
                    dax        = '\n'.join(dax_expr),
                    ds_name    = ds.get('name', ''),
                    worksheets = _bin_ws,
                )
                continue
            raw_formula = calc['formula']
            for internal, display in ds.get('calc_caption_map', {}).items():
                raw_formula = _fre.sub(
                    r'\[' + _fre.escape(internal) + r'\]',
                    '[' + display + ']',
                    raw_formula
                )
            _tr_cc  = _translate_with_trace(
                original_formula = calc.get('formula', ''),
                raw_formula      = raw_formula,
                table_name       = table_name,
                col_name_map     = col_name_map,
                col_type_map     = {},
                all_measure_names= set(),
                param_ref_map    = param_ref_map,
            )
            dax_col           = _tr_cc['dax']
            _cc_loss_stage    = _tr_cc['loss_stage']
            _cc_fail_reason   = _tr_cc['failure_reason']

            # ── Skip alias columns that would cause cyclic references ──────────
            # Tableau auto-creates alias columns in two forms:
            #   [Revenue (copy)]            = [Revenue]          ← bare ref
            #   [Actual ]                   = 'Sheet35'[Actual]  ← table-qualified ref
            # Both just duplicate an existing data column. In PBI DAX, a calculated
            # column referencing another column in the SAME table creates a cyclic
            # evaluation error. Safe to skip — the original column already exists.
            import re as _re_alias
            _raw_stripped = raw_formula.strip()
            # Pattern 1: bare [ColumnName]
            _alias_bare = _re_alias.match(r"^\s*\[([^\]]+)\]\s*$", _raw_stripped)
            # Pattern 2: 'TableName'[ColumnName]  or "TableName"[ColumnName] —
            # the table-name portion MUST be quoted (real Tableau-generated
            # alias formulas always are). A previous version of this pattern
            # (`['"]?[^'"]+['"]?\[...\]$`) made the quotes optional, so
            # `[^'"]+` could greedily match ANY prefix ending in a bracket —
            # confirmed a real bug on LocBar's 'neg profit' (`-[Profit]`) and
            # 'Cost Amt' (`[Quantity]*[Profit]`): both are genuine formulas,
            # not aliases, but matched this pattern (capturing "Profit", an
            # existing base column) and were silently dropped from the model
            # entirely — not a cosmetic miss, a real missing-field bug, found
            # while investigating why they were also missing from the audit
            # (Increment 23). Requiring a matching quote pair anchors this to
            # ONLY the genuine `'Table'[Col]` alias shape.
            _alias_tbl  = _re_alias.match(
                r"""^\s*(['"])[^'"]+\1\[([^\]]+)\]\s*$""", _raw_stripped)
            _alias_ref  = None
            if _alias_bare:
                _alias_ref = _alias_bare.group(1).strip()
            elif _alias_tbl:
                _alias_ref = _alias_tbl.group(2).strip()
            if _alias_ref:
                _col_names_low = {c['name'].lower().strip()
                                  for c in ds.get('columns', [])}
                _src_names_low = {
                    (c.get('source_name') or c['name']).strip('[] ').lower()
                    for c in ds.get('columns', [])
                }
                if (_alias_ref.lower() in _col_names_low or
                        _alias_ref.lower() in _src_names_low):
                    seen_field_names.add(col_name.lower())
                    # Deliberately NOT recorded in the audit (tried
                    # `_audit.record_skipped()` here, reverted): that method
                    # hard-codes status='FAILED'/confidence=0, which would
                    # misrepresent a correct, intentional skip as a
                    # translation failure and drag down the workbook's
                    # overall confidence score — the opposite of what
                    # Increment 23's bin-calc audit fix was for. A duplicate
                    # alias isn't a distinct calculation Power BI needs to
                    # represent (the base column already covers it), so
                    # omitting it from total_calculations is correct, not a
                    # coverage gap — unlike bin calcs, which produce a real,
                    # distinct output column that WAS being silently dropped
                    # from the audit while still being generated correctly.
                    continue   # skip — original column already exists in table

            # ── Infer data type from formula ──────────────────────────────────
            # Build name→datatype map for all existing columns in this table
            import re as _re_cc
            _fc = raw_formula.strip()
            _col_dtype_map = {}
            for _c in ds.get('columns', []):
                _col_dtype_map[_c['name'].lower().strip()] = _c.get('datatype','string')
                _src = (_c.get('source_name') or _c['name']).strip('[] ').lower()
                _col_dtype_map[_src] = _c.get('datatype','string')
            _numeric_dtypes = {'int64','double','decimal','int32','currency',
                               'whole','fixed decimal'}

            if _re_cc.match(r'^-?\d+$', _fc):
                col_datatype = 'int64'
            elif _re_cc.match(r'^-?\d*\.\d+$', _fc):
                col_datatype = 'double'
            elif _re_cc.search(
                r'\b(?:DATEVALUE|DATE|DATEADD|DATESMTD|DATESQTD|DATESYTD|'
                r'EOMONTH|EDATE|TODAY|NOW|CALENDAR|CALENDARAUTO|DATETIME)\s*\(',
                _fc, _re_cc.I
            ):
                col_datatype = 'dateTime'
            elif _re_cc.search(
                r'\b(?:SUM|AVERAGE|DIVIDE|ABS|ROUND|ROUNDUP|ROUNDDOWN|'
                r'INT|SQRT|POWER|MOD|FLOOR|CEILING)\s*\(', _fc, _re_cc.I
            ):
                col_datatype = 'double'
            else:
                # Check all [ColumnName] references in formula to infer return type
                _refs = _re_cc.findall(r'\[([^\]]+)\]', _fc)
                _inferred_numeric = any(
                    _col_dtype_map.get(r.lower().strip(), 'string') in _numeric_dtypes
                    for r in _refs
                )
                # Also infer from arithmetic operators between column refs
                _has_arithmetic = bool(_re_cc.search(
                    r"'[^']+'\[[^\]]+\]\s*[-+*/]\s*'[^']+'\[[^\]]+\]", _fc))
                col_datatype = 'double' if (_inferred_numeric or _has_arithmetic) else 'string'

            _cc_real_fmt = _tableau_default_format_to_pbi(calc.get('tableau_format', ''))
            pbi_calc_columns.append({
                "type":        "calculated",
                "name":        col_name,
                "dataType":    col_datatype,
                "isDataTypeInferred": True,
                "expression":  dax_col.splitlines() if '\n' in dax_col else [dax_col],
                "lineageTag":  _guid(),
                "summarizeBy": "none" if col_datatype == 'string' else "sum",
                "annotations": [{"name": "SummarizationSetBy", "value": "Automatic"}],
                **({"formatString": _cc_real_fmt} if _cc_real_fmt else {}),
            })
            seen_field_names.add(col_name.lower())
            # ── Audit this calculated column ─────────────────────────────────
            _cc_sem  = (_global_registry.get(col_name).get('sem_class', 'calc_col')
                        if _global_registry and _global_registry.get(col_name)
                        else 'calc_col')
            _cc_deps = sorted(_global_registry.deps_of(col_name)
                              if _global_registry else set())
            _cc_ws   = []
            for _ws in workbook.get('worksheets', []):
                _all_ws_f = set(
                    _ws.get('shelf_row_fields', []) + _ws.get('shelf_col_fields', []) +
                    _ws.get('all_row_measure_fields', []) +
                    [_ws.get('x_field',''), _ws.get('y_field',''),
                     _ws.get('color_field',''), _ws.get('detail_field','')]
                )
                if col_name in _all_ws_f:
                    _cc_ws.append(_ws['name'])
            _audit.record(
                calc_name               = col_name,
                formula                 = calc.get('formula', ''),
                sem_class               = _cc_sem,
                deps                    = _cc_deps,
                dax                     = dax_col,
                ds_name                 = ds.get('name', ''),
                worksheets              = _cc_ws,
                fallback_reason         = _cc_fail_reason,
                loss_stage              = _cc_loss_stage,
                failure_reason          = _cc_fail_reason,
                parsed_formula          = raw_formula,
                post_processing_warning = _tr_cc.get('post_processing_warning', ''),
            )

        # ── Semantic dependency guard (registry-driven) ──────────────────
        # Uses CalcRegistry.validate_dependency() to enforce strict
        # separation between Measures and Calculated Columns:
        #
        # Rule 1 — Calculated Column → Measure reference is INVALID in DAX
        #          (row context cannot call a measure).  Promote to Measure.
        #
        # Rule 2 — Calc col → calc col cross-reference can cause cyclic
        #          evaluation in PBI.  Promote to Measure.
        #
        # Rule 3 — Names in _cyclic_names are excluded by registry upstream;
        #          this guard catches any that reach calc_columns anyway.
        import re as _cyc_re
        calc_col_names_set  = {e['name'].lower()
                               for e in pbi_calc_columns
                               if e.get('type') == 'calculated'}
        safe_calc_cols      = []
        promoted_to_measure = []

        for _cc_entry in pbi_calc_columns:
            if _cc_entry.get('type') != 'calculated':
                safe_calc_cols.append(_cc_entry)
                continue

            _cc_name = _cc_entry['name']
            _cc_expr = ' '.join(_cc_entry.get('expression', []))

            # Rule 3: cyclic node → promote to measure
            if _cc_name in _cyclic_names:
                promoted_to_measure.append({
                    "name":        _cc_name,
                    "lineageTag":  _guid(),
                    "expression":  _cc_expr,
                    "formatString": _cc_entry.get('formatString', '#,##0'),
                })
                continue

            # Rule 1 + 2: registry.validate_dependency check
            _unsafe = False
            if _global_registry is not None:
                for _dep_name in _global_registry.deps_of(_cc_name):
                    if not _global_registry.validate_dependency(_cc_name, _dep_name):
                        _unsafe = True
                        break

            # Fallback DAX-scan (no registry, or registry has no node for this name)
            if not _unsafe:
                _cc_refs = {m.lower() for m in _cyc_re.findall(
                    r"'" + _cyc_re.escape(table_name) + r"'\[([^\]]+)\]",
                    _cc_expr, _cyc_re.IGNORECASE
                )}
                _measure_lowers = {m.lower() for m in all_measure_names}
                if (_cc_refs & calc_col_names_set - {_cc_name.lower()}
                        or _cc_refs & _measure_lowers):
                    _unsafe = True

            if _unsafe:
                promoted_to_measure.append({
                    "name":        _cc_name,
                    "lineageTag":  _guid(),
                    "expression":  _cc_expr,
                    "formatString": _cc_entry.get('formatString', '#,##0'),
                })
            else:
                safe_calc_cols.append(_cc_entry)

        pbi_calc_columns = safe_calc_cols
        pbi_measures.extend(promoted_to_measure)

        # Auto-generate COUNT measures for columns used as chart categories.
        # Tableau's COUNT([Field]) → PBI: COUNTA('T'[Field])
        # FIX: Only generate COUNTA measures when the column is EXPLICITLY used
        # with a cnt: prefix on the shelf (meaning Tableau specifically computed
        # COUNT of that dimension). Do NOT auto-generate COUNT for every category
        # column — PBI can handle Count natively via the field well aggregation,
        # and generating these measures creates clutter (duplicate fields) in the
        # PBI field list that confuses users.
        # We restrict to: cnt:<colname> explicitly on a shelf token only.

        all_ws_fields = []
        ws_x_fields = set()
        for ws_info in workbook.get('worksheets', []):
            all_ws_fields.extend(ws_info.get('fields', []))
            all_ws_fields.append(ws_info.get('y_field', ''))
            all_ws_fields.append(ws_info.get('x_field', ''))

        import re as _re_cnt
        for col in ds.get('columns', []):
            if col.get('hidden'):
                continue
            if col.get('datatype') in ('date', 'dateTime'):
                continue
            count_name = f"Count of {col['name']}"
            col_norm     = col['name'].lower().replace(' ', '').replace('-', '')
            source_lower = (col.get('source_name') or col['name']).lower().lstrip('[').rstrip(']')

            # FIX: Only generate when EXPLICITLY referenced via cnt: shelf prefix
            # (not for every category column on an axis)
            needs_count = any(
                f"cnt:{source_lower}" in f.lower()
                for f in all_ws_fields
            )
            if needs_count and count_name.lower() not in seen_field_names:
                count_msr_name = _unique_name(count_name, seen_field_names, case_insensitive=True)
                pbi_measures.append({
                    "name": count_msr_name,
                    "lineageTag": _guid(),
                    "expression": f"COUNTA('{table_name}'[{col['name']}])",
                    "formatString": "#,##0"
                })

        # ── Auto-generate DISTINCTCOUNT measures for ctd: shelf tokens ────────
        # Tableau uses ctd:<ColName>:qk on chart shelves for COUNT DISTINCT of a
        # dimension column (COUNTD() in Tableau).  The column is role='dimension'
        # so it does not appear in measure_cols and gets no SUM measure.
        # We scan worksheets for any ctd_fields entry (set in parse_tableau_workbook
        # from column-instance derivation='CountD' attributes) and generate a
        # dedicated DISTINCTCOUNT DAX measure for each referenced column.
        # The measure name is stored in ds['_ctd_measure_map'] so build_report_layout
        # can resolve ctd: Y-axis and Color roles without knowing the DAX measure name.
        _ctd_measure_map: dict = {}   # col_caption → 'Count Distinct of col_caption'
        _all_ctd_fields: set = set()
        for _ws_inf2 in workbook.get('worksheets', []):
            _ws_ds2 = _ws_inf2.get('ds_names', [])
            if (raw_name          not in _ws_ds2
                    and ds.get('name','')     not in _ws_ds2
                    and ds.get('raw_name','') not in _ws_ds2):
                continue
            for _cf2 in _ws_inf2.get('ctd_fields', []):
                _all_ctd_fields.add(_cf2.strip().lower().replace(' ','').replace('-',''))

        for _col2 in dimension_cols + measure_cols:
            if _col2.get('hidden'): continue
            _cn2 = _col2['name'].strip().lower().replace(' ','').replace('-','')
            _sn2 = (_col2.get('source_name') or _col2['name']).strip().lower()\
                        .replace(' ','').replace('-','')
            if _cn2 not in _all_ctd_fields and _sn2 not in _all_ctd_fields:
                continue
            _dc_msr_name2 = f"Count Distinct of {_col2['name']}"
            if _dc_msr_name2.lower() in seen_field_names:
                _ctd_measure_map[_col2['name']] = _dc_msr_name2
                continue
            _dc_reg2 = _unique_name(_dc_msr_name2, seen_field_names, case_insensitive=True)
            _pbi_col_name2 = col_name_map.get(_col2['name'], _col2['name'])
            pbi_measures.append({
                "name": _dc_reg2,
                "lineageTag": _guid(),
                "expression": f"DISTINCTCOUNT('{table_name}'[{_pbi_col_name2}])",
                "formatString": "#,##0"
            })
            _ctd_measure_map[_col2['name']] = _dc_reg2

        ds['_ctd_measure_map'] = _ctd_measure_map

        # Fallback: promote numeric columns to implicit SUM measures only when
        # there are no explicit calculations AND the name is not already taken.
        if not pbi_measures:
            for col in measure_cols:
                if col['name'].lower() in seen_field_names:
                    continue
                measure_name = _unique_name(col['name'], seen_field_names, case_insensitive=True)
                col_name_map[col['name']] = measure_name
                pbi_measures.append({
                    "name": measure_name,
                    "lineageTag": _guid(),
                    "expression": f"SUM('{table_name}'[{measure_name}])",
                    "formatString": "#,0"
                })

        # ── Auto-generate SUM DAX measures for chart Y-axis numeric columns ───
        # Power BI chart visuals require a Measure reference (not a bare Column
        # reference) for Y-axis values. When a Tableau chart puts a plain numeric
        # column on the rows shelf (e.g. "Cash Flow"), we need a corresponding
        # SUM DAX measure so the chart can reference it as a Measure.
        #
        # A PBI table cannot have a column and a measure with the same name, so
        # we use the name "Sum of {col_name}" which is also what PBI Desktop
        # uses when auto-aggregating columns via the field well.
        #
        # The mapping col_name → sum_measure_name is stored on the datasource
        # dict (ds['_sum_measure_map']) so that build_report_layout can look it
        # up when building chart visual configs.
        sum_measure_map: dict = {}

        # Collect numeric columns referenced as Y-axis values in non-scatter charts.
        # Scatter charts now use Aggregation(Column, Sum) expressions which don't
        # require a pre-built DAX measure — so we skip scatter here.
        # Bar/column/line/pie/combo charts still need "Sum of X" DAX measures because
        # their visual queries require Measure references.
        chart_y_col_names: set = set()
        for ws_info in workbook.get('worksheets', []):
            ws_ds_names = ws_info.get('ds_names', [])
            if (raw_name          not in ws_ds_names
                    and ds.get('name', '')     not in ws_ds_names
                    and ds.get('raw_name', '') not in ws_ds_names):
                continue
            ct = ws_info.get('chart_type', '')
            if ct == 'scatterChart':
                # Scatter axes use "Sum of X" measures.  Add both x_field and
                # shelf_row_fields so the axis measures are generated.
                for field in ([ws_info.get('x_field', '')] +
                              ws_info.get('shelf_row_fields', [])):
                    norm = field.strip().lower().replace(' ','').replace('-','')
                    mc = next(
                        (c for c in measure_cols
                         if c['name'].strip().lower().replace(' ','').replace('-','') == norm),
                        None
                    )
                    if mc:
                        chart_y_col_names.add(mc['name'])
                continue
            if ct not in ('clusteredColumnChart', 'clusteredBarChart',
                          'columnChart',   'barChart',
                          'hundredPercentStackedColumnChart',
                          'hundredPercentStackedBarChart',
                          'pieChart', 'donutChart', 'lineChart', 'areaChart',
                          'lineClusteredColumnComboChart'):
                continue
            for srf in ws_info.get('shelf_row_fields', []):
                # Only create a SUM measure if this field maps to a numeric column
                # (not a calculation — those already become DAX measures above).
                norm_srf = srf.strip().lower().replace(' ', '').replace('-', '')
                mc = next(
                    (c for c in measure_cols
                     if c['name'].strip().lower().replace(' ', '').replace('-', '') == norm_srf),
                    None
                )
                if mc:
                    chart_y_col_names.add(mc['name'])

        for col_name in sorted(chart_y_col_names):
            sum_name = f"Sum of {col_name}"
            if sum_name.lower() in seen_field_names:
                # Already exists (perhaps two worksheets share the column) — record mapping
                existing = next((n for n in seen_field_names if n == sum_name.lower()), sum_name)
                sum_measure_map[col_name] = sum_name
                continue
            registered = _unique_name(sum_name, seen_field_names, case_insensitive=True)
            # The column name in PBI may have been renamed by _unique_name earlier
            pbi_col_name = col_name_map.get(col_name, col_name)
            pbi_measures.append({
                "name": registered,
                "lineageTag": _guid(),
                "expression": f"SUM('{table_name}'[{pbi_col_name}])",
                "formatString": "#,##0"
            })
            sum_measure_map[col_name] = registered

        # Persist mapping on the datasource dict — read by build_report_layout
        ds['_sum_measure_map'] = sum_measure_map
        # Persist the fact table's own final PBI table/column names — read
        # below (Increment 22) to wire real dimension-table relationships
        # using this table's already-deduped column names as the FK side.
        ds['_pbi_table_name'] = table_name
        ds['_col_name_map']   = col_name_map

        # ── Build M query ──────────────────────────────────────────────────
        # sheet_name must be the actual Excel sheet TAB name.
        # Priority:
        #   1. sheet_tab — parsed from <relation name="SheetName$"> (most reliable)
        #   2. conn['schema'] — sometimes set for older Tableau connections
        #   3. original_sheet / ds name — caption used as last resort
        # NEVER use table_name — that's the PBI-sanitized identifier.
        sheet_name = (conn.get('sheet_tab', '')
                      or conn.get('schema', '')
                      or ds.get('original_sheet', '')
                      or ds.get('name', '')
                      or conn.get('dbname', '')
                      or table_name)
        all_cols = dimension_cols + measure_cols

        if ds.get('_join_tree') and not embed_sample_data:
            # ── Physical join-tree datasource (classic <relation type='join'>) ──
            # Real Tableau-declared join reconstruction (Table.NestedJoin +
            # the exact JoinKind Tableau's `join=` attribute names) instead
            # of this loop's normal single-connection flatten — see
            # _parse_relation_join_tree / _build_joined_m_query for the full
            # schema citation and verification method. Takes priority over
            # is_live_connection/CSV/Excel below since `conn`/`conn_class`
            # here only reflect ONE arbitrary side of the join (the first
            # <relation type="table"> found), not the real multi-table
            # structure this datasource actually has.
            # Not used in embed_sample_data mode: Tableau's own extract
            # already performed the join when the .hyper file was built, so
            # the embedded rows are already correctly joined — reconstructing
            # the join again at the M-query level would be redundant.
            m_query, _joined_cols = _build_joined_m_query(ds['_join_tree'], set(), ds.get('_join_leaf_columns', {}))
            log('info', f"  ↳ '{table_name}': physical join-tree reconstructed "
                         f"({len(_joined_cols)} column(s) from the joined tables)")
        elif is_live_connection:
            # ── Live database connection (Databricks, Snowflake, etc.) ─────
            # Build a direct M query using the connector-specific builder.
            # No file path parameter is needed.
            m_query = live_builder(conn, all_cols)
            log('info',
                f"  ↳ '{table_name}': live {conn_class} connection  "
                f"server={conn.get('server','?')!r}  "
                f"db={conn.get('dbname','?')!r}  "
                f"schema={conn.get('schema','?')!r}  "
                f"table={conn.get('db_table','?')!r}"
                + (f"  http_path={conn['v-http-path']!r}"
                   if conn_class == 'databricks' and conn.get('v-http-path') else '')
            )
        elif embed_sample_data:
            # Embedded mode: generate a self-contained inline table using real
            # extracted rows (Tier 1/2) or synthetic fallback (Tier 3).
            # ds_caption is the Tableau datasource caption used as the lookup
            # key in extracted_data['datasources'].
            ds_caption_key = ds.get('name', '') or raw_name or ''
            m_query = _build_sample_m_query(
                table_name, all_cols,
                extracted_data=extracted_data,
                ds_caption=ds_caption_key,
                month_num_cols=_month_num_pairs,
                day_first=_locale_prefers_day_first(conn.get('locale', '')),
            )
        elif (conn.get('filename', '').lower().endswith('.csv')
              or conn.get('filename', '').lower().endswith('.tsv')
              or conn.get('filename', '').lower().endswith('.txt')
              or conn_class in ('csv', 'text-file', 'staticcsv')):
            # CSV / TSV / plain-text files — must use Csv.Document(), NOT Excel.Workbook().
            # Tableau uses conn_class='textscan' for local CSV files; if the filename
            # also ends in .csv/.tsv/.txt we catch it here BEFORE the textscan→Excel branch.
            _csv_delim = '\t' if conn.get('filename','').lower().endswith('.tsv') else ','
            m_query = _build_csv_m_query(table_name, param_name, all_cols,
                                         delimiter=_csv_delim)
        elif (conn_class in ('excel', 'textscan', 'excel-direct')
              or conn.get('filename', '').lower().endswith('.xlsx')
              or conn.get('filename', '').lower().endswith('.xls')
              or conn.get('filename', '').lower().endswith('.xlsm')):
            # Excel files (and any remaining textscan connections that are not .csv/.tsv)
            m_query = _build_excel_m_query(table_name, sheet_name, param_name, all_cols)
        else:
            # Generic last-resort fallback (Increment 27): this connection
            # class has no known M-query builder (see _LIVE_DB_BUILDERS) and
            # no cached extract data was available to embed instead. The
            # table/column schema is still fully preserved — every visual
            # keeps working structurally — but produces zero rows until the
            # user manually wires the real data source in Power BI Desktop.
            # Surfaced explicitly (log + audit report) rather than silently
            # shipping a blank table with no explanation, per this project's
            # standing "never let a gap look like success" discipline.
            m_query = _build_generic_m_query(table_name, param_name, all_cols)
            log('warn',
                f"[DataSource] '{table_name}' (connection class "
                f"{conn_class!r}) has no native query builder and no "
                f"extractable data — generated with an empty data source. "
                f"See migration_audit.md for detail.")
            _audit.record_unsupported_datasource(table_name, conn_class, raw_name)

        # ── Build PBI hierarchies from Tableau <drill-path> definitions ─────
        # Each Tableau drill-path becomes a PBI TOM hierarchy with one level
        # per field.  A level references a column that must exist in this table;
        # we skip levels whose column cannot be found to keep the TOM valid.
        pbi_hierarchies = []
        for dp in ds.get('drill_paths', []):
            dp_levels = []
            for ordinal, col_display in enumerate(dp.get('levels', [])):
                # Find the PBI column name for this level (using col_name_map
                # which maps Tableau caption → final PBI column name).
                pbi_col_name = col_name_map.get(col_display, col_display)
                # Verify the column actually exists in pbi_columns
                col_exists = any(c.get('name') == pbi_col_name
                                 or c.get('name') == col_display
                                 for c in pbi_columns + pbi_calc_columns)
                if not col_exists:
                    continue   # skip levels whose backing column is missing
                # Use the resolved PBI column name for the level
                final_col = pbi_col_name if any(c.get('name') == pbi_col_name
                                                 for c in pbi_columns + pbi_calc_columns) \
                            else col_display
                dp_levels.append({
                    "name":        col_display,   # level display name = column caption
                    "ordinal":     ordinal,
                    "column":      final_col,     # must match a column name in this table
                    "lineageTag":  _guid(),
                })
            if len(dp_levels) >= 2:   # a hierarchy needs at least 2 levels
                pbi_hierarchies.append({
                    "name":       dp['name'],
                    "lineageTag": _guid(),
                    "levels":     dp_levels,
                })

        data_table = {
            "name": table_name,
            "lineageTag": _guid(),
            "columns": pbi_columns + pbi_calc_columns,   # calculated columns follow source cols
            "measures": [],          # filled after global dedup below
            "partitions": [{
                "name": table_name,
                "mode": "import",
                "source": {
                    "type": "m",
                    # PBI Desktop stores M expressions as a JSON array of lines.
                    # Both string and array are accepted by PBI, but array is the
                    # native format and avoids any line-ending edge cases.
                    "expression": m_query.splitlines()
                }
            }],
            "annotations": [
                {"name": "PBI_ResultType", "value": "Table"},
                {"name": "PBIDesktopVersion", "value": "2.128.952.0 (24.04)"}
            ],
            **({"hierarchies": pbi_hierarchies} if pbi_hierarchies else {}),
        }

        # ── Global measure name deduplication ──────────────────────────────
        # PBI TOM requires every measure name to be unique across the ENTIRE
        # model, not just within its own table.  When a name collides, suffix
        # it with " (<datasource caption>)" to keep it meaningful.
        ds_caption = (ds.get('name') or raw_name or table_name).replace('_', ' ')
        for msr in pbi_measures:
            candidate = msr['name']
            if candidate.lower() in seen_model_measure_names:
                # Build a disambiguated name: "Measure (TableCaption)"
                candidate = f"{msr['name']} ({ds_caption})"
                if candidate.lower() in seen_model_measure_names:
                    # Last resort: append table_name (sanitised)
                    candidate = f"{msr['name']} ({table_name})"
            seen_model_measure_names.add(candidate.lower())
            data_table['measures'].append({**msr, 'name': candidate})

        tables.append(data_table)


    # ── Increment 22: real dimension tables + valid relationships ──────────────
    # Replaces logic that used to emit relationship objects referencing
    # Tableau sub-table names which never existed as PBI tables (100%
    # dangling — confirmed against every real fixture with relationships;
    # see MIGRATION_ENGINE_PROGRESS.md Increment 22). The fact table built
    # above is untouched (every existing chart/DAX binding keeps working);
    # this step ADDS real standalone dimension tables + relationship objects
    # wired to them, built entirely from schema-verified Tableau relationship
    # + <metadata-records> XML (see parse_tableau_workbook) — never guessed.
    pbi_model_rels = []
    _dim_notes: list = []   # (description, status, detail) for the audit report

    def _sample_key_unique(_tbl_cap, _raw_key):
        """Cardinality check: is this column unique in the real extracted
        sample rows for that table (fact OR dimension side — this is no
        longer dimension-only, see below)? Returns True/False when the real
        extracted data settles it, None when unknown (no extracted data) —
        callers must not treat None as a negative. Non-null values only:
        Power BI's own uniqueness constraint on a relationship's "one" side
        ignores BLANK/null, so a key that only repeats via nulls is still a
        valid one-side key."""
        _entry = (extracted_data or {}).get('datasources', {}).get(_tbl_cap)
        if not _entry or not _entry.get('rows'):
            return None
        def _nrm(s): return str(s).lower().replace(' ', '').replace('_', '').replace('-', '')
        _kn = _nrm(_raw_key)
        _vals = []
        for _row in _entry['rows']:
            for _k, _v in _row.items():
                if _nrm(_k) == _kn:
                    if _v not in (None, ''):
                        _vals.append(_v)
                    break
        if not _vals:
            return None
        return len(_vals) == len(set(_vals))

    for ds in workbook['datasources']:
        _split = ds.get('_dim_split')
        if not _split or not ds.get('_pbi_table_name'):
            continue
        fact_pbi_table = ds['_pbi_table_name']
        fact_col_map   = ds.get('_col_name_map', {})
        col_table      = _split['col_table']
        fact_ds_cap    = ds.get('name', '') or ds.get('raw_name', '')
        _fact_table_dict = next((t for t in tables if t['name'] == fact_pbi_table), None)
        _fact_col_dtypes = ({c['name']: c.get('dataType')
                              for c in _fact_table_dict.get('columns', [])}
                             if _fact_table_dict else {})

        for _dim_raw_name, _dim_conn in _split['dim_tables'].items():
            _dim_cols = [c for c in ds['columns']
                         if col_table.get(c.get('source_name') or c['name'], {}).get('table') == _dim_raw_name]
            # Synthesize the PK column from <metadata-records> when Tableau
            # never emitted a <column> element for it at all — same real gap
            # as the FK side (see the main loop's _relationship_fk_names
            # synthesis above; confirmed real on Sales Param's
            # 'Region (People)'/'Order ID (Returns)').
            _dim_col_keys = {(c.get('source_name') or c['name']) for c in _dim_cols}
            for _rel in _split['relationships']:
                if _rel['toTable'] != _dim_raw_name or _rel['toColumn'] in _dim_col_keys:
                    continue
                _meta = col_table.get(_rel['toColumn'])
                if not isinstance(_meta, dict):
                    continue
                _dtype = {
                    'integer': 'int64', 'real': 'double', 'string': 'string',
                    'date': 'date', 'datetime': 'dateTime', 'boolean': 'boolean',
                }.get(_meta.get('local_type', 'string'), 'string')
                _dim_cols.append({
                    'name': _rel['toColumn'], 'source_name': _meta.get('remote_name') or _rel['toColumn'],
                    'datatype': _dtype, 'role': 'dimension', 'measure': False,
                    'hidden': False, 'tableau_format': '',
                })
                _dim_col_keys.add(_rel['toColumn'])
            if not _dim_cols:
                _dim_notes.append((_dim_raw_name, 'skipped',
                                    'no columns resolved to this real table via metadata-records'))
                continue
            _dim_table_dict, _dim_param_table, _dim_col_map, _dim_pbi_name = _build_dimension_table(
                _dim_raw_name, _dim_cols, _dim_conn, seen_table_names,
                embed_sample_data, extracted_data,
                day_first=_locale_prefers_day_first(ds.get('connection', {}).get('locale', ''))
            )
            tables.append(_dim_table_dict)
            if _dim_param_table:
                tables.append(_dim_param_table)

            _dim_col_dtypes = {c['name']: c.get('dataType') for c in _dim_table_dict.get('columns', [])}

            for _rel in _split['relationships']:
                if _rel['toTable'] != _dim_raw_name or _rel['fromTable'] != _split['fact_table']:
                    continue
                _fk_final = fact_col_map.get(_rel['fromColumn'])
                _pk_final = _dim_col_map.get(_rel['toColumn'])
                if not _fk_final or not _pk_final:
                    _dim_notes.append((f"{_rel['fromTable']}.{_rel['fromColumn']} -> "
                                        f"{_rel['toTable']}.{_rel['toColumn']}", 'skipped',
                                        'FK or PK column did not resolve to a real generated column'))
                    continue

                # ── Datatype compatibility (master-spec requirement) ────────
                # Never create a relationship whose two sides have different
                # final PBI datatypes — that is exactly what produces "DAX
                # comparison operations do not support comparing values of
                # type Number with values of type Text" once Power BI tries
                # to build/use the relationship. Skip rather than silently
                # emit a broken one; VALUE()/FORMAT() coercion is deliberately
                # not attempted here (would mask a real schema mismatch).
                _fk_dtype = _fact_col_dtypes.get(_fk_final)
                _pk_dtype = _dim_col_dtypes.get(_pk_final)
                if _fk_dtype and _pk_dtype and _fk_dtype != _pk_dtype:
                    _dim_notes.append((
                        f"{fact_pbi_table}.{_fk_final} -> {_dim_pbi_name}.{_pk_final}",
                        'skipped',
                        f"datatype mismatch — fact key is '{_fk_dtype}', "
                        f"dimension key is '{_pk_dtype}'; creating this "
                        f"relationship would risk a DAX Number-vs-Text error"
                    ))
                    continue

                # ── Cardinality inference from real extracted data ──────────
                # Tableau's <relationships> logical layer always DECLARES a
                # detail(many)->dimension(one) join, but that is only a
                # declaration of INTENT — Power BI enforces uniqueness on
                # whichever side is marked "one" at the DATA level. Check
                # both sides against real extracted sample rows when
                # available (never trust the Tableau convention blindly) —
                # confirmed necessary: a naive many:one default would emit an
                # invalid model whenever the "one" side's real data actually
                # contains duplicates (e.g. Power BI's own "Column '...'
                # contains a duplicate value ... this is not allowed for
                # columns on the one side of a many-to-one relationship").
                _raw_pk  = _strip_dim_disambig_suffix(_rel['toColumn'], _dim_raw_name)
                _raw_fk  = _rel['fromColumn']
                _dim_unique  = _sample_key_unique(_dim_raw_name, _raw_pk)
                _fact_unique = _sample_key_unique(fact_ds_cap, _raw_fk)

                if _dim_unique is True and _fact_unique is True:
                    _from_card, _to_card, _cf_dir = 'one', 'one', 'oneDirection'
                    _card_note = 'one:one (both keys confirmed unique by sample data)'
                elif _dim_unique is True:
                    _from_card, _to_card, _cf_dir = 'many', 'one', 'oneDirection'
                    _card_note = ('many:one (dimension key confirmed unique; fact key '
                                  + ('confirmed non-unique)' if _fact_unique is False
                                     else 'not verified)'))
                elif _fact_unique is True:
                    # Real data contradicts Tableau's fact(many)->dim(one)
                    # convention for this key — the fact side is actually the
                    # unique one. Swap so Power BI's own one-side uniqueness
                    # constraint isn't violated.
                    _from_card, _to_card, _cf_dir = 'one', 'many', 'oneDirection'
                    _card_note = ('one:many (fact key confirmed unique; dimension key is '
                                  'not — swapped from the Tableau many:one convention)')
                elif _dim_unique is False:
                    # Dimension key confirmed NON-unique (with or without
                    # fact-side confirmation) — many:one would be a genuinely
                    # invalid model. many:many is the only cardinality Power
                    # BI can load without erroring on this real data.
                    _from_card, _to_card, _cf_dir = 'many', 'many', 'bothDirections'
                    _card_note = ('many:many (dimension key confirmed NON-unique by sample '
                                  'data — many:one would violate Power BI\'s one-side '
                                  'uniqueness constraint)')
                else:
                    # Neither side verifiable (no extracted sample data for
                    # either) — keep the existing conservative default, but
                    # label it as an unverified heuristic, not a confirmed fact.
                    _from_card, _to_card, _cf_dir = 'many', 'one', 'oneDirection'
                    _card_note = ('many:one (Tableau relationship convention — unverified, '
                                  'no extracted sample data for either side)')

                pbi_model_rels.append({
                    "name":                   f"{fact_pbi_table}_{_fk_final}_{_dim_pbi_name}_{_pk_final}",
                    "fromTable":              fact_pbi_table,
                    "fromColumn":             _fk_final,
                    "toTable":                _dim_pbi_name,
                    "toColumn":               _pk_final,
                    # Schema-verified TMSL property names from
                    # learn.microsoft.com/analysis-services/tmsl/
                    # relationships-object-tmsl.
                    "fromCardinality":        _from_card,
                    "toCardinality":          _to_card,
                    "crossFilteringBehavior": _cf_dir,
                    "joinOnDateBehavior":     "datePartOnly",
                    "isActive":               True,
                })
                _dim_notes.append((
                    f"{fact_pbi_table}.{_fk_final} -> {_dim_pbi_name}.{_pk_final}",
                    'created',
                    f'cardinality {_card_note}'
                ))

    # ── Data model validation & repair (master-spec requirement) ────────────
    # Confirm every relationship references real tables/columns before
    # writing the .pbit — a dangling reference is exactly what makes Power
    # BI Desktop show "Relationship object doesn't exist" on open. Anything
    # that fails is dropped (never silently written) and reported.
    _table_cols_by_name = {t['name']: {c['name'] for c in t.get('columns', [])} for t in tables}
    _all_table_names = set(_table_cols_by_name.keys())
    _validated_rels: list = []
    _seen_rel_names: set = set()
    for _r in pbi_model_rels:
        _problems = []
        if _r['fromTable'] not in _all_table_names:
            _problems.append(f"fromTable '{_r['fromTable']}' does not exist")
        if _r['toTable'] not in _all_table_names:
            _problems.append(f"toTable '{_r['toTable']}' does not exist")
        if _r['fromTable'] in _table_cols_by_name and _r['fromColumn'] not in _table_cols_by_name[_r['fromTable']]:
            _problems.append(f"fromColumn '{_r['fromColumn']}' does not exist on '{_r['fromTable']}'")
        if _r['toTable'] in _table_cols_by_name and _r['toColumn'] not in _table_cols_by_name[_r['toTable']]:
            _problems.append(f"toColumn '{_r['toColumn']}' does not exist on '{_r['toTable']}'")
        if _r['fromTable'] == _r['toTable']:
            _problems.append('fromTable and toTable are the same table')
        if _problems:
            _dim_notes.append((_r['name'], 'repaired (dropped)', '; '.join(_problems)))
            log('warn', f"[DataModel] Dropped invalid relationship '{_r['name']}': {'; '.join(_problems)}")
            continue
        _rname, _n_i = _r['name'], 2
        while _rname in _seen_rel_names:
            _rname = f"{_r['name']}_{_n_i}"
            _n_i += 1
        _seen_rel_names.add(_rname)
        _r['name'] = _rname
        _validated_rels.append(_r)
    pbi_model_rels = _validated_rels

    # ── Placeholder datasource path scan (master-spec requirement) ──────────
    # The generated Power BI report must never contain a fake placeholder
    # path (see _resolve_literal_file_path) unless the real datasource
    # location genuinely could not be resolved from the workbook/package —
    # in which case this must be a clear, visible audit warning rather than
    # a silent broken query. Scans every table's M-query text, not just
    # FilePath parameter tables, since a literal join-leaf path (physical
    # join-tree M queries) is inlined directly rather than parameterised.
    for _t in tables:
        for _part in _t.get('partitions', []):
            _expr = _part.get('source', {}).get('expression', '')
            _expr_text = '\n'.join(_expr) if isinstance(_expr, list) else str(_expr)
            if 'path\\\\to\\\\' in _expr_text or 'path\\to\\' in _expr_text:
                _dim_notes.append((
                    _t['name'], 'warning',
                    'generated M query still contains a placeholder datasource path — '
                    'the real source file location could not be resolved from the '
                    'workbook/package; point Power BI\'s file-path parameter at the '
                    'real file before refreshing'
                ))
                log('warn', f"[DataModel] Table '{_t['name']}' has an unresolved "
                    f"placeholder datasource path")
                break

    # Finalise audit — log summary; write() is called from write_pbit
    _audit.set_data_model([t['name'] for t in tables], pbi_model_rels, _dim_notes)
    _audit.log_summary()
    workbook['_migration_audit'] = _audit
    workbook['_param_tables'] = _param_tables

    return {
        "name": wb_name,
        "compatibilityLevel": 1550,
        "model": {
            "culture": "en-US",
            "dataAccessOptions": {
                "legacyRedirects": True,
                "returnErrorValuesAsNull": True
            },
            "defaultPowerBIDataSourceVersion": "powerBI_V3",
            "sourceQueryCulture": "en-US",
            "tables": tables,
            "relationships": pbi_model_rels,
            "annotations": [
                {"name": "PBIDesktopVersion", "value": "2.128.952.0 (24.04)"},
                {
                    "name": "PBI_QueryOrder",
                    "value": json.dumps([t["name"] for t in tables
                                         if not any(a.get("name") == "PBI_ResultType"
                                                    and a.get("value") in ('"\"Text\""', '\"Text\"')
                                                    for a in t.get("annotations", []))])
                }
            ]
        }
    }

# ── Report Layout builder ─────────────────────────────────────────────────────


def _build_pbi_visual_filters(table, filter_fields, filter_specs, col_name_resolver=None):
    """Build the PBI native (SemanticQuery) visual-level filter list for one
    worksheet's Tableau filters. Shared by _make_chart_vc / _make_card_vc /
    _make_table_vc so quantitative-range, Top-N, relative-date and context
    handling live in exactly one place instead of being triplicated.

    filter_specs entries (all keyed by 'field', all other keys optional):
      values, exclude          categorical include/exclude member list (existing behaviour)
      context: True            Tableau context filter → ordered first (closest PBI approximation)
      kind='quantitative'      min/max     → native Advanced Between filter
      kind='relative-date'     rel_start/rel_end (pre-resolved static snapshot) → Advanced Between
      kind='topn'              topn_count/topn_direction/topn_measure → native TopN filter

    col_name_resolver(field_caption) -> actual backing column name; defaults
    to identity (the table visual passes one that resolves through col_by_norm).
    """
    import re as _re_bpvf
    import hashlib as _hl_bpvf

    resolver = col_name_resolver or (lambda f: f)

    def _norm_key(s):
        return _re_bpvf.sub(r'[^a-z0-9]', '', (s or '').lower())

    def _numeric_literal(raw):
        """PBI SQE numeric literals need a type suffix: L for whole numbers,
        D for decimals — using L unconditionally would truncate/misparse a
        Tableau bound like '99.5'."""
        s = str(raw).strip()
        try:
            return f"{int(s)}L"
        except ValueError:
            return f"{float(s)}D"

    def _entry(col, spec):
        spec = spec or {}
        alias = table[0].lower()
        col_hash = _hl_bpvf.md5(f"{table}.{col}".encode()).hexdigest()[:20]
        colref = {'Column': {'Expression': {'SourceRef': {'Source': alias}}, 'Property': col}}
        base = {
            'name':       col_hash,
            'expression': {'Column': {'Expression': {'SourceRef': {'Entity': table}}, 'Property': col}},
            'type':       'Categorical',
            'howCreated': 1,
            'objects':    {},
        }
        kind = spec.get('kind', 'categorical')

        if kind == 'quantitative' and (spec.get('min') is not None or spec.get('max') is not None):
            conds = []
            if spec.get('min') is not None:
                conds.append({'Comparison': {'ComparisonKind': 2, 'Left': colref,
                                              'Right': {'Literal': {'Value': _numeric_literal(spec['min'])}}}})
            if spec.get('max') is not None:
                conds.append({'Comparison': {'ComparisonKind': 3, 'Left': colref,
                                              'Right': {'Literal': {'Value': _numeric_literal(spec['max'])}}}})
            cond = conds[0] if len(conds) == 1 else {'And': {'Left': conds[0], 'Right': conds[1]}}
            base['type'] = 'Advanced'
            base['filter'] = {'Version': 2, 'From': [{'Name': alias, 'Entity': table, 'Type': 0}],
                               'Where': [{'Condition': cond}]}
            return base

        if kind == 'relative-date' and spec.get('rel_start') and spec.get('rel_end'):
            cond = {'And': {
                'Left':  {'Comparison': {'ComparisonKind': 2, 'Left': colref,
                                          'Right': {'Literal': {'Value': f"datetime'{spec['rel_start']}T00:00:00'"}}}},
                'Right': {'Comparison': {'ComparisonKind': 3, 'Left': colref,
                                          'Right': {'Literal': {'Value': f"datetime'{spec['rel_end']}T23:59:59'"}}}},
            }}
            base['type'] = 'Advanced'
            base['filter'] = {'Version': 2, 'From': [{'Name': alias, 'Entity': table, 'Type': 0}],
                               'Where': [{'Condition': cond}]}
            return base

        if kind == 'topn' and spec.get('topn_count'):
            order_expr = colref
            if spec.get('topn_measure'):
                order_expr = {'Measure': {'Expression': {'SourceRef': {'Source': alias}},
                                           'Property': spec['topn_measure']}}
            cond = {'TopN': {
                'Expressions': [colref],
                'N': int(spec['topn_count']),
                'OrderBy': [{'Direction': 2 if spec.get('topn_direction', 'top') == 'top' else 1,
                             'Expression': order_expr}],
            }}
            base['type'] = 'TopN'
            base['filter'] = {'Version': 2, 'From': [{'Name': alias, 'Entity': table, 'Type': 0}],
                               'Where': [{'Condition': cond}]}
            return base

        # Default categorical path — identical output to the original
        # per-visual _pbi_filter/_pbi_filter_c/_pbi_filter_t implementations.
        values = spec.get('values')
        if values:
            in_cond = {'In': {
                'Expressions': [colref],
                'Values': [[{'Literal': {'Value': f"'{v}'"}}] for v in values],
            }}
            cond = {'Not': {'Expression': in_cond}} if spec.get('exclude') else in_cond
            base['filter'] = {'Version': 2, 'From': [{'Name': alias, 'Entity': table, 'Type': 0}],
                               'Where': [{'Condition': cond}]}
        return base

    fsp_map = {}
    for fs in (filter_specs or []):
        fsp_map.setdefault(_norm_key(fs['field']), fs)

    # Context filters first — Tableau computes them ahead of the sheet's other
    # filters; ordering them first in the Filters pane is the closest safe
    # Power BI approximation (stable sort keeps all other filters in place).
    ordered_fields = sorted(
        (filter_fields or []),
        key=lambda fn: 0 if fsp_map.get(_norm_key(fn), {}).get('context') else 1
    )

    entries, emitted = [], set()
    for fn in ordered_fields:
        key = _norm_key(fn)
        if key in emitted:
            continue
        entries.append(_entry(resolver(fn), fsp_map.get(key)))
        emitted.add(key)
    for fs in (filter_specs or []):
        key = _norm_key(fs['field'])
        if key in emitted:
            continue
        if fs.get('values') or fs.get('kind') in ('quantitative', 'topn', 'relative-date'):
            entries.append(_entry(resolver(fs['field']), fs))
            emitted.add(key)
    return entries


# ── Shared field-resolution helpers ───────────────────────────────────────
# build_report_layout() renders every worksheet through one of two parallel
# code paths — dashboard-zone tiles and standalone worksheet pages — that
# were independently written and used their own separate lookup helpers and
# per-chart-type field-resolution logic. That duplication is not cosmetic:
# a real bug (Treemap/Bubble/Scatter-with-size worksheets rendering an
# unrelated measure) was fixed in one path during a prior session and had to
# be separately rediscovered and fixed in the other. These functions are the
# single shared implementation both paths now call, so a fix (or a future
# chart type) only has to be written once.

def _field_norm_key(s: str) -> str:
    """Normalised matching key: lowercase, strip whitespace/hyphen/underscore
    separators only — NOT all punctuation. Stripping everything (the zone
    path's original behaviour) collapses a calculated field's name onto an
    unrelated base column whenever the calc name is the column name plus a
    trailing symbol (confirmed against a real sample: HR Analytics'
    calculated field "Attrition #" normalised identically to the raw
    dimension "Attrition", silently dropping the calc from every chart that
    used it as its actual measure)."""
    import re as _r
    return _r.sub(r'[\s\-_]', '', str(s).lower())


import re as _re_copy_sfx
_COPY_SUFFIX_RE = _re_copy_sfx.compile(r'^\(copy\s*\d*\)$', _re_copy_sfx.I)


def _is_copy_suffix_of(candidate_key: str, nn: str) -> bool:
    """True when candidate_key is exactly nn plus a Tableau '(copy)'/'(copy 2)'
    duplicate-rename marker — e.g. candidate 'accountspayable(copy)' vs
    nn 'accountspayable'.

    A bare `startswith(nn)` (this function's predecessor) also matches any
    UNRELATED longer name that happens to start with the same characters —
    confirmed as a real bug against Sales Param's 'Line graph' worksheet,
    where looking up base column 'Sales' incorrectly resolved to the
    unrelated calc 'Sales Threshold' (both '_lookup_measure' and
    '_lookup_col' share this helper) purely because "salesthreshold".
    startswith("sales"). Requiring the remainder to actually look like a
    copy-marker keeps the intended '(copy)'-suffix match while rejecting
    that false positive.
    """
    if not candidate_key.startswith(nn):
        return False
    return bool(_COPY_SUFFIX_RE.match(candidate_key[len(nn):]))


def _lookup_col(name, cols):
    """Find a column dict by normalised name (exact match, then '(copy)'-suffix)."""
    if not name:
        return None
    nn = _field_norm_key(name)
    r = next((c for c in cols if _field_norm_key(c['name']) == nn), None)
    if r:
        return r
    return next(
        (c for c in cols if _is_copy_suffix_of(_field_norm_key(c['name']), nn)),
        None)


def _lookup_measure(name, msrs):
    """Find a DAX measure/calc dict by normalised name (exact match, then
    '(copy)'-suffix — handles Tableau's '(copy)' suffix, e.g. a calc renamed
    'Accounts Payable (copy)')."""
    if not name:
        return None
    nn = _field_norm_key(name)
    r = next((m for m in msrs if _field_norm_key(m['name']) == nn), None)
    if r:
        return r
    return next(
        (m for m in msrs if _is_copy_suffix_of(_field_norm_key(m['name']), nn)),
        None)


def _as_plain_col_item(col):
    """Tag a raw column dict for use as a non-measure category/detail field."""
    return {'name': col['name'], 'datatype': col.get('datatype', 'string'),
            'measure': False, 'is_measure': False}


_TREEMAP_NUM_DTYPES = ('int64', 'double', 'decimal', 'int32', 'real')


def _resolve_treemap_bubble_fields(chart_kind, size_name, color_names, detail_names,
                                    cols, msrs):
    """
    Resolve category/value/extra-role fields for Tableau's Treemap and packed-
    Bubble chart types — both driven by size/color ENCODINGS rather than
    rows/cols SHELVES.

    Returns (category_fields, value_fields, extra_fields) ready for
    _make_chart_vc's category_fields / value_fields / extra_fields kwargs.
    """
    # Size: prefer a real DAX measure, then a raw numeric column, then any
    # numeric/measure-flagged column as a last resort.
    size_c, size_is_measure = None, False
    if size_name:
        _sm = _lookup_measure(size_name, msrs)
        if _sm:
            size_c, size_is_measure = _sm, True
        else:
            size_c = _lookup_col(size_name, cols)
    if size_c is None:
        size_c = next(
            (c for c in cols
             if c.get('measure') or c.get('datatype', '') in ('int64', 'double')),
            None)

    # Color → Category dimension. Exclude numeric datatypes as well as the
    # 'measure' flag: some numeric columns are stored with measure=False
    # despite being int64/double (an unreliable data-model flag), which
    # would otherwise let a continuous count column outrank the real
    # dimension (confirmed against a real sample: AB_NYC Dashboard's "Host
    # Name and Reviews" treemap, color='price' correctly excluded as a
    # measure, but the fallback was landing on 'number_of_reviews' —
    # mislabeled measure=False despite being int64 — instead of 'host_name').
    # Kept separate from the fallback (rather than resolved in one step) so
    # a genuine color encoding can still surface the naive first-dimension
    # fallback as a second Treemap hierarchy level (Group role) below.
    color_from_encoding = next(
        (c for c in (_lookup_col(cn, cols) for cn in color_names)
         if c and not c.get('measure')
         and c.get('datatype', 'string') not in _TREEMAP_NUM_DTYPES),
        None)
    first_dim_fallback = next(
        (c for c in cols
         if not c.get('measure')
         and c.get('datatype', 'string') not in _TREEMAP_NUM_DTYPES),
        None)
    color_c = color_from_encoding or first_dim_fallback

    extra_dims = []
    for dn in detail_names:
        dc = _lookup_col(dn, cols)
        if dc and (not color_c or _field_norm_key(dc['name']) != _field_norm_key(color_c['name'])):
            extra_dims.append(dc)

    def _size_extra(c):
        return ({**c, 'is_measure': True, 'is_pie_agg': False} if size_is_measure
                else {**c, 'is_pie_agg': True, 'is_measure': False})

    cat_f, val_f, extra = [], [], {}
    if chart_kind == 'treemap':
        if color_c:
            cat_f.append(_as_plain_col_item(color_c))
        cat_f.extend(_as_plain_col_item(dc) for dc in extra_dims)
        # Group role: a second hierarchy level. Only when the color
        # encoding resolved to something DIFFERENT from the naive
        # first-dimension fallback, and there's no detail breakdown already
        # subdividing the treemap (details already provide a second level).
        if (color_from_encoding and first_dim_fallback and not extra_dims
                and _field_norm_key(color_from_encoding['name'])
                != _field_norm_key(first_dim_fallback['name'])):
            extra['Group'] = [_as_plain_col_item(first_dim_fallback)]
        if size_c:
            extra['Values'] = [_size_extra(size_c)]
    else:   # bubbleChart (packed)
        if size_c:
            cat_f.append(_as_plain_col_item(size_c))
        cat_f.extend(_as_plain_col_item(dc) for dc in extra_dims)
        if color_c:
            cat_f.append(_as_plain_col_item(color_c))
            extra['Details'] = [_as_plain_col_item(color_c)]
        if size_c:
            extra['Size'] = [_size_extra(size_c)]

    return cat_f, val_f, extra


def _resolve_scatter_size_extra(size_name, cols, msrs):
    """Resolve a scatter chart's optional Size role (a real Tableau bubble-
    scatter: continuous X/Y axes PLUS a size field). Returns an extra_fields
    dict, empty if there's no size field to wire."""
    if not size_name:
        return {}
    m = _lookup_measure(size_name, msrs)
    if m:
        return {'Size': [{**m, 'is_measure': True, 'is_pie_agg': False}]}
    c = _lookup_col(size_name, cols)
    if c:
        return {'Size': [{**c, 'is_pie_agg': True, 'is_measure': False}]}
    return {}


def _resolve_scatter_xy_fields(x_field_candidates, y_field_candidates, detail_fields,
                               color_names, cols, all_ds_cols,
                               ctd_fields=None, ctd_map=None):
    """
    Resolve category (Details)/value (X, Y)/legend fields for a genuine
    Tableau scatter chart — two independent continuous axes, NOT a
    bar/column-style single value chain (that's what _resolve_measure_values
    is for; forcing scatter through it drops one of the two axes, since it's
    designed to resolve ONE measure chain, not two independent columns).

    x_field_candidates/y_field_candidates are ordered lists (e.g.
    all_col_fields + a bare x_field fallback), not single field names — the
    bare x_field/y_field can be empty even when a real axis measure exists
    (confirmed against a real sample: AB_NYC Dashboard's "Reviews by
    Neighbourhood Group", whose x_field is '' while all_col_fields correctly
    holds 'Longitude' — both rows and cols are continuous measures for this
    worksheet, a shape the plain x_field/y_field assignment doesn't cover).

    ctd_fields/ctd_map let a ctd: (COUNT DISTINCT) shelf token resolve to its
    real DISTINCTCOUNT measure instead of falling through to an unrelated
    column (confirmed against a real sample: LocBar's "Sheet 14", whose rows
    shelf is `ctd:Product Name:qk` — without this check it silently
    resolved to the OTHER axis's raw column instead).

    X/Y are Column references (is_scatter_col=True) unless resolved via
    ctd_map, in which case they're a named DAX Measure — matches Power BI's
    own scatter-chart Select shape: Column{Property:"Total Charges"} with a
    NativeReferenceName so the axis label shows the plain field name while
    the default (Sum) aggregation still applies.

    Detail (mark-identity) priority: Tableau "lod" encoding columns → an
    auto-detected identifier column (id/key) → first non-axis dimension.

    Returns (detail_fields_resolved, value_fields, legend_fields).
    """
    ctd_fields = ctd_fields or []
    ctd_map = ctd_map or {}

    def _first_axis_item(candidates, exclude_name=None):
        excl = _field_norm_key(exclude_name) if exclude_name else None
        for name in candidates:
            if not name or (excl and _field_norm_key(name) == excl):
                continue
            if any(_field_norm_key(name) == _field_norm_key(cf) for cf in ctd_fields):
                for k, v in ctd_map.items():
                    if _field_norm_key(k) == _field_norm_key(name):
                        return {'name': v, 'is_measure': True, 'is_scatter_col': False,
                                'is_agg': False, 'datatype': 'double'}
            c = _lookup_col(name, cols)
            if (c and (c.get('measure') or c.get('datatype') in ('int64', 'double'))
                    and (not excl or _field_norm_key(c['name']) != excl)):
                return {**c, 'is_scatter_col': True, 'is_measure': False, 'is_agg': False}
        return None

    x_col = _first_axis_item(x_field_candidates)
    # Exclude whatever X resolved to — a scatter needs two DISTINCT axes;
    # the same field appearing in both candidate lists (confirmed against a
    # real sample, LocBar's "Sheet 14") should fall through to the next
    # candidate for Y rather than plot the same value against itself.
    y_col = _first_axis_item(y_field_candidates, exclude_name=x_col['name'] if x_col else None)
    val_f = []
    if x_col:
        val_f.append(x_col)
    if y_col:
        val_f.append(y_col)

    axis_names = {(x_col['name'] if x_col else ''), (y_col['name'] if y_col else '')}
    det_f = []
    for lod_name in detail_fields:
        lod_c = _lookup_col(lod_name, all_ds_cols)
        if lod_c and lod_c not in det_f:
            det_f.append(_as_plain_col_item(lod_c))

    if not det_f:
        id_col = next(
            (c for c in all_ds_cols
             if not c.get('measure')
             and any(k in c['name'].lower() for k in ('id', 'key', 'customerid', 'customer id'))),
            None)
        if id_col:
            det_f.append(_as_plain_col_item(id_col))

    if not det_f:
        fallback = next(
            (c for c in cols if not c.get('measure') and c['name'] not in axis_names),
            cols[0] if cols else None)
        if fallback:
            det_f.append(_as_plain_col_item(fallback))

    leg_f = []
    for cn in color_names:
        c = _lookup_col(cn, cols)
        if c:
            leg_f.append(_as_plain_col_item(c))

    return det_f, val_f, leg_f


def _resolve_multirow_card_fields(names, cols, msrs):
    """Resolve Tableau's ':Measure Names on a shelf + Measure Values as text,
    filtered to N measures' KPI strip into a value_fields list for
    _make_multirow_card_vc."""
    fields = []
    for nm in names:
        m = _lookup_measure(nm, msrs)
        if m:
            fields.append({**m, 'is_measure': True})
            continue
        c = _lookup_col(nm, cols)
        if c and (c.get('measure') or c.get('datatype', '') in
                  ('int64', 'double', 'decimal', 'int32')):
            fields.append({**c, 'is_measure': False})
    return fields


def _as_measure_ref(name: str) -> dict:
    """Tag a bare measure name (e.g. an auto-generated 'Count of X') for use
    in value_fields — a named DAX Measure reference, not a column."""
    return {'name': name, 'is_measure': True, 'datatype': 'double'}


def _resolve_measure_values(chart_type, is_hbar, val_field_candidates, y_field_name,
                            shelf_row_fields, ctd_fields, ctd_map, sum_map,
                            measure_names_filter_fields, cat_f,
                            cols, msrs, ds, measure_registry,
                            row_measure_fallback=None):
    """
    Resolve Y-axis/value measure(s) for bar/column/line/combo charts — the
    single shared implementation for what used to be two independently
    written copies (a ~250-line priority chain in the standalone-page path,
    and a much thinner shelf-based fallback in the dashboard-zone path).
    Handles, in priority order:

      - horizontal-bar axis swap: the measure lives on the COLS shelf, not
        ROWS, for a Tableau clusteredBarChart/barChart. val_field_candidates
        is an ordered list (e.g. all_col_fields + a bare x-field fallback),
        tried in turn, NOT a single field name — the bare axis field alone
        can resolve to the category dimension instead of the measure
        depending on chart orientation.
      - ctd: shelf tokens → DISTINCTCOUNT measure
      - cnt: shelf tokens → CountNonNull() Aggregation (not a named measure)
      - side-by-side multi-measure detection (2+ measures on the rows shelf
        → grouped/side-by-side bars, merging in any :Measure Names filter
        measures not already resolved from the shelf)
      - the ":Measure Names" pattern alone (Tableau's "Multiple Values" combo
        placeholder — actual measures come from the filter's member list)
      - ratio-vs-value auto-combo-upgrade: when a side-by-side set mixes a
        plain value measure (Revenue) with a ratio/percentage-looking one
        (Profit Margin %), auto-promotes the chart to a combo chart with the
        ratio on a second axis, rather than plotting a 0-1 line squashed flat
        against a value in the millions
      - single-measure priority chain: shelf calc → shelf numeric column →
        first numeric calc → y_field calc/column → legacy cnt: pattern →
        first numeric column in the datasource → COUNT of the category field

    Returns (value_fields, resolved_chart_type, color_is_measure_names).
    resolved_chart_type may differ from the input chart_type (the ratio-vs-
    value auto-upgrade promotes clustered bar/column to the combo chart);
    color_is_measure_names is True when the caller should force per-measure
    metadata-selector coloring (multiple measures with no separate legend
    dimension to split them).
    """
    import re as _re_cnt

    row_measure_fallback = row_measure_fallback or []
    color_is_measure_names = False
    y_msr, y_msr_is_col, y_col_for_agg = None, False, None
    y_is_agg_count, y_agg_col = False, None

    # The "measure shelf" to scan for one-or-more measures: for a horizontal
    # bar/column chart the measure(s) live on the COLS shelf
    # (val_field_candidates, e.g. all_col_fields — tried as a full list, not
    # just the bare x-field, because the bare field alone can resolve to the
    # CATEGORY dimension instead: confirmed against a real sample, LocBar's
    # "LocBar" worksheet, x_field='Region' the category, real measure
    # 'Sale Amt' only in all_col_fields). Otherwise the measure(s) live on
    # the ROWS shelf (shelf_row_fields). Using ONE shared scan for both
    # orientations (rather than a single-value-only hbar special case) is
    # what lets a multi-measure HORIZONTAL chart also get proper side-by-side
    # detection — confirmed against a real sample, LocBar's "Sheet 3"
    # (clusteredBarChart, 3 measures on the cols shelf): a single-value-only
    # hbar path silently dropped 2 of the 3 measures.
    measure_shelf = val_field_candidates if is_hbar else shelf_row_fields
    primary_field_name = (
        next((c for c in reversed(val_field_candidates) if c), '')
        if is_hbar else y_field_name)

    # ctd: on the primary field (the bare x/y-field — checked as a single
    # field, same as Tableau's own ctd: shelf-token convention)
    if any(_field_norm_key(primary_field_name) == _field_norm_key(cf) for cf in ctd_fields):
        for k, v in ctd_map.items():
            if _field_norm_key(k) == _field_norm_key(primary_field_name):
                y_msr = v
                break

    # cnt: prefix → CountNonNull Aggregation, not a named measure
    if 'cnt:' in (primary_field_name or '').lower():
        m_cnt = _re_cnt.match(r'cnt:(.+?):qk', primary_field_name, _re_cnt.I)
        base = m_cnt.group(1) if m_cnt else ''
        cnt_col = next(
            (c for c in cols
             if base and _field_norm_key(c.get('source_name') or c['name']) == _field_norm_key(base)),
            None)
        if cnt_col is None and cols:
            cnt_col = cols[0]
        if cnt_col:
            y_is_agg_count, y_agg_col = True, cnt_col['name']
            if not base:
                for srf in measure_shelf:
                    sc = _lookup_col(srf, cols)
                    if sc:
                        y_agg_col = sc['name']
                        break

    def _scan_measure_shelf(shelf):
        """One complete side-by-side scan over a single shelf-field list.
        Kept as a self-contained pass (own dedup set) rather than merging
        multiple shelf sources into one loop, because two sources can each
        independently resolve the SAME underlying field to a DIFFERENTLY
        NAMED entry (e.g. a raw 'sum:DPO:qk' token resolving via sum_map to
        a synthetic 'Sum of DPO', while the already-cleaned name 'DPO'
        resolves directly to its own DAX calc) — name-based dedup across
        two mixed sources can't catch that, so callers try ONE shelf list
        at a time and only fall back to a second if the first yields
        nothing at all (confirmed against a real sample: LocBar's
        "DSO vs DPO", which produced 6 measures — 2 real, 4 duplicate — when
        both sources were scanned together)."""
        found, seen = [], set()
        for srf in shelf:
            if srf.strip().lower() in ('multiple values', ''):
                continue
            if any(_field_norm_key(srf) == _field_norm_key(cf) for cf in ctd_fields):
                for k, v in ctd_map.items():
                    if _field_norm_key(k) == _field_norm_key(srf):
                        if _field_norm_key(v) not in seen:
                            found.append(_as_measure_ref(v))
                            seen.add(_field_norm_key(v))
                        break
                continue
            calc_cand = _lookup_measure(srf, msrs)
            if calc_cand:
                if _field_norm_key(calc_cand['name']) not in seen:
                    found.append({**calc_cand, 'is_measure': True,
                                  'datatype': calc_cand.get('datatype', 'double')})
                    seen.add(_field_norm_key(calc_cand['name']))
                continue
            col_cand = _lookup_col(srf, cols)
            if (col_cand and (col_cand.get('measure')
                              or col_cand.get('datatype') in ('int64', 'double'))
                    and _field_norm_key(col_cand['name']) not in seen):
                seen.add(_field_norm_key(col_cand['name']))
                sum_key = sum_map.get(col_cand['name'])
                if sum_key:
                    found.append(_as_measure_ref(sum_key))
                else:
                    reg_item = measure_registry.resolve(col_cand['name'], ds)
                    if reg_item:
                        found.append({**reg_item, 'is_measure': True})
                    else:
                        found.append({**col_cand, 'is_measure': False, 'is_agg': True})
        return found

    all_shelf_msrs = []
    if not y_is_agg_count and not (y_msr or y_col_for_agg):
        # Side-by-side (multiple-measure) detection: Tableau puts 2+ measures
        # on the measure shelf (e.g. [Sales]+[Profit]+[Quantity]) for a
        # grouped bar/column chart. Try the shelf as given first; if that
        # yields nothing, retry with row_measure_fallback (cleaned names,
        # e.g. all_row_measure_fields) — some raw shelf tokens (e.g.
        # "cum:sum:Profit") never resolve at all, silently losing a measure
        # the cleaned list already had correctly.
        all_shelf_msrs = _scan_measure_shelf(measure_shelf)
        if not all_shelf_msrs and row_measure_fallback:
            all_shelf_msrs = _scan_measure_shelf(row_measure_fallback)

        if all_shelf_msrs:
            # Merge in any :Measure Names filter measures not already resolved
            # (combo charts mixing a rows-shelf measure with Measure-Names ones).
            existing = {_field_norm_key(m['name']) for m in all_shelf_msrs}
            for mnf in measure_names_filter_fields:
                if _field_norm_key(mnf) in existing:
                    continue
                cc = _lookup_measure(mnf, msrs)
                if cc:
                    all_shelf_msrs.append({**cc, 'is_measure': True,
                                           'datatype': cc.get('datatype', 'double')})
                    continue
                co = _lookup_col(mnf, cols)
                if co and (co.get('measure') or co.get('datatype') in ('int64', 'double')):
                    all_shelf_msrs.append({**co, 'is_measure': False, 'is_agg': True})
            if len(all_shelf_msrs) > 1:
                color_is_measure_names = True

        elif not all_shelf_msrs:
            # Nothing on the shelf — check the ":Measure Names" filter alone
            # (Tableau's "Multiple Values" grouped-measure pattern).
            for mnf in measure_names_filter_fields:
                calc_c = _lookup_measure(mnf, msrs)
                if calc_c:
                    all_shelf_msrs.append({**calc_c, 'is_measure': True,
                                           'datatype': calc_c.get('datatype', 'double')})
                    continue
                col_c = _lookup_col(mnf, cols)
                if col_c and (col_c.get('measure') or col_c.get('datatype') in ('int64', 'double')):
                    sum_key2 = sum_map.get(col_c['name'])
                    if sum_key2:
                        all_shelf_msrs.append(_as_measure_ref(sum_key2))
                    else:
                        reg_item2 = measure_registry.resolve(col_c['name'], ds)
                        if reg_item2:
                            all_shelf_msrs.append({**reg_item2, 'is_measure': True})
                        else:
                            all_shelf_msrs.append({**col_c, 'is_measure': False, 'is_agg': True})
            if len(all_shelf_msrs) > 1:
                color_is_measure_names = True

        if not all_shelf_msrs:
            # ── Single-measure priority chain ──────────────────────────────
            for srf in shelf_row_fields:
                if srf.strip().lower() in ('multiple values', ''):
                    continue
                calc_cand = _lookup_measure(srf, msrs)
                if calc_cand:
                    y_msr = calc_cand['name']
                    break

            if not y_msr and not y_col_for_agg:
                for srf in measure_shelf:
                    if srf.strip().lower() in ('multiple values', ''):
                        continue
                    cand = _lookup_col(srf, cols)
                    if cand and (cand.get('measure') or cand.get('datatype') in ('int64', 'double')):
                        y_msr_is_col, y_col_for_agg = True, cand
                        break

            if not y_msr and msrs:
                msr_cand = next(
                    (c for c in msrs
                     if c.get('datatype', 'double') in ('double', 'integer', 'int64', None, '')
                     and c['name'] not in ('Max Year', 'Is Current Year')),
                    msrs[0])
                y_msr = msr_cand['name']

            if not y_msr and primary_field_name:
                calc_cand = _lookup_measure(primary_field_name, msrs)
                if calc_cand:
                    y_msr = calc_cand['name']
                if not y_msr and not y_col_for_agg:
                    cand = _lookup_col(primary_field_name, cols)
                    if cand and (cand.get('measure') or cand.get('datatype') in ('int64', 'double')):
                        y_msr_is_col, y_col_for_agg = True, cand

            if not y_msr and 'cnt:' in (primary_field_name or '').lower():
                m3 = _re_cnt.match(r'cnt:(.+?):qk', primary_field_name, _re_cnt.I)
                base3 = m3.group(1) if m3 else ''
                y_msr = next(
                    (f"Count of {c['name']}" for c in cols
                     if base3 and _field_norm_key(c.get('source_name') or c['name']) == _field_norm_key(base3)),
                    None)
                if not y_msr and cols:
                    y_msr = f"Count of {cols[0]['name']}"

            if not y_msr and not y_col_for_agg:
                num_cand = next(
                    (c for c in cols
                     if c.get('measure') or c.get('datatype') in ('int64', 'double')),
                    None)
                if num_cand:
                    y_msr_is_col, y_col_for_agg = True, num_cand

            if not y_msr:
                y_msr = f"Count of {cat_f[0]['name']}" if cat_f else None

    # ── Build value_fields ───────────────────────────────────────────────
    if y_is_agg_count and y_agg_col:
        val_f = [{'name': y_agg_col, 'is_measure': False, 'is_agg': False,
                  'is_agg_count': True, 'datatype': 'int64',
                  '_display_name': 'Count of ' + y_agg_col}]
    elif all_shelf_msrs:
        val_f = all_shelf_msrs
        # Ratio-vs-value auto-combo-upgrade: mixing a plain value measure
        # with a percentage/ratio-looking one on the same axis squashes the
        # ratio flat — auto-promote to a combo chart with the ratio on Y2.
        if len(val_f) >= 2 and chart_type in (
                'clusteredColumnChart', 'clusteredBarChart', 'columnChart', 'barChart'):
            def _is_ratio_msr(m):
                nl = m['name'].lower().replace(' ', '').replace('_', '')
                formula = (m.get('formula') or '').lower()
                # Unambiguous percentage/ratio name signals — always a ratio.
                strong_kw = ('pct', 'percent', 'profitmargin', 'grosspct')
                if any(k in nl for k in strong_kw):
                    return True
                # Formula shape that IS a ratio regardless of naming.
                if '/' in formula and formula.count('sum(') >= 2:
                    return True
                if '*100' in formula.replace(' ', '') or '* 100' in formula:
                    return True
                # Ambiguous name-only keywords ("Margin", "Rate", "Return", …)
                # can equally name a plain dollar amount (e.g. Sale - Cost
                # named "Margin" — confirmed against a real sample, LocBar's
                # "Margin" calc, formula = subtraction, not a ratio at all).
                # Only trust these when the formula itself also looks like a
                # ratio (a division), not on the name alone.
                weak_kw = ('margin', 'ratio', 'rate', 'growth', 'yield',
                           'return', 'efficiency')
                if any(k in nl for k in weak_kw) and '/' in formula:
                    return True
                return False

            ratio_msrs = [v for v in val_f if _is_ratio_msr(v)]
            value_msrs = [v for v in val_f if not _is_ratio_msr(v)]
            if ratio_msrs and value_msrs:
                for v in value_msrs: v['_combo_role'] = 'bar'
                for v in ratio_msrs: v['_combo_role'] = 'line'
                val_f = value_msrs + ratio_msrs
                chart_type = 'lineClusteredColumnComboChart'
                color_is_measure_names = False   # combo handles its own colors
    else:
        y_calc = _lookup_measure(y_msr, msrs) if y_msr else None
        if y_calc:
            val_f = [{**y_calc, 'is_measure': True, 'datatype': y_calc.get('datatype', 'double')}]
        elif y_msr_is_col and y_col_for_agg:
            sum_key3 = sum_map.get(y_col_for_agg['name'])
            if sum_key3:
                val_f = [_as_measure_ref(sum_key3)]
            else:
                reg_item3 = measure_registry.resolve(y_col_for_agg['name'], ds)
                if reg_item3:
                    val_f = [{**reg_item3, 'is_measure': True, 'is_agg': False}]
                else:
                    val_f = [{**y_col_for_agg, 'is_measure': False, 'is_agg': True}]
        elif y_msr:
            val_f = [_as_measure_ref(y_msr)]
        else:
            val_f = []

    return val_f, chart_type, color_is_measure_names


_CAT_NUM_DTYPES = ('int64', 'double', 'decimal', 'int32')


def _resolve_category_fields(cat_field_candidates, is_hbar, cols, ds_calculations,
                              date_shelf_groupings, all_col_fields):
    """
    Shared category (X-axis / dimension) resolver for bar/column/line/combo
    charts — the single implementation for what used to be two independently
    written copies (a thin shelf-based scan in the dashboard-zone path, and a
    more sophisticated bare-field priority chain in the standalone-page
    path). Handles, in priority order:

      - bin-calc match: a Tableau bin calculated column (e.g. "Tenure (bin)")
        must be referenced by its PBI display name, not the raw source
        column it bins.
      - DATEPART date-hierarchy match: a yr:/qr:/mn:/wk:/dt:-prefixed shelf
        token becomes one or more HierarchyLevel category entries instead of
        a plain column reference.
      - plain column resolution, using an ORDERED CANDIDATE LIST rather than
        a single bare field name — the bare x/y-field can be empty or
        resolve to the wrong thing (e.g. a measure instead of the category)
        depending on chart orientation, the same root cause found repeatedly
        elsewhere in this phase (see _resolve_measure_values).
      - multi-field column-shelf grouping: when Tableau has multiple
        dimensions on the Columns shelf (e.g. Quarter + Client + Year), the
        remaining fields become additional Category entries so Power BI
        renders the full grouping hierarchy — vertical (column) charts only,
        preserving Tableau's own shelf order.
      - final fallback: the first non-numeric, non-measure column in scope.

    cat_field_candidates: ordered list of shelf-token/field-name strings to
    try, most-specific first (e.g. all_col_fields + [x_field] +
    all_col_dim_fields for a vertical chart).
    ds_calculations: the datasource's full calculation list (for bin-calc
    lookup — bin calcs are calculated COLUMNS, not measures, so they live in
    ds['calculations'], not in the pre-filtered value/measure list).
    """
    # ── Bin-calc match (checked across the whole candidate list first —
    # takes priority over plain column / hierarchy resolution regardless of
    # which candidate a bin calc matches) ──────────────────────────────────
    for cand in cat_field_candidates:
        if not cand:
            continue
        bin_calc = next(
            (c for c in ds_calculations
             if c.get('is_bin_calc') and (
                 _field_norm_key(c.get('bin_tableau_name', c['name'])) == _field_norm_key(cand)
                 or _field_norm_key(c['name']) == _field_norm_key(cand)
                 or _field_norm_key(c.get('bin_tableau_name', c['name']).lower()
                                     .replace('(bins)', '(bin)'))
                    == _field_norm_key(cand.lower().replace('(bins)', '(bin)'))
             )),
            None)
        if bin_calc:
            return [{'name': bin_calc['name'], 'datatype': 'double',
                     'measure': False, 'is_measure': False}]

    # ── Plain column resolution (first candidate that resolves to a real,
    # non-numeric, non-measure column) ─────────────────────────────────────
    x_col, cand_used = None, None
    for cand in cat_field_candidates:
        if not cand:
            continue
        c = _lookup_col(cand, cols)
        if c and c.get('datatype', 'string') not in _CAT_NUM_DTYPES and not c.get('measure'):
            x_col, cand_used = c, cand
            break

    if x_col:
        # DATEPART date-hierarchy grouping for the resolved candidate.
        hier_entries = [e for e in date_shelf_groupings
                        if _field_norm_key(e['col']) == _field_norm_key(cand_used)]
        if hier_entries:
            return [
                {**_as_plain_col_item(x_col), 'is_hierarchy_level': True,
                 'hierarchy_level': e['level']}
                for e in hier_entries
            ]

        cat_f = [_as_plain_col_item(x_col)]

        # Multi-field column shelf → grouped X-axis (vertical charts only).
        if not is_hbar and len(all_col_fields) > 1:
            for extra_name in all_col_fields[1:]:
                extra_col = _lookup_col(extra_name, cols)
                if extra_col and not any(
                        _field_norm_key(extra_name) == _field_norm_key(cf['name'])
                        for cf in cat_f):
                    extra_copy = dict(extra_col)
                    extra_nl = extra_name.lower().replace(' ', '')
                    if 'year' in extra_nl or extra_nl == 'yr':
                        extra_copy['datatype'] = 'int64'
                    cat_f.append(_as_plain_col_item(extra_copy))
        return cat_f

    # Final fallback: first non-numeric, non-measure column in scope.
    for c in cols:
        if c.get('datatype', 'string') not in _CAT_NUM_DTYPES and not c.get('measure'):
            return [_as_plain_col_item(c)]
    return []


def _resolve_pie_fields(color_names, cols, msrs, shelf_row_fields,
                         pie_size_field, ds, measure_registry):
    """
    Shared pie/donut category+value resolver. In Tableau, pie/donut charts
    encode: color -> the dimension that creates each slice (PBI Category,
    which also drives per-slice legend coloring — no separate Series role
    needed); wedge-size -> the column whose aggregate drives slice size (PBI
    Y as Aggregation(Column), not a named Measure, unless it's itself a real
    calculated field).

    This is the single implementation for what used to be two independent
    copies: a thin zone-path version (_resolve_pie_cat/_resolve_pie_val,
    color/detail only, no action-filter or synthetic-artifact exclusion,
    and — the actual bug this consolidation fixes — never actually called,
    so every pie/donut zone silently inherited cat_f/val_f left over from
    whichever zone was rendered immediately before it) and a richer,
    never-executed standalone-page-path version (action-filter exclusion,
    'doughnut'-artifact exclusion, a 3-tier wedge-size priority chain).
    """
    # ── Category: first non-action color-encoding dimension ────────────────
    cat_f = []
    for cn in color_names:
        if 'action' in cn.lower():
            continue
        c = _lookup_col(cn, cols)
        if c and not c.get('measure'):
            cat_f = [_as_plain_col_item(c)]
            break
    if not cat_f:
        # Fallback: first non-measure, non-action string column.
        for c in cols:
            if (not c.get('measure')
                    and 'action' not in c.get('name', '').lower()
                    and c.get('datatype', 'string') == 'string'):
                cat_f = [_as_plain_col_item(c)]
                break
    if not cat_f:
        cat_f = [_as_plain_col_item(c) for c in cols[:1] if not c.get('measure')]
    if not cat_f and cols:
        cat_f = [_as_plain_col_item(cols[0])]

    # ── Value: wedge-size priority chain ────────────────────────────────────
    # 1. the wedge-size encoding field itself (measure name takes priority
    #    over a same-named raw column — consistent with every other shared
    #    resolver in this phase, e.g. _resolve_treemap_bubble_fields).
    # 2. shelf_row_fields, excluding synthetic 'Doughnut (copy)'-style helper
    #    calcs Tableau inserts for the donut's inner ring.
    # 3. first real numeric column (excluding doughnut artifacts and the
    #    generic 'Number of Records').
    pie_raw, pie_is_calc = None, False
    if pie_size_field:
        m = _lookup_measure(pie_size_field, msrs)
        if m:
            pie_raw, pie_is_calc = m, True
        else:
            pie_raw = _lookup_col(pie_size_field, cols)
    if pie_raw is None:
        for srf in shelf_row_fields:
            if 'doughnut' in srf.lower():
                continue
            c2 = _lookup_col(srf, cols)
            if c2 and c2.get('measure'):
                pie_raw = c2
                break
    if pie_raw is None:
        for c2 in cols:
            if (c2.get('measure')
                    and 'doughnut' not in c2['name'].lower()
                    and 'number of records' not in c2['name'].lower()):
                pie_raw = c2
                break

    val_f = []
    if pie_raw is not None:
        if pie_is_calc:
            val_f = [{**pie_raw, 'is_measure': True, 'is_pie_agg': False}]
        else:
            reg_item = measure_registry.resolve(pie_raw.get('name', ''), ds)
            if reg_item:
                val_f = [{**reg_item, 'is_measure': True, 'is_pie_agg': False}]
            else:
                val_f = [{**pie_raw, 'is_measure': False, 'is_pie_agg': True}]

    return cat_f, val_f


def _resolve_legend_fields(color_names, cat_f, cols, msrs):
    """
    Shared legend/Series field resolver for bar/column/line/combo/area
    charts — the single implementation for what used to be a thin
    column-only scan in the zone path (`_resolve_leg`, no dedup against the
    already-resolved category field, no calc-based legend support) and a
    richer, never-executed version in the standalone-page path (handles a
    color encoding that resolves to a calculated field, excluding
    boolean/comparison calcs — those produce True/False and can't serve as
    a PBI Series dimension — and dedupes a column that's already the
    Category field).

    Returns possibly more than one entry if color_names lists more than one
    usable field (rare, but the page-path version allowed it and no real
    sample contradicts it).
    """
    _num = ('int64', 'double', 'decimal', 'int32')
    leg_f = []
    for cn in color_names:
        c = _lookup_col(cn, cols)
        if (c and not c.get('measure')
                and c.get('datatype', 'string') not in _num
                and not any(_field_norm_key(c['name']) == _field_norm_key(cf['name'])
                            for cf in cat_f)):
            leg_f.append(_as_plain_col_item(c))
            continue
        if not c:
            calc_c = _lookup_measure(cn, msrs)
            if calc_c:
                formula = (calc_c.get('formula') or '').lower()
                is_bool = any(op in formula for op in ('>', '<', '=', '!='))
                if not is_bool:
                    leg_f.append({**calc_c, 'is_measure': False,
                                  'datatype': calc_c.get('datatype', 'string')})
    return leg_f


def _resolve_combo_roles(val_f, chart_type, measure_names_filter_fields):
    """
    Shared Y (bar/column) vs Y2 (line) role assignment for
    lineClusteredColumnComboChart — the single implementation for what used
    to only exist in the standalone-page path.

    Pattern A only: Measure Names filter active -> measures named in the
    mnff list are line-axis (Y2); any other resolved measure (an explicit
    shelf measure alongside the Measure-Names ones, e.g. Finance Dashboard's
    "DSO vs DPO": Cal_Gap on the shelf, DPO/DSO via mnff) is bar-axis (Y).
    Confirmed against that real worksheet's pane marks (Line, Line, Bar) and
    its rows shelf (Multiple Values + an explicit sum: measure).

    The page path's original "Pattern B" (map each pane's mark type to
    shelf_row_fields by position when no Measure Names filter is active) was
    deliberately dropped rather than ported: verifying it against Finance
    Dashboard's "Revenue vs Profit Margin" showed Tableau's pane list isn't
    reliably one-pane-per-measure (that worksheet has an extra 'Automatic'
    pane carrying a `:Measure Names` color encoding, not a real second
    measure), so a positional mark->field zip produced a confident-looking
    but WRONG split (it flipped a case already correct via
    _make_chart_vc's own "no tags -> first measure bar, rest line" default).
    Guessing here risks a wrong Y/Y2 split, which is worse than leaving that
    default in place — same discipline as the already-blocked Waterfall/Box
    Plot/Gantt native-mapping items. If a future real workbook needs it,
    Pattern B should be re-derived from a case where the pane-to-measure
    correspondence is independently confirmed, not assumed.

    Does nothing if _resolve_measure_values already assigned _combo_role
    (its ratio-vs-value auto-upgrade case) — that tagging is already
    verified; this only fills the gap for charts that were *already*
    lineClusteredColumnComboChart before value resolution ran.
    """
    if chart_type != 'lineClusteredColumnComboChart' or len(val_f) < 2:
        return val_f
    if any(v.get('_combo_role') for v in val_f):
        return val_f

    mnff_names = {_field_norm_key(f) for f in measure_names_filter_fields}
    if not mnff_names:
        return val_f

    for v in val_f:
        v['_combo_role'] = ('line' if _field_norm_key(v['name']) in mnff_names
                             else 'bar')

    bar_vals  = [v for v in val_f if v.get('_combo_role') == 'bar']
    line_vals = [v for v in val_f if v.get('_combo_role') != 'bar']
    return (bar_vals + line_vals) if (bar_vals or line_vals) else val_f


def _maybe_downgrade_stacked(chart_type, leg_f):
    """
    Stacked charts require a separate Series/Legend dimension (distinct from
    the Category axis column) so Power BI can split each bar into segments.
    If no separate stacking column was resolved, downgrade to the clustered
    equivalent — a single-series clustered bar/column chart correctly shows
    one bar per category with the Tableau palette color, instead of Power BI
    rendering a stacked chart with nothing to stack.
    """
    if not leg_f and chart_type in ('barChart', 'columnChart',
                                     'hundredPercentStackedBarChart',
                                     'hundredPercentStackedColumnChart'):
        return ('clusteredBarChart'
                if chart_type in ('barChart', 'hundredPercentStackedBarChart')
                else 'clusteredColumnChart')
    return chart_type


def _resolve_default_sort(explicit_sort_field, explicit_sort_dir, explicit_sort_is_col,
                           chart_type, cat_f, val_f):
    """
    Shared default-sort resolver for column/bar charts when Tableau specified
    no explicit sort. Column and bar charts sort by the primary Y measure
    (descending) by default — matching how PBI authors typically build these
    charts. EXCEPTION: when the category axis is a time-period field
    (Quarter, Month, Year, Week, Day), use ascending category (column) sort
    so the axis reads in natural period order rather than by measure value.
    Line charts and anything else keep natural data order (no OrderBy).
    """
    if explicit_sort_field:
        return explicit_sort_field, explicit_sort_dir, explicit_sort_is_col
    if chart_type not in ('clusteredColumnChart', 'clusteredBarChart',
                          'columnChart', 'barChart',
                          'hundredPercentStackedColumnChart',
                          'hundredPercentStackedBarChart') or not val_f:
        return explicit_sort_field, explicit_sort_dir, explicit_sort_is_col
    import re as _re_sort
    cat_name = cat_f[0]['name'] if cat_f else ''
    if _re_sort.search(r'\b(quarter|month|year|week|day)\b', cat_name, _re_sort.I):
        return cat_name, 1, True     # Ascending column sort
    return val_f[0]['name'], 2, False   # Descending measure sort


def _border_vc_objects(border_color: str, border_width) -> dict:
    """Return a vcObjects 'border' entry for a real Tableau zone border —
    schema-verified against the real Power BI Report Theme JSON Schema
    (github.com/microsoft/powerbi-desktop-samples, definitions.commonCards.
    border: [{show, color, width, radius}]), using the same solid-color /
    'expr':{'Literal':...} wrapper already proven for 'background' (see
    _make_chart_vc's background_color wiring). Only called when
    border_color is truthy — callers already gate on Tableau's own
    <zone-style> border-style != 'none' (see parse_tableau_workbook's
    _collect_zone), so this never fabricates a border Tableau didn't
    explicitly declare.
    """
    return {'border': [{'properties': {
        'show':  {'expr': {'Literal': {'Value': 'true'}}},
        'color': {'solid': {'color': {'expr': {'Literal': {'Value': f"'{border_color}'"}}}}},
        'width': {'expr': {'Literal': {'Value': str(border_width)}}},
    }}]}


def _title_font_vc_properties(font_family='', font_size=0, bold=False,
                               italic=False, color='', bg_color='') -> dict:
    """Extra vcObjects.title 'properties' entries for real Tableau worksheet
    title font/color formatting (<style-rule element='title'> — font-family/
    font-size/font-weight/color/background-color) — schema-verified against
    the real Power BI Report Theme JSON Schema (definitions.commonCards.
    title: fontFamily, fontSize, bold, italic, fontColor, background).
    fontSize uses the 'D' (decimal) M-literal suffix, matching this
    codebase's own existing precedent (_make_card_vc's label fontSize).
    Meant to be spread with ** into an existing title properties dict
    alongside 'text'/'show' — returns only the keys Tableau actually
    declared, nothing invented for unset properties.
    """
    props: dict = {}
    if font_family:
        props['fontFamily'] = {'expr': {'Literal': {'Value': f"'{font_family}'"}}}
    if font_size:
        props['fontSize'] = {'expr': {'Literal': {'Value': f'{font_size}D'}}}
    if bold:
        props['bold'] = {'expr': {'Literal': {'Value': 'true'}}}
    if italic:
        props['italic'] = {'expr': {'Literal': {'Value': 'true'}}}
    if color:
        props['fontColor'] = {'solid': {'color': {'expr': {'Literal': {'Value': f"'{color}'"}}}}}
    if bg_color:
        props['background'] = {'solid': {'color': {'expr': {'Literal': {'Value': f"'{bg_color}'"}}}}}
    return props


def _axis_legend_font_vc_properties(font_family='', font_size=0, bold=False,
                                     italic=False, color='') -> dict:
    """Extra vcObjects 'properties' entries for real Tableau axis-label /
    legend text font formatting (<style-rule element='worksheet'> for axis
    labels, element='legend'> for legend text — font-family/font-size/
    font-weight/color, via _collect_worksheet_style_font).

    Distinct from _title_font_vc_properties: the categoryAxis/valueAxis/
    legend cards use 'labelColor' for text color (not 'fontColor'), per two
    independent real Power BI theme JSON files cross-checked directly
    (Apress's pro-power-bi-theme-creation companion repo and deldersveld's
    PowerBI-ThemeTemplates) — e.g. a real valueAxis card:
    `{"labelColor": {...}, "fontSize": 8, "fontFamily": "Arial", ...}`.
    The lowercase-camelCase gridline property names in both sources
    (`gridlineShow`/`gridlineColor`) match this codebase's own
    already-verified valueAxis.gridlineShow from Increment 20, which is why
    this helper follows the same source's 'labelColor' convention rather
    than the other source's conflicting 'legendColor'/'color' variant.
    Meant to be spread with ** into an existing categoryAxis/valueAxis/
    legend properties dict.
    """
    props: dict = {}
    if font_family:
        props['fontFamily'] = {'expr': {'Literal': {'Value': f"'{font_family}'"}}}
    if font_size:
        props['fontSize'] = {'expr': {'Literal': {'Value': f'{font_size}D'}}}
    if bold:
        props['bold'] = {'expr': {'Literal': {'Value': 'true'}}}
    if italic:
        props['italic'] = {'expr': {'Literal': {'Value': 'true'}}}
    if color:
        props['labelColor'] = {'solid': {'color': {'expr': {'Literal': {'Value': f"'{color}'"}}}}}
    return props


def _make_chart_vc(name, x, y, z, width, height, visual_type,
                   category_fields, value_fields, legend_fields,
                   pbi_table_name, zone_name='', data_colors=None,
                   legend_values=None, explicit_color_map=None,
                   color_is_measure_names=False, show_data_labels=False,
                   label_format='',
                   sort_field=None, sort_dir=1, sort_is_col=True,
                   pane_mark_colors=None,
                   filter_specs=None, filter_fields=None,
                   extra_fields=None,
                   small_multiple_fields=None,
                   reference_lines=None, trendline=None,
                   show_title=True, background_color='',
                   axis_title_value='', axis_title_value2='',
                   axis_title_category='', gridlines_hidden=False,
                   border_color='', border_width=1,
                   title_font_family='', title_font_size=0, title_bold=False,
                   title_italic=False, title_color='', title_bg_color='',
                   axis_label_font_family='', axis_label_font_size=0,
                   axis_label_bold=False, axis_label_italic=False,
                   axis_label_color='',
                   legend_font_family='', legend_font_size=0,
                   legend_bold=False, legend_italic=False, legend_color='',
                   datalabel_font_family='', datalabel_font_size=0,
                   datalabel_bold=False, datalabel_italic=False,
                   datalabel_color='',
                   **kwargs):
    """
    Build a proper chart visual container (column, bar, scatter, pie, line, combo).

    visual_type: 'clusteredColumnChart' | 'clusteredBarChart' |
                 'scatterChart' | 'pieChart' | 'lineChart' | 'areaChart' |
                 'lineClusteredColumnComboChart' | 'tableEx'

    category_fields      : list of column dicts  → X-axis / category
    value_fields         : list of column/measure dicts → Y-axis / size
    legend_fields        : list of column dicts  → series colour split
    data_colors          : ordered palette hex strings (Tableau 10 or custom)
    legend_values        : dict {field_name: [distinct_value_strings, ...]}
    explicit_color_map   : dict {field_name: {value_str: '#hex', ...}}
                           When a Tableau workbook stores explicit color-map
                           assignments for a field's values, use those exact
                           hex colors instead of the default palette ordering.
    color_is_measure_names : bool — True when Tableau colors by ':Measure Names'
                           (each measure gets one color via metadata selector).
    """
    # ── Visual type normalisation ─────────────────────────────────────────────
    # 'bubbleChart' is a Power BI MARKETPLACE custom visual — it is NOT built-in
    # and causes "add custom visual first" errors when opening the .pbix.
    # Remap to the built-in 'scatterChart' which supports X/Y/Size/Details.
    # All other aliases follow the same pattern.
    _VT_REMAP = {
        'bubbleChart': 'scatterChart',   # marketplace custom visual → built-in scatter
        'filledMap':   'map',            # filledMap crashes PBI without exact geo metadata
                                         # → use robust built-in 'map' visual instead
        'bar':         'clusteredBarChart',
        'column':      'clusteredColumnChart',
        'line':        'lineChart',
        'area':        'areaChart',
        'pie':         'pieChart',
        'donut':       'donutChart',
        'scatter':     'scatterChart',
    }
    visual_type = _VT_REMAP.get(visual_type, visual_type)

    T     = pbi_table_name
    alias = T[0].lower()

    # ── Map Tableau chart roles → PBI projection keys ─────────────────────────
    role_map = {
        'clusteredColumnChart':              {'cat': 'Category', 'val': 'Y',  'leg': 'Series'},
        'columnChart':                {'cat': 'Category', 'val': 'Y',  'leg': 'Series'},
        'hundredPercentStackedColumnChart':  {'cat': 'Category', 'val': 'Y',  'leg': 'Series'},
        'clusteredBarChart':                 {'cat': 'Category', 'val': 'Y',  'leg': 'Series'},
        'barChart':                   {'cat': 'Category', 'val': 'Y',  'leg': 'Series'},
        'hundredPercentStackedBarChart':     {'cat': 'Category', 'val': 'Y',  'leg': 'Series'},
        'scatterChart':                      {'cat': 'Details',  'val': 'X',  'leg': 'Legend'},
        'treemap':                           {'cat': 'Category', 'val': 'Y',  'leg': 'Series'},
        'bubbleChart':                       {'cat': 'Details',  'val': 'X',  'leg': 'Legend'},
        'pieChart':                          {'cat': 'Category', 'val': 'Y',  'leg': 'Series'},
        'donutChart':                        {'cat': 'Category', 'val': 'Y',  'leg': 'Series'},
        'lineChart':                         {'cat': 'Category', 'val': 'Y',  'leg': 'Series'},
        'areaChart':                         {'cat': 'Category', 'val': 'Y',  'leg': 'Series'},
        'lineClusteredColumnComboChart':     {'cat': 'Category', 'val': 'Y',  'leg': 'Series'},
        'tableEx':                           {'cat': 'Rows',     'val': 'Values', 'leg': 'Rows'},
    }
    roles = role_map.get(visual_type, role_map['clusteredColumnChart'])
    cat_role = roles['cat']
    val_role = roles['val']
    leg_role = roles['leg']

    # For scatter, Y-axis gets second value field
    y_role = 'Y' if visual_type == 'scatterChart' else None

    # For combo chart, split value_fields: first half → Y (line), second → Y2 (column)
    is_combo = visual_type == 'lineClusteredColumnComboChart'

    # ── Build Select list ─────────────────────────────────────────────────────
    def _col_sel(c):
        return {
            'Column': {'Expression': {'SourceRef': {'Source': alias}},
                       'Property': c['name']},
            'Name': f"{T}.{c['name']}"
        }
    def _hier_sel(c):
        """HierarchyLevel select for a DATEPART-grouped date column.
        Emits the PBI 'Date Hierarchy' PropertyVariationSource expression used
        when a Tableau chart has DATEPART(year/quarter/month/…, [DateField])
        on a shelf.  Level is stored in c['hierarchy_level'] (e.g. 'Year').
        Name format: T.col.Variation.Date Hierarchy.Level
        NativeReferenceName: 'col Level' (e.g. 'Order Date Year')
        """
        level = c.get('hierarchy_level', 'Year')
        col   = c['name']
        return {
            'HierarchyLevel': {
                'Expression': {
                    'Hierarchy': {
                        'Expression': {
                            'PropertyVariationSource': {
                                'Expression': {'SourceRef': {'Source': alias}},
                                'Name': 'Variation',
                                'Property': col
                            }
                        },
                        'Hierarchy': 'Date Hierarchy'
                    }
                },
                'Level': level
            },
            'Name': f"{T}.{col}.Variation.Date Hierarchy.{level}",
            'NativeReferenceName': f"{col} {level}"
        }
    def _hier_queryref(c):
        """Return the projection queryRef for a HierarchyLevel category field."""
        return f"{T}.{c['name']}.Variation.Date Hierarchy.{c.get('hierarchy_level','Year')}"
    def _msr_sel(c):
        return {
            'Measure': {'Expression': {'SourceRef': {'Source': alias}},
                        'Property': c['name']},
            'Name': f"{T}.{c['name']}"
        }
    def _agg_sel(c):
        """Aggregation(Column, Sum=0) for any numeric column Y-axis value.
        Uses Sum(T.col) Name and 'Sum of col' NativeReferenceName so the
        projection queryRef and the prototypeQuery Select Name both agree,
        allowing PBI to bind the aggregated value to the axis correctly."""
        return {
            'Aggregation': {
                'Expression': {
                    'Column': {
                        'Expression': {'SourceRef': {'Source': alias}},
                        'Property': c['name']
                    }
                },
                'Function': 0     # 0 = Sum
            },
            'Name': f"Sum({T}.{c['name']})",
            'NativeReferenceName': f"Sum of {c['name']}"
        }

    def _agg_count_sel(c):
        """Aggregation(Column, CountNonNull=fn5) — used for Tableau cnt: shelf prefix.
        Equivalent to COUNTA; PBI Function=5 = CountNonNull."""
        return {
            'Aggregation': {
                'Expression': {
                    'Column': {
                        'Expression': {'SourceRef': {'Source': alias}},
                        'Property': c['name']
                    }
                },
                'Function': 5     # 5 = CountNonNull ≈ COUNTA
            },
            'Name': f"CountNonNull({T}.{c['name']})"
        }

    def _scatter_col_sel(c):
        """Column reference for scatter X/Y with NativeReferenceName.
        The reference PBIT uses:
          Name = "Sum(T.ColName)",  NativeReferenceName = "ColName"
        PBI displays NativeReferenceName as the axis label."""
        return {
            'Column': {'Expression': {'SourceRef': {'Source': alias}},
                       'Property': c['name']},
            'Name': f"Sum({T}.{c['name']})",
            'NativeReferenceName': c['name']
        }

    def _pie_agg_sel(c):
        """Aggregation(Column, Sum=0) for pie/donut Y value.
        PBI pie/donut charts require a raw Aggregation, NOT a named Measure.
        queryRef uses "Sum(T.ColName)" prefix; NativeReferenceName = "Sum of ColName"."""
        return {
            'Aggregation': {
                'Expression': {
                    'Column': {
                        'Expression': {'SourceRef': {'Source': alias}},
                        'Property': c['name']
                    }
                },
                'Function': 0    # 0 = Sum
            },
            'Name': f"Sum({T}.{c['name']})",
            'NativeReferenceName': f"Sum of {c['name']}"
        }

    # Detect pie/donut — these need special Category+Series dual roles and Aggregation value
    is_pie_donut = visual_type in ('pieChart', 'donutChart')

    # Detect ordering patterns needed for all_sel and selects_dt
    is_stacked_with_cnt = (
        visual_type in ('columnChart', 'barChart',
                        'clusteredColumnChart', 'clusteredBarChart',
                        'hundredPercentStackedColumnChart', 'hundredPercentStackedBarChart')
        and any(c.get('is_agg_count') for c in value_fields)
        and bool(legend_fields)
    )
    # Bin-category stacked charts (e.g. Tenure Churn): reference emits Y → Series → Category.
    cat_is_bin = (is_stacked_with_cnt and bool(category_fields)
                  and category_fields[0].get('datatype') == 'int64'
                  and not category_fields[0].get('measure'))

    def _cat_sel(c):
        """Emit _hier_sel for DATEPART-grouped date fields, _col_sel for everything else."""
        return _hier_sel(c) if c.get('is_hierarchy_level') else _col_sel(c)

    all_sel = []
    # For bin-category stacked charts: emit category LAST (Y → Series → Category)
    if not (is_stacked_with_cnt and cat_is_bin):
        for c in category_fields:
            all_sel.append(_cat_sel(c))

    # For stacked column/bar charts with an agg_count Y value AND a legend field:
    # the reference PBIT emits the Series (legend) column BEFORE the Y Aggregation.
    # Order: Category → Series → Y
    # For scatter: Details → Legend → X → Y

    if visual_type == 'scatterChart':
        # Scatter: Details (already in category_fields) → Legend → X → Y
        for c in legend_fields:
            all_sel.append(_col_sel(c))
        for c in value_fields:
            if c.get('is_scatter_col'):
                all_sel.append(_scatter_col_sel(c))
            elif c.get('is_agg'):
                all_sel.append(_agg_sel(c))
            elif c.get('is_measure'):
                all_sel.append(_msr_sel(c))
            else:
                all_sel.append(_col_sel(c))
    elif is_stacked_with_cnt:
        # Stacked chart with cnt Y: two sub-cases based on whether category is bin:
        # - Bin category (e.g. Tenure Bin): REF order is Y → Series → Category
        # - Non-bin category (e.g. Contract): REF order is Category → Series → Y
        if cat_is_bin:
            # Y → Series → Category  (bin-column category)
            for c in value_fields:
                if c.get('is_agg_count'):
                    all_sel.append(_agg_count_sel(c))
                elif c.get('is_measure'):
                    all_sel.append(_msr_sel(c))
                else:
                    all_sel.append(_col_sel(c))
            for c in legend_fields:
                all_sel.append(_col_sel(c))
            for c in category_fields:
                all_sel.append(_cat_sel(c))
        else:
            # Category → Series → Y  (standard dimension category)
            # (category already added above)
            for c in legend_fields:
                all_sel.append(_col_sel(c))
            for c in value_fields:
                if c.get('is_agg_count'):
                    all_sel.append(_agg_count_sel(c))
                elif c.get('is_pie_agg'):
                    all_sel.append(_pie_agg_sel(c))
                elif c.get('is_measure'):
                    all_sel.append(_msr_sel(c))
                elif c.get('is_agg'):
                    all_sel.append(_agg_sel(c))
                else:
                    all_sel.append(_col_sel(c))
    else:
        # Standard: Category → Y value(s) → Series
        # Priority: is_agg_count > is_pie_agg > is_measure > is_agg > column
        # is_measure is checked BEFORE is_agg so registry-promoted fields
        # (is_measure=True after dependency propagation) emit _msr_sel
        # (named Measure reference) not _agg_sel (inline Aggregation).
        for c in value_fields:
            if c.get('is_agg_count'):
                all_sel.append(_agg_count_sel(c))
            elif c.get('is_pie_agg'):
                all_sel.append(_pie_agg_sel(c))
            elif c.get('is_measure'):
                all_sel.append(_msr_sel(c))
            elif c.get('is_agg'):
                all_sel.append(_agg_sel(c))
            else:
                all_sel.append(_col_sel(c))
        for c in legend_fields:
            all_sel.append(_col_sel(c))

    # ── Projections ───────────────────────────────────────────────────────────
    projections = {}
    base_idx = 0

    if category_fields and not (is_stacked_with_cnt and cat_is_bin):
        projections[cat_role] = [
            {'queryRef': _hier_queryref(c), 'active': True}
            if c.get('is_hierarchy_level')
            else {'queryRef': f"{T}.{c['name']}", 'active': True}
            for c in category_fields
        ]
        # Pie/donut: category field also needs a Series projection (without active).
        # PBI uses Series to assign per-slice colors — without it all slices are one colour.
        if is_pie_donut:
            projections['Series'] = [
                {'queryRef': f"{T}.{c['name']}"}
                for c in category_fields
            ]

    def _val_qref(c):
        """
        Return the queryRef string for a value field.

        Must exactly match the 'Name' field emitted in the Select list so
        PBI can bind each select entry to the correct projection slot.

        Priority (mirrors _make_val_sel_dt and all_sel dispatch):
          is_agg_count                                → CountNonNull(T.col)
          is_pie_agg                                  → Sum(T.col)
          is_measure (checked before is_agg so that
            registry-promoted fields use T.col even  → T.col
            when legacy code also set is_agg=True)
          is_scatter_col / is_agg                     → Sum(T.col)
          plain column                                → T.col
        """
        if c.get('is_agg_count'):
            return f"CountNonNull({T}.{c['name']})"
        if c.get('is_pie_agg'):
            return f"Sum({T}.{c['name']})"
        if c.get('is_measure'):
            # Named semantic measure — always T.col regardless of is_agg flag
            return f"{T}.{c['name']}"
        if c.get('is_scatter_col') or c.get('is_agg'):
            return f"Sum({T}.{c['name']})"
        return f"{T}.{c['name']}"

    val_idx_start = len(category_fields)
    if value_fields:
        if visual_type == 'scatterChart' and len(value_fields) >= 2:
            projections['X'] = [{'queryRef': _val_qref(value_fields[0]), 'active': True}]
            projections['Y'] = [{'queryRef': _val_qref(value_fields[1])}]   # no 'active' on Y
        elif is_combo and len(value_fields) >= 2:
            # PBI lineClusteredColumnComboChart:
            #   Y  = clustered column (bar) axis
            #   Y2 = line axis
            # The val_f reorder in build_report_layout already puts bar measures
            # first (Bar/GanttBar pane marks) then line measures.
            # Detect the split point: count how many leading values came from
            # bar panes (tagged '_combo_role'='bar' by the reorder block, or
            # default to 1 bar + rest line when no tags are present).
            _n_bar = sum(1 for v in value_fields if v.get('_combo_role') == 'bar')
            if _n_bar == 0 or _n_bar == len(value_fields):
                _n_bar = 1   # fallback: first → Y (bar), rest → Y2 (line)
            projections['Y']  = [{'queryRef': _val_qref(c), 'active': True}
                                  for c in value_fields[:_n_bar]]
            projections['Y2'] = [{'queryRef': _val_qref(c), 'active': True}
                                  for c in value_fields[_n_bar:]]
        else:
            # agg_count, pie_agg, and is_agg Y projections omit 'active' (matches reference)
            projections[val_role] = [
                ({'queryRef': _val_qref(c)}
                 if (c.get('is_agg_count') or c.get('is_pie_agg') or c.get('is_agg'))
                 else {'queryRef': _val_qref(c), 'active': True})
                for c in value_fields
            ]

    if legend_fields:
        projections[leg_role] = [
            {'queryRef': f"{T}.{c['name']}", 'active': True}
            for c in legend_fields
        ]
        # For scatter charts, the color/legend field (e.g. Churn) must also appear
        # as a separate 'Series' projection entry — this is what tells PBI to render
        # one color per Series value, making the Legend panel actually assign colors.
        # The reference PBIT has: Legend: [{Churn, active:true}], Series: [{Churn}]
        # Without the Series projection, PBI renders a legend panel but doesn't
        # split markers by color — all dots appear in one color.
        if visual_type == 'scatterChart':
            projections['Series'] = [
                {'queryRef': f"{T}.{c['name']}"}   # no 'active' key on Series
                for c in legend_fields
            ]

    # For bin-category stacked charts, Category projection comes after Y and Series.
    # The Series projection also omits 'active' in the reference for bin-category charts.
    if is_stacked_with_cnt and cat_is_bin and category_fields:
        if leg_role in projections:
            projections[leg_role] = [   # re-emit without 'active'
                {'queryRef': f"{T}.{c['name']}"}
                for c in legend_fields
            ]
        projections[cat_role] = [
            {'queryRef': _hier_queryref(c), 'active': True}
            if c.get('is_hierarchy_level')
            else {'queryRef': f"{T}.{c['name']}", 'active': True}
            for c in category_fields
        ]

    # ── Extra projections: Group / Values / Details (treemap, bubble) ─────────
    # extra_fields = {'Group': [col_dict, …], 'Values': [col_dict, …], …}
    # Values fields use Sum() format (like is_pie_agg); others use plain Column.
    if extra_fields:
        for _role, _flds in extra_fields.items():
            _proj_entries = []
            for _c in _flds:
                if _c.get('is_agg_count'):
                    _proj_entries.append({'queryRef': f"CountNonNull({T}.{_c['name']})"})
                elif _c.get('is_pie_agg') or _c.get('is_agg'):
                    _proj_entries.append({'queryRef': f"Sum({T}.{_c['name']})"})
                elif _c.get('is_measure'):
                    _proj_entries.append({'queryRef': f"{T}.{_c['name']}", 'active': True})
                else:
                    _proj_entries.append({'queryRef': f"{T}.{_c['name']}", 'active': True})
            if _proj_entries:
                projections[_role] = _proj_entries

    # ── FIX: Small Multiples projection (Tableau Pages shelf → PBI SmallMultiple)
    # When Tableau has a field on the Pages shelf, it creates one chart per value
    # of that field — called "small multiples" in PBI (projection role 'SmallMultiple').
    # PBI supports SmallMultiple for: clusteredColumnChart, clusteredBarChart,
    # lineChart, areaChart (not combo, pie, scatter, table).
    _sm_fields = kwargs.get('small_multiple_fields', [])
    _sm_vis_types = {
        'clusteredColumnChart', 'clusteredBarChart', 'lineChart', 'areaChart',
        'stackedColumnChart', 'stackedBarChart',
    }
    if _sm_fields and visual_type in _sm_vis_types:
        projections['SmallMultiple'] = [
            {'queryRef': f"{T}.{c['name']}", 'active': True}
            for c in _sm_fields
        ]

    # ── dataTransforms selects ────────────────────────────────────────────────
    def _underlying_type(c):
        dt = c.get('datatype', 'string')
        if dt == 'double':            return 259
        if dt == 'int64':             return 261
        if dt in ('date', 'dateTime'): return 519   # PBI dateTime underlying type
        return 1

    def _col_format(c):
        """Return the PBI format string for a column's datatype."""
        dt = c.get('datatype', 'string')
        if dt in ('date', 'dateTime'): return 'D'   # date display format
        if dt == 'double':             return '#,0.##'
        if dt == 'int64':              return '#,0'
        return ''

    def _make_val_sel_dt(c, r):
        """Build a single dataTransforms select entry for a value field."""
        is_msr         = c.get('is_measure',    False)
        is_agg         = c.get('is_agg',        False)
        is_agg_count   = c.get('is_agg_count',  False)
        is_scatter_col = c.get('is_scatter_col', False)
        is_pie_agg     = c.get('is_pie_agg',    False)
        display_name   = c.get('_display_name', c['name'])
        # Priority:
        #  1. is_agg_count  — CountNonNull aggregation (always inline)
        #  2. is_pie_agg    — pie/donut Sum aggregation (always inline per PBI spec)
        #  3. is_measure    — semantic DAX Measure (check BEFORE is_agg so
        #                     registry-promoted fields use Measure expression)
        #  4. is_scatter_col — scatter X/Y column reference
        #  5. is_agg        — raw numeric column inline Sum (no pre-built measure)
        #  6. plain column
        if is_agg_count:
            expr_dt = {'Aggregation': {'Expression': {'Column': {
                'Expression': {'SourceRef': {'Entity': T}}, 'Property': c['name']}},
                'Function': 5}}
            qname = f"CountNonNull({T}.{c['name']})"
        elif is_pie_agg:
            # Pie/donut always uses inline Aggregation per PBI visual spec.
            expr_dt = {'Aggregation': {'Expression': {'Column': {
                'Expression': {'SourceRef': {'Entity': T}}, 'Property': c['name']}},
                'Function': 0}}
            qname = f"Sum({T}.{c['name']})"
            display_name = f"Sum of {c['name']}"
        elif is_msr:
            # Semantic DAX Measure — wins over is_agg for registry-promoted fields
            expr_dt = {'Measure': {'Expression': {'SourceRef': {'Entity': T}},
                                   'Property': c['name']}}
            qname = f"{T}.{c['name']}"
        elif is_scatter_col:
            expr_dt = {'Column': {'Expression': {'SourceRef': {'Entity': T}},
                                   'Property': c['name']}}
            qname = f"Sum({T}.{c['name']})"
        elif is_agg:
            # Raw numeric column with no pre-built measure — inline Sum aggregation.
            expr_dt = {'Aggregation': {'Expression': {'Column': {
                'Expression': {'SourceRef': {'Entity': T}}, 'Property': c['name']}},
                'Function': 0}}
            qname        = f"Sum({T}.{c['name']})"
            display_name = f"Sum of {c['name']}"
        else:
            expr_dt = {'Column': {'Expression': {'SourceRef': {'Entity': T}},
                                   'Property': c['name']}}
            qname = f"{T}.{c['name']}"
        return {'displayName': display_name, 'queryName': qname,
                'roles': {r: True},
                'type': {'category': None, 'underlyingType': _underlying_type(c)},
                'expr': expr_dt}

    def _make_leg_sel_dt(c):
        """Build a dataTransforms select entry for a legend/series field."""
        leg_roles = {leg_role: True}
        if visual_type == 'scatterChart':
            leg_roles['Series'] = True
        return {'displayName': c['name'], 'queryName': f"{T}.{c['name']}",
                'roles': leg_roles,
                'type': {'category': None, 'underlyingType': _underlying_type(c)},
                'expr': {'Column': {'Expression': {'SourceRef': {'Entity': T}},
                                    'Property': c['name']}}}

    selects_dt = []
    # For bin-category stacked charts (cat_is_bin): emit Category LAST
    if not (is_stacked_with_cnt and cat_is_bin):
        for c in category_fields:
            # Pie/donut: category field needs BOTH 'Category' and 'Series' roles.
            cat_roles = {cat_role: True}
            if is_pie_donut:
                cat_roles['Series'] = True

            if c.get('is_hierarchy_level'):
                # DATEPART-grouped date column → HierarchyLevel expression
                level  = c.get('hierarchy_level', 'Year')
                qname  = _hier_queryref(c)
                entry  = {
                    'displayName': level,           # e.g. 'Year', 'Month'
                    'queryName':   qname,
                    'roles':       cat_roles,
                    'type':        {'category': None, 'underlyingType': 519},
                    'expr': {
                        'HierarchyLevel': {
                            'Expression': {
                                'Hierarchy': {
                                    'Expression': {
                                        'PropertyVariationSource': {
                                            'Expression': {'SourceRef': {'Entity': T}},
                                            'Name': 'Variation',
                                            'Property': c['name']
                                        }
                                    },
                                    'Hierarchy': 'Date Hierarchy'
                                }
                            },
                            'Level': level
                        }
                    }
                }
            else:
                entry = {
                    'displayName': c['name'],
                    'queryName':   f"{T}.{c['name']}",
                    'roles':       cat_roles,
                    'type':        {'category': None, 'underlyingType': _underlying_type(c)},
                    'expr':        {'Column': {'Expression': {'SourceRef': {'Entity': T}},
                                               'Property': c['name']}}
                }
                fmt = _col_format(c)
                if fmt:
                    entry['format'] = fmt
                # Add sort metadata when this category field IS the sort field.
                if (sort_field and sort_is_col
                        and c['name'].lower() == sort_field.lower()
                        and sort_dir == 1):
                    entry['sort']      = 1
                    entry['sortOrder'] = 0
            selects_dt.append(entry)

    if visual_type == 'scatterChart':
        # Scatter order: Details (category) → Legend+Series → X → Y
        for c in legend_fields:
            selects_dt.append(_make_leg_sel_dt(c))
        for i, c in enumerate(value_fields):
            selects_dt.append(_make_val_sel_dt(c, 'X' if i == 0 else 'Y'))
    elif is_stacked_with_cnt and cat_is_bin:
        # Bin-category stacked: Y → Series → Category
        for c in value_fields:
            selects_dt.append(_make_val_sel_dt(c, val_role))
        for c in legend_fields:
            selects_dt.append(_make_leg_sel_dt(c))
        for c in category_fields:
            entry = {
                'displayName': c['name'],
                'queryName':   f"{T}.{c['name']}",
                'roles':       {cat_role: True},
                'type':        {'category': None, 'underlyingType': _underlying_type(c)},
                'expr':        {'Column': {'Expression': {'SourceRef': {'Entity': T}},
                                           'Property': c['name']}}
            }
            selects_dt.append(entry)
    elif is_stacked_with_cnt:
        # Non-bin stacked cnt: Category (already added) → Series → Y
        for c in legend_fields:
            selects_dt.append(_make_leg_sel_dt(c))
        for c in value_fields:
            selects_dt.append(_make_val_sel_dt(c, val_role))
    else:
        # Standard: Category → Y/value(s) → Series
        for i, c in enumerate(value_fields):
            r = 'Y' if is_combo and i == 0 else ('Y2' if is_combo else val_role)
            selects_dt.append(_make_val_sel_dt(c, r))
        for c in legend_fields:
            selects_dt.append(_make_leg_sel_dt(c))

    # ── Extra selects: Group / Values / Details (treemap, bubble) ────────────
    if extra_fields:
        for _role, _flds in extra_fields.items():
            for _c in _flds:
                if _c.get('is_pie_agg') or _c.get('is_agg'):
                    selects_dt.append(_make_val_sel_dt(_c, _role))
                else:
                    # Build roles dict — Details in bubble also gets Category role
                    _roles = {_role: True}
                    if _role == 'Details' and visual_type == 'scatterChart':
                        _roles['Category'] = True
                    selects_dt.append({
                        'displayName': _c['name'],
                        'queryName':   f"{T}.{_c['name']}",
                        'roles':       _roles,
                        'type':        {'category': None, 'underlyingType': _underlying_type(_c)},
                        'expr':        {'Column': {'Expression': {'SourceRef': {'Entity': T}},
                                                   'Property': _c['name']}}
                    })

    proj_ord = {}
    idx = 0
    if category_fields:
        proj_ord[cat_role] = list(range(idx, idx + len(category_fields)))
        idx += len(category_fields)
    if value_fields:
        if visual_type == 'scatterChart' and len(value_fields) >= 2:
            proj_ord['X'] = [idx];     idx += 1
            proj_ord['Y'] = [idx];     idx += 1
        elif is_combo and len(value_fields) >= 2:
            proj_ord['Y']  = [idx];    idx += 1
            proj_ord['Y2'] = list(range(idx, idx + len(value_fields) - 1))
            idx += len(value_fields) - 1
        else:
            proj_ord[val_role] = list(range(idx, idx + len(value_fields)))
            idx += len(value_fields)
    if legend_fields:
        proj_ord[leg_role] = list(range(idx, idx + len(legend_fields)))
        idx += len(legend_fields)
    if extra_fields:
        for _role, _flds in extra_fields.items():
            if _flds:
                proj_ord[_role] = list(range(idx, idx + len(_flds)))
                idx += len(_flds)

    data_transforms = {
        'projectionOrdering':    proj_ord,
        'projectionActiveItems': {
            k: [
                # queryRef MUST match the Name in the Select list exactly.
                # _val_qref() dispatches purely on the column's own flags
                # (is_agg_count/is_pie_agg/is_measure/is_scatter_col/is_agg),
                # not on which role it's projected into, so it's correct for
                # ANY role — including extra_fields roles like bubble/treemap
                # 'Size' and 'Values', which previously fell through to a bare
                # 'T.col' queryRef here even when their actual Select entry
                # (built by _make_val_sel_dt, same flag dispatch) used
                # 'Sum(T.col)' — a queryRef/Select-Name mismatch that risks a
                # "can't load this field" repair prompt in Power BI Desktop.
                {'queryRef': _val_qref(c), 'suppressConcat': False}
                for c in (category_fields if k == cat_role
                          else (value_fields if k in (val_role, 'X', 'Y', 'Y2')
                                else (legend_fields if k == leg_role
                                      else (extra_fields or {}).get(k, []))))
            ]
            for k in proj_ord
        },
        'queryMetadata': {
            'Select': [
                {
                     # Type: 1=Measure, 2=Column, 4=Aggregation
                     # Pick the innermost Property name for Restatement.
                     'Restatement': (
                         s.get('Measure',
                               s.get('Column',
                                     s.get('Aggregation', {})
                                      .get('Expression', {})
                                      .get('Column', {})))
                          .get('Property', '')
                     ),
                     'Name': s['Name'],
                     'Type': (1 if 'Measure' in s
                              else 4 if 'Aggregation' in s
                              else 2)
                }
                for s in all_sel
            ]
        },
        'visualElements': [{
            'DataRoles': [
                {'Name': role, 'Projection': i, 'isActive': True}
                for role, idxs in proj_ord.items()
                for i in idxs
            ]
        }],
        'selects': selects_dt
    }

    # ── Build OrderBy expression ──────────────────────────────────────────────
    # Sort strategy (generic, applies to all chart types):
    #
    # 1. When a Tableau <sort> element is present → honour it exactly.
    # 2. When the category axis has a HierarchyLevel (DATEPART date grouping):
    #    → sort ascending by every HierarchyLevel field on the axis (chronological).
    # 3. When no explicit sort and no date grouping on category axis:
    #    → sort ascending by the first plain Column category field (alphabetical).
    # 4. When there is no meaningful category to sort by (scatter, bubble, etc.):
    #    → sort descending by the first Y Aggregation (highest-value first).
    #
    # This produces ascending-date for time-series, ascending-category for bar/column,
    # and measure-descending for unordered visuals — matching the reference behaviour.

    order_by = []

    if sort_field:
        # Explicit Tableau sort spec
        if sort_is_col:
            order_by = [{
                'Direction': sort_dir,
                'Expression': {
                    'Column': {
                        'Expression': {'SourceRef': {'Source': alias}},
                        'Property': sort_field
                    }
                }
            }]
        else:
            msr_match = next(
                (c for c in value_fields if c.get('name','').lower() == sort_field.lower()),
                None
            )
            # is_measure=True → named DAX Measure sort expression
            # is_agg=True only → inline Aggregation sort expression
            # (is_agg may be True even after registry promotion; is_measure wins)
            if msr_match and msr_match.get('is_measure') and not msr_match.get('is_agg'):
                order_by = [{
                    'Direction': sort_dir,
                    'Expression': {
                        'Measure': {
                            'Expression': {'SourceRef': {'Source': alias}},
                            'Property': msr_match['name']
                        }
                    }
                }]
            else:
                # Inline aggregation sort — used for is_agg fields and unknowns
                _sort_prop = msr_match['name'] if msr_match else sort_field
                order_by = [{
                    'Direction': sort_dir,
                    'Expression': {
                        'Aggregation': {
                            'Expression': {
                                'Column': {
                                    'Expression': {'SourceRef': {'Source': alias}},
                                    'Property': _sort_prop
                                }
                            },
                            'Function': 0
                        }
                    }
                }]

    elif category_fields:
        # No explicit sort — derive sort from category axis type.
        # Separate plain columns from HierarchyLevel fields.
        plain_cats  = [c for c in category_fields if not c.get('is_hierarchy_level')]
        hier_cats   = [c for c in category_fields if c.get('is_hierarchy_level')]

        # Build ascending-column OrderBy for each plain dimension category.
        # FIX: For month-name string columns (Month, Mon, etc.) sort by the
        # hidden "Month Number" integer column (added as a real M Table.AddColumn
        # step) so PBI orders Jan→Feb→...→Dec instead of alphabetical Apr→Aug→Dec.
        _MONTH_KEYWORDS = {'month', 'mon'}
        for c in plain_cats:
            _cname_l = c['name'].lower().replace(' ', '').replace('_', '')
            _is_month = any(kw in _cname_l for kw in _MONTH_KEYWORDS)
            if _is_month:
                # Sort by the hidden integer Month Number column
                _num_col = c['name'] + ' Number'
                order_by.append({
                    'Direction': 1,
                    'Expression': {
                        'Column': {
                            'Expression': {'SourceRef': {'Source': alias}},
                            'Property': _num_col
                        }
                    }
                })
            else:
                order_by.append({
                    'Direction': 1,   # ascending
                    'Expression': {
                        'Column': {
                            'Expression': {'SourceRef': {'Source': alias}},
                            'Property': c['name']
                        }
                    }
                })

        # Build ascending-HierarchyLevel OrderBy for each date-grouped category.
        for c in hier_cats:
            level = c.get('hierarchy_level', 'Year')
            order_by.append({
                'Direction': 1,   # ascending (chronological)
                'Expression': {
                    'HierarchyLevel': {
                        'Expression': {
                            'Hierarchy': {
                                'Expression': {
                                    'PropertyVariationSource': {
                                        'Expression': {'SourceRef': {'Source': alias}},
                                        'Name': 'Variation',
                                        'Property': c['name']
                                    }
                                },
                                'Hierarchy': 'Date Hierarchy'
                            }
                        },
                        'Level': level
                    }
                }
            })

        # If ONLY value/measure fields exist on both axes (e.g. scatter/bubble),
        # fall back to measure-descending on the first Y value.
        if not order_by and value_fields:
            _y = value_fields[0]
            if _y.get('is_measure'):
                order_by = [{
                    'Direction': 2,
                    'Expression': {
                        'Measure': {
                            'Expression': {'SourceRef': {'Source': alias}},
                            'Property': _y['name']
                        }
                    }
                }]
            elif _y.get('is_agg') or _y.get('is_pie_agg'):
                order_by = [{
                    'Direction': 2,
                    'Expression': {
                        'Aggregation': {
                            'Expression': {
                                'Column': {
                                    'Expression': {'SourceRef': {'Source': alias}},
                                    'Property': _y['name']
                                }
                            },
                            'Function': 0
                        }
                    }
                }]

    proto_query = {
        'Version': 2,
        'From': [{'Name': alias, 'Entity': T, 'Type': 0}],
        'Select': all_sel,
        'OrderBy': order_by
    }

    query = {
        'Commands': [{
            'SemanticQueryDataShapeCommand': {
                'Query': proto_query,
                'Binding': {
                    'Primary': {'Groupings': [{'Projections': list(range(len(all_sel)))}]},
                    'DataReduction': {'DataVolume': 4, 'Primary': {'Window': {'Count': 1000}}},
                    'Version': 1
                },
                'ExecutionMetricsKind': 1
            }
        }]
    }

    tab_order = z * 1000

    # ── Build dataPoint color objects from the Tableau palette ────────────────
    #
    # Three cases handled in priority order:
    #
    # A) Explicit color-map in TWB (<color-map><bucket value="'v'" color="#hex"/>):
    #    The author deliberately chose colors per value — use those exactly,
    #    no sorting needed (order from the map).
    #
    # B) Coloring by :Measure Names (each measure/field gets one color):
    #    Use {"metadata": "Table.FieldName"} selector — one entry per value_field.
    #    This matches what PBI Desktop generates for multi-measure colored charts.
    #
    # C) Dimension legend field with known distinct values (default palette):
    #    Sort values ALPHABETICALLY before assigning colors.
    #    Tableau's default color assignment for unordered string dimensions is
    #    alphabetical — 'No' < 'Yes' so No=color[0], Yes=color[1].
    #    NOT first-appearance order.
    #
    # D) Single-series chart (no legend field):
    #    One dataPoint entry with selector=null.
    objects_cfg: dict = {}
    colors = data_colors or []

    if colors and visual_type not in ('tableEx',):
        dp_entries = []
        ecm = explicit_color_map or {}   # {field_name: {value: hex}}

        leg_field = legend_fields[0] if legend_fields else None

        if color_is_measure_names:
            # ── Case B: color by Measure Names ───────────────────────────────
            # Each value_field (measure/pane) gets one entry with a metadata selector
            # (queryName = "Table.FieldName").
            #
            # Per-pane mark-color/stroke-color from Tableau style rules take priority
            # over the default palette when available.  This preserves author-defined
            # series colors on dual-axis and multi-measure charts (e.g. a bar series
            # explicitly colored #6b167e by the Tableau workbook author).
            for i, vf in enumerate(value_fields):
                pane_c = (pane_mark_colors[i]
                          if pane_mark_colors
                          and i < len(pane_mark_colors)
                          and pane_mark_colors[i]
                          else None)
                hex_color = pane_c if pane_c else colors[i % len(colors)]
                query_name = f"{T}.{vf['name']}"
                dp_entries.append({
                    'properties': {'fill': {'solid': {'color': {
                        'expr': {'Literal': {'Value': f"'{hex_color}'"}}
                    }}}},
                    'selector': {'metadata': query_name}
                })

        elif leg_field:
            leg_name = leg_field['name']
            leg_vals_raw = (legend_values or {}).get(leg_name, [])

            # Helper: build a scopeId.Comparison selector for a specific value.
            # The reference PBIT uses this format alongside data:[] entries:
            #   { "selector": { "data": [{ "scopeId": { "Comparison": {
            #       "ComparisonKind": 0,
            #       "Left": { "Column": {..., "Property": "Churn"} },
            #       "Right": { "Literal": { "Value": "'Yes'" } }
            #   }}}]}}
            def _scope_selector(col_name, val):
                safe = val.replace("'", "\\'")
                return {'data': [{'scopeId': {'Comparison': {
                    'ComparisonKind': 0,
                    'Left': {'Column': {
                        'Expression': {'SourceRef': {'Entity': T}},
                        'Property': col_name
                    }},
                    'Right': {'Literal': {'Value': f"'{safe}'"}}
                }}}]}

            # Helper: build an expr.In selector (keep for explicit color-map case)
            def _in_selector(col_name, val):
                safe = val.replace("'", "\\'")
                return {'data': [{'expr': {'In': {
                    'Expressions': [{'Column': {
                        'Expression': {'SourceRef': {'Entity': T}},
                        'Property': col_name
                    }}],
                    'Values': [[{'Literal': {'Value': f"'{safe}'"}}]]
                }}}]}

            # ── Case A: explicit color-map for this field ─────────────────────
            field_ecm = ecm.get(leg_name, {})
            if field_ecm and leg_vals_raw:
                # Use exact author-specified colors; iterate in explicit-map order.
                # Emit palette-indexed entries (data:[]) first, then scopeId entries.
                vals_ordered = [v for v in field_ecm if v in leg_vals_raw]
                leg_vals_sorted_a = sorted(leg_vals_raw)
                # Palette entries (data:[]) — one per value at palette index
                for i, val in enumerate(leg_vals_sorted_a):
                    hc = list(field_ecm.values())[i % len(field_ecm)] \
                         if i < len(field_ecm) else colors[i % len(colors)]
                    dp_entries.append({
                        'properties': {'fill': {'solid': {'color': {
                            'expr': {'Literal': {'Value': f"'{hc}'"}}
                        }}}},
                        'selector': {'data': []}
                    })
                # scopeId entries — one per explicit value
                for val, hex_color in field_ecm.items():
                    if val in leg_vals_raw:
                        dp_entries.append({
                            'properties': {'fill': {'solid': {'color': {
                                'expr': {'Literal': {'Value': f"'{hex_color}'"}}
                            }}}},
                            'selector': _scope_selector(leg_name, val)
                        })

            elif leg_vals_raw:
                # ── Case C: default palette, reference format ────────────────
                # The reference PBIT emits color entries in two passes:
                #   Pass 1: one entry per palette color with selector data:[]
                #   Pass 2: one entry per dimension value with scopeId.Comparison
                # Pass 1 determines the visual's palette (which colors are available).
                # Pass 2 pins each value to its color by value-comparison lookup.
                leg_vals_sorted = sorted(leg_vals_raw)
                # Pass 1: palette entries (data:[])
                for i in range(len(leg_vals_sorted)):
                    dp_entries.append({
                        'properties': {'fill': {'solid': {'color': {
                            'expr': {'Literal': {'Value': f"'{colors[i % len(colors)]}'"}}
                        }}}},
                        'selector': {'data': []}
                    })
                # Pass 2: scopeId.Comparison per value (uppercase hex to match PBI)
                for i, val in enumerate(leg_vals_sorted):
                    hex_upper = colors[i % len(colors)].upper()
                    dp_entries.append({
                        'properties': {'fill': {'solid': {'color': {
                            'expr': {'Literal': {'Value': f"'{hex_upper}'"}}
                        }}}},
                        'selector': _scope_selector(leg_name, val)
                    })

            # No leg_vals: emit the full palette as data:[] entries.
            # When embedded data is unavailable (file-path connections, no hyper),
            # we can't know the actual distinct series values.  Emitting N palette
            # entries with selector data:[] tells PBI which colors to cycle through
            # for whatever series values exist at render time — much better than a
            # single null-selector entry which makes everything one color.
            if not dp_entries:
                for i, hex_color in enumerate(colors):
                    dp_entries.append({
                        'properties': {'fill': {'solid': {'color': {
                            'expr': {'Literal': {'Value': f"'{hex_color}'"}}
                        }}}},
                        'selector': {'data': []}
                    })

        else:
            # ── Case D: single-series — one colour entry with null selector ───
            dp_entries.append({
                'properties': {'fill': {'solid': {'color': {
                    'expr': {'Literal': {'Value': f"'{colors[0]}'"}}
                }}}},
                'selector': None
            })

        if dp_entries:
            objects_cfg['dataPoint'] = dp_entries

    # Add legend position when the chart has a Series/Legend field.
    # The reference PBIT always sets position='Right' for charts with a legend.
    # Tableau doesn't encode this explicitly — 'Right' is the standard default.
    if legend_fields and visual_type not in ('tableEx', 'pivotTable', 'card', 'donutChart'):
        objects_cfg['legend'] = [{'properties': {
            'position': {'expr': {'Literal': {'Value': "'Right'"}}},
            **_axis_legend_font_vc_properties(legend_font_family, legend_font_size,
                                               legend_bold, legend_italic, legend_color),
        }}]

    # FIX 8: For combo charts always show the secondary Y axis so the line
    # series has its own independent scale on the right side.
    if is_combo:
        objects_cfg['valueAxis2'] = [{'properties': {
            'show': {'expr': {'Literal': {'Value': 'true'}}},
            'position': {'expr': {'Literal': {'Value': "'Right'"}}}
        }}]

    # Add data labels when Tableau mark-labels-show = 'true'.
    # PBI chart data labels are controlled by the 'labels' key in objects.
    if show_data_labels and visual_type not in ('tableEx', 'pivotTable', 'card',
                                                 'scatterChart', 'treemap', 'bubbleChart'):
        import re as _re_lf
        _label_props = {'show': {'expr': {'Literal': {'Value': 'true'}}}}

        # Translate Tableau text-format → PBI label properties.
        #
        # Tableau format conventions:
        #   c"$"#,##0,,.0M  → currency, millions, 1 decimal
        #   c"$"#,##0       → currency, exact
        #   n#,##0.00       → number, 2 decimals
        #   n#,##0.0        → number, 1 decimal
        #   p0%             → percentage, 0 decimals
        #   p2%             → percentage, 2 decimals
        #
        # PBI label properties:
        #   labelPrecision       → decimal places (e.g. "2L")
        #   labelDisplayUnits   → scale: 1D=none, 1000=K, 1000000=M, 1000000000=B
        #   labelStyle           → for pie/donut: "'Percent of total'"
        #   percentageLabelPrecision → decimals for pie % labels
        #   labelFormatString    → only for unusual custom formats

        _lf = (label_format or '').strip()

        # ── Pie/Donut: use "Percent of total" label style ────────────────────
        if visual_type in ('pieChart', 'donutChart'):
            # Tableau wedge/pcto encoding → show percentage per slice
            _dec = 0
            _pct_m = _re_lf.match(r'^p(\d+)%?$', _lf, _re_lf.I)
            if _pct_m:
                _dec = int(_pct_m.group(1))
            _label_props['labelStyle'] = {
                'expr': {'Literal': {'Value': "'Percent of total'"}}
            }
            _label_props['percentageLabelPrecision'] = {
                'expr': {'Literal': {'Value': f'{_dec}L'}}
            }
        else:
            # ── Non-pie charts: derive precision and scale from format ─────
            if _lf:
                # Count how many ,, or , groups appear before decimal point
                # e.g. ,,.0M → 2 commas → millions (1e6), ,.0K → 1 comma → thousands (1e3)
                _scale_m = _re_lf.search(r'(,+)', _lf.split('.')[0])
                _n_commas = len(_scale_m.group(1)) if _scale_m else 0
                _scale_map = {0: None, 1: 1000, 2: 1000000, 3: 1000000000}
                _scale = _scale_map.get(min(_n_commas, 3))

                # Count decimal places: look for .0, .00, .000 etc.
                _dec_m = _re_lf.search(r'\.([0#]+)', _lf)
                _decimals = len(_dec_m.group(1)) if _dec_m else 0

                # Percentage: p0% / p2%
                _pct_m = _re_lf.match(r'^p(\d+)%?$', _lf, _re_lf.I)
                if _pct_m:
                    _decimals = int(_pct_m.group(1))
                    _pbi_fmt = '0.' + '0' * _decimals + '%' if _decimals else '0%'
                    _label_props['labelFormatString'] = {
                        'expr': {'Literal': {'Value': f"'{_pbi_fmt}'"}}
                    }
                elif _scale:
                    # Explicit scale (K/M/B): set both scale and precision
                    _label_props['labelDisplayUnits'] = {
                        'expr': {'Literal': {'Value': f'{_scale}L'}}
                    }
                    if _decimals:
                        _label_props['labelPrecision'] = {
                            'expr': {'Literal': {'Value': f'{_decimals}L'}}
                        }
                elif _decimals:
                    # Decimal format with no scale abbreviation → labelPrecision
                    _label_props['labelPrecision'] = {
                        'expr': {'Literal': {'Value': f'{_decimals}L'}}
                    }
                elif _lf.startswith('n') or _lf.startswith('N'):
                    # Generic number format with no decimals — leave as show:true only
                    pass
                else:
                    # Unusual/custom format — pass as-is to labelFormatString
                    _label_props['labelFormatString'] = {
                        'expr': {'Literal': {'Value': f"'{_lf}'"}}
                    }
            # No label_format → just show:true, let PBI use its defaults

        # Data-label font — real, schema-verified signal (<style-rule
        # element='datalabel'>...) — the PBI 'labels' card uses bare
        # 'color'/'fontFamily'/'fontSize' for its text (not 'fontColor' or
        # 'labelColor'), confirmed directly from the same two real theme
        # JSON files verified for _axis_legend_font_vc_properties (both
        # sources agree here: `"labels": [{"color": {...}, "fontFamily":
        # ..., "fontSize": ...}]`).
        if datalabel_font_family:
            _label_props['fontFamily'] = {'expr': {'Literal': {'Value': f"'{datalabel_font_family}'"}}}
        if datalabel_font_size:
            _label_props['fontSize'] = {'expr': {'Literal': {'Value': f'{datalabel_font_size}D'}}}
        if datalabel_bold:
            _label_props['bold'] = {'expr': {'Literal': {'Value': 'true'}}}
        if datalabel_italic:
            _label_props['italic'] = {'expr': {'Literal': {'Value': 'true'}}}
        if datalabel_color:
            _label_props['color'] = {'solid': {'color': {'expr': {'Literal': {'Value': f"'{datalabel_color}'"}}}}}

        objects_cfg['labels'] = [{'properties': _label_props}]

    # ── Reference lines / trend lines → Power BI Analytics pane ──────────────
    # Tableau side is schema-verified (2026.2 TWB XSD). PBI side reuses the
    # same per-visual objects_cfg mechanism already used above for
    # labels/legend/axis — a wrong property name here degrades to "the line
    # doesn't render," not file corruption, unlike a page-level JSON guess.
    # Only handled where the translation is unambiguous:
    #   - reference-line formula='constant' (a literal fixed value) — the only
    #     type with a real static number. Aggregate types (average/median/
    #     sum/min/max/...) need Power BI's own dynamic Analytics-pane line
    #     feature, not an invented static number, so those are left for the
    #     quality-score report to flag instead of guessing a value.
    #   - trendline fit='linear' — Power BI's native trend line is linear-
    #     regression only; polynomial/log/exp/power fits have no PBI
    #     equivalent and are likewise left for the report to flag.
    if visual_type in ('lineChart', 'areaChart', 'clusteredColumnChart', 'columnChart',
                        'clusteredBarChart', 'barChart', 'lineClusteredColumnComboChart'):
        _const_lines = [rl for rl in (reference_lines or [])
                        if rl.get('formula') == 'constant' and rl.get('value') not in (None, '')]
        if _const_lines:
            _rl0 = _const_lines[0]  # PBI's built-in constant-line object supports one active line
            try:
                _rl_val = float(_rl0['value'])
                _cl_props = {
                    'show':          {'expr': {'Literal': {'Value': 'true'}}},
                    'value':         {'expr': {'Literal': {'Value': f'{_rl_val}D'}}},
                    'lineColor':     {'solid': {'color': {'expr': {'Literal': {'Value': "'#666666'"}}}}},
                    'transparency':  {'expr': {'Literal': {'Value': '20D'}}},
                    'dataLabelShow': {'expr': {'Literal': {
                        'Value': 'true' if _rl0.get('label_type') != 'none' else 'false'}}},
                }
                if _rl0.get('label'):
                    _cl_props['text'] = {'expr': {'Literal': {'Value': f"'{_rl0['label']}'"}}}
                objects_cfg['constantLine'] = [{'properties': _cl_props}]
            except (TypeError, ValueError):
                pass

        if trendline and (trendline.get('fit') or 'linear').lower() == 'linear':
            objects_cfg['trend'] = [{'properties': {
                'show':      {'expr': {'Literal': {'Value': 'true'}}},
                'lineColor': {'solid': {'color': {'expr': {'Literal': {'Value': "'#666666'"}}}}},
                'style':     {'expr': {'Literal': {'Value': "'dashed'"}}},
            }}]

    # ── FIX 9: Build axis title vcObjects ────────────────────────────────────
    # Generate X/Y axis title labels from the first category/value field names,
    # UNLESS Tableau has a real custom axis title override (schema-verified
    # <style-rule element='axis'><format attr='title' .../>, parsed per
    # worksheet in parse_tableau_workbook — confirmed real on Finance
    # Dashboard, e.g. 'DSO vs DPO' worksheet's value axis reads 'Amount($)'/
    # 'DSO vs DPO', not the raw field name it would otherwise show, and
    # AB_NYC's 'Availability and Price' value axis reads 'availability').
    # The override always wins when present since it reflects an explicit
    # user customization the raw field name can't recover.
    _x_label = axis_title_category or (category_fields[0]['name'] if category_fields else '')
    _y_label  = axis_title_value or (value_fields[0]['name']    if value_fields    else '')
    _vc_objects: dict = {
        'title': [{'properties': {
            'text': {'expr': {'Literal': {'Value': f"'{zone_name}'"}}},
            'show': {'expr': {'Literal': {'Value': 'true' if show_title else 'false'}}},
            **_title_font_vc_properties(title_font_family, title_font_size,
                                         title_bold, title_italic,
                                         title_color, title_bg_color),
        }}]
    }
    # Worksheet plot-area background color — schema-verified real signal
    # (see parse_tableau_workbook's background_color capture); e.g. Netfix
    # Workbook's Netflix-themed dashboard sets every worksheet's background
    # to black, which the default white PBI visual background would
    # otherwise silently lose.
    if background_color:
        _vc_objects['background'] = [{'properties': {
            'color': {'solid': {'color': {'expr': {'Literal': {'Value': f"'{background_color}'"}}}}},
            'transparency': {'expr': {'Literal': {'Value': '0'}}},
        }}]
    # Zone container border — schema-verified real signal (see
    # _border_vc_objects and parse_tableau_workbook's _collect_zone).
    if border_color:
        _vc_objects.update(_border_vc_objects(border_color, border_width))
    _axis_vis_types = {
        'clusteredBarChart', 'clusteredColumnChart', 'barChart', 'columnChart',
        'lineChart', 'areaChart', 'lineClusteredColumnComboChart',
        'stackedBarChart', 'stackedColumnChart',
        'hundredPercentStackedBarChart', 'hundredPercentStackedColumnChart',
    }
    _axis_label_font_props = _axis_legend_font_vc_properties(
        axis_label_font_family, axis_label_font_size,
        axis_label_bold, axis_label_italic, axis_label_color)
    if visual_type in _axis_vis_types or is_combo:
        if _x_label or _axis_label_font_props:
            _cat_axis_props = {'show': {'expr': {'Literal': {'Value': 'true'}}}}
            if _x_label:
                _cat_axis_props['titleText'] = {'expr': {'Literal': {'Value': f"'{_x_label}'"}}}
                _cat_axis_props['axisStyle'] = {'expr': {'Literal': {'Value': "'showTitleOnly'"}}}
            _cat_axis_props.update(_axis_label_font_props)
            _vc_objects['categoryAxis'] = [{'properties': _cat_axis_props}]
        if _y_label or gridlines_hidden or _axis_label_font_props:
            # FIX Y-axis precision: labelDisplayUnits=0 disables PBI's auto-rounding
            # (which shows '30M' instead of '30,000,000'). precision=2 keeps 2 decimal
            # places for ratio/percentage measures. This matches the Tableau behaviour
            # of showing exact tick values without abbreviation.
            _value_axis_props = {
                'show':               {'expr': {'Literal': {'Value': 'true'}}},
                'axisStyle':          {'expr': {'Literal': {'Value': "'showTitleOnly'"}}},
                'labelDisplayUnits':  {'expr': {'Literal': {'Value': '0'}}},
            }
            _value_axis_props.update(_axis_label_font_props)
            if _y_label:
                _value_axis_props['titleText'] = {'expr': {'Literal': {'Value': f"'{_y_label}'"}}}
            if gridlines_hidden:
                # Real, schema-verified signal (<style-rule element='axis'>
                # <format attr='stroke-size' value='0'/>) — confirmed real
                # and deliberate only on Sales Param's 'Line graph'
                # worksheet (never an ambient default anywhere in the 10
                # fixtures, unlike stroke-color's near-universal '#c0c0c0'
                # cached default, which was surveyed and deliberately NOT
                # replicated — see parse_tableau_workbook). gridlineShow is
                # a real property confirmed directly from a live Power BI
                # theme JSON (not just a search summary), inside the same
                # valueAxis object this codebase already writes.
                _value_axis_props['gridlineShow'] = {'expr': {'Literal': {'Value': 'false'}}}
            _vc_objects['valueAxis'] = [{'properties': _value_axis_props}]
        if is_combo and len(value_fields) > 1:
            _y2_label = axis_title_value2 or value_fields[-1]['name']
            _value_axis2_props = {
                'show':               {'expr': {'Literal': {'Value': 'true'}}},
                'position':           {'expr': {'Literal': {'Value': "'Right'"}}},
                'titleText':          {'expr': {'Literal': {'Value': f"'{_y2_label}'"}}},
                'labelDisplayUnits':  {'expr': {'Literal': {'Value': '0'}}},
            }
            _value_axis2_props.update(_axis_label_font_props)
            if gridlines_hidden:
                _value_axis2_props['gridlineShow'] = {'expr': {'Literal': {'Value': 'false'}}}
            _vc_objects['valueAxis2'] = [{'properties': _value_axis2_props}]

    config = _jmin({
        'name': name,
        'layouts': [{'id': 0, 'position': {
            'x': x, 'y': y, 'z': z,
            'width': width, 'height': height,
            'tabOrder': tab_order
        }}],
        'singleVisual': {
            'visualType': visual_type,
            'projections': projections,
            'prototypeQuery': proto_query,
            'drillFilterOtherVisuals': True,
            **(({'objects': objects_cfg}) if objects_cfg else {}),
            'vcObjects': _vc_objects,
        }
    })

    # ── Visual-level filters ──────────────────────────────────────────────────
    # Native SemanticQuery filters (categorical/quantitative-range/topN/
    # relative-date/context) built by the shared helper — see
    # _build_pbi_visual_filters for the format notes.
    _chart_pbi_filters = _build_pbi_visual_filters(T, filter_fields, filter_specs)

    return {
        'id':             abs(hash(name)) % (2**31),
        'x': x, 'y': y, 'z': z,
        'width': width, 'height': height,
        'config':         config,
        'filters':        _jmin(_chart_pbi_filters) if _chart_pbi_filters else '[]',
        'query':          _jmin(query),
        'queryHash':      0,
        'dataTransforms': _jmin(data_transforms)
    }


# ══════════════════════════════════════════════════════════════════════════════
# MeasureRegistry — Centralised semantic measure lookup for visual binding
#
# Reads ds['_sum_measure_map'] / ds['_ctd_measure_map'] written by the
# schema builder so all visual code references the same authoritative measure
# names instead of re-deriving them or falling back to inline Aggregation{}.
# ══════════════════════════════════════════════════════════════════════════════

class MeasureRegistry:
    """
    Centralised lookup: raw column/calc name → pre-built DAX measure name.

    Build once at the top of build_report_layout from schema-builder output,
    then call resolve() in every visual-building code path that previously
    fell back to emitting is_agg=True (inline Aggregation{} expression).

    Resolution order
    ----------------
    1. Named DAX calc that is itself an aggregate measure
    2. Count-distinct measure (_ctd_measure_map)
    3. Sum-of-column measure (_sum_measure_map)
    Returns None when no pre-built measure exists (scatter Aggregation path).
    """

    def __init__(self, datasources: list):
        self._sum:  dict = {}   # ds_name → {nk(col) → measure_name}
        self._ctd:  dict = {}   # ds_name → {nk(col_cap) → ctd_measure_name}
        self._calc: dict = {}   # ds_name → {nk(name) → calc_dict}

        for ds in datasources:
            dsn = ds.get('name', '')
            self._sum[dsn]  = {}
            self._ctd[dsn]  = {}
            self._calc[dsn] = {}

            for col_name, msr_name in ds.get('_sum_measure_map', {}).items():
                k = self._nk(col_name)
                self._sum[dsn][k] = msr_name
                self._sum[dsn][self._nk(msr_name)] = msr_name   # self-key

            for col_cap, ctd_name in ds.get('_ctd_measure_map', {}).items():
                k = self._nk(col_cap)
                self._ctd[dsn][k] = ctd_name
                self._ctd[dsn][self._nk(ctd_name)] = ctd_name   # self-key

            for calc in ds.get('calculations', []):
                if not calc.get('is_agg_calc', True):
                    continue
                cname = calc.get('name', '').strip()
                if cname:
                    self._calc[dsn][self._nk(cname)] = calc

    # ── Public API ─────────────────────────────────────────────────────────────

    def resolve(self, field_name: str, ds: 'dict | str',
                prefer_ctd: bool = False) -> 'dict | None':
        """
        Return an is_measure=True field dict for *field_name* in *ds*, or None.
        The returned dict is safe to spread into a val_f entry.
        """
        if not field_name:
            return None
        dsn = ds.get('name', '') if isinstance(ds, dict) else str(ds)
        key = self._nk(field_name)

        # 1. Named calc
        calc = self._calc.get(dsn, {}).get(key)
        if calc:
            return {**calc, 'is_measure': True, 'is_agg': False,
                    'datatype': calc.get('datatype', 'double')}

        # 2. Count-distinct
        ctd_name = self._ctd.get(dsn, {}).get(key)
        if ctd_name:
            return {'name': ctd_name, 'is_measure': True, 'is_agg': False,
                    'datatype': 'double'}

        # 3. Sum-of-column
        msr_name = self._sum.get(dsn, {}).get(key)
        if msr_name:
            return {'name': msr_name, 'is_measure': True, 'is_agg': False,
                    'datatype': 'double'}

        return None

    def resolve_ctd(self, field_name: str, ds: 'dict | str') -> 'dict | None':
        """Resolve count-distinct measure specifically."""
        if not field_name:
            return None
        dsn = ds.get('name', '') if isinstance(ds, dict) else str(ds)
        ctd_name = self._ctd.get(dsn, {}).get(self._nk(field_name))
        return ({'name': ctd_name, 'is_measure': True, 'is_agg': False,
                 'datatype': 'double'} if ctd_name else None)

    def has_measure(self, field_name: str, ds: 'dict | str') -> bool:
        """True when a pre-built measure exists for *field_name* in *ds*."""
        return self.resolve(field_name, ds) is not None

    def sum_measures_for_ds(self, ds: 'dict | str') -> dict:
        """Return {col_name: measure_name} for all sum-measures in *ds*."""
        return dict((ds if isinstance(ds, dict) else {}).get('_sum_measure_map', {}))

    @staticmethod
    def _nk(s: str) -> str:
        """Normalised key: lowercase, no spaces, no hyphens."""
        return s.strip().lower().replace(' ', '').replace('-', '')


def build_report_layout(workbook: dict) -> dict:
    """
    Build the PBI Report/Layout.

    Page strategy (Issue 1 — Dashboard-first):
    - One PBI page per Tableau DASHBOARD (primary output).
    - One additional PBI page per visible Tableau WORKSHEET (for detail/drill).
    - Dashboard pages contain all worksheet visuals tiled at their Tableau coords.
    - Worksheet pages show the individual chart for reference.

    Issue 9 — Error handling:
    - Individual visual build failures are caught and logged.
    - Broken visuals are replaced with a safe textbox placeholder.
    - Partial conversion continues rather than crashing the full report.
    """
    _line_measures = []   # ✅ FIX
    wb_name     = workbook['name']
    worksheets  = workbook.get('worksheets', [])
    dashboards  = workbook.get('dashboards', [])
    datasources = [ds for ds in workbook['datasources']
                   if ds.get('columns') or ds.get('calculations')
                   or ds.get('name')]   # keep ALL named datasources even if column list empty

    # Tableau color palette extracted during parsing; used for chart series colors.
    data_colors = workbook.get('data_colors') or [
        '#4e79a7', '#f28e2b', '#59a14f', '#e15759',
        '#76b7b2', '#edc948', '#b07aa1', '#ff9da7',
        '#9c755f', '#bab0ac',
    ]
    # Explicit value→color mappings parsed from <color-map> elements.
    explicit_color_map = workbook.get('explicit_color_map', {})

    # Build the list of pages.
    # Exclude worksheets that are:
    #   1. Marked hidden=True (from Tableau <windows> analysis)
    #   2. Pure Shape-mark indicator panels (all pane marks are 'Shape')
    #   3. Named Icon_* (icon panels placed on dashboards for decoration)
    def _is_helper_ws(ws):
        marks = ws.get('pane_marks', [])
        if marks and all(m == 'Shape' for m in marks):
            return True
        if ws.get('name', '').startswith('Icon_'):
            return True
        return False

    # Separate visible worksheets from hidden ones
    visible_ws = [ws for ws in worksheets
                  if not ws.get('hidden', False) and not _is_helper_ws(ws)]

    # ALL worksheets by name — dashboard zones reference hidden sheets too
    _ws_by_name = {ws['name']: ws for ws in worksheets}

    def _ws_to_page(ws):
        return {
            'name':                        ws['name'],
            'width':                       1280, 'height': 720,
            'is_dashboard':                False,
            'ds_names':                    ws.get('ds_names', []),
            'fields':                      ws.get('fields', []),
            'chart_type':                  ws.get('chart_type', 'tableEx'),
            'x_field':                     ws.get('x_field', ''),
            'y_field':                     ws.get('y_field', ''),
            'all_row_measure_fields':      ws.get('all_row_measure_fields', []),
            'all_col_dim_fields':          ws.get('all_col_dim_fields', []),
            'all_col_fields':              ws.get('all_col_fields', []),
            'color_fields':                ws.get('color_fields', []),
            'detail_fields':               ws.get('detail_fields', []),
            'pcto_field':                  ws.get('pcto_field'),
            'show_data_labels':            ws.get('show_data_labels', False),
            'label_format':                ws.get('label_format', ''),
            'background_color':            ws.get('background_color', ''),
            'title_font_family':           ws.get('title_font_family', ''),
            'title_font_size':             ws.get('title_font_size', 0),
            'title_bold':                  ws.get('title_bold', False),
            'title_italic':                ws.get('title_italic', False),
            'title_color':                 ws.get('title_color', ''),
            'title_bg_color':              ws.get('title_bg_color', ''),
            'axis_label_font_family':      ws.get('axis_label_font_family', ''),
            'axis_label_font_size':        ws.get('axis_label_font_size', 0),
            'axis_label_bold':             ws.get('axis_label_bold', False),
            'axis_label_italic':           ws.get('axis_label_italic', False),
            'axis_label_color':            ws.get('axis_label_color', ''),
            'legend_font_family':          ws.get('legend_font_family', ''),
            'legend_font_size':            ws.get('legend_font_size', 0),
            'legend_bold':                 ws.get('legend_bold', False),
            'legend_italic':               ws.get('legend_italic', False),
            'legend_color':                ws.get('legend_color', ''),
            'datalabel_font_family':       ws.get('datalabel_font_family', ''),
            'datalabel_font_size':         ws.get('datalabel_font_size', 0),
            'datalabel_bold':              ws.get('datalabel_bold', False),
            'datalabel_italic':            ws.get('datalabel_italic', False),
            'datalabel_color':             ws.get('datalabel_color', ''),
            'axis_title_value':            ws.get('axis_title_value', ''),
            'axis_title_value2':           ws.get('axis_title_value2', ''),
            'axis_title_category':         ws.get('axis_title_category', ''),
            'gridlines_hidden':            ws.get('gridlines_hidden', False),
            'sort_field':                  ws.get('sort_field'),
            'sort_dir':                    ws.get('sort_dir', 1),
            'sort_is_col':                 ws.get('sort_is_col', True),
            'text_enc_field':              ws.get('text_enc_field'),
            'pie_size_field':              ws.get('pie_size_field'),
            'size_enc_field':              ws.get('size_enc_field'),
            'date_shelf_groupings':        ws.get('date_shelf_groupings', []),
            'shelf_row_fields':            ws.get('shelf_row_fields', []),
            'filter_fields':               ws.get('filter_fields', []),
            'filter_specs':                ws.get('filter_specs', []),
            'measure_names_filter_fields': ws.get('measure_names_filter_fields', []),
            'color_is_measure_names':      ws.get('color_is_measure_names', False),
            'ctd_fields':                  ws.get('ctd_fields', []),
            'pane_mark_colors':            ws.get('chart_pane_colors', []),
            'pages_fields':                ws.get('pages_fields', []),
            'row_type':                    ws.get('row_type', 'EMPTY'),
            'col_type':                    ws.get('col_type', 'EMPTY'),
            'map_location_field':          ws.get('map_location_field', ''),
            'map_size_field':              ws.get('map_size_field', ''),
            'reference_lines':             ws.get('reference_lines', []),
            'trendline':                   ws.get('trendline'),
        }

    pages = []

    # ── Priority 1 (doc §5.1): DASHBOARD-CENTRIC page generation ─────────────
    # The correct mapping per the Enterprise Guide:
    #   1 Tableau Dashboard → 1 Power BI Page
    #   Worksheets → visuals inside that page   (NOT standalone pages)
    # Worksheets NOT referenced by any dashboard → ONE orphan diagnostics page.

    # Track which worksheets are referenced by at least one dashboard
    _referenced_ws: set = set()
    for d in dashboards:
        for zone in d.get('zones', []) + d.get('filter_zones', []):
            zn = zone.get('name', '')
            if zn and zn in _ws_by_name:
                _referenced_ws.add(zn)

    # One page per Tableau dashboard
    for d in dashboards:
        db_ds_names = []
        for zone in d.get('zones', []):
            zname = zone.get('name', '')
            if zname and zname in _ws_by_name:
                for dsn in _ws_by_name[zname].get('ds_names', []):
                    if dsn not in db_ds_names:
                        db_ds_names.append(dsn)
        tab_w = max(d.get('width',  1280), 1)
        tab_h = max(d.get('height', 720),  1)
        pbi_w = 1280
        pbi_h = max(720, int(tab_h * pbi_w / tab_w))
        pages.append({
            'name':            d['name'],
            'width':           pbi_w,
            'height':          pbi_h,
            'is_dashboard':    True,
            'db_zones':        d.get('zones', []),
            'db_filter_zones': d.get('filter_zones', []),
            'db_parameter_zones': d.get('parameter_zones', []),
            'db_text_zones':   d.get('text_zones', []),
            'layout_tree':     d.get('layout_tree', []),   # Stage 3/7
            'db_tab_w':        tab_w,
            'db_tab_h':        tab_h,
            'ds_names':        db_ds_names,
            'fields':          [],
            'chart_type':      'tableEx',
            'shelf_row_fields': [],
            'filter_fields':   [],
            'color_is_measure_names': False,
        })

    # ── Stories: one page per story-point, in Tableau's story-point order ────
    # A Tableau Story has no direct Power BI report-level equivalent (no
    # native story-point navigation strip in the internal Report.json format
    # we could safely emit), so the closest safe approximation is one full
    # page per story point, in order — reusing the exact same single-zone
    # dashboard-style page shape already proven below for the orphan-
    # worksheet page, rather than inventing new rendering logic. Marking each
    # captured worksheet as "referenced" here (before the orphan-page
    # computation runs) keeps it from also being duplicated onto that page.
    _story_notes = []
    for _story in workbook.get('stories', []):
        _seen_pg_names: set = set()
        _story_page_names = []
        for _si, _pt in enumerate(_story['points']):
            _sheet_name = _pt['sheet']
            if _sheet_name not in _ws_by_name:
                continue   # captured-sheet references a worksheet this workbook doesn't have
            _referenced_ws.add(_sheet_name)
            _base_name = (f"{_story['name']}: {_pt['caption']}" if _pt['caption']
                          else f"{_story['name']} ({_si + 1})")
            _pg_name, _dupe_n = _base_name, 2
            while _pg_name in _seen_pg_names:
                _pg_name = f"{_base_name} ({_dupe_n})"
                _dupe_n += 1
            _seen_pg_names.add(_pg_name)
            _story_page_names.append(_pg_name)
            _sws = _ws_by_name[_sheet_name]
            pages.append({
                'name': _pg_name, 'width': 1280, 'height': 720,
                'is_dashboard': True,
                'db_zones': [{'name': _sheet_name, 'type': '',
                              'x': 0, 'y': 0, 'w': 1280, 'h': 720}],
                'db_filter_zones': [], 'layout_tree': [],
                'db_tab_w': 1280, 'db_tab_h': 720,
                'ds_names': list(_sws.get('ds_names', [])), 'fields': [],
                'chart_type': 'tableEx',
                'shelf_row_fields': [], 'filter_fields': [],
                'color_is_measure_names': False,
            })
        if _story_page_names:
            log('info', f"Layout: Story '{_story['name']}' → "
                        f"{len(_story_page_names)} page(s): {', '.join(_story_page_names)}")
            _story_notes.append(
                f"Story \"{_story['name']}\" converted to {len(_story_page_names)} "
                f"sequential page(s), in its original story-point order. Power BI has "
                f"no native story-navigation strip; to restore click-through "
                f"navigation, add a Bookmark per page (View > Bookmarks > Add) and a "
                f"Back/Next button pair manually."
            )
    workbook['_story_notes'] = _story_notes

    # Orphan worksheets: visible but not in any dashboard → ONE combined page
    _orphan_ws = [ws for ws in visible_ws if ws['name'] not in _referenced_ws]
    if _orphan_ws:
        _o_zones, _cols, _cell_w, _cell_h = [], 2, 640, 360
        for _oi, _ows in enumerate(_orphan_ws):
            _o_zones.append({'name':_ows['name'], 'type':'',
                             'x':(_oi%_cols)*_cell_w, 'y':(_oi//_cols)*_cell_h,
                             'w':_cell_w, 'h':_cell_h})
        _o_h = max(720, ((len(_orphan_ws)-1)//_cols+1)*_cell_h)
        _o_ds = []
        for _ows in _orphan_ws:
            for dsn in _ows.get('ds_names',[]):
                if dsn not in _o_ds: _o_ds.append(dsn)
        pages.append({
            'name':'Worksheets', 'width':1280, 'height':_o_h,
            'is_dashboard':True, 'db_zones':_o_zones, 'db_filter_zones':[],
            'layout_tree':[], 'db_tab_w':1280, 'db_tab_h':_o_h,
            'ds_names':_o_ds, 'fields':[], 'chart_type':'tableEx',
            'shelf_row_fields':[], 'filter_fields':[], 'color_is_measure_names':False,
        })
        log('info', f"Layout: {len(_orphan_ws)} orphan worksheet(s) → 'Worksheets' page")

    # Layout-fidelity signal for the migration quality score: a worksheet kept
    # its real Tableau dashboard position (dashboard-referenced); an orphan
    # worksheet was auto-arranged onto a synthetic grid page instead, which is
    # a real loss of layout fidelity worth reporting rather than hiding.
    workbook['_layout_fidelity'] = {
        'referenced': sorted(_referenced_ws),
        'orphaned':   [ws['name'] for ws in _orphan_ws],
        'hidden_or_helper': [
            ws['name'] for ws in worksheets
            if ws.get('hidden', False) or _is_helper_ws(ws)
        ],
    }

    if not pages:
        pages = [{'name': wb_name, 'width': 1280, 'height': 720,
                  'is_dashboard': False, 'ds_names': [], 'fields': [],
                  'chart_type': 'tableEx', 'shelf_row_fields': [],
                  'filter_fields': [], 'color_is_measure_names': False}]

    # ── Clean page display names (remove machine-generated suffixes) ──────────
    import re
    _CLEAN_SUFFIXES = re.compile(
        r'(_Count|_copy|\s+copy|\s+\(\d+\)|_\d+$|^Sheet\s*\d+$'
        r'|_temp$|_tmp$|\s*\(copy\d*\))',
        re.IGNORECASE
    )
    for _p in pages:
        _raw = _p.get('name', '')
        _cleaned = _CLEAN_SUFFIXES.sub('', _raw).strip()
        _p['display_name'] = _cleaned if _cleaned else _raw

    log('info',
        f"Layout: {sum(1 for p in pages if p.get('is_dashboard'))} dashboard(s) + "
        f"{sum(1 for p in pages if not p.get('is_dashboard'))} worksheet(s)")

    # Build the sanitized table name mapping so visuals reference real PBI tables
    def _safe(raw):
        import re as _re
        name = _re.sub(r'[^\w\s]', '_', raw.strip())
        name = _re.sub(r'[\s_]+', '_', name).strip('_')
        if name and name[0].isdigit():
            name = 'T_' + name
        return name or 'Table'

    # Pre-compute PBI table name for each datasource
    ds_pbi_names = {ds['name']: _safe(ds['name']) for ds in datasources}

    # ── Semantic Measure Registry ────────────────────────────────────────────
    # Single authoritative source: reads _sum_measure_map and _ctd_measure_map
    # written by build_data_model_schema instead of re-deriving names here.
    # All inline-aggregation fallback paths must call _measure_registry.resolve()
    # before emitting is_agg=True so numeric-column Y-axes bind to pre-built
    # DAX Measures rather than Aggregation{} expressions in the visual query.
    _measure_registry = MeasureRegistry(datasources)

    # Thin compatibility shim: older code paths index ds_sum_maps[ds_name][col]
    # directly. Populate from the authoritative map; fall back to re-derivation
    # only when the schema builder has not yet run (e.g. unit tests).
    ds_sum_maps: dict = {}
    for ds in datasources:
        _authoritative = ds.get('_sum_measure_map', {})
        if _authoritative:
            ds_sum_maps[ds['name']] = dict(_authoritative)
        else:
            # Schema builder hasn't run yet — re-derive as before
            _measure_cols = [c for c in ds.get('columns', [])
                             if (c.get('measure') or c.get('datatype') in ('int64','double'))
                             and not c.get('hidden')]
            _col_by_norm  = {c['name'].strip().lower().replace(' ','').replace('-',''): c
                             for c in _measure_cols}
            _sum_map: dict = {}
            for ws in worksheets:
                _ds_names = ws.get('ds_names', [])
                if (ds.get('raw_name','') not in _ds_names
                        and ds.get('name','') not in _ds_names):
                    continue
                ct = ws.get('chart_type', '')
                if ct == 'scatterChart':
                    for _field in ([ws.get('x_field','')] + ws.get('shelf_row_fields',[])):
                        if not _field: continue
                        _norm = _field.strip().lower().replace(' ','').replace('-','')
                        _mc   = _col_by_norm.get(_norm)
                        if _mc and _mc['name'] not in _sum_map:
                            _sum_map[_mc['name']] = f"Sum of {_mc['name']}"
                    continue
                for _srf in ws.get('shelf_row_fields', []):
                    if not _srf: continue
                    _norm = _srf.strip().lower().replace(' ','').replace('-','')
                    _mc   = _col_by_norm.get(_norm)
                    if _mc and _mc['name'] not in _sum_map:
                        _sum_map[_mc['name']] = f"Sum of {_mc['name']}"
                for _mnf in ws.get('measure_names_filter_fields', []):
                    if not _mnf: continue
                    _norm = _mnf.strip().lower().replace(' ','').replace('-','')
                    _mc   = _col_by_norm.get(_norm)
                    if _mc and _mc['name'] not in _sum_map:
                        _sum_map[_mc['name']] = f"Sum of {_mc['name']}"
            ds_sum_maps[ds['name']] = _sum_map


    # Pre-compute COUNT DISTINCT measure names for ctd: columns.
    # The schema builder stores ds['_ctd_measure_map'] = {col_caption: dax_measure_name}.
    # We mirror it here so the layout builder can look up by normalized col name.
    ds_ctd_maps: dict = {}   # ds_name → {col_caption → 'Count Distinct of col_caption'}
    for ds in datasources:
        ds_ctd_maps[ds['name']] = ds.get('_ctd_measure_map', {})

    # Pre-compute map-column names: raw geo col → sanitised "{col} (map)" calc column.
    # The schema builder generates these for every geographic column to exclude
    # blank and multi-value strings before they reach the Bing geocoder.
    ds_map_col_maps: dict = {}   # ds_name → {raw_col_name → 'Col (map)'}
    for ds in datasources:
        ds_map_col_maps[ds['name']] = ds.get('_map_col_map', {})

    sections = []
    for page_idx, page in enumerate(pages):
        W = int(page.get('width',  1280))
        H = int(page.get('height', 720))
        page_name  = page['name']
        page_ds_names = page.get('ds_names', [])
        page_fields   = page.get('fields', [])

        # Pick the datasource for this page:
        # 1. Match by raw_name (internal Tableau name) or caption name
        # 2. Fall back to page-name match, then first datasource
        # Note: `datasources` is already filtered to only those with columns/calcs.
        ds = None
        if datasources:
            for ws_ds_name in page_ds_names:
                match = next(
                    (d for d in datasources
                     if d['name'] == ws_ds_name
                     or d.get('raw_name', '') == ws_ds_name
                     or d.get('raw_name', '').lower() == ws_ds_name.lower()),
                    None
                )
                if match:
                    ds = match
                    break
            if ds is None:
                page_lower = page_name.lower()
                for candidate in datasources:
                    if candidate['name'].lower() == page_lower:
                        ds = candidate
                        break
            if ds is None:
                ds = datasources[0]

        visual_containers = []
        z = 1

        # ── Issue 10: Title text box — use cleaned display_name, sized by page type ──
        _disp_name = page.get('display_name', page_name)
        _is_db_pg  = page.get('is_dashboard', False)
        _title_h   = 52 if _is_db_pg else 40
        _font_sz   = 20 if _is_db_pg else 16
        visual_containers.append(_make_textbox_vc(
            name=_guid(), x=0, y=0, z=z, width=W, height=_title_h,
            text=_disp_name, font_size=_font_sz, bold=True))
        z += 1

        # ── DASHBOARD PAGE ────────────────────────────────────────────────────
        if page.get('is_dashboard'):
            TITLE_H = 52   # matches _title_h for dashboard pages above
            tab_w = float(page.get('db_tab_w', W))
            tab_h = float(page.get('db_tab_h', H))
            sx = W  / tab_w          if tab_w > 0 else 1.0
            sy = (H - TITLE_H) / tab_h if tab_h > 0 else 1.0

            # ── Stage 7 / Priority 2: Layout Tree Renderer ────────────────────
            # Build PBI canvas coordinates from the layout tree FIRST.
            # This respects horizontal/vertical/tiled/floating containers and
            # distributes space proportionally — matching the Enterprise Guide's
            # algorithm (§4.3, §6.3).
            # Result: _pbi_zone_coords[zone_name] = (x, y, w, h) in PBI pixels.
            _pbi_zone_coords: dict = {}

            # ── Seed _pbi_zone_coords from db_zones (AUTHORITATIVE source) ────
            # db_zones come from _collect_zone which reads the ACTUAL Tableau zone
            # coordinates (x,y,w,h in 0-100000 space, already converted to PBI px).
            # These are the CORRECT positions as Tableau laid them out.
            #
            # We seed _pbi_zone_coords with these BEFORE running _distribute so
            # that the _sz() function's Priority-1 lookup gets the RIGHT position.
            # _distribute may later OVERWRITE these — but ONLY if it computes a
            # LARGER area (largest-area-wins guard in the leaf handler below).
            #
            # Without this seeding, _distribute writes proportional (wrong) positions
            # first, and _sz() Priority-1 returns those instead of the correct ones.
            #
            # db_filter_zones/db_parameter_zones are DELIBERATELY excluded from
            # this seed loop. Tableau's own quick-filter-card zones frequently
            # reuse the SAME 'name' as the worksheet they filter (confirmed on
            # HR Analytics' 'KPI', AB_NYC's neighbourhood_group, LocBar's
            # 'CustBar'/'Custpie' filters — two separate <zone> elements, same
            # name, unrelated x/y/w/h). Seeding from a filter zone here would
            # overwrite the real worksheet's chart rect with the filter
            # card's own tiny one under the same dict key — a real,
            # confirmed bug (HR Analytics' 'KPI' multiRowCard was already
            # silently squashed to its filter's 9x132/188x131 rect before
            # this fix). Filter/parameter zones get their own position via
            # _sz_own() instead, which never touches this cache.
            _tab_w_canvas = float(page.get('db_tab_w', W) or W)
            _tab_h_canvas = float(page.get('db_tab_h', H - TITLE_H) or (H - TITLE_H))
            _sx_seed = W  / max(_tab_w_canvas, 1)
            _sy_seed = (H - TITLE_H) / max(_tab_h_canvas, 1)
            for _dz in page.get('db_zones', []):
                _dzn = _dz.get('name', '')
                if not _dzn or _dzn not in _ws_by_name:
                    continue
                # db_zones x,y,w,h are already in pixel space (scaled by _collect_zone)
                # but they used actual_w/actual_h canvas → rescale to PBI canvas size
                _dz_x = max(0, int(_dz.get('x', 0) * _sx_seed))
                _dz_y = max(TITLE_H, int(_dz.get('y', 0) * _sy_seed) + TITLE_H)
                _dz_w = max(80, min(int(_dz.get('w', 200) * _sx_seed), W - _dz_x - 4))
                _dz_h = max(50, min(int(_dz.get('h', 150) * _sy_seed), H - _dz_y - 4))
                _pbi_zone_coords[_dzn] = (_dz_x, _dz_y, _dz_w, _dz_h)

            # ── Layout fidelity constants ──────────────────────────────────────
            # INNER_PAD: pixels of breathing room inside every container edge.
            # CHILD_GAP: gutter between sibling visuals in the same container.
            # MIN_VIS_W / MIN_VIS_H: hard lower bounds for any rendered visual.
            # These are the ONLY knobs; no other layout logic is changed.
            _INNER_PAD  = 4    # container-edge padding (each side)
            _CHILD_GAP  = 6    # inter-sibling gutter
            _MIN_VIS_W  = 120  # minimum rendered visual width  (px)
            _MIN_VIS_H  = 80   # minimum rendered visual height (px)

            def _child_weight_w(c: dict) -> float:
                """
                Return the horizontal weight for child *c*.

                Priority order (highest to lowest):
                  1. Explicit Tableau zone pixel-width  (w > 1  → reliable hint)
                  2. Explicit Tableau zone pixel-height (h > 1  → used only when w absent)
                  3. Uniform fallback weight of 1.0
                This lets containers with known Tableau size hints distribute
                space proportionally instead of equally.
                """
                w = c.get('w', 0)
                if w > 1:
                    return float(w)
                h = c.get('h', 0)
                if h > 1:
                    return float(h)
                return 1.0

            def _child_weight_h(c: dict) -> float:
                """
                Return the vertical weight for child *c*.

                Priority order:
                  1. Explicit Tableau zone pixel-height (h > 1)
                  2. Explicit Tableau zone pixel-width  (w > 1, fallback)
                  3. Uniform fallback weight of 1.0
                """
                h = c.get('h', 0)
                if h > 1:
                    return float(h)
                w = c.get('w', 0)
                if w > 1:
                    return float(w)
                return 1.0

            def _safe_split(total: int, weights: list, minimum: int) -> list:
                """
                Divide *total* pixels among len(weights) slots proportionally,
                honouring a per-slot *minimum*, and guaranteeing that the
                returned list sums to exactly *total* (no overflow, no gap).

                Algorithm:
                  1. Give every slot its weighted share (floored).
                  2. Raise any slot below *minimum* to *minimum*.
                  3. If the sum now exceeds *total* (minimum constraints pushed
                     us over), scale each slot down proportionally — still
                     keeping every slot >= 1 — until the sum fits.
                  4. Distribute leftover pixels (from floor rounding) one-by-one
                     to the slots with the largest fractional remainders, so the
                     last slot never has to absorb all rounding error.
                  5. Force the final slot to absorb any remaining 1-pixel
                     discrepancy so the list always sums to exactly *total*.
                """
                n = len(weights)
                if n == 0:
                    return []
                total_wgt = sum(weights) or 1.0

                # Step 1: raw proportional float shares
                raw = [total * w / total_wgt for w in weights]

                # Step 2: apply minimum
                shares = [max(float(minimum), r) for r in raw]

                # Step 3: if minimums push us over *total*, scale back
                s = sum(shares)
                if s > total:
                    # Scale uniformly, keep each slot >= 1
                    factor = total / s
                    shares = [max(1.0, sh * factor) for sh in shares]

                # Step 4: floor + distribute remainders by largest-fraction
                floored    = [int(sh) for sh in shares]
                remainders = [(shares[i] - floored[i], i) for i in range(n)]
                leftover   = total - sum(floored)
                for _, i in sorted(remainders, reverse=True)[:max(0, leftover)]:
                    floored[i] += 1

                # Step 5: final single-pixel correction on last slot
                diff = total - sum(floored)
                floored[-1] = max(1, floored[-1] + diff)

                return floored

            def _distribute(node, off_x, off_y, avail_w, avail_h):
                """
                Recursively assign PBI pixel rectangles to every leaf zone
                in the layout tree, honouring container type semantics and
                preserving nested container proportions.

                Rules (ONLY layout logic is changed; nothing else):
                  - Horizontal containers: divide avail_w by weighted child widths.
                  - Vertical containers:   divide avail_h by weighted child heights.
                  - Floating containers:   restore original Tableau coords, scaled
                                           to the current PBI canvas region.
                  - Tiled/unknown:         proportional grid using actual child sizes.
                  - Padding (_INNER_PAD) is consumed from the available region
                    before children receive any space, so nested containers never
                    bleed into their parent's edges.
                  - A gap (_CHILD_GAP) separates adjacent siblings.
                  - Every leaf is clamped to at least _MIN_VIS_W × _MIN_VIS_H.
                  - Nested containers are NOT flattened.
                """
                if not node:
                    return

                zname    = node.get('name', '')
                layout   = node.get('layout', 'leaf')
                children = node.get('children', [])

                # ── Leaf node ─────────────────────────────────────────────────
                if layout == 'leaf' or not children:
                    if zname and zname in _ws_by_name:
                        leaf_x = max(0, off_x)
                        leaf_y = max(TITLE_H, off_y + TITLE_H)
                        leaf_w = max(_MIN_VIS_W, avail_w)
                        leaf_h = max(_MIN_VIS_H, avail_h)
                        # Largest-area-wins: Tableau dashboards often have the same
                        # worksheet name appearing in BOTH the main chart panel AND a
                        # narrow legend/color strip alongside it.  The strip is processed
                        # after the chart panel and would overwrite the correct coords.
                        # Always keep whichever registration covers the LARGEST area.
                        _new_area = leaf_w * leaf_h
                        _old = _pbi_zone_coords.get(zname)
                        if _old is None or (_new_area > _old[2] * _old[3]):
                            _pbi_zone_coords[zname] = (leaf_x, leaf_y, leaf_w, leaf_h)
                    return

                n = len(children)
                if n == 0:
                    return

                # ── Apply container-edge padding ──────────────────────────────
                # Shrink the available region by _INNER_PAD on all sides so that
                # children never touch the container boundary.
                pad_x    = off_x  + _INNER_PAD
                pad_y    = off_y  + _INNER_PAD
                pad_w    = max(1, avail_w - 2 * _INNER_PAD)
                pad_h    = max(1, avail_h - 2 * _INNER_PAD)

                # ── Total gutter budget consumed by sibling gaps ──────────────
                total_h_gap = _CHILD_GAP * max(0, n - 1)
                total_w_gap = _CHILD_GAP * max(0, n - 1)

                # ── Horizontal / Vertical / Tiled containers ────────────────────
                # All three share ONE real-relative-position scaling (Increment
                # 18): every Tableau zone already carries a final, real,
                # absolute position, so a container's children are placed
                # using their own recorded offset from the CONTAINER's own
                # origin, scaled into whatever region this container was
                # assigned — never a weight-normalized split that forces the
                # tree-visible children to consume 100% of the container.
                #
                # That normalized-to-100% approach (the previous
                # horizontal/vertical behavior, and the tiled branch's old
                # cols=min(n,2) grid before it too) is wrong whenever a
                # skip-typed sibling — filter/parameter/text/color/legend
                # zones are deliberately excluded from this tree, rendered
                # via their own separate paths instead — occupies real space
                # Tableau reserved for it. Confirmed real and not
                # hypothetical: House Sales Dashboard's left sidebar is one
                # 'vertical' container whose real XML has TWO children (a
                # quick-filter-card zone, plus the 'Filters' worksheet below
                # it), but only 'Filters' is tree-visible (the filter zone is
                # skip-typed and rendered separately as a slicer) — giving
                # the lone visible child a weight-normalized 100% share
                # stretched 'Filters' up into the filter card's own space,
                # a real, visible overlap. Scaling by real recorded position
                # relative to the container's own real bounding box instead
                # leaves that space as an honest gap (matching where the
                # invisible sibling actually sits), not overwritten.
                if layout in ('horizontal', 'vertical', 'tiled'):
                    _cont_x = node.get('x', 0); _cont_y = node.get('y', 0)
                    _cont_w = max(1, node.get('w', 1)); _cont_h = max(1, node.get('h', 1))
                    _scale_x = pad_w / _cont_w
                    _scale_y = pad_h / _cont_h
                    for child in children:
                        _rel_x = child.get('x', _cont_x) - _cont_x
                        _rel_y = child.get('y', _cont_y) - _cont_y
                        cx = pad_x + int(round(_rel_x * _scale_x))
                        cy = pad_y + int(round(_rel_y * _scale_y))
                        cw = max(_MIN_VIS_W, int(round(child.get('w', 200) * _scale_x)))
                        ch = max(_MIN_VIS_H, int(round(child.get('h', 150) * _scale_y)))
                        # Clamp within this container's own assigned region.
                        cx = max(pad_x, min(cx, pad_x + pad_w - _MIN_VIS_W))
                        cy = max(pad_y, min(cy, pad_y + pad_h - _MIN_VIS_H))
                        cw = min(cw, pad_x + pad_w - cx)
                        ch = min(ch, pad_y + pad_h - cy)
                        _distribute(child, cx, cy, cw, ch)

                # ── Floating container ────────────────────────────────────────
                elif layout == 'floating':
                    # Preserve original Tableau coordinates scaled to the current
                    # available canvas region.  tab_w / tab_h are the source
                    # dashboard dimensions captured from the page metadata.
                    scale_x = avail_w / max(tab_w, 1)
                    scale_y = avail_h / max(tab_h, 1)
                    for child in children:
                        raw_x = child.get('x', 0)
                        raw_y = child.get('y', 0)
                        raw_w = child.get('w', 200)
                        raw_h = child.get('h', 150)
                        # Clamp origin before sizing so the size budget is always
                        # positive and the visual never starts outside the region.
                        cx = max(0, min(int(round(raw_x * scale_x)),
                                        avail_w - _MIN_VIS_W - _INNER_PAD))
                        cy = max(0, min(int(round(raw_y * scale_y)),
                                        avail_h - _MIN_VIS_H - _INNER_PAD))
                        # Size is bounded by the remaining room from the clamped origin.
                        cw = max(_MIN_VIS_W,
                                 min(int(round(raw_w * scale_x)),
                                     avail_w - cx - _INNER_PAD))
                        ch = max(_MIN_VIS_H,
                                 min(int(round(raw_h * scale_y)),
                                     avail_h - cy - _INNER_PAD))
                        _distribute(child, off_x + cx, off_y + cy, cw, ch)

                # ── Safety fallback ─────────────────────────────────────────
                # Every real ctype _build_layout_tree ever assigns is one of
                # 'floating'/'horizontal'/'vertical'/'tiled'/'leaf' (the leaf
                # case is handled earlier, above); this only exists so an
                # unexpected future ctype degrades to a plain equal grid
                # instead of raising.
                else:
                    cols = min(n, 2)
                    rows = max(1, (n + cols - 1) // cols)
                    col_w = max(_MIN_VIS_W, pad_w // cols)
                    row_h = max(_MIN_VIS_H, pad_h // rows)
                    for idx, child in enumerate(children):
                        ci, ri = idx % cols, idx // cols
                        _distribute(child, pad_x + ci * col_w, pad_y + ri * row_h,
                                    col_w, row_h)

            _layout_tree = page.get('layout_tree', [])
            if _layout_tree:
                _container_roots = [r for r in _layout_tree
                                     if not r.get('name') or r.get('children')]
                _named_leaf_roots = [r for r in _layout_tree
                                      if r.get('name') and not r.get('children')]
                _tab_w_f = float(page.get('db_tab_w', W) or W)
                _tab_h_f = float(page.get('db_tab_h', H - TITLE_H) or (H - TITLE_H))
                _sx_abs  = W  / max(_tab_w_f, 1)
                _sy_abs  = (H - TITLE_H) / max(_tab_h_f, 1)
                # When multiple leaf nodes share the same name (e.g. Tableau color-legend
                # strips alongside the main chart zone), always use the LARGEST one by area.
                # The main chart zone is always the largest; the legend/axis strips are tiny.
                _best_leaf: dict = {}
                for _lr in _named_leaf_roots:
                    _lname = _lr.get('name', '')
                    if not _lname or _lname not in _ws_by_name:
                        continue
                    _area = _lr.get('w', 0) * _lr.get('h', 0)
                    if _lname not in _best_leaf or _area > _best_leaf[_lname]['area']:
                        _best_leaf[_lname] = {**_lr, 'area': _area}
                for _lname, _lr in _best_leaf.items():
                    _raw_x = _lr.get('x', 0); _raw_y = _lr.get('y', 0)
                    _raw_w = _lr.get('w', _MIN_VIS_W); _raw_h = _lr.get('h', _MIN_VIS_H)
                    _leaf_x = max(0, int(_raw_x * _sx_abs))
                    _leaf_y = max(TITLE_H, int(_raw_y * _sy_abs) + TITLE_H)
                    _leaf_w = max(_MIN_VIS_W, min(int(_raw_w * _sx_abs), W - _leaf_x - _INNER_PAD))
                    _leaf_h = max(_MIN_VIS_H, min(int(_raw_h * _sy_abs), H - _leaf_y - _INNER_PAD))
                    _pbi_zone_coords[_lname] = (_leaf_x, _leaf_y, _leaf_w, _leaf_h)
                if _container_roots:
                    n_roots        = len(_container_roots)
                    root_canvas_w  = W
                    root_canvas_h  = H - TITLE_H
                    root_weights   = [_child_weight_w(r) for r in _container_roots]
                    total_root_gap = _CHILD_GAP * max(0, n_roots - 1)
                    usable_root_w  = max(1, root_canvas_w - total_root_gap)
                    root_shares    = _safe_split(usable_root_w, root_weights, _MIN_VIS_W)
                    rx = 0
                    for ri, (root_node, rw_share) in enumerate(
                            zip(_container_roots, root_shares)):
                        _distribute(root_node, rx, 0, rw_share, root_canvas_h)
                        rx += rw_share + (_CHILD_GAP if ri < n_roots - 1 else 0)

            # Collision tracker for _sz fallback
            _placed_boxes: list = []

            def _sz_own(zone):
                """
                Proportional sx/sy scaling of a zone's OWN raw (x,y,w,h) with
                collision nudge — no _pbi_zone_coords lookup at all.

                Used directly (not via _sz()) for filter/parameter dashboard
                zones. Schema-verified real Tableau convention (confirmed on
                HR Analytics' 'KPI' filter, AB_NYC's neighbourhood_group
                filter, and LocBar's 'CustBar'/'Custpie' filters): a
                quick-filter-card zone's own 'name' attribute is frequently
                the SAME string as the worksheet it filters, even though
                they're two entirely separate <zone> elements with their own
                independent x/y/w/h. _pbi_zone_coords is a single
                name-keyed cache meant for worksheet chart positions only —
                looking a filter/parameter zone up in it by that shared name
                returns (or, worse, overwrites) the WORKSHEET's chart rect
                instead of the filter card's own small one. Confirmed as a
                real, already-shipped bug this way, not a hypothetical: HR
                Analytics' 'KPI' multiRowCard was already silently squashed
                to its filter-slicer's tiny rect (9,132,188,131) in the
                pre-existing code, before this function existed — verified
                via a direct dump of the generated PBIT's own Report/Layout,
                not assumed. LocBar's 'CustBar'/'Custpie' hit the same
                collision the moment their filter zones started being
                correctly classified (see _zone_type()) instead of silently
                dropped.
                """
                GAP = 3
                zx = max(0,       int(zone.get('x', 0) * sx))
                zy = max(TITLE_H, int(zone.get('y', 0) * sy) + TITLE_H)
                zw = max(80, min( int(zone.get('w', 200) * sx) - GAP, W - zx - GAP))
                zh = max(50, min( int(zone.get('h', 150) * sy) - GAP, H - zy - GAP))
                for _ in range(12):
                    if not any(zx < px + pw and zx + zw > px and
                               zy < py + ph and zy + zh > py
                               for (px, py, pw, ph) in _placed_boxes):
                        break
                    if zy + zh + GAP * 4 < H:   zy += GAP * 4
                    elif zx + zw + GAP * 4 < W:  zx += GAP * 4; zy = TITLE_H
                    else:                          break
                _placed_boxes.append((zx, zy, zw, zh))
                return zx, zy, zw, zh

            def _sz(zone):
                """
                Return (x, y, w, h) for a zone in PBI pixel space.
                Priority 1: use layout-tree-derived coordinates (respects containers).
                Priority 2: proportional sx/sy scaling with collision nudge.
                """
                GAP   = 3
                zname = zone.get('name', '')
                if zname and zname in _pbi_zone_coords:
                    zx, zy, zw, zh = _pbi_zone_coords[zname]
                    zw = max(80, min(zw, W - zx - GAP))
                    zh = max(50, min(zh, H - zy - GAP))
                    _placed_boxes.append((zx, zy, zw, zh))
                    return zx, zy, zw, zh
                return _sz_own(zone)

            # ── Normalise (strip whitespace/hyphen/underscore separators) ──────
            # Previously stripped ALL non-alphanumeric characters, which
            # collapses a calculated field's name onto an unrelated base
            # column whenever the calc name is the column name plus a
            # trailing symbol — confirmed against a real sample: HR
            # Analytics' calculated field "Attrition #" normalised identically
            # to the raw dimension "Attrition", so _fc/_fm/the calc-column
            # merge in _filter_ds all silently treated the calc as "already
            # present" and every worksheet using "Attrition #" as its actual
            # measure (a bar chart, a treemap size, an area chart value) lost
            # it, falling back to the wrong plain "Attrition" dimension
            # instead. Keeping symbols like '#' preserves that distinction
            # while still absorbing the spacing/case/hyphen variance this
            # helper exists for.
            def _nz(s):
                import re as _r
                return _r.sub(r'[\s\-_]', '', str(s).lower())

            # ── Datasource resolution ──────────────────────────────────────────
            def _zone_ds(zone_ws):
                for dsn in zone_ws.get('ds_names', []):
                    d = next((d for d in datasources
                               if d['name'] == dsn
                               or d.get('raw_name', '').lower() == dsn.lower()), None)
                    if d: return d
                return datasources[0] if datasources else None

            # ── Column / calc lookup ───────────────────────────────────────────
            def _fc(nm, cols):
                """Find column by name (normalised match, then '(copy)'-suffix —
                see _is_copy_suffix_of; NOT a bare prefix, which would also
                match an unrelated longer name)."""
                if not nm: return None
                nn = _nz(nm)
                r = next((c for c in cols if _nz(c['name']) == nn), None)
                if r: return r
                return next((c for c in cols
                             if _is_copy_suffix_of(_nz(c['name']), nn)), None)

            def _fm(nm, msrs):
                """Find DAX calc/measure by name (normalised match, then
                '(copy)'-suffix — see _is_copy_suffix_of; NOT a bare prefix,
                which would also match an unrelated longer name)."""
                if not nm: return None
                nn = _nz(nm)
                r = next((m for m in msrs if _nz(m['name']) == nn), None)
                if r: return r
                return next((m for m in msrs
                             if _is_copy_suffix_of(_nz(m['name']), nn)), None)

            # ── Filtered datasource view ───────────────────────────────────────
            def _filter_ds(z_ds, zone_pg):
                """
                Return (z_fcols, z_fagg) scoped to this zone's worksheet.

                IMPORTANT: z_fagg contains only real DAX calc objects from the
                datasource. Numeric columns are in z_fcols (not z_fagg).
                The caller must use _resolve_val() which handles both correctly:
                  - DAX calc    → is_measure=True  → Measure{} in PBI query
                  - numeric col → is_agg=True       → Aggregation{Sum} in PBI query
                """
                z_acols = z_ds.get('columns', [])
                z_calcs = [c for c in z_ds.get('calculations', [])
                           if not c.get('is_action_calc')]
                z_agg   = [c for c in z_calcs if  c.get('is_agg_calc', True)]
                z_ccol  = [c for c in z_calcs if not c.get('is_agg_calc', True)]

                # Collect ALL field names this worksheet references (every shelf)
                all_fld_norms = set()
                for flist in [
                    zone_pg.get('fields', []),
                    zone_pg.get('shelf_row_fields', []),
                    zone_pg.get('all_row_measure_fields', []),
                    zone_pg.get('all_col_fields', []),
                    zone_pg.get('all_col_dim_fields', []),
                    zone_pg.get('color_fields', []),
                    [zone_pg.get('x_field', '')],
                    [zone_pg.get('y_field', '')],
                    [zone_pg.get('text_enc_field', '')],
                    [zone_pg.get('pie_size_field', '')],
                ]:
                    for f in flist:
                        if f: all_fld_norms.add(_nz(f))

                # Filter columns to worksheet's field list
                z_flds = zone_pg.get('fields', [])
                if z_flds:
                    cmap = {_nz(c['name']): c for c in z_acols}
                    z_fcols = [c for f in z_flds for c in [cmap.get(_nz(f))] if c]
                    z_fcols = list({id(c): c for c in z_fcols}.values())
                    if not z_fcols:
                        z_fcols = list(z_acols)
                else:
                    z_fcols = list(z_acols)

                # Filter DAX calcs to those referenced; fall back to all if empty
                z_fagg = ([c for c in z_agg if _nz(c['name']) in all_fld_norms]
                          or z_agg)
                z_fcc  = [c for c in z_ccol if _nz(c['name']) in all_fld_norms]

                # ── Registry augmentation ────────────────────────────────────
                # For every numeric column referenced on a shelf whose name is NOT
                # already in z_fagg, inject a synthetic measure stub so _fm() can
                # find it by name and _resolve_val emits is_measure=True instead of
                # falling through to is_agg=True (inline Aggregation expression).
                _fagg_norms = {_nz(c['name']) for c in z_fagg}
                for _fld_norm in all_fld_norms:
                    if _fld_norm in _fagg_norms:
                        continue
                    # Find the raw field name from the normalized key
                    _raw_fld = next(
                        (f for flist in [
                            zone_pg.get('fields', []),
                            zone_pg.get('shelf_row_fields', []),
                            zone_pg.get('all_row_measure_fields', []),
                            zone_pg.get('all_col_fields', []),
                            [zone_pg.get('x_field', '')],
                            [zone_pg.get('y_field', '')],
                            [zone_pg.get('pie_size_field', '')],
                        ] for f in flist if f and _nz(f) == _fld_norm),
                        None
                    )
                    if not _raw_fld:
                        continue
                    _msr_item = _measure_registry.resolve(_raw_fld, z_ds)
                    if _msr_item and _nz(_msr_item['name']) not in _fagg_norms:
                        z_fagg.append(_msr_item)
                        _fagg_norms.add(_nz(_msr_item['name']))

                # Merge non-agg calcs (calculated columns) into fcols
                for cc in z_fcc:
                    e = {'name': cc['name'], 'source_name': cc['name'],
                         'datatype': cc.get('datatype', 'double'),
                         'role': 'measure', 'hidden': False,
                         'measure': True, 'is_calc_col': True}
                    if not any(_nz(e['name']) == _nz(c['name']) for c in z_fcols):
                        z_fcols.append(e)

                return z_fcols, z_fagg

            # ── Category field resolution ──────────────────────────────────────
            # Shared with the standalone-page path — see _resolve_category_fields
            # for bin-calc / date-hierarchy / multi-field-grouping handling.
            def _resolve_cat(zone_pg, z_fcols, is_hbar=False):
                if is_hbar:
                    candidates = (zone_pg.get('shelf_row_fields', [])[:1]
                                  + [zone_pg.get('y_field', '')])
                else:
                    candidates = (zone_pg.get('all_col_fields', [])
                                  + [zone_pg.get('x_field', '')]
                                  + zone_pg.get('all_col_dim_fields', []))

                return _resolve_category_fields(
                    candidates, is_hbar, z_fcols,
                    z_ds.get('calculations', []),
                    zone_pg.get('date_shelf_groupings', []),
                    zone_pg.get('all_col_fields', []))

            # ── Value field resolution ─────────────────────────────────────────
            def _resolve_val(zone_pg, z_fcols, z_fagg, is_hbar=False):
                """
                Resolve value (Y-axis) field(s).

                KEY RULE (matches both individual sheets AND dashboard):
                  - If field found in z_fagg (real DAX calc) → is_measure=True
                    → _make_chart_vc emits Measure{Property:'name'} ✓
                  - If field found in z_fcols as numeric column → is_agg=True
                    → _make_chart_vc emits Aggregation{Sum, Column:'name'} ✓
                  - NEVER emit is_measure=True for a plain numeric column —
                    that would create a Measure{} reference to a non-existent
                    DAX measure, causing a blank visual.

                Fallback chain:
                  all_row_measure_fields → y_field → shelf_row_fields → all z_fagg
                  → all numeric z_fcols
                """
                _num = ('int64', 'double', 'decimal', 'int32', 'currency', 'real')

                if is_hbar:
                    candidates = (zone_pg.get('all_col_fields', [])
                                  + [zone_pg.get('x_field', '')])
                else:
                    candidates = (zone_pg.get('all_row_measure_fields', [])
                                  + [zone_pg.get('y_field', '')]
                                  + zone_pg.get('shelf_row_fields', []))

                val_f = []
                seen  = set()

                def _add(nm):
                    if not nm or _nz(nm) in seen: return
                    # 1. Real DAX calc → Measure{}
                    obj = _fm(nm, z_fagg)
                    if obj:
                        seen.add(_nz(obj['name']))
                        val_f.append({**obj, 'is_measure': True, 'is_agg': False})
                        return
                    # 2. Numeric column → prefer pre-built measure, fallback to Aggregation{Sum}
                    obj = _fc(nm, z_fcols)
                    if obj and (obj.get('datatype', '') in _num or obj.get('measure')):
                        seen.add(_nz(obj['name']))
                        _reg_item = _measure_registry.resolve(obj['name'], z_ds)
                        if _reg_item:
                            val_f.append({**_reg_item, 'is_measure': True, 'is_agg': False})
                        else:
                            val_f.append({**obj, 'is_measure': False, 'is_agg': True})

                for nm in candidates:
                    _add(nm)

                # If still empty, use all scoped DAX calcs
                if not val_f:
                    for m in z_fagg:
                        if _nz(m['name']) not in seen:
                            seen.add(_nz(m['name']))
                            val_f.append({**m, 'is_measure': True, 'is_agg': False})

                # Last resort: all numeric columns — prefer pre-built measure
                if not val_f:
                    for c in z_fcols:
                        if (c.get('datatype', '') in _num or c.get('measure')) \
                                and _nz(c['name']) not in seen:
                            seen.add(_nz(c['name']))
                            _reg_item = _measure_registry.resolve(c['name'], z_ds)
                            if _reg_item:
                                val_f.append({**_reg_item, 'is_measure': True, 'is_agg': False})
                            else:
                                val_f.append({**c, 'is_measure': False, 'is_agg': True})
                            break   # just one, avoid flooding the chart

                return val_f

            # ── Legend field resolution ────────────────────────────────────────
            # Shared with the standalone-page path — see _resolve_legend_fields.
            def _resolve_leg(zone_pg, z_fcols, z_fcat_f):
                return _resolve_legend_fields(
                    zone_pg.get('color_fields', []), z_fcat_f, z_fcols, z_fagg)

            # ── Pie/donut category + value ──────────────────────────────────────
            # Shared with the standalone-page path — see _resolve_pie_fields.
            def _resolve_pie(zone_pg, z_fcols, z_fagg):
                return _resolve_pie_fields(
                    zone_pg.get('color_fields', []), z_fcols, z_fagg,
                    zone_pg.get('shelf_row_fields', []),
                    zone_pg.get('pie_size_field', ''),
                    z_ds, _measure_registry)

            _CHARTS = {
                'clusteredColumnChart', 'columnChart',
                'clusteredBarChart', 'barChart',
                'lineChart', 'areaChart',
                'stackedColumnChart', 'stackedBarChart',
                'hundredPercentStackedColumnChart', 'hundredPercentStackedBarChart',
                'lineClusteredColumnComboChart',
                'scatterChart', 'treemap', 'bubbleChart',
                'filledMap', 'mapChart',
            }

            rendered = set()

            # ── Slicer / filter zones ──────────────────────────────────────────
            for fzone in page.get('db_filter_zones', []):
                fname = fzone.get('name', '')
                if not fname or fname in rendered: continue
                if fname not in _ws_by_name:
                    print(f"[DEBUG except] Slicer '{fname}': not in _ws_by_name")
                    continue
                rendered.add(fname + '__slicer')
                fx, fy, fw, fh = _sz_own(fzone)
                f_ws  = _ws_by_name[fname]
                f_ds  = _zone_ds(f_ws)
                if not f_ds:
                    print(f"[DEBUG except] Slicer '{fname}': no datasource")
                    continue
                f_tbl = ds_pbi_names.get(f_ds['name'], _safe(f_ds['name']))
                # Prefer the filter zone's OWN 'param' attribute (the exact field
                # the author put on this filter card) over guessing from the
                # worksheet's x_field — see the note in _collect_zone/the
                # filter_field resolution step in parse_tableau_workbook for why
                # the old guess-only approach was confirmed wrong on a real
                # sample (HR Analytics' "KPI" Department filter resolving to
                # the unrelated column "Attrition").
                f_col = None
                _f_param_field = fzone.get('filter_field', '')
                if _f_param_field:
                    f_col = (_fc(_f_param_field, f_ds.get('columns', []))
                             or _fm(_f_param_field, f_ds.get('calculations', [])))
                if f_col is None:
                    f_fn  = (f_ws.get('x_field') or
                             next((c['name'] for c in f_ds.get('columns', [])
                                   if not c.get('measure')), None))
                    if not f_fn:
                        print(f"[DEBUG except] Slicer '{fname}': no field")
                        continue
                    f_col = _fc(f_fn, f_ds.get('columns', []))
                if not f_col:
                    print(f"[DEBUG except] Slicer '{fname}': field '{_f_param_field}' not found")
                    continue
                # 'dropdown' mode = single-value selector; 'checkdropdown' (or
                # any other/absent mode) = the existing multi-select checklist.
                f_single_select = 'true' if fzone.get('filter_mode') == 'dropdown' else 'false'
                try:
                    s_cfg = _jmin({
                        'name': _guid(),
                        'layouts': [{'id': 0, 'position': {
                            'x': fx, 'y': fy, 'z': z, 'width': fw, 'height': fh}}],
                        'singleVisual': {
                            'visualType': 'slicer',
                            'projections': {'Values': [
                                {'queryRef': f'{f_tbl}.{f_col["name"]}', 'active': True}]},
                            'prototypeQuery': {
                                'Version': 2,
                                'From': [{'Name': 's', 'Entity': f_tbl, 'Type': 0}],
                                'Select': [{'Column': {
                                    'Expression': {'SourceRef': {'Source': 's'}},
                                    'Property': f_col['name']},
                                    'Name': f'{f_tbl}.{f_col["name"]}'}]},
                            'objects': {
                                'general': [{'properties': {'orientation': {
                                    'expr': {'Literal': {'Value': "'horizontal'"}}}}}],
                                'selection': [{'properties': {'singleSelect': {
                                    'expr': {'Literal': {'Value': f_single_select}}}}}]},
                            'vcObjects': {}, 'display': {}}})
                    s_q = _jmin({'Commands': [{'SemanticQueryDataShapeCommand': {
                        'Query': {
                            'Version': 2,
                            'From': [{'Name': 's', 'Entity': f_tbl, 'Type': 0}],
                            'Select': [{'Column': {
                                'Expression': {'SourceRef': {'Source': 's'}},
                                'Property': f_col['name']},
                                'Name': f'{f_tbl}.{f_col["name"]}'}],
                            'OrderBy': [{'Direction': 1, 'Expression': {'Column': {
                                'Expression': {'SourceRef': {'Source': 's'}},
                                'Property': f_col['name']}}}]},
                        'Binding': {
                            'Primary': {'Groupings': [{'Projections': [0]}]},
                            'DataReduction': {'DataVolume': 3,
                                             'Primary': {'Window': {'Count': 200}}},
                            'Version': 1}}}]})
                    visual_containers.append({
                        'x': fx, 'y': fy, 'z': z, 'width': fw, 'height': fh,
                        'config': s_cfg, 'query': s_q,
                        'dataTransforms': _jmin({'selects': [{
                            'displayName': f_col['name'],
                            'queryName': f'{f_tbl}.{f_col["name"]}',
                            'roles': {'Values': True}}]})})
                    z += 1
                except Exception as _se:
                    print(f"[DEBUG except] Slicer '{fname}': {_se}")
                    import traceback as _stb; print(_stb.format_exc())

            # ── Parameter-control zones → slicer bound to the What-if parameter
            # table built in build_data_model_schema (workbook['_param_tables']).
            # Reuses the exact same slicer JSON shape as the filter-zone slicer
            # above — the only difference is which table/column it points at.
            for pzone in page.get('db_parameter_zones', []):
                pname = pzone.get('name', '')
                pcaption = pzone.get('param', '')
                if not pname or pname in rendered or not pcaption:
                    continue
                _ptbl_info = workbook.get('_param_tables', {}).get(pcaption)
                if not _ptbl_info:
                    # 'any'-domain parameter (or unresolved) — no enumerable
                    # table exists to slice on; already flagged in the
                    # Parameters audit section, nothing more to do here.
                    print(f"[DEBUG except] Parameter slicer '{pname}': "
                          f"'{pcaption}' has no What-if table (non-enumerable domain)")
                    continue
                rendered.add(pname + '__param_slicer')
                px, py, pw, ph = _sz_own(pzone)
                p_tbl = _ptbl_info['table']
                p_col = _ptbl_info['column']
                try:
                    s_cfg = _jmin({
                        'name': _guid(),
                        'layouts': [{'id': 0, 'position': {
                            'x': px, 'y': py, 'z': z, 'width': pw, 'height': ph}}],
                        'singleVisual': {
                            'visualType': 'slicer',
                            'projections': {'Values': [
                                {'queryRef': f'{p_tbl}.{p_col}', 'active': True}]},
                            'prototypeQuery': {
                                'Version': 2,
                                'From': [{'Name': 's', 'Entity': p_tbl, 'Type': 0}],
                                'Select': [{'Column': {
                                    'Expression': {'SourceRef': {'Source': 's'}},
                                    'Property': p_col},
                                    'Name': f'{p_tbl}.{p_col}'}]},
                            'objects': {
                                'general': [{'properties': {'orientation': {
                                    'expr': {'Literal': {'Value': "'horizontal'"}}}}}],
                                'selection': [{'properties': {'singleSelect': {
                                    'expr': {'Literal': {'Value': 'true'}}}}}]},
                            'vcObjects': {}, 'display': {}}})
                    s_q = _jmin({'Commands': [{'SemanticQueryDataShapeCommand': {
                        'Query': {
                            'Version': 2,
                            'From': [{'Name': 's', 'Entity': p_tbl, 'Type': 0}],
                            'Select': [{'Column': {
                                'Expression': {'SourceRef': {'Source': 's'}},
                                'Property': p_col},
                                'Name': f'{p_tbl}.{p_col}'}],
                            'OrderBy': [{'Direction': 1, 'Expression': {'Column': {
                                'Expression': {'SourceRef': {'Source': 's'}},
                                'Property': p_col}}}]},
                        'Binding': {
                            'Primary': {'Groupings': [{'Projections': [0]}]},
                            'DataReduction': {'DataVolume': 3,
                                             'Primary': {'Window': {'Count': 200}}},
                            'Version': 1}}}]})
                    visual_containers.append({
                        'x': px, 'y': py, 'z': z, 'width': pw, 'height': ph,
                        'config': s_cfg, 'query': s_q,
                        'dataTransforms': _jmin({'selects': [{
                            'displayName': p_col,
                            'queryName': f'{p_tbl}.{p_col}',
                            'roles': {'Values': True}}]})})
                    z += 1
                except Exception as _pse:
                    print(f"[DEBUG except] Parameter slicer '{pname}': {_pse}")
                    import traceback as _pstb; print(_pstb.format_exc())

            # ── Dashboard Text Object zones → real formatted textbox visual ────
            # Real, schema-verified (<zone type='text'><formatted-text><run
            # .../></formatted-text>), previously dropped entirely (both
            # _skip_types and _LAYOUT_SKIP_TYPES excluded them, so no PBI
            # visual was ever generated). No 'name' attribute exists on
            # these zones (confirmed across all 10 fixtures), so there's no
            # name to dedup/collide on — use _sz_own() directly, same as
            # filter/parameter zones, never _pbi_zone_coords.
            for tzone in page.get('db_text_zones', []):
                _truns = tzone.get('runs', [])
                if not _truns:
                    continue
                tx, ty, tw, th = _sz_own(tzone)
                try:
                    visual_containers.append(_make_dashboard_text_vc(
                        name=_guid(), x=tx, y=ty, z=z, width=tw, height=th,
                        runs=_truns,
                        background_color=tzone.get('background_color', '')))
                    z += 1
                except Exception as _tze:
                    print(f"[DEBUG except] Text zone at ({tx},{ty}): {_tze}")
                    import traceback as _tztb; print(_tztb.format_exc())

            # ── Chart / table zones ────────────────────────────────────────────
            for zone in page.get('db_zones', []):
                zname = zone.get('name', '')
                z_show_title = zone.get('show_title', True)
                z_border_color = zone.get('border_color', '')
                z_border_width = zone.get('border_width', 1)
                if not zname or zname in rendered: continue
                if zname not in _ws_by_name:
                    print(f"[DEBUG except] Zone '{zname}': not in _ws_by_name")
                    continue
                rendered.add(zname)

                zx, zy, zw, zh = _sz(zone)
                if zw < 40 or zh < 30:
                    print(f"[DEBUG except] Zone '{zname}': too small ({zw}x{zh})")
                    continue

                zone_ws = _ws_by_name[zname]
                zone_pg = _ws_to_page(zone_ws)
                z_background_color = zone_pg.get('background_color', '')
                z_title_font_family = zone_pg.get('title_font_family', '')
                z_title_font_size   = zone_pg.get('title_font_size', 0)
                z_title_bold        = zone_pg.get('title_bold', False)
                z_title_italic      = zone_pg.get('title_italic', False)
                z_title_color       = zone_pg.get('title_color', '')
                z_title_bg_color    = zone_pg.get('title_bg_color', '')
                z_axis_label_font_family = zone_pg.get('axis_label_font_family', '')
                z_axis_label_font_size   = zone_pg.get('axis_label_font_size', 0)
                z_axis_label_bold        = zone_pg.get('axis_label_bold', False)
                z_axis_label_italic      = zone_pg.get('axis_label_italic', False)
                z_axis_label_color       = zone_pg.get('axis_label_color', '')
                z_legend_font_family = zone_pg.get('legend_font_family', '')
                z_legend_font_size   = zone_pg.get('legend_font_size', 0)
                z_legend_bold        = zone_pg.get('legend_bold', False)
                z_legend_italic      = zone_pg.get('legend_italic', False)
                z_legend_color       = zone_pg.get('legend_color', '')
                z_datalabel_font_family = zone_pg.get('datalabel_font_family', '')
                z_datalabel_font_size   = zone_pg.get('datalabel_font_size', 0)
                z_datalabel_bold        = zone_pg.get('datalabel_bold', False)
                z_datalabel_italic      = zone_pg.get('datalabel_italic', False)
                z_datalabel_color       = zone_pg.get('datalabel_color', '')
                z_axis_title_value    = zone_pg.get('axis_title_value', '')
                z_axis_title_value2   = zone_pg.get('axis_title_value2', '')
                z_axis_title_category = zone_pg.get('axis_title_category', '')
                z_gridlines_hidden    = zone_pg.get('gridlines_hidden', False)
                z_ds    = _zone_ds(zone_ws)
                if not z_ds:
                    print(f"[DEBUG except] Zone '{zname}': no datasource")
                    continue
                z_tbl  = ds_pbi_names.get(z_ds['name'], _safe(z_ds['name']))

                try:
                    z_fcols, z_fagg = _filter_ds(z_ds, zone_pg)
                except Exception as _fde:
                    print(f"[DEBUG except] Zone '{zname}': _filter_ds: {_fde}")
                    z_fcols = z_ds.get('columns', [])
                    z_fagg  = [c for c in z_ds.get('calculations', [])
                                if c.get('is_agg_calc', True)
                                and not c.get('is_action_calc')]

                z_dsv   = {**z_ds, 'columns': z_fcols, 'calculations': z_fagg}
                z_chart = zone_pg.get('chart_type', 'tableEx')
                _hbar   = z_chart in ('clusteredBarChart', 'barChart',
                                       'hundredPercentStackedBarChart')

                # Debug: print exactly what each zone resolved to
                print(f"[DEBUG] zone='{zname}' chart={z_chart} "
                      f"x='{zone_pg.get('x_field','')}' "
                      f"y='{zone_pg.get('y_field','')}' "
                      f"all_row={zone_pg.get('all_row_measure_fields',[])} "
                      f"shelf={zone_pg.get('shelf_row_fields',[])} "
                      f"fagg_names={[m['name'] for m in z_fagg[:5]]} "
                      f"fcols={[c['name'] for c in z_fcols[:5]]}")

                try:
                    if z_chart == 'card':
                        z_tf = zone_pg.get('text_enc_field') or zone_pg.get('y_field', '')
                        z_vc = _fm(z_tf, z_fagg) if z_tf else None
                        # Before falling back to an arbitrary z_fagg[0], also try
                        # z_fcols — _filter_ds() merges non-aggregating calcs
                        # (calculated columns, e.g. a bare parameter passthrough
                        # like 'formula=[Parameters].[Parameter 1]', which has no
                        # aggregation function so _is_aggregating_formula tags it
                        # is_agg_calc=False and it never lands in z_fagg) into
                        # z_fcols instead. Confirmed against a real sample: Sales
                        # Param's "Sales Value" card, whose real text-encoding
                        # field 'Paramter1' is exactly this kind of calc — the old
                        # code always missed it in z_fagg and silently substituted
                        # whatever calc happened to be z_fagg[0] (a completely
                        # unrelated text-valued calc, 'Sales Threshold').
                        if z_vc is None and z_tf:
                            z_vc = _fc(z_tf, z_fcols)
                        if z_vc is None and z_fagg:
                            z_vc = z_fagg[0]
                        if z_vc is None:
                            z_vc = next((c for c in z_fcols
                                         if c.get('datatype') in
                                         ('int64', 'double', 'int32', 'decimal')), None)
                        if z_vc:
                            visual_containers.append(_make_card_vc(
                                name=_guid(), x=zx, y=zy, z=z,
                                width=zw, height=zh,
                                value_fields=[z_vc], pbi_table_name=z_tbl,
                                zone_name=zname, data_colors=data_colors,
                                filter_specs=zone_pg.get('filter_specs', []),
                                filter_fields=zone_pg.get('filter_fields', []),
                                show_title=z_show_title,
                                border_color=z_border_color, border_width=z_border_width,
                                title_font_family=z_title_font_family, title_font_size=z_title_font_size,
                                title_bold=z_title_bold, title_italic=z_title_italic,
                                title_color=z_title_color, title_bg_color=z_title_bg_color))
                            print(f"[DEBUG] '{zname}' → card: '{z_vc['name']}'")
                        else:
                            print(f"[DEBUG except] '{zname}' (card): no measure → table fallback")
                            raise ValueError('no card measure')

                    elif z_chart == 'multiRowCard':
                        # Tableau's ":Measure Names on a shelf + Measure
                        # Values as text, filtered to N measures" KPI strip.
                        # measure_names_filter_fields is already the ordered
                        # list of captions from that filter's member list
                        # (built once, independent of chart_type, in the
                        # worksheet parser).
                        z_mrc_fields = _resolve_multirow_card_fields(
                            zone_pg.get('measure_names_filter_fields', []),
                            z_fcols, z_fagg)
                        if z_mrc_fields:
                            visual_containers.append(_make_multirow_card_vc(
                                name=_guid(), x=zx, y=zy, z=z,
                                width=zw, height=zh,
                                value_fields=z_mrc_fields, pbi_table_name=z_tbl,
                                zone_name=zname, data_colors=data_colors,
                                filter_specs=zone_pg.get('filter_specs', []),
                                filter_fields=zone_pg.get('filter_fields', []),
                                show_title=z_show_title,
                                border_color=z_border_color, border_width=z_border_width,
                                title_font_family=z_title_font_family, title_font_size=z_title_font_size,
                                title_bold=z_title_bold, title_italic=z_title_italic,
                                title_color=z_title_color, title_bg_color=z_title_bg_color))
                            print(f"[DEBUG] '{zname}' → multiRowCard: "
                                  f"{[f['name'] for f in z_mrc_fields]}")
                        else:
                            print(f"[DEBUG except] '{zname}' (multiRowCard): "
                                  f"no measures resolved → table fallback")
                            raise ValueError('no multiRowCard measures')

                    elif z_chart == 'slicer':
                        # Date-indicator / filter sheets (Month, Year pickers in Tableau)
                        # rendered as PBI slicers
                        z_sf = zone_pg.get('x_field', '') or zone_pg.get('y_field', '')
                        if not z_sf:
                            _acd = zone_pg.get('all_col_dim_fields', [])
                            if _acd: z_sf = _acd[0]
                        z_sc = _fc(z_sf, z_fcols) if z_sf else None
                        if z_sc is None and z_fcols:
                            z_sc = next((c for c in z_fcols if not c.get('measure')), z_fcols[0])
                        if z_sc:
                            _sl_cfg = _jmin({
                                'name': _guid(),
                                'layouts': [{'id': 0, 'position': {
                                    'x': zx, 'y': zy, 'z': z,
                                    'width': float(zw), 'height': float(zh)}}],
                                'singleVisual': {
                                    'visualType': 'slicer',
                                    'projections': {'Values': [
                                        {'queryRef': f'{z_tbl}.{z_sc["name"]}', 'active': True}]},
                                    'prototypeQuery': {
                                        'Version': 2,
                                        'From': [{'Name': 'sl', 'Entity': z_tbl, 'Type': 0}],
                                        'Select': [{'Column': {
                                            'Expression': {'SourceRef': {'Source': 'sl'}},
                                            'Property': z_sc['name']},
                                            'Name': f'{z_tbl}.{z_sc["name"]}'}]},
                                    'objects': {'general': [{'properties': {'orientation': {
                                        'expr': {'Literal': {'Value': "'horizontal'"}}}}}]},
                                    'vcObjects': {'title': [{'properties': {
                                        'text': {'expr': {'Literal': {'Value': f"'{zname}'"}}},
                                        'show': {'expr': {'Literal': {'Value': 'true' if z_show_title else 'false'}}}
                                    }}]},
                                    'drillFilterOtherVisuals': True,
                                }})
                            visual_containers.append({
                                'x': zx, 'y': zy, 'z': z,
                                'width': zw, 'height': zh,
                                'config': _sl_cfg,
                                'filters': '[]', 'tabOrder': z * 1000,
                            })
                            print(f"[DEBUG] '{zname}' → slicer: '{z_sc['name']}'")
                        else:
                            raise ValueError('no slicer field')

                    elif z_chart in ('pieChart', 'donutChart'):
                        cat_f, val_f = _resolve_pie(zone_pg, z_fcols, z_fagg)
                        print(f"[DEBUG] '{zname}' → {z_chart}: "
                              f"cat={[f['name'] for f in cat_f]} "
                              f"val={[f['name'] for f in val_f]}")
                        visual_containers.append(_make_chart_vc(
                            name=_guid(), x=zx, y=zy, z=z,
                            width=zw, height=zh, visual_type=z_chart,
                            category_fields=cat_f, value_fields=val_f,
                            legend_fields=[], pbi_table_name=z_tbl,
                            zone_name=zname, data_colors=data_colors,
                            legend_values={}, explicit_color_map=explicit_color_map,
                            color_is_measure_names=False,
                            show_data_labels=zone_pg.get('show_data_labels', False),
                            label_format=zone_pg.get('label_format', ''),
                            sort_field=zone_pg.get('sort_field'),
                            sort_dir=zone_pg.get('sort_dir', 2), sort_is_col=False,
                            filter_specs=zone_pg.get('filter_specs', []),
                            reference_lines=zone_pg.get('reference_lines', []),
                            trendline=zone_pg.get('trendline'),
                            filter_fields=zone_pg.get('filter_fields', []),
                            show_title=z_show_title,
                            background_color=z_background_color,
                            border_color=z_border_color, border_width=z_border_width,
                            title_font_family=z_title_font_family, title_font_size=z_title_font_size,
                            title_bold=z_title_bold, title_italic=z_title_italic,
                            title_color=z_title_color, title_bg_color=z_title_bg_color,
                            axis_label_font_family=z_axis_label_font_family, axis_label_font_size=z_axis_label_font_size,
                            axis_label_bold=z_axis_label_bold, axis_label_italic=z_axis_label_italic,
                            axis_label_color=z_axis_label_color,
                            legend_font_family=z_legend_font_family, legend_font_size=z_legend_font_size,
                            legend_bold=z_legend_bold, legend_italic=z_legend_italic,
                            legend_color=z_legend_color,
                            datalabel_font_family=z_datalabel_font_family, datalabel_font_size=z_datalabel_font_size,
                            datalabel_bold=z_datalabel_bold, datalabel_italic=z_datalabel_italic,
                            datalabel_color=z_datalabel_color))

                    elif z_chart in _CHARTS:
                        if z_chart in ('mapChart', 'filledMap'):
                            z_loc_name  = zone_pg.get('map_location_field', '')
                            z_size_name = zone_pg.get('map_size_field', '')
                            z_loc_col = _fc(z_loc_name, z_fcols) if z_loc_name else None
                            if z_loc_col is None:
                                z_loc_col = next(
                                    (c for c in z_fcols
                                     if c.get('datatype', '') in ('string', 'wstring', 'str')
                                     and not c.get('measure')),
                                    z_fcols[0] if z_fcols else None
                                )
                            z_size_col = _fm(z_size_name, z_fagg) if z_size_name else None
                            # If not found in calcs, try raw numeric column (e.g. avg:price:qk → 'Price')
                            # Only accept numeric columns — avoid picking string/date cols as size
                            if z_size_col is None and z_size_name:
                                _sz_raw = _fc(z_size_name, z_fcols)
                                if _sz_raw and _sz_raw.get('datatype','') in ('integer','int64','double','decimal','real'):
                                    z_size_col = {**_sz_raw, 'is_measure': True,
                                                  'datatype': _sz_raw.get('datatype', 'double')}
                            # Final fallback: first numeric aggregate measure
                            if z_size_col is None:
                                z_size_col = next(
                                    (m for m in z_fagg
                                     if m.get('datatype', '') in ('double', 'int64', 'integer', 'decimal')),
                                    z_fagg[0] if z_fagg else None
                                )
                            if z_loc_col:
                                # Both filledMap (choropleth) and mapChart (bubble) use
                                # PBI's built-in 'map' visual via _make_map_vc.
                                # Reason: PBI's native 'filledMap' visual crashes with
                                # "Object reference not set" unless very specific
                                # geo-type metadata is present in the query Select.
                                # The 'map' visual is robust and works for both types.
                                visual_containers.append(_make_map_vc(
                                    name=_guid(), x=zx, y=zy, z=z,
                                    width=zw, height=zh,
                                    location_field=z_loc_col,
                                    size_field=z_size_col,
                                    pbi_table_name=z_tbl,
                                    zone_name=zname,
                                    data_colors=data_colors,
                                    show_title=z_show_title,
                                    background_color=z_background_color,
                                    border_color=z_border_color, border_width=z_border_width,
                                    title_font_family=z_title_font_family, title_font_size=z_title_font_size,
                                    title_bold=z_title_bold, title_italic=z_title_italic,
                                    title_color=z_title_color, title_bg_color=z_title_bg_color,
                                ))
                                print(f"[DEBUG] '{zname}' → {z_chart}: loc='{z_loc_col['name']}'")
                                z += 1
                                continue
                            else:
                                raise ValueError('no location field for map')

                        elif z_chart in ('treemap', 'bubbleChart'):
                            # Treemap and packed-Bubble both drive their key
                            # measure from Tableau's size/color ENCODINGS, not
                            # rows/cols SHELVES — see _resolve_treemap_bubble_fields
                            # (shared with the standalone-page rendering path).
                            cat_f, val_f, z_extra = _resolve_treemap_bubble_fields(
                                z_chart,
                                zone_pg.get('size_enc_field', ''),
                                zone_pg.get('color_fields', []),
                                zone_pg.get('detail_fields', []),
                                z_fcols, z_fagg)

                            print(f"[DEBUG] '{zname}' → {z_chart}: "
                                  f"cat={[f['name'] for f in cat_f]} "
                                  f"extra={ {k: [f['name'] for f in v] for k, v in z_extra.items()} }")
                            visual_containers.append(_make_chart_vc(
                                name=_guid(), x=zx, y=zy, z=z,
                                width=zw, height=zh, visual_type=z_chart,
                                category_fields=cat_f, value_fields=val_f,
                                legend_fields=[], pbi_table_name=z_tbl,
                                zone_name=zname, data_colors=data_colors,
                                legend_values={}, explicit_color_map=explicit_color_map,
                                color_is_measure_names=False,
                                show_data_labels=zone_pg.get('show_data_labels', False),
                                label_format=zone_pg.get('label_format', ''),
                                sort_field=None, sort_dir=1, sort_is_col=False,
                                filter_specs=zone_pg.get('filter_specs', []),
                                reference_lines=zone_pg.get('reference_lines', []),
                                trendline=zone_pg.get('trendline'),
                                filter_fields=zone_pg.get('filter_fields', []),
                                extra_fields=z_extra,
                                show_title=z_show_title,
                                background_color=z_background_color,
                                border_color=z_border_color, border_width=z_border_width,
                                title_font_family=z_title_font_family, title_font_size=z_title_font_size,
                                title_bold=z_title_bold, title_italic=z_title_italic,
                                title_color=z_title_color, title_bg_color=z_title_bg_color,
                                axis_label_font_family=z_axis_label_font_family, axis_label_font_size=z_axis_label_font_size,
                                axis_label_bold=z_axis_label_bold, axis_label_italic=z_axis_label_italic,
                                axis_label_color=z_axis_label_color,
                                legend_font_family=z_legend_font_family, legend_font_size=z_legend_font_size,
                                legend_bold=z_legend_bold, legend_italic=z_legend_italic,
                                legend_color=z_legend_color,
                                datalabel_font_family=z_datalabel_font_family, datalabel_font_size=z_datalabel_font_size,
                                datalabel_bold=z_datalabel_bold, datalabel_italic=z_datalabel_italic,
                                datalabel_color=z_datalabel_color,
                            ))
                            z += 1
                            continue

                        if z_chart == 'scatterChart':
                            # A genuine scatter is two independent continuous
                            # axes, not a single value chain — shared with the
                            # standalone-page rendering path, see
                            # _resolve_scatter_xy_fields. Previously this zone
                            # path ran scatter through the generic bar/column
                            # value resolver, which can only track ONE measure
                            # chain and silently dropped one of the two axes
                            # (confirmed against a real sample: AB_NYC
                            # Dashboard's "Reviews by Neighbourhood Group" lost
                            # its Longitude axis this way).
                            cat_f, val_f, leg_f = _resolve_scatter_xy_fields(
                                zone_pg.get('all_col_fields', []) + [zone_pg.get('x_field', '')],
                                zone_pg.get('all_row_measure_fields', []) + [zone_pg.get('y_field', '')],
                                zone_pg.get('detail_fields', []),
                                zone_pg.get('color_fields', []),
                                z_fcols, z_ds.get('columns', []),
                                zone_pg.get('ctd_fields', []),
                                ds_ctd_maps.get(z_ds.get('name', ''), {}))
                            _z_cim = False
                        else:
                            cat_f = _resolve_cat(zone_pg, z_fcols, _hbar)

                            # Shared with the standalone-page rendering path —
                            # see _resolve_measure_values. Previously this
                            # zone (the path that renders every real
                            # dashboard) used a much thinner shelf-based
                            # fallback with none of this sophistication: no
                            # ctd:/cnt: shelf-token handling, no side-by-side
                            # multi-measure detection, no :Measure Names
                            # merging, and no ratio-vs-value auto-combo-
                            # upgrade — all of which the standalone-page path
                            # had accumulated over many prior sessions but
                            # which never applied to any real dashboard, since
                            # every real page renders through this zone path
                            # instead.
                            _z_val_candidates = (
                                zone_pg.get('all_col_fields', []) + [zone_pg.get('x_field', '')]
                                if _hbar else
                                zone_pg.get('all_row_measure_fields', []) + [zone_pg.get('y_field', '')])
                            val_f, z_chart, _z_cim = _resolve_measure_values(
                                z_chart, _hbar, _z_val_candidates, zone_pg.get('y_field', ''),
                                zone_pg.get('shelf_row_fields', []),
                                zone_pg.get('ctd_fields', []),
                                ds_ctd_maps.get(z_ds.get('name', ''), {}),
                                ds_sum_maps.get(z_ds.get('name', ''), {}),
                                zone_pg.get('measure_names_filter_fields', []),
                                cat_f, z_fcols, z_fagg, z_ds, _measure_registry,
                                row_measure_fallback=zone_pg.get('all_row_measure_fields', []))

                            # Shared with the standalone-page rendering path —
                            # see _resolve_combo_roles. Assigns Y (bar) vs Y2
                            # (line) for a genuine Tableau-authored combo chart
                            # (as opposed to the ratio-vs-value auto-upgrade
                            # case above, which _resolve_measure_values already
                            # tags itself).
                            val_f = _resolve_combo_roles(
                                val_f, z_chart,
                                zone_pg.get('measure_names_filter_fields', []))

                            leg_f = _resolve_leg(zone_pg, z_fcols, cat_f)

                            # Shared with the standalone-page rendering path —
                            # see _maybe_downgrade_stacked. A stacked chart
                            # with no separate Series dimension has nothing
                            # to stack; render as clustered instead.
                            z_chart = _maybe_downgrade_stacked(z_chart, leg_f)

                        # A scatter with a real Size encoding (Circle mark +
                        # continuous X/Y measures + a size field) is a bubble
                        # scatter — Power BI's scatter chart with its Size role
                        # populated, not a different visual. Previously the
                        # size field was silently dropped for zone-rendered
                        # scatter charts (confirmed against a real sample:
                        # AB_NYC Dashboard's "Reviews by Neighbourhood Group",
                        # which encodes review count as size).
                        z_extra_scatter = (
                            _resolve_scatter_size_extra(
                                zone_pg.get('size_enc_field', ''), z_fcols, z_fagg)
                            if z_chart == 'scatterChart' else {})

                        # Shared with the standalone-page rendering path — see
                        # _resolve_default_sort. A no-op for scatter/treemap/
                        # bubble/map/etc — only applies to bar/column charts.
                        _z_sort_field, _z_sort_dir, _z_sort_is_col = _resolve_default_sort(
                            zone_pg.get('sort_field'), zone_pg.get('sort_dir', 2), False,
                            z_chart, cat_f, val_f)

                        print(f"[DEBUG] '{zname}' → {z_chart}: "
                              f"cat={[f['name'] for f in cat_f]} "
                              f"val={[(f['name'], 'MSR' if f.get('is_measure') else 'AGG') for f in val_f]} "
                              f"leg={[f['name'] for f in leg_f]}")
                        visual_containers.append(_make_chart_vc(
                            name=_guid(), x=zx, y=zy, z=z,
                            width=zw, height=zh, visual_type=z_chart,
                            category_fields=cat_f, value_fields=val_f,
                            legend_fields=leg_f, pbi_table_name=z_tbl,
                            zone_name=zname, data_colors=data_colors,
                            legend_values={}, explicit_color_map=explicit_color_map,
                            color_is_measure_names=(
                                _z_cim or zone_pg.get('color_is_measure_names', False)),
                            show_data_labels=zone_pg.get('show_data_labels', False),
                            label_format=zone_pg.get('label_format', ''),
                            sort_field=_z_sort_field,
                            sort_dir=_z_sort_dir, sort_is_col=_z_sort_is_col,
                            filter_specs=zone_pg.get('filter_specs', []),
                            reference_lines=zone_pg.get('reference_lines', []),
                            trendline=zone_pg.get('trendline'),
                            filter_fields=zone_pg.get('filter_fields', []),
                            extra_fields=z_extra_scatter,
                            show_title=z_show_title,
                            background_color=z_background_color,
                            border_color=z_border_color, border_width=z_border_width,
                            title_font_family=z_title_font_family, title_font_size=z_title_font_size,
                            title_bold=z_title_bold, title_italic=z_title_italic,
                            title_color=z_title_color, title_bg_color=z_title_bg_color,
                            axis_title_value=z_axis_title_value,
                            axis_title_value2=z_axis_title_value2,
                            axis_title_category=z_axis_title_category,
                            gridlines_hidden=z_gridlines_hidden,
                            axis_label_font_family=z_axis_label_font_family, axis_label_font_size=z_axis_label_font_size,
                            axis_label_bold=z_axis_label_bold, axis_label_italic=z_axis_label_italic,
                            axis_label_color=z_axis_label_color,
                            legend_font_family=z_legend_font_family, legend_font_size=z_legend_font_size,
                            legend_bold=z_legend_bold, legend_italic=z_legend_italic,
                            legend_color=z_legend_color,
                            datalabel_font_family=z_datalabel_font_family, datalabel_font_size=z_datalabel_font_size,
                            datalabel_bold=z_datalabel_bold, datalabel_italic=z_datalabel_italic,
                            datalabel_color=z_datalabel_color))

                    else:
                        # tableEx / pivotTable / unknown
                        z_shelf = zone_pg.get('shelf_row_fields', [])
                        z_tf    = zone_pg.get('text_enc_field')
                        if z_tf and not z_shelf:
                            z_shelf = [z_tf]
                        print(f"[DEBUG] '{zname}' → tableEx shelf={z_shelf[:3]}")
                        visual_containers.append(_make_table_vc(
                            name=_guid(), x=zx, y=zy, z=z,
                            width=zw, height=zh, datasource=z_dsv,
                            zone_name=zname, pbi_table_name=z_tbl,
                            shelf_fields=z_shelf,
                            filter_fields=zone_pg.get('filter_fields', []),
                            filter_specs=zone_pg.get('filter_specs', []),
                            visual_type='tableEx', show_title=z_show_title,
                            background_color=z_background_color,
                            border_color=z_border_color, border_width=z_border_width,
                            title_font_family=z_title_font_family, title_font_size=z_title_font_size,
                            title_bold=z_title_bold, title_italic=z_title_italic,
                            title_color=z_title_color, title_bg_color=z_title_bg_color))

                except Exception as _ze:
                    print(f"[DEBUG except] Zone '{zname}' ({z_chart}): {_ze}")
                    import traceback as _ztb; print(_ztb.format_exc())
                    log('warn',
                        f"Dashboard '{page_name}' zone '{zname}' ({z_chart}): {_ze}",
                        page_name)
                    try:
                        visual_containers.append(_make_table_vc(
                            name=_guid(), x=zx, y=zy, z=z,
                            width=zw, height=zh, datasource=z_dsv,
                            zone_name=zname, pbi_table_name=z_tbl,
                            shelf_fields=[], filter_fields=[],
                            filter_specs=[], visual_type='tableEx',
                            show_title=z_show_title,
                            background_color=z_background_color,
                            border_color=z_border_color, border_width=z_border_width,
                            title_font_family=z_title_font_family, title_font_size=z_title_font_size,
                            title_bold=z_title_bold, title_italic=z_title_italic,
                            title_color=z_title_color, title_bg_color=z_title_bg_color))
                    except Exception as _zfe:
                        print(f"[DEBUG except] Zone '{zname}' fallback table: {_zfe}")
                z += 1

            # Fallback if nothing rendered
            if len(visual_containers) <= 1:
                _has_zones = bool(page.get('db_zones') or page.get('db_filter_zones'))
                if not _has_zones:
                    visual_containers.append(_make_textbox_vc(
                        name=_guid(), x=0, y=TITLE_H, z=z,
                        width=W, height=max(80, H - TITLE_H - 4),
                        text=f"Dashboard '{page_name}' has no desktop layout in the source Tableau workbook.",
                        font_size=12, bold=False))
                elif datasources:
                    _fb  = datasources[0]
                    _fbt = ds_pbi_names.get(_fb['name'], _safe(_fb['name']))
                    try:
                        visual_containers.append(_make_table_vc(
                            name=_guid(), x=0, y=TITLE_H, z=z,
                            width=W, height=H - TITLE_H - 4,
                            datasource={**_fb, 'columns': _fb.get('columns', []),
                                'calculations': [c for c in _fb.get('calculations', [])
                                                 if c.get('is_agg_calc', True)
                                                 and not c.get('is_action_calc')]},
                            zone_name=page_name, pbi_table_name=_fbt,
                            shelf_fields=[], filter_fields=[],
                            filter_specs=[], visual_type='tableEx'))
                    except Exception as _fbe:
                        print(f"[DEBUG except] Dashboard '{page_name}' fallback table: {_fbe}")


        # ── WORKSHEET PAGE ────────────────────────────────────────────────────
        # Table visual — filter columns to those used in this worksheet
        elif ds:
            pbi_table_name = ds_pbi_names.get(ds['name'], _safe(ds['name']))

            # Build a filtered column list matching the worksheet's fields.
            # If the worksheet specified fields, show those; otherwise show all.
            if page_fields:
                all_ds_cols = ds.get('columns', [])
                # Normalise for matching (strip spaces, lower)
                def _norm(s): return s.lower().replace(' ', '').replace('-', '')
                norm_fields = {_norm(f): f for f in page_fields}
                # Build filtered_cols in the SAME ORDER as page_fields (shelf order),
                # not datasource definition order. This gives each page a distinct
                # column ordering that reflects what the Tableau worksheet emphasised.
                col_by_norm = {_norm(c['name']): c for c in all_ds_cols}
                filtered_cols = []
                for field in page_fields:
                    c = col_by_norm.get(_norm(field))
                    if c and c not in filtered_cols:
                        filtered_cols.append(c)

                # ── FIX 2: Blank-page fallback ────────────────────────────────
                # When shelf field names don't match any datasource column captions
                # (e.g. because they are Calculation_XXXX internal names that were
                # not resolved in the caption map), filtered_cols comes out empty
                # and the visual renders blank.  Fall back to all datasource columns
                # so the page always has something to show.
                if not filtered_cols:
                    filtered_cols = list(all_ds_cols)
                # Split datasource calculations into:
                #   filtered_calcs  — DAX Measures   (is_agg_calc=True)
                #   filtered_cc     — Calc Columns    (is_agg_calc=False)
                # Only include calcs whose names appear in this page's fields.
                # RC1: Always exclude Action() set-action synthetic calcs — they are
                # Tableau UI interaction artifacts and should never appear on chart axes.
                calcs = [c for c in ds.get('calculations', [])
                         if not c.get('is_action_calc')]
                _agg_calcs_all  = [c for c in calcs if c.get('is_agg_calc', True)]
                _col_calcs_all  = [c for c in calcs if not c.get('is_agg_calc', True)]
                filtered_calcs  = [c for c in _agg_calcs_all
                                   if _norm(c['name']) in norm_fields]
                filtered_cc     = [c for c in _col_calcs_all
                                   if _norm(c['name']) in norm_fields]
                # Fall back: if no matches, include all of each type
                if not filtered_calcs and not filtered_cc:
                    filtered_calcs = _agg_calcs_all
                    filtered_cc    = _col_calcs_all
                elif not filtered_calcs:
                    filtered_calcs = _agg_calcs_all
                elif not filtered_cc:
                    filtered_cc    = _col_calcs_all
            else:
                def _norm(s): return s.lower().replace(' ', '').replace('-', '')
                # RC1: exclude Action() calcs here too
                calcs           = [c for c in ds.get('calculations', [])
                                   if not c.get('is_action_calc')]
                filtered_cols   = ds.get('columns', [])
                filtered_calcs  = [c for c in calcs if c.get('is_agg_calc', True)]
                filtered_cc     = [c for c in calcs if not c.get('is_agg_calc', True)]

            # Merge calc columns into filtered_cols so they are treated as
            # Column-type expressions (can be SUM'd, used in Category, etc.).
            # Tag each with 'is_calc_col': True so downstream can distinguish
            # them from source columns if needed.
            for _cc in filtered_cc:
                _cc_entry = {
                    'name':        _cc['name'],
                    'source_name': _cc['name'],
                    'datatype':    _cc.get('datatype', 'double'),
                    'role':        'measure',
                    'hidden':      False,
                    'measure':     True,
                    'is_calc_col': True,
                }
                if not any(_norm(_cc_entry['name']) == _norm(c['name'])
                           for c in filtered_cols):
                    filtered_cols.append(_cc_entry)

            # Build a temporary ds view with filtered columns/calcs for the visual
            ds_view = {**ds, 'columns': filtered_cols, 'calculations': filtered_calcs}

            chart_type   = page.get('chart_type', 'tableEx')
            x_field_name = page.get('x_field', '')
            y_field_name = page.get('y_field', '')
            color_names  = page.get('color_fields', [])

            def _norm_match(a, b):
                return a.lower().replace(' ','').replace('-','') ==                        b.lower().replace(' ','').replace('-','')

            def _find_col(name, cols):
                if not name: return None
                return next((c for c in cols if _norm_match(c['name'], name)), None)

            def _find_msr(name, msrs):
                if not name: return None
                # Exact normalized match first
                result = next((m for m in msrs if _norm_match(m['name'], name)), None)
                if result: return result
                # '(copy)'-suffix match only (see _is_copy_suffix_of) — NOT a bare
                # startswith, which would also match an unrelated longer name
                # (e.g. base column "Sales" incorrectly matching calc "Sales
                # Threshold").
                name_n = name.lower().replace(' ','').replace('-','')
                return next(
                    (m for m in msrs
                     if _is_copy_suffix_of(m['name'].lower().replace(' ','').replace('-',''), name_n)),
                    None
                )

            # Build measure lookup (schema measures for this table)
            # We need to tag items as is_measure so _make_chart_vc emits Measure not Column
            all_cols_flat = filtered_cols
            all_msrs_flat = filtered_calcs + [
                {'name': f"Count of {c['name']}", 'is_measure': True}
                for c in filtered_cols
            ]

            def _as_measure_item(name):
                """Return a dict tagged is_measure=True for use in value_fields."""
                return {'name': name, 'is_measure': True, 'datatype': 'double'}

            def _as_col_item(col):
                return {**col, 'is_measure': False}

            if chart_type == 'card':
                # ── KPI Card ─────────────────────────────────────────────────
                # Priority order for the card's measure:
                # 1. text_enc_field — the exact measure from the Tableau text or shape
                #    encoding (most faithful to what the author intended to display).
                # 2. First calculation/measure in filtered_calcs.
                # 3. First numeric column in filtered_cols.
                text_field = page.get('text_enc_field')
                val_col = None
                if text_field:
                    # Try to match the named field in calcs first, then columns
                    val_col = next(
                        (c for c in filtered_calcs
                         if c['name'].lower() == text_field.lower()),
                        None
                    )
                    if val_col is None:
                        val_col = next(
                            (c for c in filtered_cols
                             if c['name'].lower() == text_field.lower()),
                            None
                        )
                        if val_col is not None:
                            val_col = {'name': val_col['name'], 'is_measure': True,
                                       'datatype': val_col.get('datatype', 'double')}
                    if val_col is None:
                        # Field name known but not in filtered set — create a synthetic entry
                        val_col = {'name': text_field, 'is_measure': True,
                                   'datatype': 'double'}
                if val_col is None:
                    # Fallback: first calc, then first numeric column
                    num_col = next(
                        (c for c in filtered_cols if c.get('datatype') in ('int64', 'double')),
                        filtered_cols[0] if filtered_cols else None
                    )
                    val_col = (filtered_calcs[0]
                               if filtered_calcs
                               else ({'name': num_col['name'], 'is_measure': True,
                                      'datatype': num_col.get('datatype', 'double')}
                                     if num_col else None))
                if val_col:
                    visual_containers.append(_make_card_vc(
                        name=_guid(), x=0, y=48, z=z,
                        width=W, height=H - 52,
                        value_fields=[val_col],
                        pbi_table_name=pbi_table_name,
                        zone_name=page_name,
                        data_colors=data_colors,
                        filter_specs=page.get('filter_specs', []),
                        filter_fields=page.get('filter_fields', []),
                    ))
                else:
                    visual_containers.append(_make_table_vc(
                        name=_guid(), x=0, y=48, z=z,
                        width=W, height=H - 52,
                        datasource=ds_view, zone_name=page_name,
                        pbi_table_name=pbi_table_name,
                        shelf_fields=page.get('shelf_row_fields', []),
                        filter_fields=page.get('filter_fields', []),
                        filter_specs=page.get('filter_specs', []),
                    ))

            elif chart_type == 'multiRowCard':
                # ── Multi-row Card (Measure-Names KPI strip) ─────────────────
                # Shared with the dashboard-zone rendering path — see
                # _resolve_multirow_card_fields. Previously this chart_type
                # (added for the dashboard-zone path) had no standalone-page
                # counterpart at all, so a KPI-strip worksheet that happened
                # to render as its own page instead of a dashboard zone fell
                # through to a generic table — the exact kind of path-specific
                # gap this consolidation exists to close.
                mrc_fields = _resolve_multirow_card_fields(
                    page.get('measure_names_filter_fields', []),
                    filtered_cols, filtered_calcs)
                if mrc_fields:
                    visual_containers.append(_make_multirow_card_vc(
                        name=_guid(), x=0, y=48, z=z,
                        width=W, height=H - 52,
                        value_fields=mrc_fields,
                        pbi_table_name=pbi_table_name,
                        zone_name=page_name,
                        data_colors=data_colors,
                        filter_specs=page.get('filter_specs', []),
                        filter_fields=page.get('filter_fields', []),
                    ))
                else:
                    visual_containers.append(_make_table_vc(
                        name=_guid(), x=0, y=48, z=z,
                        width=W, height=H - 52,
                        datasource=ds_view, zone_name=page_name,
                        pbi_table_name=pbi_table_name,
                        shelf_fields=page.get('shelf_row_fields', []),
                        filter_fields=page.get('filter_fields', []),
                        filter_specs=page.get('filter_specs', []),
                    ))

            elif chart_type == 'filledMap':
                # ── Filled Map (Choropleth) → PBI 'map' visual ───────────────
                # Tableau Multipolygon marks (filledMap) are rendered in PBI as
                # a 'map' (bubble map) visual — verified against a working
                # reference PBIT.  PBI's filledMap visual crashes with
                # "Cannot read properties of undefined (reading 'kind')" due to
                # missing geo-type metadata; the 'map' visual is robust.
                #
                # Field resolution is shared with mapChart via _make_map_vc.
                loc_name  = page.get('map_location_field', '')
                size_name = page.get('map_size_field', '')

                # Location: prefer explicit map_location_field, fall back to
                # first string column with a geo_category set, then any string.
                loc_col = _find_col(loc_name, filtered_cols) if loc_name else None
                if loc_col is None:
                    loc_col = next(
                        (c for c in filtered_cols if c.get('geo_category')),
                        None
                    )
                if loc_col is None:
                    loc_col = next(
                        (c for c in filtered_cols
                         if c.get('datatype', 'string') == 'string'),
                        filtered_cols[0] if filtered_cols else None
                    )

                # Size/color measure: prefer map_size_field, then color_fields,
                # then first calc.  Handles ctd:-derived DISTINCTCOUNT measures.
                _ctd_map_fm = ds_ctd_maps.get(ds.get('name', ''), {})
                size_msr = (_find_msr(size_name, filtered_calcs)
                            if size_name else None)
                if size_msr is None:
                    for _cn_fm in color_names:
                        size_msr = _find_msr(_cn_fm, filtered_calcs)
                        if size_msr:
                            break
                        for _kfm, _vfm in _ctd_map_fm.items():
                            if _norm_match(_kfm, _cn_fm):
                                size_msr = {'name': _vfm, 'is_measure': True,
                                            'datatype': 'double'}
                                break
                        if size_msr:
                            break
                if size_msr is None and filtered_calcs:
                    size_msr = filtered_calcs[0]

                if loc_col:
                    visual_containers.append(_make_map_vc(
                        name=_guid(), x=0, y=48, z=z,
                        width=W, height=H - 52,
                        location_field=loc_col,
                        size_field=size_msr,
                        pbi_table_name=pbi_table_name,
                        zone_name=page_name,
                        data_colors=data_colors,
                    ))
                else:
                    # No location field — fall back to table
                    visual_containers.append(_make_table_vc(
                        name=_guid(), x=0, y=48, z=z,
                        width=W, height=H - 52,
                        datasource=ds_view, zone_name=page_name,
                        pbi_table_name=pbi_table_name,
                        shelf_fields=page.get('shelf_row_fields', []),
                        filter_fields=page.get('filter_fields', []),
                        filter_specs=page.get('filter_specs', []),
                    ))

            elif chart_type == 'mapChart':
                # ── Geographic Map ────────────────────────────────────────────
                # Tableau geographic maps use Latitude/Longitude (generated) on
                # shelves and put the actual location dimension in color/detail.
                # Power BI map visual accepts:
                #   Location  → geocoded string field (city / state / country)
                #   Size      → bubble-size measure
                # Note: Tableau pie overlays on maps have no direct PBI equivalent;
                #       we render the closest available bubble map.
                loc_name  = page.get('map_location_field', '')
                size_name = page.get('map_size_field', '')

                # Resolve location field (prefer column; it's the geocoded dimension)
                loc_col = (_find_col(loc_name, filtered_cols)
                           if loc_name else None)
                if loc_col is None and loc_name:
                    loc_col = _find_msr(loc_name, filtered_calcs)
                # Fallback: first string column
                if loc_col is None:
                    loc_col = next(
                        (c for c in filtered_cols
                         if c.get('datatype', 'string') == 'string'),
                        filtered_cols[0] if filtered_cols else None
                    )

                # Resolve size measure
                size_col = (_find_msr(size_name, filtered_calcs)
                            if size_name else None)
                if size_col is None and size_name:
                    size_col = _find_col(size_name, filtered_cols)
                    if size_col:
                        size_col = {'name': size_col['name'], 'is_measure': True,
                                    'datatype': size_col.get('datatype', 'double')}
                # Fallback: first measure/calc
                if size_col is None and filtered_calcs:
                    size_col = filtered_calcs[0]

                if loc_col:
                    visual_containers.append(_make_map_vc(
                        name=_guid(), x=0, y=48, z=z,
                        width=W, height=H - 52,
                        location_field=loc_col,
                        size_field=size_col,
                        pbi_table_name=pbi_table_name,
                        zone_name=page_name,
                        data_colors=data_colors,
                    ))
                else:
                    # No location field found — fall back to table
                    visual_containers.append(_make_table_vc(
                        name=_guid(), x=0, y=48, z=z,
                        width=W, height=H - 52,
                        datasource=ds_view, zone_name=page_name,
                        pbi_table_name=pbi_table_name,
                        shelf_fields=page.get('shelf_row_fields', []),
                        filter_fields=page.get('filter_fields', []),
                        filter_specs=page.get('filter_specs', []),
                    ))

            elif chart_type in ('clusteredColumnChart', 'clusteredBarChart',
                                'columnChart',   'barChart',
                                'hundredPercentStackedColumnChart',
                                'hundredPercentStackedBarChart',
                                'scatterChart', 'pieChart', 'donutChart',
                                'lineChart', 'areaChart', 'lineClusteredColumnComboChart',
                                'treemap', 'bubbleChart'):
                # ── Determine category, value, and legend fields ──────────────

                # Helper: collect distinct values for legend/series columns from
                # embedded data so we can build proper per-value colour selectors.
                def _distinct_legend_vals(fields, wb, ds_cap):
                    result = {}
                    ed = wb.get('extracted_data', {})
                    if not ed.get('has_data'):
                        return result
                    rows = (ed.get('datasources', {})
                              .get(ds_cap, {})
                              .get('rows', []))
                    for f in fields:
                        seen, ordered = set(), []
                        for row in rows:
                            v = row.get(f['name'])
                            if v is not None:
                                s = str(v)
                                if s not in seen:
                                    seen.add(s)
                                    ordered.append(s)
                        if ordered:
                            result[f['name']] = ordered
                    return result

                if chart_type == 'treemap':
                    # ── Treemap ──────────────────────────────────────────────
                    # Shared with the dashboard-zone rendering path — see
                    # _resolve_treemap_bubble_fields.
                    cat_f, val_f, treemap_extra = _resolve_treemap_bubble_fields(
                        'treemap', page.get('size_enc_field', ''),
                        color_names, page.get('detail_fields', []),
                        filtered_cols, filtered_calcs)

                    visual_containers.append(_make_chart_vc(
                        name=_guid(), x=0, y=48, z=z,
                        width=W, height=H - 52,
                        visual_type='treemap',
                        category_fields=cat_f,
                        value_fields=val_f,
                        legend_fields=[],
                        pbi_table_name=pbi_table_name,
                        zone_name=page_name,
                        data_colors=data_colors,
                        legend_values={},
                        explicit_color_map=explicit_color_map,
                        color_is_measure_names=False,
                        show_data_labels=page.get('show_data_labels', False),
                        label_format=page.get('label_format', ''),
                        sort_field=None,
                        sort_dir=1,
                        sort_is_col=False,
                        pane_mark_colors=page.get('pane_mark_colors', []),
                        filter_specs=page.get('filter_specs', []),
                        reference_lines=page.get('reference_lines', []), trendline=page.get('trendline'),
                        filter_fields=page.get('filter_fields', []),
                        extra_fields=treemap_extra,
                    ))

                elif chart_type == 'bubbleChart':
                    # ── Packed Bubble / Bubble Chart ─────────────────────────
                    # Tableau packed bubble: Circle marks, empty shelves, size
                    # encoding. Shared with the dashboard-zone rendering path
                    # — see _resolve_treemap_bubble_fields. PBI maps this to
                    # its built-in scatterChart visual with non-standard roles
                    # (Category holding the size/detail/label columns, Size +
                    # Details in extra_fields, no X/Y/Legend/Series).
                    cat_f, val_f, bubble_extra = _resolve_treemap_bubble_fields(
                        'bubbleChart', page.get('size_enc_field', ''),
                        color_names, page.get('detail_fields', []),
                        filtered_cols, filtered_calcs)

                    visual_containers.append(_make_chart_vc(
                        name=_guid(), x=0, y=48, z=z,
                        width=W, height=H - 52,
                        visual_type='scatterChart',
                        category_fields=cat_f,
                        value_fields=val_f,
                        legend_fields=[],
                        pbi_table_name=pbi_table_name,
                        zone_name=page_name,
                        data_colors=data_colors,
                        legend_values={},
                        explicit_color_map=explicit_color_map,
                        color_is_measure_names=False,
                        show_data_labels=page.get('show_data_labels', False),
                        label_format=page.get('label_format', ''),
                        sort_field=None,
                        sort_dir=1,
                        sort_is_col=True,
                        pane_mark_colors=page.get('pane_mark_colors', []),
                        filter_specs=page.get('filter_specs', []),
                        reference_lines=page.get('reference_lines', []), trendline=page.get('trendline'),
                        filter_fields=page.get('filter_fields', []),
                        extra_fields=bubble_extra,
                    ))

                elif chart_type == 'scatterChart':
                    # A genuine scatter is two independent continuous axes,
                    # not a single value chain — shared with the dashboard-
                    # zone rendering path, see _resolve_scatter_xy_fields.
                    det_f, val_f, leg_f = _resolve_scatter_xy_fields(
                        page.get('all_col_fields', []) + [x_field_name],
                        page.get('all_row_measure_fields', []) + [y_field_name],
                        page.get('detail_fields', []), color_names,
                        filtered_cols, ds.get('columns', []),
                        page.get('ctd_fields', []),
                        ds_ctd_maps.get(ds.get('name', ''), {}))
                    cat_f = []

                    # Collect distinct values for each legend field from the
                    # embedded data so _make_chart_vc can build proper selectors.
                    ds_caption_key = ds.get('caption') or ds.get('name', '')
                    leg_vals_scatter = _distinct_legend_vals(
                        leg_f, workbook, ds_caption_key)

                    # A Tableau scatter with a real Size encoding (Circle mark +
                    # continuous X/Y measures + a size field, e.g. a bubble whose
                    # position AND size both carry meaning — as opposed to the
                    # 'bubbleChart' branch above, which is Tableau's PACKED bubble
                    # with no axes at all) is Power BI's scatter chart with its
                    # Size role populated — the same built-in visual, not a
                    # different one. Reuses the exact extra_fields['Size']
                    # wiring already proven by the packed-bubble case.
                    scatter_extra = _resolve_scatter_size_extra(
                        page.get('size_enc_field', ''), filtered_cols, filtered_calcs)

                    visual_containers.append(_make_chart_vc(
                        name=_guid(), x=0, y=48, z=z,
                        width=W, height=H - 52,
                        visual_type='scatterChart',
                        category_fields=det_f,
                        value_fields=val_f,
                        legend_fields=leg_f,
                        pbi_table_name=pbi_table_name,
                        zone_name=page_name,
                        data_colors=data_colors,
                        legend_values=leg_vals_scatter,
                        explicit_color_map=explicit_color_map,
                        color_is_measure_names=page.get('color_is_measure_names', False),
                        show_data_labels=page.get('show_data_labels', False),
                        label_format=page.get('label_format', ''),
                        sort_field=page.get('sort_field'),
                        sort_dir=page.get('sort_dir', 1),
                        sort_is_col=page.get('sort_is_col', True),
                        pane_mark_colors=page.get('pane_mark_colors', []),
                        filter_specs=page.get('filter_specs', []),
                        reference_lines=page.get('reference_lines', []), trendline=page.get('trendline'),
                        filter_fields=page.get('filter_fields', []),
                        extra_fields=scatter_extra,
                    ))

                elif chart_type in ('lineChart', 'areaChart', 'lineClusteredColumnComboChart'):
                    # ── Line and Combo charts ─────────────────────────────────
                    # Category (X-axis): collect ALL dimensions from cols shelf
                    # This handles hierarchical groupings (Quarter + Year, etc.)
                    # Priority:
                    #   1. All non-measure fields from cols shelf (if available)
                    #   2. Primary x field + any date/string dimensions
                    #   3. First non-measure column fallback
                    cat_f = []
                    
                    # Approach A: if we have cols_txt, parse all field tokens and build cat_f
                    # This handles hierarchical dimensions like Quarter + Year for grouping
                    # SKIP measure_names_filter_fields - they are Y2 line measures, not dimensions
                    cols_txt = page.get('shelf_col_fields_text', '')
                    _mnff_skip = {_norm(f) for f in page.get('measure_names_filter_fields', [])}
                    if cols_txt:
                        import re as _re_cat
                        # Extract all [field] tokens from cols shelf
                        col_tokens = _re_cat.findall(r'\[([^\[\]]+)\]', cols_txt)
                        for tok_raw in col_tokens:
                            # Clean field name (strip prefixes like yr:, mn:, etc.)
                            tok_clean = _clean_field_name(tok_raw, local_caption_map)
                            if tok_clean:
                                if _norm(tok_clean) in _mnff_skip:
                                    continue
                                tok_col = _find_col(tok_clean, filtered_cols)
                                # Include as dimension if not a measure, OR if it's temporal (even if marked measure)
                                _col_name_temp = tok_col.get('name', '').lower().replace(' ', '').replace('_', '') if tok_col else ''
                                _is_temporal_cat = any(k in _col_name_temp for k in ('year', 'quarter', 'month', 'week', 'day', 'date', 'time', 'hour', 'minute'))
                                if tok_col and (not tok_col.get('measure') or _is_temporal_cat):
                                    if not any(_norm_match(tok_col['name'], c['name']) for c in cat_f):
                                        cat_f.append(_as_col_item(tok_col))
                    
                    # Approach B: if no cols shelf fields found, try primary x_field_name
                    if not cat_f:
                        x_col = _find_col(x_field_name, filtered_cols)
                        # Fallback: look for any date/string dimension
                        if x_col is None:
                            for _fc in filtered_cols:
                                _nl = _fc['name'].lower().replace(' ','').replace('_','')
                                if (not _fc.get('measure')
                                        and any(k in _nl for k in ('month','quarter','year','date'))):
                                    x_col = _fc
                                    break
                        if x_col is None:
                            x_col = next((c for c in filtered_cols if not c.get('measure')), None)
                        cat_f = [_as_col_item(x_col)] if x_col else []
                    
                    # CRITICAL: Ensure Quarter grouping - add Quarter if Year exists but Quarter missing
                    _has_year = any('year' in c['name'].lower().replace(' ','').replace('_','') for c in cat_f)
                    _has_quarter = any('quarter' in c['name'].lower().replace(' ','').replace('_','') for c in cat_f)
                    if _has_year and not _has_quarter:
                        for _qc in filtered_cols:
                            _qn_lower = _qc['name'].lower().replace(' ','').replace('_','')
                            if 'quarter' in _qn_lower and (not _qc.get('measure') or any(k in _qn_lower for k in ('year', 'quarter', 'month', 'week', 'day', 'date', 'time', 'hour', 'minute'))):
                                if not any(_norm_match(_qc['name'], c['name']) for c in cat_f):
                                    cat_f.insert(0, _as_col_item(_qc))
                                    break

                    # Values (Y-axis): collect all measures for this worksheet.
                    # Power BI requires all Y-axis values to be DAX Measure refs.
                    #
                    # Collection priority (in order):
                    #   1. Shelf row fields (explicit measures/calcs on rows shelf)
                    #   2. DISTINCTCOUNT fields (ctd: prefixed shelf fields)
                    #   3. Filtered calcs (calculated measures from datasource)
                    #   4. Measure Names filter fields (Measure Names pattern: DSO vs DPO)
                    #
                    sum_map = ds_sum_maps.get(ds.get('name',''), {})
                    _ctd_map_lc  = ds_ctd_maps.get(ds.get('name',''), {})
                    _ctd_flds_lc = page.get('ctd_fields', [])
                    val_f = []
                    _existing_measures = set()
                    _bar_measures = []
                    _line_measures = []
                    _bar_measures = []
                    _line_measures = []

                    # 1. Collect shelf_row_fields first (highest priority)
                    #    These are explicit measures/calcs the user placed on rows.
                    for _srf_lc in page.get('shelf_row_fields', []):
                        if _norm(_srf_lc) in _existing_measures:
                            continue
                        # 1a. Check if this is a ctd field (DISTINCTCOUNT)
                        if any(_norm_match(_srf_lc, _cf) for _cf in _ctd_flds_lc):
                            for _klc, _vlc in _ctd_map_lc.items():
                                if _norm_match(_klc, _srf_lc):
                                    val_f.append({'name': _vlc, 'is_measure': True, 'datatype': 'double'})
                                    _existing_measures.add(_norm(_vlc))
                                    break
                            continue
                        # 1b. Check if it's a DAX measure (calc)
                        _calc_cand = _find_msr(_srf_lc, filtered_calcs)
                        if _calc_cand:
                            _c_dt = _calc_cand.get('datatype', 'double')
                            _c_formula = (_calc_cand.get('formula') or '').lower()
                            # Skip string-returning calcs — they are legend fields
                            _is_str_calc = (
                                _c_dt == 'string'
                                or ('then \'' in _c_formula)
                                or ('then "' in _c_formula)
                            )
                            if not _is_str_calc:
                                val_f.append({**_calc_cand, 'is_measure': True, 'datatype': _c_dt})
                                _existing_measures.add(_norm(_calc_cand['name']))
                            continue
                        # 1c. Check if it's a numeric column → use "Sum of X" measure
                        _col_cand = _find_col(_srf_lc, filtered_cols)
                        if _col_cand and (_col_cand.get('measure') or
                                         _col_cand.get('datatype') in ('int64', 'double')):
                            # Skip temporal fields (Year, Quarter, etc.) — they are dimensions
                            _col_name_temp = _col_cand.get('name', '').lower().replace(' ', '').replace('_', '')
                            _is_temporal_col = any(k in _col_name_temp for k in ('year', 'quarter', 'month', 'week', 'day', 'date', 'time', 'hour', 'minute'))
                            if _is_temporal_col:
                                # Don't add temporal columns as measures
                                continue
                            _sum_msr = sum_map.get(_col_cand['name'])
                            if _sum_msr:
                                val_f.append(_as_measure_item(_sum_msr))
                                _existing_measures.add(_norm(_col_cand['name']))
                            else:
                                # Try registry before falling back to inline Aggregation
                                _reg_item = _measure_registry.resolve(_col_cand['name'], ds)
                                if _reg_item:
                                    val_f.append({**_reg_item, 'is_measure': True})
                                else:
                                    val_f.append({**_col_cand, 'is_measure': False, 'is_agg': True})
                                _existing_measures.add(_norm(_col_cand['name']))

                    # 2. If no shelf measures collected, fall back to filtered_calcs
                    if not val_f:
                        for c in filtered_calcs:
                            if _norm(c['name']) in _existing_measures:
                                continue
                            _c_dt = c.get('datatype', 'double')
                            _c_formula = (c.get('formula') or '').lower()
                            _is_string_calc = (
                                _c_dt == 'string'
                                or ('then \'' in _c_formula)
                                or ('then "' in _c_formula)
                            )
                            if not _is_string_calc:
                                val_f.append({**c, 'is_measure': True, 'datatype': _c_dt})
                                _existing_measures.add(_norm(c['name']))

                    # 3. Last resort: numeric columns with auto-SUM measures
                    if not val_f:
                        for c in filtered_cols:
                            if _norm(c['name']) in _existing_measures:
                                continue
                            if c.get('datatype') in ('int64', 'double') or c.get('measure'):
                                sum_msr = sum_map.get(c['name'])
                                if sum_msr:
                                    val_f.append(_as_measure_item(sum_msr))
                                    _existing_measures.add(_norm(c['name']))

                    # 4. Final resort: COUNT of first column
                    if not val_f and filtered_cols:
                        val_f = [_as_measure_item(
                            f"Count of {filtered_cols[0]['name']}")]
                        _existing_measures.add(_norm(filtered_cols[0]['name']))

                    # ── Merge measure_names_filter_fields into val_f ──────────────
                    # Tableau "Multiple Values / Measure Names" charts (e.g. DSO vs DPO)
                    # encode their per-series measures in the :Measure Names filter.
                    # We add any mnff entry NOT already in val_f.
                    _mnff_line = page.get('measure_names_filter_fields', [])
                    if _mnff_line:
                        for _mnf in _mnff_line:
                            if _norm(_mnf) in _existing_measures:
                                continue
                            # Priority 1: named DAX measure
                            _cc = _find_msr(_mnf, filtered_calcs)
                            if _cc:
                                _cc_dt = _cc.get('datatype', 'double')
                                _cc_formula = (_cc.get('formula') or '').lower()
                                _is_str = (_cc_dt == 'string'
                                           or 'then \'' in _cc_formula
                                           or 'then "' in _cc_formula)
                                if not _is_str:
                                    _m = {**_cc, 'is_measure': True, 'datatype': _cc_dt, '_combo_role': 'line'}
                                    val_f.append(_m)
                                    _line_measures.append(_m)
                                    _existing_measures.add(_norm(_cc['name']))
                                continue
                            # Priority 2: numeric column → use "Sum of X" measure
                            _co = _find_col(_mnf, filtered_cols)
                            if _co and (_co.get('measure') or
                                        _co.get('datatype') in ('int64', 'double')):
                                _sum_msr = sum_map.get(_co['name'])
                                if _sum_msr:
                                    _m = _as_measure_item(_sum_msr)
                                    _m['_combo_role'] = 'line'
                                    val_f.append(_m)
                                    _line_measures.append(_m)
                                    _existing_measures.add(_norm(_co['name']))
                                else:
                                    _reg_item = _measure_registry.resolve(_co['name'], ds)
                                    if _reg_item:
                                        _m = {**_reg_item, 'is_measure': True, '_combo_role': 'line'}
                                    else:
                                        _m = {**_co, 'is_measure': False, 'is_agg': True, '_combo_role': 'line'}
                                    val_f.append(_m)
                                    _line_measures.append(_m)
                                    _existing_measures.add(_norm(_co['name']))
                        if len(val_f) > 1:
                            page['color_is_measure_names'] = True
                    
                    # Fallback: if any measure_names_filter_fields weren't found, try broader matching
                    if _mnff_line and len(_line_measures) < len(_mnff_line):
                        _collected_mnff = {_norm(m.get('name', '')) for m in _line_measures if '_combo_role' in m and m['_combo_role'] == 'line'}
                        for _mnf in _mnff_line:
                            if _norm(_mnf) not in _existing_measures and _norm(_mnf) not in _collected_mnff:
                                # Try broader search in filtered_cols
                                for _fc_col in filtered_cols:
                                    if _norm_match(_mnf, _fc_col['name']) and not any(_norm_match(_fc_col['name'], c['name']) for c in [_m for _m in val_f]):
                                        _broad_reg = _measure_registry.resolve(_fc_col['name'], ds)
                                        if _broad_reg:
                                            _m = {**_broad_reg, 'is_measure': True, '_combo_role': 'line'}
                                        else:
                                            _m = {**_fc_col, 'is_measure': False, 'is_agg': True, '_combo_role': 'line'}
                                        val_f.append(_m)
                                        _line_measures.append(_m)
                                        _existing_measures.add(_norm(_fc_col['name']))
                                        break

                    leg_f = []
                    for cn in color_names:
                        c = _find_col(cn, filtered_cols)
                        if c and not any(_norm_match(c['name'], cf['name']) for cf in cat_f):
                            # For line/combo charts, only allow string dimensions in legend
                            if not c.get('measure') and c.get('datatype') == 'string':
                                leg_f.append(_as_col_item(c))

                    # ── Combo chart bar/line role assignment ────────────────────
                    # Shared with the dashboard-zone rendering path — see
                    # _resolve_combo_roles.
                    val_f = _resolve_combo_roles(
                        val_f, chart_type,
                        page.get('measure_names_filter_fields', []))

                    ds_caption_key = ds.get('caption') or ds.get('name', '')
                    leg_vals_line = _distinct_legend_vals(leg_f, workbook, ds_caption_key)

                    visual_containers.append(_make_chart_vc(
                        name=_guid(), x=0, y=48, z=z,
                        width=W, height=H - 52,
                        visual_type=chart_type,
                        category_fields=cat_f,
                        value_fields=val_f,
                        legend_fields=leg_f,
                        pbi_table_name=pbi_table_name,
                        zone_name=page_name,
                        data_colors=data_colors,
                        legend_values=leg_vals_line,
                        explicit_color_map=explicit_color_map,
                        color_is_measure_names=page.get('color_is_measure_names', False),
                        show_data_labels=page.get('show_data_labels', False),
                        label_format=page.get('label_format', ''),
                        sort_field=page.get('sort_field'),
                        sort_dir=page.get('sort_dir', 1),
                        sort_is_col=page.get('sort_is_col', True),
                        pane_mark_colors=page.get('pane_mark_colors', []),
                        filter_specs=page.get('filter_specs', []),
                        reference_lines=page.get('reference_lines', []), trendline=page.get('trendline'),
                        filter_fields=page.get('filter_fields', []),
                    ))

                else:
                    # ── Column, Bar, or Pie/Donut chart ───────────────────────
                    # Pie/donut category+value resolution is shared with the
                    # dashboard-zone path — see _resolve_pie_fields.
                    _is_pie_donut = chart_type in ('pieChart', 'donutChart')
                    if _is_pie_donut:
                        cat_f, val_f = _resolve_pie_fields(
                            color_names, filtered_cols, filtered_calcs,
                            page.get('shelf_row_fields', []),
                            page.get('pie_size_field', ''),
                            ds, _measure_registry)
                        leg_f = []   # No separate Series bucket — Category handles coloring

                        ds_caption_key = ds.get('caption') or ds.get('name', '')
                        leg_vals_chart = {}
                        visual_containers.append(_make_chart_vc(
                            name=_guid(), x=0, y=48, z=z,
                            width=W, height=H - 52,
                            visual_type=chart_type,
                            category_fields=cat_f,
                            value_fields=val_f,
                            legend_fields=leg_f,
                            pbi_table_name=pbi_table_name,
                            zone_name=page_name,
                            data_colors=data_colors,
                            legend_values=leg_vals_chart,
                            explicit_color_map=explicit_color_map,
                            color_is_measure_names=page.get('color_is_measure_names', False),
                            show_data_labels=page.get('show_data_labels', False),
                        label_format=page.get('label_format', ''),
                            sort_field=page.get('sort_field'),
                            sort_dir=page.get('sort_dir', 2),
                            sort_is_col=False,   # sort by measure value, descending
                            pane_mark_colors=page.get('pane_mark_colors', []),
                            filter_specs=page.get('filter_specs', []),
                        reference_lines=page.get('reference_lines', []), trendline=page.get('trendline'),
                            filter_fields=page.get('filter_fields', []),
                        ))

                    else:
                        # ── Horizontal bar vs vertical column chart axis mapping ──
                        #
                        # For clusteredColumnChart (vertical):
                        #   cols shelf = category dimension (X-axis)  → cat_f
                        #   rows shelf = measure                       → val_f
                        # For clusteredBarChart (horizontal):
                        #   rows shelf = category dimension (Y labels) → cat_f
                        #   cols shelf = measure (bar length)          → val_f
                        #
                        # In both cases x_field = cols-shelf field, y_field = rows-shelf field.
                        # We select the right field for Category based on chart orientation.
                        _is_hbar = chart_type in ('clusteredBarChart', 'barChart',
                                                   'hundredPercentStackedBarChart')

                        # The field name that drives the category axis:
                        _cat_field_name = y_field_name if _is_hbar else x_field_name
                        # The field name that drives the value axis:
                        _val_field_name = x_field_name if _is_hbar else y_field_name

                        # ── Category resolution ───────────────────────────────────
                        # Shared with the dashboard-zone rendering path — see
                        # _resolve_category_fields for bin-calc / date-hierarchy /
                        # multi-field-grouping handling.
                        if _is_hbar:
                            _cat_candidates = (page.get('shelf_row_fields', [])[:1]
                                                + [y_field_name])
                        else:
                            _cat_candidates = (page.get('all_col_fields', [])
                                                + [x_field_name]
                                                + page.get('all_col_dim_fields', []))
                        cat_f = _resolve_category_fields(
                            _cat_candidates, _is_hbar, filtered_cols,
                            ds.get('calculations', []),
                            page.get('date_shelf_groupings', []),
                            page.get('all_col_fields', []))
                        if not cat_f:
                            cat_f = [_as_col_item(c) for c in filtered_cols[:1]
                                     if not c.get('measure')]

                        # ── Y-value (measure) resolution ─────────────────────────
                        # Shared with the dashboard-zone rendering path — see
                        # _resolve_measure_values. val_field_candidates tries
                        # all_col_fields/all_row_measure_fields before the bare
                        # x/y-field name, since the bare field can resolve to
                        # the category dimension instead of the measure for
                        # some chart orientations.
                        _val_candidates = (
                            page.get('all_col_fields', []) + [x_field_name]
                            if _is_hbar else
                            page.get('all_row_measure_fields', []) + [y_field_name])
                        val_f, chart_type, _cim = _resolve_measure_values(
                            chart_type, _is_hbar, _val_candidates, y_field_name,
                            page.get('shelf_row_fields', []),
                            page.get('ctd_fields', []),
                            ds_ctd_maps.get(ds.get('name', ''), {}),
                            ds_sum_maps.get(ds.get('name', ''), {}),
                            page.get('measure_names_filter_fields', []),
                            cat_f, filtered_cols, filtered_calcs, ds, _measure_registry,
                            row_measure_fallback=page.get('all_row_measure_fields', []))
                        if _cim:
                            page['color_is_measure_names'] = True


                        # Shared with the dashboard-zone rendering path — see
                        # _resolve_legend_fields.
                        leg_f = _resolve_legend_fields(
                            color_names, cat_f, filtered_cols, filtered_calcs)

                        # Shared with the dashboard-zone rendering path — see
                        # _maybe_downgrade_stacked.
                        chart_type = _maybe_downgrade_stacked(chart_type, leg_f)

                        # FIX 6: Multiple measures with no legend dimension → merging bars
                        # When multiple measures (e.g. Revenue + Cost + Profit) are on the
                        # Y-axis but there is no separate Series/Legend dimension, PBI collapses
                        # them all into one bar because there is nothing to split by.
                        # Force color_is_measure_names=True so the Case-B coloring path
                        # uses metadata selectors — one colour per measure — which tells PBI
                        # to render one bar/column per measure, side-by-side.
                        if len(val_f) > 1 and not leg_f:
                            page['color_is_measure_names'] = True

                        # Collect distinct series values for colour selectors
                        ds_caption_key = ds.get('caption') or ds.get('name', '')
                        leg_vals_chart = _distinct_legend_vals(
                            leg_f, workbook, ds_caption_key)

                        # Shared with the dashboard-zone rendering path — see
                        # _resolve_default_sort.
                        _chart_sort_field, _chart_sort_dir, _chart_sort_is_col = (
                            _resolve_default_sort(
                                page.get('sort_field'), page.get('sort_dir', 1),
                                page.get('sort_is_col', True),
                                chart_type, cat_f, val_f))

                        visual_containers.append(_make_chart_vc(
                            name=_guid(), x=0, y=48, z=z,
                            width=W, height=H - 52,
                            visual_type=chart_type,
                            category_fields=cat_f,
                            value_fields=val_f,
                            legend_fields=leg_f,
                            pbi_table_name=pbi_table_name,
                            zone_name=page_name,
                            data_colors=data_colors,
                            legend_values=leg_vals_chart,
                            explicit_color_map=explicit_color_map,
                            color_is_measure_names=page.get('color_is_measure_names', False),
                            show_data_labels=page.get('show_data_labels', False),
                            label_format=page.get('label_format', ''),
                            sort_field=_chart_sort_field,
                            sort_dir=_chart_sort_dir,
                            sort_is_col=_chart_sort_is_col,
                            pane_mark_colors=page.get('pane_mark_colors', []),
                            filter_specs=page.get('filter_specs', []),
                        reference_lines=page.get('reference_lines', []), trendline=page.get('trendline'),
                            filter_fields=page.get('filter_fields', []),
                            # FIX: Pages shelf → PBI Small Multiples
                            small_multiple_fields=[
                                _as_col_item(c) for c in filtered_cols
                                if any(_norm_match(c['name'], pf)
                                       for pf in page.get('pages_fields', []))
                            ],
                        ))
            else:
                # Default: table visual (tableEx) or pivot table (pivotTable).
                # Special case: when the Tableau worksheet has no rows/cols shelves
                # but has a text encoding (sum:Value etc.), it's a single-measure KPI
                # display — pass only that one field as shelf_fields, not the full
                # datasource column list.  This prevents the code from dumping all
                # datasource columns into the table when only one measure should show.
                text_field = page.get('text_enc_field')
                effective_shelf = (
                    [text_field] if text_field and not page.get('shelf_row_fields')
                    else page.get('shelf_row_fields', [])
                )
                visual_containers.append(_make_table_vc(
                    name=_guid(),
                    x=0, y=48, z=z,
                    width=W, height=H - 52,
                    datasource=ds_view, zone_name=page_name,
                    pbi_table_name=pbi_table_name,
                    shelf_fields=effective_shelf,
                    filter_fields=page.get('filter_fields', []),
                    filter_specs=page.get('filter_specs', []),
                    visual_type=chart_type,
                    pcto_field=page.get('pcto_field'),
                ))

        section = {
            "id": page_idx,
            "name": __import__('re').sub(r'[^A-Za-z0-9_]', '_', page_name),
            "displayName": page.get('display_name', page_name),
            "objectId": _guid(),
            "displayOption": 1,
            "ordinal": page_idx,
            "width": float(W),
            "height": float(H),
            "config": _jmin({
                "relationships": [],
                "objects": {
                    "section": [{"properties": {
                        "verticalAlignment": {"expr": {"Literal": {"Value": "'Top'"}}}
                    }}]
                }
            }),
            "filters": "[]",
            "visualContainers": visual_containers
        }
        sections.append(section)

    config = _jmin({
        "version": "5.70",
        "themeCollection": {"baseTheme": {
            "name": "CY26SU02",
            "type": 2,
            "version": {"visual": "2.6.0", "report": "3.1.0", "page": "2.3.0"}
        }},
        "activeSectionIndex": 0,
        "defaultDrillFilterOtherVisuals": True,
        "linguisticSchemaSyncVersion": 2,
        "settings": {
            "useNewFilterPaneExperience": True,
            "useStylableVisualContainerHeader": True,
            "useEnhancedTooltips": True,
            "allowChangeFilterTypes": True,
            "queryLimitOption": 6,
            "exportDataMode": 1,
            "useDefaultAggregateDisplayName": True,
        },
        "objects": {
            "section": [{"properties": {
                "verticalAlignment": {"expr": {"Literal": {"Value": "'Top'"}}}
            }}]
        }
    })

    return {
        "id": 0,
        "resourcePackages": [{
            "resourcePackage": {
                "name": "SharedResources",
                "type": 2,
                "items": [{"type": 202, "path": "BaseThemes/CY26SU02.json", "name": "CY26SU02"}],
                "disabled": False
            }
        }],
        "sections": sections,
        "pods": [],
        "config": config,
        "reportId": _guid(),
        "filters": "[]",
        "layoutOptimization": 0,
        "publicCustomVisuals": []
    }



def _make_map_vc(name, x, y, z, width, height, location_field, size_field,
                 pbi_table_name, zone_name='', data_colors=None, show_title=True,
                 background_color='', border_color='', border_width=1,
                 title_font_family='', title_font_size=0, title_bold=False,
                 title_italic=False, title_color='', title_bg_color=''):
    """
    Build a PBI 'map' (Bing bubble-map) visual container for any Tableau
    geographic map worksheet (both Multipolygon/filledMap and ordinary maps).

    Structure is verified against a manually-built reference PBIT.
    PBI map visual roles:
      Category → geocoded string dimension (geo column)
      Size     → numeric measure controlling bubble size (optional)

    Critical requirements (from reference analysis):
      1. visualType must be 'map' (not 'filledMap' — filledMap crashes)
      2. Projection order: Size[0], Category[1]
      3. query.Select order: Measure first, Column second (with NativeReferenceName)
      4. DataReduction: Top:{} (NOT Window — map uses Top)
      5. OrderBy: descending by size measure (if present)
      6. selects[geo_col].type.category = geo_category string (e.g. 'Country')
      7. selects[geo_col].type.underlyingType = 6751233 (Geography text PBI type)
      8. queryMetadata.Select[geo_col].DataCategory = integer geo code
    """
    T     = pbi_table_name
    alias = T[0].lower()
    tab_order = z * 1000

    loc_name       = location_field['name']
    loc_geo_cat    = location_field.get('geo_category', '')   # e.g. 'Country'

    # ── Geo type constants from PBI internals (verified from reference PBIT) ─
    # underlyingType = 6751233 (0x670401) for any string geographic column
    _GEO_UNDERLYING_TYPE = 6751233
    # queryMetadata.DataCategory integer codes for each geo category
    _GEO_DC_INT = {
        'Country':        5,
        'StateOrProvince': 10,
        'City':           2,
        'PostalCode':     9,
        'Continent':      3,
        'County':         5,
        'Latitude':       6,
        'Longitude':      7,
        'Place':          8,
    }
    geo_dc_int = _GEO_DC_INT.get(loc_geo_cat, 5)   # default 5 (Country)

    # ── Select lists ──────────────────────────────────────────────────────────
    # Reference order: Measure FIRST, then geo Column — opposite of what we
    # might expect.  Both items carry NativeReferenceName.

    # Geo column select (Category role)
    col_sel = {
        'Column': {
            'Expression': {'SourceRef': {'Source': alias}},
            'Property': loc_name
        },
        'Name': f"{T}.{loc_name}",
        'NativeReferenceName': loc_name
    }
    col_sel_ent = {
        'Column': {
            'Expression': {'SourceRef': {'Entity': T}},
            'Property': loc_name
        }
    }

    # Size measure select (optional)
    sz_name       = size_field['name']     if size_field else ''
    sz_sel        = None
    sz_sel_ent    = None
    if size_field:
        sz_sel = {
            'Measure': {
                'Expression': {'SourceRef': {'Source': alias}},
                'Property': sz_name
            },
            'Name': f"{T}.{sz_name}",
            'NativeReferenceName': sz_name
        }
        sz_sel_ent = {
            'Measure': {
                'Expression': {'SourceRef': {'Entity': T}},
                'Property': sz_name
            }
        }

    # Reference: Measure FIRST, Column SECOND in Select lists
    query_selects = []
    if sz_sel:
        query_selects.append(sz_sel)
    query_selects.append(col_sel)

    # ── Projections ───────────────────────────────────────────────────────────
    # Reference order: Size[0], Category[1]
    proj_sz_idx  = 0 if sz_sel else None
    proj_cat_idx = 1 if sz_sel else 0
    projections  = {}
    if sz_sel:
        projections['Size']     = [{'queryRef': f"{T}.{sz_name}"}]
    projections['Category'] = [{'queryRef': f"{T}.{loc_name}", 'active': True}]

    proj_ord = {}
    if sz_sel:
        proj_ord['Size']     = [0]
        proj_ord['Category'] = [1]
    else:
        proj_ord['Category'] = [0]

    # ── prototypeQuery ────────────────────────────────────────────────────────
    proto_query = {
        'Version': 2,
        'From':    [{'Name': alias, 'Entity': T, 'Type': 0}],
        'Select':  query_selects,
        'OrderBy': []
    }

    # ── Full SemanticQueryDataShapeCommand query ───────────────────────────────
    # Reference uses DataReduction: Top:{} (NOT Window — map visual uses Top)
    # OrderBy: descending by size measure when present
    order_by = []
    if sz_sel:
        order_by = [{
            'Direction': 2,
            'Expression': {
                'Measure': {
                    'Expression': {'SourceRef': {'Source': alias}},
                    'Property': sz_name
                }
            }
        }]

    query = {
        'Commands': [{
            'SemanticQueryDataShapeCommand': {
                'Query': {
                    'Version': 2,
                    'From':    [{'Name': alias, 'Entity': T, 'Type': 0}],
                    'Select':  query_selects,
                    'OrderBy': order_by
                },
                'Binding': {
                    'Primary': {
                        'Groupings': [{'Projections': list(range(len(query_selects)))}]
                    },
                    'DataReduction': {
                        'DataVolume': 4,
                        'Primary': {'Top': {}}   # map uses Top, not Window
                    },
                    'Version': 1
                },
                'ExecutionMetricsKind': 1
            }
        }]
    }

    # ── dataTransforms ────────────────────────────────────────────────────────
    # selects[geo_col].type MUST have:
    #   category = geo_category string (e.g. 'Country')  ← crashes without this
    #   underlyingType = 6751233 (Geography text PBI type)
    # queryMetadata.Select[geo_col] MUST have DataCategory integer

    selects_dt = []
    qmeta_selects = []

    if sz_sel:
        # Size measure select — with sort/sortOrder and format (from reference)
        selects_dt.append({
            'displayName': sz_name,
            'format':      '#,##0',
            'queryName':   f"{T}.{sz_name}",
            'roles':       {'Size': True},
            'sort':        2,
            'sortOrder':   0,
            'type':        {'category': None, 'underlyingType': 260},  # whole number
            'expr':        sz_sel_ent
        })
        qmeta_selects.append({
            'Restatement': sz_name,
            'Name':        f"{T}.{sz_name}",
            'Type':        3,
            'Format':      '#,##0'
        })

    # Category (geo column) select — critical geo type metadata
    cat_select_dt = {
        'displayName': loc_name,
        'queryName':   f"{T}.{loc_name}",
        'roles':       {'Category': True},
        'type': {
            'category':       loc_geo_cat,       # e.g. 'Country' — REQUIRED
            'underlyingType': _GEO_UNDERLYING_TYPE  # 6751233 — REQUIRED
        },
        'expr': col_sel_ent
    }
    selects_dt.append(cat_select_dt)
    qmeta_selects.append({
        'Restatement':  loc_name,
        'Name':         f"{T}.{loc_name}",
        'Type':         2048,
        'DataCategory': geo_dc_int               # e.g. 5 for Country — REQUIRED
    })

    data_roles = []
    if sz_sel:
        data_roles.append({'Name': 'Size',     'Projection': 0, 'isActive': False})
        data_roles.append({'Name': 'Category', 'Projection': 1, 'isActive': True})
    else:
        data_roles.append({'Name': 'Category', 'Projection': 0, 'isActive': True})

    data_transforms = {
        'projectionOrdering': proj_ord,
        'projectionActiveItems': {
            'Category': [{
                'queryRef': f"{T}.{loc_name}",
                'suppressConcat': False
            }]
        },
        'queryMetadata': {
            'Select': qmeta_selects
        },
        'visualElements': [{'DataRoles': data_roles}],
        'selects': selects_dt
    }

    # ── Config ────────────────────────────────────────────────────────────────
    config = _jmin({
        'name': name,
        'layouts': [{'id': 0, 'position': {
            'x': x, 'y': y, 'z': z,
            'width': float(width), 'height': float(height),
            'tabOrder': tab_order
        }}],
        'singleVisual': {
            'visualType': 'map',        # 'map' (bubble), NOT 'filledMap'
            'projections': projections,
            'prototypeQuery': proto_query,
            'drillFilterOtherVisuals': True,
            'vcObjects': {
                'title': [{'properties': {
                    'text': {'expr': {'Literal': {'Value': f"'{zone_name}'"}}},
                    'show': {'expr': {'Literal': {'Value': 'true' if show_title else 'false'}}},
                    **_title_font_vc_properties(title_font_family, title_font_size,
                                                 title_bold, title_italic,
                                                 title_color, title_bg_color),
                }}],
                **({'background': [{'properties': {
                    'color': {'solid': {'color': {'expr': {'Literal': {'Value': f"'{background_color}'"}}}}},
                    'transparency': {'expr': {'Literal': {'Value': '0'}}},
                }}]} if background_color else {}),
                **(_border_vc_objects(border_color, border_width) if border_color else {}),
            }
        }
    })

    return {
        'x': x, 'y': y, 'z': z,
        'width': float(width), 'height': float(height),
        'config':         config,
        'filters':        '[]',
        'query':          _jmin(query),
        'dataTransforms': _jmin(data_transforms)
    }



def _make_card_vc(name, x, y, z, width, height, value_fields, pbi_table_name,
                  zone_name='', data_colors=None,
                  filter_specs=None, filter_fields=None, show_title=True,
                  border_color='', border_width=1,
                  title_font_family='', title_font_size=0, title_bold=False,
                  title_italic=False, title_color='', title_bg_color=''):
    """
    Build a PBI **card** visual container for single-measure KPI pages.

    Tableau KPI pages (rows=EMPTY, cols=EMPTY, text encoding = single measure)
    are represented in PBI as a **card** (single number) visual — NOT tableEx.
    This matches what PBI users expect: a large formatted number with a title.
    """
    import re as _re_card

    # ── Derive a clean display title for this KPI card ────────────────────────
    # Priority order:
    # 1. Categorical filter value (e.g. Type='EBITDA' → title='EBITDA')
    #    This correctly differentiates Finance KPI cards that all read from the
    #    same 'Value' column but are filtered to different Type members.
    # 2. Clean zone_name: strip common Tableau suffixes like '_Count', '_KPI',
    #    ' Count', ' KPI', and replace underscores with spaces.
    # 3. Raw zone_name as-is.
    _display_title = zone_name
    _cat_filter_values = []
    for _fs in (filter_specs or []):
        _fvals = _fs.get('values', [])
        if _fvals and isinstance(_fvals[0], str):
            _cat_filter_values.extend(_fvals)
    if _cat_filter_values:
        # Use first categorical filter value as the KPI title
        _display_title = _cat_filter_values[0]
    elif zone_name:
        # Clean up common Tableau KPI worksheet naming conventions
        _display_title = _re_card.sub(
            r'[\s_]*(Count|KPI|Card|Metric|Value|Total|Sum|Agg)$',
            '', zone_name, flags=_re_card.I).strip()
        _display_title = _display_title.replace('_', ' ').strip()
        if not _display_title:
            _display_title = zone_name
    T     = pbi_table_name
    alias = T[0].lower()
    tab_order = z * 1000

    field = value_fields[0] if value_fields else None
    if field is None:
        field = {'name': 'Count', 'is_measure': True, 'datatype': 'int64'}

    fname = field['name']
    # is_measure=True means a pre-built DAX Measure from the semantic model.
    # is_agg=True means a numeric column with no pre-built measure — emit as
    # Aggregation(Column, Sum) inline.  Both produce a single number on card.
    _is_semantic_msr = bool(field.get('is_measure'))
    _is_inline_agg   = bool(field.get('is_agg')) and not _is_semantic_msr
    is_msr           = _is_semantic_msr   # used by the rest of the function

    if _is_semantic_msr:
        sel_expr = {'Measure': {
            'Expression': {'SourceRef': {'Source': alias}},
            'Property': fname
        }}
        query_name   = f"{T}.{fname}"
        display_name = fname
    else:
        # Inline aggregation (no pre-built measure) — or plain column fallback
        sel_expr = {'Aggregation': {
            'Expression': {'Column': {
                'Expression': {'SourceRef': {'Source': alias}},
                'Property': fname
            }},
            'Function': 0  # Sum
        }}
        query_name   = f"Sum({T}.{fname})"
        display_name = f"Sum of {fname}"

    agg_expr_ent = {'Aggregation': {
        'Expression': {'Column': {
            'Expression': {'SourceRef': {'Entity': T}},
            'Property': fname
        }},
        'Function': 0
    }}

    sel     = {**sel_expr, 'Name': query_name, 'NativeReferenceName': display_name}
    proj    = {'Values': [{'queryRef': query_name, 'active': True}]}

    proto_query = {
        'Version': 2,
        'From': [{'Name': alias, 'Entity': T, 'Type': 0}],
        'Select': [sel],
    }
    query = {
        'Commands': [{'SemanticQueryDataShapeCommand': {
            'Query': proto_query,
            'Binding': {
                'Primary': {'Groupings': [{'Projections': [0]}]},
                'DataReduction': {'DataVolume': 3, 'Primary': {'Top': {}}},
                'Version': 1,
            },
            'ExecutionMetricsKind': 1,
        }}]
    }

    data_transforms = {
        'projectionOrdering': {'Values': [0]},
        'projectionActiveItems': {
            'Values': [{'queryRef': query_name, 'suppressConcat': False}]
        },
        'queryMetadata': {
            'Select': [{'Restatement': display_name,
                        'Name': query_name,
                        'Type': 1 if is_msr else 4}]
        },
        'visualElements': [{'DataRoles': [{'Name': 'Values', 'Projection': 0,
                                           'isActive': True}]}],
        'selects': [{'displayName': display_name,
                     'queryName': query_name,
                     'roles': {'Values': True},
                     'type': {'category': None,
                              'underlyingType': 259},
                     'expr': agg_expr_ent if not is_msr else {
                         'Measure': {
                             'Expression': {'SourceRef': {'Entity': T}},
                             'Property': fname
                         }
                     }}],
    }

    # Card visual format: large number, currency symbol if numeric
    _fmt_str = "\\$#,0;(\\$#,0)" if field.get('datatype') in ('double','int64','decimal') else "#,0"

    config = _jmin({
        'name': name,
        'layouts': [{'id': 0, 'position': {
            'x': x, 'y': y, 'z': z, 'width': width, 'height': height,
            'tabOrder': tab_order
        }}],
        'singleVisual': {
            'visualType': 'card',
            'projections': proj,
            'prototypeQuery': proto_query,
            'drillFilterOtherVisuals': True,
            'vcObjects': {
                'title': [{'properties': {
                    'text': {'expr': {'Literal': {'Value': f"'{_display_title}'"}}},
                    'show': {'expr': {'Literal': {'Value': 'true' if show_title else 'false'}}},
                    **_title_font_vc_properties(title_font_family, title_font_size,
                                                 title_bold, title_italic,
                                                 title_color, title_bg_color),
                }}],
                **(_border_vc_objects(border_color, border_width) if border_color else {}),
                'labels': [{'properties': {
                    'labelDisplayUnits': {'expr': {'Literal': {'Value': '0'}}},
                    'fontSize': {'expr': {'Literal': {'Value': '28D'}}},
                }}],
                'categoryLabels': [{'properties': {
                    'show': {'expr': {'Literal': {'Value': 'true'}}},
                }}],
            }
        }
    })

    # ── Visual-level filters (native SemanticQuery format) ───────────────────
    _card_filters = _build_pbi_visual_filters(T, filter_fields, filter_specs)

    return {
        'id':             abs(hash(name)) % (2**31),
        'x': x, 'y': y, 'z': z, 'width': width, 'height': height,
        'config':         config,
        'filters':        _jmin(_card_filters) if _card_filters else '[]',
        'query':          _jmin(query),
        'queryHash':      0,
        'dataTransforms': _jmin(data_transforms),
    }


def _make_multirow_card_vc(name, x, y, z, width, height, value_fields, pbi_table_name,
                           zone_name='', data_colors=None,
                           filter_specs=None, filter_fields=None, show_title=True,
                           border_color='', border_width=1,
                           title_font_family='', title_font_size=0, title_bold=False,
                           title_italic=False, title_color='', title_bg_color=''):
    """
    Build a PBI **multiRowCard** visual container for Tableau's canonical
    multi-KPI construction: ":Measure Names" dropped on a shelf + Measure
    Values shown as text, filtered down to N specific measures (e.g. a
    worksheet literally named "KPI" showing Age/Attrition/Income/etc. side
    by side). Previously this pattern had no dedicated detection and fell
    through every chart-type branch to a generic tableEx table.

    Structurally a straight generalisation of _make_card_vc's proven
    single-field 'Values' role to N fields — Power BI's built-in Multi-row
    Card uses the identical 'Values' role as Card, just accepting more than
    one field (each becomes its own row) — not a different, unverified
    internal shape.
    """
    T     = pbi_table_name
    alias = T[0].lower()
    tab_order = z * 1000

    fields = value_fields or [{'name': 'Count', 'is_measure': True, 'datatype': 'int64'}]

    sels, proj_items, active_items = [], [], []
    select_meta, dt_selects, data_roles = [], [], []
    for idx, field in enumerate(fields):
        fname  = field['name']
        is_msr = bool(field.get('is_measure'))
        if is_msr:
            sel_expr = {'Measure': {'Expression': {'SourceRef': {'Source': alias}},
                                    'Property': fname}}
            query_name, display_name = f"{T}.{fname}", fname
            expr_ent = {'Measure': {'Expression': {'SourceRef': {'Entity': T}},
                                    'Property': fname}}
        else:
            sel_expr = {'Aggregation': {'Expression': {'Column': {
                'Expression': {'SourceRef': {'Source': alias}}, 'Property': fname}},
                'Function': 0}}
            query_name, display_name = f"Sum({T}.{fname})", f"Sum of {fname}"
            expr_ent = {'Aggregation': {'Expression': {'Column': {
                'Expression': {'SourceRef': {'Entity': T}}, 'Property': fname}},
                'Function': 0}}

        sels.append({**sel_expr, 'Name': query_name, 'NativeReferenceName': display_name})
        proj_items.append({'queryRef': query_name, 'active': idx == 0})
        active_items.append({'queryRef': query_name, 'suppressConcat': False})
        select_meta.append({'Restatement': display_name, 'Name': query_name,
                            'Type': 1 if is_msr else 4})
        dt_selects.append({'displayName': display_name, 'queryName': query_name,
                           'roles': {'Values': True},
                           'type': {'category': None, 'underlyingType': 259},
                           'expr': expr_ent})
        data_roles.append({'Name': 'Values', 'Projection': idx, 'isActive': idx == 0})

    proto_query = {
        'Version': 2,
        'From': [{'Name': alias, 'Entity': T, 'Type': 0}],
        'Select': sels,
    }
    query = {
        'Commands': [{'SemanticQueryDataShapeCommand': {
            'Query': proto_query,
            'Binding': {
                'Primary': {'Groupings': [{'Projections': list(range(len(fields)))}]},
                'DataReduction': {'DataVolume': 3, 'Primary': {'Top': {}}},
                'Version': 1,
            },
            'ExecutionMetricsKind': 1,
        }}]
    }

    data_transforms = {
        'projectionOrdering': {'Values': list(range(len(fields)))},
        'projectionActiveItems': {'Values': active_items},
        'queryMetadata': {'Select': select_meta},
        'visualElements': [{'DataRoles': data_roles}],
        'selects': dt_selects,
    }

    config = _jmin({
        'name': name,
        'layouts': [{'id': 0, 'position': {
            'x': x, 'y': y, 'z': z, 'width': width, 'height': height,
            'tabOrder': tab_order
        }}],
        'singleVisual': {
            'visualType': 'multiRowCard',
            'projections': {'Values': proj_items},
            'prototypeQuery': proto_query,
            'drillFilterOtherVisuals': True,
            'vcObjects': {
                'title': [{'properties': {
                    'text': {'expr': {'Literal': {'Value': f"'{zone_name}'"}}},
                    'show': {'expr': {'Literal': {'Value': 'true' if show_title else 'false'}}},
                    **_title_font_vc_properties(title_font_family, title_font_size,
                                                 title_bold, title_italic,
                                                 title_color, title_bg_color),
                }}],
                **(_border_vc_objects(border_color, border_width) if border_color else {}),
            }
        }
    })

    _mrc_filters = _build_pbi_visual_filters(T, filter_fields, filter_specs)

    return {
        'id':             abs(hash(name)) % (2**31),
        'x': x, 'y': y, 'z': z, 'width': width, 'height': height,
        'config':         config,
        'filters':        _jmin(_mrc_filters) if _mrc_filters else '[]',
        'query':          _jmin(query),
        'queryHash':      0,
        'dataTransforms': _jmin(data_transforms),
    }


def _make_textbox_vc(name, x, y, z, width, height, text, font_size=14, bold=False):
    tab_order = z * 1000
    config = _jmin({
        "name": name,
        "layouts": [{"id": 0, "position": {"x": x, "y": y, "z": z,
                                             "width": width, "height": height,
                                             "tabOrder": tab_order}}],
        "singleVisual": {
            "visualType": "textbox",
            "objects": {
                "general": [{
                    "properties": {
                        "paragraphs": [{
                            "textRuns": [{
                                "value": text,
                                "textStyle": {
                                    "fontWeight": "bold" if bold else "normal",
                                    "fontSize": f"{font_size}pt"
                                }
                            }],
                            "horizontalTextAlignment": "Center"
                        }]
                    }
                }]
            }
        }
    })
    return {
        "id": abs(hash(name)) % (2**31),
        "x": x, "y": y, "z": z,
        "width": width, "height": height,
        "config": config, "filters": "[]"
    }


# fontalignment is xs:int in the 2026.2 TWB XSD with no documented enum —
# every real occurrence across all 10 fixtures is '1'. Mapped using the
# ordinary left/center/right ordinal UI convention; not schema-proven, but
# low-risk (a wrong guess just leaves PBI's default left alignment, not a
# broken visual).
_FONT_ALIGNMENT_MAP = {'0': 'Left', '1': 'Center', '2': 'Right'}


def _make_dashboard_text_vc(name, x, y, z, width, height, runs, background_color=''):
    """
    Real Tableau dashboard Text Object (<zone type='text'>) → a PBI
    textbox visual with multi-run rich text, reusing the exact
    textRuns/textStyle/paragraphs shape _make_textbox_vc already proves —
    just with real per-run bold/size/color/font/alignment instead of one
    hardcoded style, and multiple runs instead of always exactly one.

    `runs` is the list built in parse_tableau_workbook's _collect_zone:
    each dict has text/bold/italic/underline/fontname/fontsize/
    fontalignment/fontcolor, straight from a real <run> element inside
    <formatted-text>.
    """
    tab_order = z * 1000
    text_runs = []
    align = 'Left'
    for r in runs:
        style = {}
        if r.get('bold'):
            style['fontWeight'] = 'bold'
        if r.get('italic'):
            style['fontStyle'] = 'italic'
        if r.get('underline'):
            style['textDecoration'] = 'underline'
        if r.get('fontsize'):
            style['fontSize'] = f"{r['fontsize']}pt"
        if r.get('fontname'):
            style['fontFamily'] = r['fontname']
        if r.get('fontcolor'):
            style['color'] = r['fontcolor']
        text_runs.append({'value': r['text'], 'textStyle': style} if style
                          else {'value': r['text']})
        _al = _FONT_ALIGNMENT_MAP.get(r.get('fontalignment', ''))
        if _al:
            align = _al

    general_props = {
        'paragraphs': [{
            'textRuns': text_runs,
            'horizontalTextAlignment': align,
        }]
    }
    vc_objects = {}
    if background_color:
        vc_objects['background'] = [{'properties': {
            'color': {'solid': {'color': {'expr': {'Literal': {'Value': f"'{background_color}'"}}}}},
            'transparency': {'expr': {'Literal': {'Value': '0'}}},
        }}]

    config = _jmin({
        "name": name,
        "layouts": [{"id": 0, "position": {"x": x, "y": y, "z": z,
                                             "width": width, "height": height,
                                             "tabOrder": tab_order}}],
        "singleVisual": {
            "visualType": "textbox",
            "objects": {"general": [{"properties": general_props}]},
            **({"vcObjects": vc_objects} if vc_objects else {}),
        }
    })
    return {
        "id": abs(hash(name)) % (2**31),
        "x": x, "y": y, "z": z,
        "width": width, "height": height,
        "config": config, "filters": "[]"
    }


def _make_table_vc(name, x, y, z, width, height, datasource, zone_name,
                   pbi_table_name=None, shelf_fields=None, filter_fields=None,
                   visual_type='tableEx', pcto_field=None, filter_specs=None,
                   show_title=True, background_color='',
                   border_color='', border_width=1,
                   title_font_family='', title_font_size=0, title_bold=False,
                   title_italic=False, title_color='', title_bg_color=''):
    """
    Build a tableEx visual container with all fields PBI needs to render data.

    PBI requires three things at the VC level beyond the config:
      - 'query'          : SemanticQueryDataShapeCommand JSON string
      - 'queryHash'      : integer hash of the query (can be 0 for templates)
      - 'dataTransforms' : field role/type metadata JSON string

    Parameters
    ----------
    shelf_fields  : list of column-name strings in the order they appear on the
                    Tableau rows/cols shelf.  When provided, these fields are used
                    exactly (in that order) as the table's Rows projection instead
                    of an arbitrary slice of the datasource columns.
    filter_fields : list of column-name strings that the Tableau worksheet had in
                    its <filter> or <slices> elements.  These are written as PBI
                    visual-level filters (visible in the filter pane but with
                    operator="All" so they do not restrict data by default).
    """
    import re as _re

    raw_name = datasource['name'] if datasource else 'Table'

    def _safe(s):
        n = _re.sub(r'[^\w\s]', '_', s.strip())
        n = _re.sub(r'[\s_]+', '_', n).strip('_')
        if n and n[0].isdigit():
            n = 'T_' + n
        return n or 'Table'

    T     = pbi_table_name or _safe(raw_name)
    alias = T[0].lower()

    # ── Determine which columns go into Rows vs Values ────────────────────────
    # If the caller supplies the Tableau shelf fields, use them exactly.
    # Otherwise fall back to the old heuristic (all dims, then measures).
    all_ds_cols = datasource['columns'] if datasource else []
    ds_calcs    = datasource.get('calculations', []) or []

    def _norm(s):
        return s.lower().replace(' ', '').replace('_', '').replace('-', '')

    col_by_norm = {_norm(c['name']): c for c in all_ds_cols}

    if shelf_fields:
        # Respect the order and selection the worksheet author chose
        row_cols = []
        for fn in shelf_fields:
            c = col_by_norm.get(_norm(fn))
            if c and c not in row_cols:
                row_cols.append(c)
        # Any shelf field that is a calculation / measure → Values bucket
        row_fields   = [c for c in row_cols if not c.get('measure')]
        value_cols   = [c for c in row_cols if c.get('measure')]
        # Add explicit calculations as Values too
        value_fields = ([{**m, 'is_measure': True} for m in ds_calcs[:4]]
                        if ds_calcs else
                        [{**c, 'is_measure': True} for c in value_cols])
    else:
        # Heuristic fallback: all visible dims → Rows, numeric cols/calcs → Values
        dim_cols     = [c for c in all_ds_cols if not c.get('hidden') and not c.get('measure')]
        num_cols     = [c for c in all_ds_cols if not c.get('hidden') and c.get('measure')]
        row_fields   = dim_cols
        value_fields = ([{**m, 'is_measure': True} for m in ds_calcs[:4]]
                        if ds_calcs else
                        [{**c, 'is_measure': True} for c in num_cols[:4]])

    all_fields = row_fields + [f for f in value_fields if f not in row_fields]

    # ── Build Select list (used in both prototypeQuery and query) ─────────────
    def _col_select(col, src_alias):
        return {
            "Column": {
                "Expression": {"SourceRef": {"Source": src_alias}},
                "Property": col['name']
            },
            "Name": f"{T}.{col['name']}"
        }

    def _msr_select(m, src_alias):
        return {
            "Measure": {
                "Expression": {"SourceRef": {"Source": src_alias}},
                "Property": m['name']
            },
            "Name": f"{T}.{m['name']}"
        }

    proto_select = (
        [_col_select(c, alias) for c in row_fields] +
        [_msr_select(f, alias) if f.get('is_measure') else _col_select(f, alias)
         for f in value_fields]
    )

    # ── pivotTable with pcto: (percent-of-total) value ───────────────────────
    # When Tableau uses pcto:cnt:Col:qk as the text encoding, the reference PBI
    # pivotTable uses an Arithmetic expression for the value cell:
    #   CountNonNull(Col) / ScopedEval(CountNonNull(Col), Scope=[])
    # This is PBI's native "% of grand total" calculation.
    # NativeReferenceName on the dimension column = the display label.
    if visual_type == 'pivotTable' and pcto_field and row_fields:
        dim_col = row_fields[0]
        # Rebuild the dimension select with NativeReferenceName
        pct_dim_sel = {
            "Column": {"Expression": {"SourceRef": {"Source": alias}},
                       "Property": dim_col['name']},
            "Name": f"{T}.{dim_col['name']}",
            "NativeReferenceName": dim_col['name']
        }
        # Arithmetic: CountNonNull(pcto_field) / ScopedEval(CountNonNull(pcto_field), [])
        agg_expr = {
            "Aggregation": {
                "Expression": {"Column": {"Expression": {"SourceRef": {"Source": alias}},
                                          "Property": pcto_field}},
                "Function": 5   # 5 = CountNonNull
            }
        }
        pct_val_sel = {
            "Arithmetic": {
                "Left": agg_expr,
                "Right": {"ScopedEval": {"Expression": agg_expr, "Scope": []}},
                "Operator": 3   # 3 = Divide
            },
            "Name": f"Min({T}.{pcto_field})",
            "NativeReferenceName": f"%GT Count of {pcto_field}"
        }
        proto_select = [pct_dim_sel, pct_val_sel]
        all_table_fields_pct = [dim_col,
                                 {'name': f"%GT Count of {pcto_field}",
                                  '_query_name': f"Min({T}.{pcto_field})",
                                  'is_measure': True, 'datatype': 'double'}]
        projections = {
            "Columns": [{"queryRef": f"{T}.{dim_col['name']}", "active": True}],
            "Values":  [{"queryRef": f"Min({T}.{pcto_field})"}]
        }
        proto_query = {
            "Version": 2,
            "From": [{"Name": alias, "Entity": T, "Type": 0}],
            "Select": proto_select
        }
        # pivotTable query binding uses Secondary grouping for column headers
        query = {
            "Commands": [{
                "SemanticQueryDataShapeCommand": {
                    "Query": proto_query,
                    "Binding": {
                        "Primary": {
                            "Groupings": [{"Projections": [1], "Subtotal": 1}]
                        },
                        "Secondary": {
                            "Groupings": [{"Projections": [0]}]
                        },
                        "DataReduction": {
                            "DataVolume": 4,
                            "Primary":   {"Window": {"Count": 500}},
                            "Secondary": {"Top":    {"Count": 60}}
                        },
                        "Version": 1
                    },
                    "ExecutionMetricsKind": 1
                }
            }]
        }
        # pivotTable-specific dataTransforms: Columns/Values roles, projectionActiveItems,
        # subTotals disabled, queryMetadata with format string.
        data_transforms = {
            "objects": {
                "subTotals": [{"properties": {
                    "rowSubtotals":    {"expr": {"Literal": {"Value": "false"}}},
                    "columnSubtotals": {"expr": {"Literal": {"Value": "false"}}}
                }}]
            },
            "projectionOrdering": {"Columns": [0], "Values": [1]},
            "projectionActiveItems": {
                "Columns": [{"queryRef": f"{T}.{dim_col['name']}",
                             "suppressConcat": False}]
            },
            "queryMetadata": {
                "Select": [
                    {"Restatement": dim_col['name'],
                     "Name": f"{T}.{dim_col['name']}", "Type": 2048},
                    {"Restatement": f"%GT Count of {pcto_field}",
                     "Name": f"Min({T}.{pcto_field})",
                     "Type": 1, "Format": "#,##0.00%"}
                ],
                "Filters": [{
                    "type": 2,
                    "expression": {"Aggregation": {
                        "Expression": {"Column": {
                            "Expression": {"SourceRef": {"Entity": T}},
                            "Property": pcto_field}},
                        "Function": 5
                    }}
                }]
            },
            "visualElements": [{"DataRoles": [
                {"Name": "Columns", "Projection": 0, "isActive": True},
                {"Name": "Values",  "Projection": 1, "isActive": False}
            ]}],
            "selects": [
                {"displayName": dim_col['name'],
                 "queryName": f"{T}.{dim_col['name']}",
                 "roles": {"Columns": True},
                 "type": {"category": None, "underlyingType": 1},
                 "expr": {"Column": {"Expression": {"SourceRef": {"Entity": T}},
                                     "Property": dim_col['name']}}},
                {"displayName": f"%GT Count of {pcto_field}",
                 "queryName": f"Min({T}.{pcto_field})",
                 "roles": {"Values": True},
                 "type": {"category": None, "underlyingType": 259},
                 "format": "#,##0.00%",
                 "expr": {
                     "Arithmetic": {
                         "Left": {"Aggregation": {
                             "Expression": {"Column": {
                                 "Expression": {"SourceRef": {"Entity": T}},
                                 "Property": pcto_field}},
                             "Function": 5}},
                         "Right": {"ScopedEval": {
                             "Expression": {"Aggregation": {
                                 "Expression": {"Column": {
                                     "Expression": {"SourceRef": {"Entity": T}},
                                     "Property": pcto_field}},
                                 "Function": 5}},
                             "Scope": []}},
                         "Operator": 3
                     }
                 }}
            ]
        }
        objects_cfg = {
            "subTotals": [{"properties": {
                "rowSubtotals":    {"expr": {"Literal": {"Value": "false"}}},
                "columnSubtotals": {"expr": {"Literal": {"Value": "false"}}}
            }}]
        }
        tab_order = z * 1000
        config = _jmin({
            'name': name,
            'layouts': [{'id': 0, 'position': {
                'x': x, 'y': y, 'z': z,
                'width': width, 'height': height, 'tabOrder': tab_order
            }}],
            'singleVisual': {
                'visualType': visual_type,
                'projections': projections,
                'prototypeQuery': proto_query,
                'drillFilterOtherVisuals': True,
                'objects': objects_cfg,
                'vcObjects': {
                    'title': [{'properties': {
                        'text': {'expr': {'Literal': {'Value': f"'{zone_name or raw_name}'"}}},
                        'show': {'expr': {'Literal': {'Value': 'true' if show_title else 'false'}}},
                        **_title_font_vc_properties(title_font_family, title_font_size,
                                                     title_bold, title_italic,
                                                     title_color, title_bg_color),
                    }}],
                    **({'background': [{'properties': {
                        'color': {'solid': {'color': {'expr': {'Literal': {'Value': f"'{background_color}'"}}}}},
                        'transparency': {'expr': {'Literal': {'Value': '0'}}},
                    }}]} if background_color else {}),
                    **(_border_vc_objects(border_color, border_width) if border_color else {}),
                }
            }
        })
        return {
            'id': abs(hash(name)) % (2**31),
            'x': x, 'y': y, 'z': z, 'width': width, 'height': height,
            'config': config,
            'query': _jmin(query),
            'queryHash': '0',
            'dataTransforms': _jmin(data_transforms),
            'filters': '[]'
        }

    # ── ALL fields go into "Values" projection for a flat tableEx ────────────
    #
    # PBI tableEx has two projection roles:
    #   "Values"  → regular flat table COLUMNS  ← correct for all fields here
    #   "Rows"    → matrix row GROUP headers    ← NOT what we want; causes columns
    #               (pivot-table style)           to disappear from the table
    #
    # When fields are placed in "Rows" with an empty "Values", PBI renders a
    # matrix structure with no data columns — the table appears empty/blank.
    # All fields (both dimension columns and measures) must go in "Values".
    all_table_fields = row_fields + value_fields
    projections = {
        "Values": [
            {"queryRef": f"{T}.{c['name']}", "active": True}
            for c in all_table_fields
        ]
    }

    proto_query = {
        "Version": 2,
        "From": [{"Name": alias, "Entity": T, "Type": 0}],
        "Select": proto_select,
        "OrderBy": []
    }

    # ── query (SemanticQueryDataShapeCommand) — what PBI actually executes ────
    binding_projections = list(range(len(proto_select)))
    query = {
        "Commands": [{
            "SemanticQueryDataShapeCommand": {
                "Query": proto_query,
                "Binding": {
                    "Primary": {
                        # Subtotal: 1 matches what PBI Desktop generates for tableEx
                        "Groupings": [{"Projections": binding_projections, "Subtotal": 1}]
                    },
                    "DataReduction": {
                        "DataVolume": 4,
                        "Primary": {"Window": {"Count": 1000}}
                    },
                    "Version": 1
                },
                "ExecutionMetricsKind": 1
            }
        }]
    }

    # ── dataTransforms — field metadata PBI uses to map query → visual roles ──
    # underlyingType: 1=text, 259=decimal number, 261=whole number, 519=dateTime
    def _underlying_type(col):
        dt = col.get('datatype', 'string')
        if dt in ('double',):                 return 259
        if dt in ('int64',):                  return 261
        if dt in ('date', 'dateTime'):        return 519
        return 1

    selects_dt = []
    for i, c in enumerate(all_table_fields):
        is_measure = c.get('is_measure', False)
        # Calculated columns (is_calc_col=True) are DAX calculated columns in
        # the TOM — they bind as Column references, NOT Measure references.
        # Even though they are tagged is_measure=True (so they appear in the
        # Values bucket), their PBI expression type must be Column, otherwise
        # PBI cannot resolve them and the table column shows no data.
        is_calc_col = c.get('is_calc_col', False)
        _use_column_expr = is_calc_col or not is_measure
        # pivotTable uses 'Columns' role for the dimension header fields and
        # 'Values' for the data cells.  For a flat tableEx everything is 'Values'.
        if visual_type == 'pivotTable':
            # First non-measure field goes to Columns; rest to Values
            first_dim_done = any(
                not cf.get('is_measure') for cf in all_table_fields[:i]
            )
            role_key = 'Values' if (is_measure or first_dim_done) else 'Columns'
        else:
            role_key = 'Values'
        selects_dt.append({
            "displayName": c['name'],
            "queryName":   f"{T}.{c['name']}",
            "roles":       {role_key: True},
            "type":        {"category": None,
                            "underlyingType": 259 if (is_measure and not is_calc_col)
                                             else _underlying_type(c)},
            "expr":        (
                {"Column":  {"Expression": {"SourceRef": {"Entity": T}},
                             "Property":   c['name']}}
                if _use_column_expr else
                {"Measure": {"Expression": {"SourceRef": {"Entity": T}},
                             "Property":   c['name']}}
            )
        })

    # projectionOrdering: sequential indices, "Values" key only (no "Rows")
    # DataRoles: isActive=False for Values columns (matches PBI Desktop output)
    data_transforms = {
        "projectionOrdering": {
            "Values": list(range(len(all_table_fields)))
        },
        "projectionActiveItems": {},
        "queryMetadata": {
            "Select": [
                {
                    "Restatement": s.get("Column", s.get("Measure", {})).get("Property", ""),
                    "Name":        s["Name"],
                    "Type":        1 if "Measure" in s else 2048
                }
                for s in proto_select
            ]
        },
        "visualElements": [{
            "DataRoles": [
                {"Name": "Values", "Projection": i, "isActive": False}
                for i in range(len(all_table_fields))
            ]
        }],
        "selects": selects_dt
    }

    # ── Build PBI visual-level filters (native SemanticQuery format) ─────────
    def _resolve_filter_col(fn):
        c = col_by_norm.get(_norm(fn))
        return c['name'] if c else fn

    pbi_filters = _build_pbi_visual_filters(
        T, filter_fields, filter_specs, col_name_resolver=_resolve_filter_col)

    tab_order = z * 1000

    config = _jmin({
        "name": name,
        "layouts": [{"id": 0, "position": {
            "x": x, "y": y, "z": z,
            "width": width, "height": height,
            "tabOrder": tab_order
        }}],
        "singleVisual": {
            "visualType": visual_type,
            "projections": projections,
            "prototypeQuery": proto_query,
            "drillFilterOtherVisuals": True,
            "vcObjects": {
                "title": [{"properties": {
                    "text": {"expr": {"Literal": {"Value": f"'{zone_name or raw_name}'"}}},
                    "show": {"expr": {"Literal": {"Value": "true" if show_title else "false"}}},
                    **_title_font_vc_properties(title_font_family, title_font_size,
                                                 title_bold, title_italic,
                                                 title_color, title_bg_color),
                }}],
                **({"background": [{"properties": {
                    "color": {"solid": {"color": {"expr": {"Literal": {"Value": f"'{background_color}'"}}}}},
                    "transparency": {"expr": {"Literal": {"Value": "0"}}},
                }}]} if background_color else {}),
                **(_border_vc_objects(border_color, border_width) if border_color else {}),
            }
        }
    })

    return {
        "id":             abs(hash(name)) % (2**31),
        "x": x, "y": y, "z": z,
        "width": width, "height": height,
        "config":         config,
        "filters":        _jmin(pbi_filters) if pbi_filters else "[]",
        "query":          _jmin(query),
        "queryHash":      0,
        "dataTransforms": _jmin(data_transforms)
    }


# ── DiagramLayout builder ─────────────────────────────────────────────────────

def build_diagram_layout(workbook: dict) -> dict:
    nodes = []
    x_pos = 80
    for ds_idx, ds in enumerate(workbook['datasources']):
        nodes.append({
            "location": {"x": x_pos, "y": 90},
            "nodeIndex": ds['name'],
            "size": {"height": min(228 + len(ds['columns']) * 12, 500), "width": 284},
            "zIndex": ds_idx + 1
        })
        x_pos += 340

    return {
        "version": "1.1.0",
        "diagrams": [{
            "ordinal": 0,
            "scrollPosition": {"x": 0, "y": 0},
            "nodes": nodes,
            "name": f"{workbook['name']} Data Model",
            "zoomValue": 100,
            "pinKeyFieldsToTop": False,
            "showExtraHeaderInfo": True,
            "hideKeyFieldsWhenCollapsed": False,
            "tablesLocked": False
        }],
        "selectedDiagram": 0,
        "defaultDiagram": 0
    }


# ── Main PBIT writer ──────────────────────────────────────────────────────────

def write_pbit(workbook: dict, output_path: Path, embed_sample_data: bool = False, extracted_data: dict = None):
    """
    Write a valid .pbit file from the parsed workbook description.

    Encoding rules (confirmed from real PBIX byte analysis):
      - [Content_Types].xml  → UTF-8
      - Version              → UTF-16LE, no BOM  (plain string "1.28")
      - Metadata             → UTF-16LE, no BOM  (JSON)
      - Settings             → UTF-16LE, no BOM  (JSON)
      - DataModelSchema      → UTF-16LE, no BOM  (JSON)
      - DiagramLayout        → UTF-16LE, no BOM  (JSON)
      - Report/Layout        → UTF-16LE, no BOM  (JSON)
      - Report/StaticResources/SharedResources/BaseThemes/CY26SU02.json → UTF-8
    """
    # ── CY26SU02 base theme — embedded so PBI uses it regardless of install ──
    # The dataColors list is replaced with the Tableau workbook palette so that
    # PBI applies Tableau colors as its series defaults instead of the Office
    # blue palette (#118DFF, #12239E, …) which overrides our dataPoint entries.
    _CY26SU02_BASE = {"name":"CY26SU02","dataColors":["#118DFF","#12239E","#E66C37","#6B007B","#E044A7","#744EC2","#D9B300","#D64550","#197278","#1AAB40","#15C6F4","#4092FF","#FFA058","#BE5DC9","#F472D0","#B5A1FF","#C4A200","#FF8080","#00DBBC","#5BD667","#0091D5","#4668C5","#FF6300","#99008A","#EC008C","#533285","#99700A","#FF4141","#1F9A85","#25891C","#0057A2","#002050","#C94F0F","#450F54","#B60064","#34124F","#6A5A29","#1AAB40","#BA141A","#0C3D37","#0B511F"],"foreground":"#252423","foregroundNeutralSecondary":"#605E5C","foregroundNeutralTertiary":"#B3B0AD","background":"#FFFFFF","backgroundLight":"#F3F2F1","backgroundNeutral":"#C8C6C4","tableAccent":"#118DFF","good":"#1AAB40","neutral":"#D9B300","bad":"#D64554","maximum":"#118DFF","center":"#D9B300","minimum":"#DEEFFF","null":"#FF7F48","hyperlink":"#0078d4","visitedHyperlink":"#0078d4","textClasses":{"callout":{"fontSize":45,"fontFace":"DIN","color":{"inherited":True}},"title":{"fontSize":12,"fontFace":"DIN","color":{"inherited":True}},"header":{"fontSize":12,"fontFace":"Segoe UI","color":{"inherited":True}},"label":{"fontSize":10,"fontFace":"Segoe UI","color":{"inherited":True}}},"visualStyles":{"*":{"*":{"*":[{"properties":{"fontSize":{"value":10},"fontFamily":{"value":"Segoe UI"}}}],"background":[{"properties":{"show":{"value":False}}}],"plotArea":[{"properties":{"transparency":{"value":0}}}]}}}}

    # Replace dataColors with the Tableau workbook palette, padded to ≥ 10 entries
    _TABLEAU_10 = ['#4e79a7','#f28e2b','#59a14f','#e15759',
                   '#76b7b2','#edc948','#b07aa1','#ff9da7','#9c755f','#bab0ac']
    wb_palette = workbook.get('data_colors') or _TABLEAU_10
    # Pad to at least 10 entries cycling the palette
    while len(wb_palette) < 10:
        wb_palette = wb_palette + wb_palette
    theme_json = {**_CY26SU02_BASE, 'dataColors': wb_palette}
    theme_bytes = json.dumps(theme_json, separators=(',', ':')).encode('utf-8')

    THEME_PATH = 'Report/StaticResources/SharedResources/BaseThemes/CY26SU02.json'

    content_types = (
        '<?xml version="1.0" encoding="utf-8"?>'
        '<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">'
        '<Default Extension="json" ContentType=""/>'
        '<Default Extension="xml" ContentType="application/vnd.openxmlformats-officedocument.custom-properties+xml"/>'
        '<Override PartName="/Version" ContentType=""/>'
        '<Override PartName="/DataModelSchema" ContentType=""/>'
        '<Override PartName="/DiagramLayout" ContentType=""/>'
        '<Override PartName="/Report/Layout" ContentType=""/>'
        '<Override PartName="/Settings" ContentType="application/json"/>'
        '<Override PartName="/Metadata" ContentType="application/json"/>'
        f'<Override PartName="/{THEME_PATH}" ContentType="application/json"/>'
        '</Types>'
    )

    version_str = "1.21"

    metadata = _jstr({
        "Version": 5,
        "AutoCreatedRelationships": [],
        "CreatedFrom": "Tableau Migration Utility",
        "CreatedFromRelease": "2024.04"
    })

    settings = _jstr({
        "Version": 4,
        "ReportSettings": {},
        "QueriesSettings": {
            "TypeDetectionEnabled": True,
            "RelationshipImportEnabled": True,
            "Version": "2.128.952.0"
        }
    })

    # Auto-embed data if the workbook came from a .twbx with extracted data.
    # EXCEPTION: if ANY datasource has a live database connection (Snowflake,
    # SQL Server, Databricks, etc.) we should NOT switch to embedded mode —
    # the embedded Hyper in a .twbx is just a local cache of the live data.
    # Switching to embedded mode would hide the real connection from PBI and
    # make "Data source settings" show "No data sources found".
    _extracted = extracted_data or workbook.get('extracted_data', {})
    if _extracted.get('has_data') and not embed_sample_data:
        _has_live_db = any(
            _LIVE_DB_BUILDERS.get(
                ds.get('connection', {}).get('class', '').lower()
            ) is not None
            for ds in workbook.get('datasources', [])
        )
        if not _has_live_db:
            embed_sample_data = True
    schema = build_data_model_schema(workbook, embed_sample_data=embed_sample_data,
                                     extracted_data=_extracted)
    layout = build_report_layout(workbook)
    diagram = build_diagram_layout(workbook)

    # ── Write audit reports alongside the .pbit ───────────────────────────────
    _audit_obj = workbook.get('_migration_audit')
    if _audit_obj is not None:
        try:
            _audit_obj.set_worksheet_scores(_compute_worksheet_quality_scores(workbook, _audit_obj))
        except Exception as _se:
            log('warn', f'[Audit] Failed to compute per-worksheet quality scores: {_se}')
        try:
            _audit_obj.set_dashboard_actions(workbook.get('dashboard_actions', []))
        except Exception as _dae:
            log('warn', f'[Audit] Failed to attach dashboard actions: {_dae}')
        try:
            _audit_obj.set_story_notes(workbook.get('_story_notes', []))
        except Exception as _sne:
            log('warn', f'[Audit] Failed to attach story notes: {_sne}')
        try:
            _audit_obj.write(output_path.parent)
        except Exception as _ae:
            log('warn', f'[Audit] Failed to write audit reports: {_ae}')

    import tempfile, os as _os

    tmp_fd, tmp_path = tempfile.mkstemp(suffix='.pbit.tmp', dir=output_path.parent)
    try:
        _os.close(tmp_fd)
        with zipfile.ZipFile(tmp_path, 'w', zipfile.ZIP_DEFLATED) as zf:
            zf.writestr('[Content_Types].xml', content_types.encode('utf-8'))
            zf.writestr('Version',             version_str.encode('utf-16-le'))
            zf.writestr('Metadata',            metadata.encode('utf-16-le'))
            zf.writestr('Settings',            settings.encode('utf-16-le'))
            zf.writestr('DataModelSchema',     _sanitise_json(_jstr(schema)).encode('utf-16-le'))
            zf.writestr('DiagramLayout',       _sanitise_json(_jstr(diagram)).encode('utf-16-le'))
            zf.writestr('Report/Layout',       _sanitise_json(_jstr(layout)).encode('utf-16-le'))
            zf.writestr(THEME_PATH,            theme_bytes)

        try:
            _os.replace(tmp_path, output_path)
        except PermissionError:
            print(f"[DEBUG except] line ~11174: exception caught")
            raise PermissionError(
                f"Cannot overwrite '{output_path.name}' — close it in "
                f"Power BI Desktop first, then retry."
            )
    except Exception:
        print(f"[DEBUG except] line ~11179: exception caught")
        try:
            _os.unlink(tmp_path)
        except OSError:
            print(f"[DEBUG except] line ~11182: exception caught")
            pass
        raise


# ─────────────────────────────────────────────────────────────────────────────
# Workbook Analysis Engine
# ─────────────────────────────────────────────────────────────────────────────

def analyze_workbook(twb_path: Path) -> dict:
    """
    Extract comprehensive analysis data from a Tableau workbook (.twb/.twbx).
    Returns a structured dict covering sheets, datasources, visualizations,
    calculations, aggregations, and connection details.
    """
    import re as _re

    # ── Load TWB XML ──────────────────────────────────────────────────────────
    if twb_path.suffix.lower() == '.twbx':
        with zipfile.ZipFile(twb_path) as z:
            twb_name = next(n for n in z.namelist() if n.endswith('.twb'))
            raw = z.read(twb_name)
    else:
        raw = twb_path.read_bytes()
    try:
        twb_text = raw.decode('utf-8', errors='replace')
    except Exception:
        print(f"[DEBUG except] line ~11208: exception caught")
        twb_text = raw.decode('latin-1', errors='replace')

    root = ET.fromstring(twb_text)

    # ── Use parse_tableau_workbook for structured data ────────────────────────
    try:
        wb = parse_tableau_workbook(twb_path)
    except Exception:
        print(f"[DEBUG except] line ~11216: exception caught")
        wb = {'name': twb_path.stem, 'datasources': [], 'worksheets': [],
              'dashboards': [], 'data_colors': [], 'explicit_color_map': {}}

    file_size_kb = twb_path.stat().st_size // 1024

    # ── Aggregation extractor from shelf text ─────────────────────────────────
    AGG_PREFIXES = {
        'sum': 'SUM', 'cnt': 'COUNT', 'avg': 'AVERAGE', 'min': 'MIN',
        'max': 'MAX', 'pcto': 'PERCENT OF TOTAL', 'attr': 'ATTRIBUTE',
        'usr': 'USER CALC', 'median': 'MEDIAN', 'stddev': 'STDEV',
        'var': 'VARIANCE', 'countd': 'COUNT DISTINCT',
    }

    def _extract_aggs(shelf_txt, ws_name):
        """Parse aggregation tokens like sum:, cnt:, avg: from shelf text."""
        results = []
        for token in _re.findall(r'\[([^\[\]]+)\]', shelf_txt):
            for prefix, label in AGG_PREFIXES.items():
                pat = _re.match(rf'^{prefix}:(.+?)(?::(?:qk|ok|nk))?$', token, _re.I)
                if pat:
                    results.append({
                        'agg_type': label,
                        'field': pat.group(1).strip(),
                        'worksheet': ws_name,
                    })
        return results

    def _shelf_fields_list(shelf_txt):
        fields = []
        for token in _re.findall(r'\[([^\[\]]+)\]\.\[([^\[\]]+)\]', shelf_txt):
            col_ref = token[1]
            m = _re.match(
                r'^(?:none|sum|cnt|avg|min|max|attr|usr|pcto|bin):(.+?)(?::(?:nk|ok|qk))?$',
                col_ref, _re.I)
            name = m.group(1) if m else col_ref
            name = _re.sub(r':(?:nk|ok|qk)$', '', name).strip()
            if name and name not in fields:
                fields.append(name)
        return fields

    # ── Datasources ────────────────────────────────────────────────────────────
    datasources_info = []
    seen_ds_names = set()
    for ds_dict in wb.get('datasources', []):
        raw_name = ds_dict.get('raw_name', ds_dict.get('name', ''))
        if raw_name in seen_ds_names:
            continue
        seen_ds_names.add(raw_name)
        conn = ds_dict.get('connection', {})
        cols = ds_dict.get('columns', [])
        calcs = ds_dict.get('calculations', [])

        dim_cols  = [c['name'] for c in cols if not c.get('measure') and not c.get('hidden')]
        msr_cols  = [c['name'] for c in cols if c.get('measure') and not c.get('hidden')]

        datasources_info.append({
            'name':          raw_name,
            'caption':       ds_dict.get('name', raw_name),
            'conn_class':    conn.get('class', 'unknown'),
            'server':        conn.get('server', ''),
            'database':      conn.get('dbname', ''),
            'schema':        conn.get('schema', ''),
            'table':         conn.get('db_table', ''),
            'http_path':     conn.get('v-http-path', ''),
            'username':      conn.get('username', ''),
            'filename':      conn.get('filename', ''),
            'custom_sql':    conn.get('custom_sql', ''),
            'total_cols':    len(dim_cols) + len(msr_cols),
            'dim_cols':      len(dim_cols),
            'msr_cols':      len(msr_cols),
            'col_names':     dim_cols + msr_cols,
            'calculations':  [{'name': c.get('name',''), 'formula': c.get('formula','')}
                              for c in calcs],
        })

    # ── Worksheets ─────────────────────────────────────────────────────────────
    worksheets_info = []
    all_aggs = []
    all_calcs = []
    viz_type_counts: dict = {}

    for ws_el in root.findall('.//worksheet'):
        ws_name = ws_el.get('name', '')
        rows_el = ws_el.find('.//rows')
        cols_el = ws_el.find('.//cols')
        rows_txt = (rows_el.text or '') if rows_el is not None else ''
        cols_txt = (cols_el.text or '') if cols_el is not None else ''

        row_fields = _shelf_fields_list(rows_txt)
        col_fields = _shelf_fields_list(cols_txt)

        # Aggregations from shelves
        all_aggs.extend(_extract_aggs(rows_txt, ws_name))
        all_aggs.extend(_extract_aggs(cols_txt, ws_name))

        # Mark / chart type from pane
        mark_classes = []
        for pane in ws_el.findall('.//pane'):
            m = pane.find('mark')
            if m is not None:
                mc = m.get('class', 'Automatic')
                if mc not in mark_classes:
                    mark_classes.append(mc)

        # Encodings
        color_fields = []
        text_fields  = []
        for enc in ws_el.findall('.//pane/encodings/color'):
            cf = enc.get('column', '')
            if cf and 'Measure Names' not in cf:
                nm = _shelf_fields_list(cf)
                color_fields.extend(nm)
        for enc in ws_el.findall('.//pane/encodings/text'):
            tf = enc.get('column', '')
            if tf:
                nm = _shelf_fields_list(tf)
                text_fields.extend(nm)

        # Filters
        filter_fields = []
        for flt in ws_el.findall('.//view/filter'):
            col_ref = flt.get('column', '')
            if 'Action (' not in col_ref:
                fn = _shelf_fields_list(col_ref)
                filter_fields.extend(fn)

        # Datasources referenced
        ds_refs = []
        for ds_dep in ws_el.findall('.//datasource-dependencies'):
            ds_name = ds_dep.get('datasource', '')
            if ds_name and ds_name not in ds_refs:
                ds_refs.append(ds_name)

        # Determine chart_type for the worksheet (reuse logic from wb)
        ws_from_wb = next((w for w in wb.get('worksheets', []) if w['name'] == ws_name), None)
        chart_type = ws_from_wb.get('chart_type', 'tableEx') if ws_from_wb else 'Unknown'
        viz_type_counts[chart_type] = viz_type_counts.get(chart_type, 0) + 1

        # Calculations referenced
        for ds_dep in ws_el.findall('.//datasource-dependencies'):
            for col in ds_dep.findall('column'):
                calc = col.find('calculation')
                if calc is not None:
                    formula = calc.get('formula', '')
                    col_name = col.get('caption', col.get('name', ''))
                    if formula:
                        all_calcs.append({
                            'worksheet':    ws_name,
                            'datasource':   ds_dep.get('datasource', ''),
                            'field_name':   col_name.strip('[]'),
                            'formula':      formula,
                            'datatype':     col.get('datatype', ''),
                            'role':         col.get('role', ''),
                        })

        worksheets_info.append({
            'name':          ws_name,
            'chart_type':    chart_type,
            'mark_classes':  ', '.join(mark_classes) if mark_classes else 'Automatic',
            'datasources':   ', '.join(ds_refs),
            'row_fields':    ', '.join(row_fields),
            'col_fields':    ', '.join(col_fields),
            'color_fields':  ', '.join(color_fields),
            'text_fields':   ', '.join(text_fields),
            'filter_fields': ', '.join(filter_fields),
            'pane_count':    len(ws_el.findall('.//pane')),
        })

    # ── Dashboards ─────────────────────────────────────────────────────────────
    dashboards_info = []
    for dash in root.findall('.//dashboard'):
        dash_name = dash.get('name', '')
        zones = dash.findall('.//zone[@name]')
        sheets_in_dash = [z.get('name','') for z in zones if _zone_type(z) not in ('layout-flow','',None)]
        dashboards_info.append({
            'name':   dash_name,
            'sheets': ', '.join(s for s in sheets_in_dash if s),
        })

    # ── De-dup calculations (collapse ds-dep duplicates) ─────────────────────
    seen_calc = set()
    calcs_dedup = []
    for c in all_calcs:
        key = (c['field_name'], c['formula'])
        if key not in seen_calc:
            seen_calc.add(key)
            calcs_dedup.append(c)

    # ── Connection type summary ────────────────────────────────────────────────
    conn_types = list({d['conn_class'] for d in datasources_info if d['conn_class']})

    return {
        'workbook_name':   wb.get('name', twb_path.stem),
        'file_path':       str(twb_path),
        'file_name':       twb_path.name,
        'file_size_kb':    file_size_kb,
        'analyzed_at':     datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
        'source_platform': root.get('source-platform', 'unknown'),
        'source_build':    root.get('source-build', ''),
        'summary': {
            'total_worksheets':  len(worksheets_info),
            'total_dashboards':  len(dashboards_info),
            'total_datasources': len(datasources_info),
            'total_calculations':len(calcs_dedup),
            'total_aggregations':len(all_aggs),
            'connection_types':  conn_types,
            'viz_type_counts':   viz_type_counts,
        },
        'worksheets':   worksheets_info,
        'dashboards':   dashboards_info,
        'datasources':  datasources_info,
        'calculations': calcs_dedup,
        'aggregations': all_aggs,
    }


def write_analysis_excel(analysis: dict, output_path: Path):
    """
    Write a comprehensive Tableau workbook analysis to an Excel file.
    Uses professional formatting with YASH brand colors.
    """
    try:
        from openpyxl import Workbook as _Workbook
        from openpyxl.styles import (Font as _Font, PatternFill as _Fill,
                                     Alignment as _Align, Border as _Border,
                                     Side as _Side)
        from openpyxl.utils import get_column_letter as _gcl
    except ImportError as _e:
        print(f"[DEBUG except] line ~11444: {_e}")
        raise RuntimeError(
            f"openpyxl could not be imported ({_e}). "
            "Try restarting the server so it can install automatically."
        ) from _e

    # ── Brand colours ─────────────────────────────────────────────────────────
    C_BLUE    = '005BA1'   # YASH blue
    C_GOLD    = 'A89044'   # YASH gold
    C_LBLUE   = 'D6E8F7'   # light blue header bg
    C_LGOLD   = 'F5EFD8'   # light gold alt row
    C_WHITE   = 'FFFFFF'
    C_DKTEXT  = '1A1D27'

    def _hfont(bold=True, size=11, color=C_WHITE):
        return _Font(name='Calibri', bold=bold, size=size, color=color)

    def _bfont(bold=False, size=10, color=C_DKTEXT):
        return _Font(name='Calibri', bold=bold, size=size, color=color)

    def _hfill(color=C_BLUE):
        return _Fill('solid', fgColor=color)

    def _afill(color=C_LBLUE):
        return _Fill('solid', fgColor=color)

    def _alt_fill():
        return _Fill('solid', fgColor='F0F4FA')

    def _border():
        s = _Side(style='thin', color='D4D8E8')
        return _Border(left=s, right=s, top=s, bottom=s)

    def _center():
        return _Align(horizontal='center', vertical='center', wrap_text=True)

    def _left():
        return _Align(horizontal='left', vertical='center', wrap_text=True)

    def _style_header(cell, color=C_BLUE, font_color=C_WHITE, size=11):
        cell.font      = _hfont(bold=True, size=size, color=font_color)
        cell.fill      = _hfill(color)
        cell.alignment = _center()
        cell.border    = _border()

    def _style_body(cell, alt=False):
        cell.font      = _bfont()
        cell.fill      = _alt_fill() if alt else _Fill('solid', fgColor=C_WHITE)
        cell.alignment = _left()
        cell.border    = _border()

    def _autofit(ws, min_w=10, max_w=55):
        for col in ws.columns:
            max_len = 0
            col_letter = _gcl(col[0].column)
            for cell in col:
                try:
                    if cell.value:
                        max_len = max(max_len, len(str(cell.value)))
                except Exception:
                    print(f"[DEBUG except] line ~11503: exception caught")
                    pass
            ws.column_dimensions[col_letter].width = max(min_w, min(max_len + 3, max_w))

    def _write_table(ws, headers, rows, start_row=1, header_color=C_BLUE, font_color=C_WHITE):
        for ci, h in enumerate(headers, 1):
            cell = ws.cell(row=start_row, column=ci, value=h)
            _style_header(cell, color=header_color, font_color=font_color)
        for ri, row in enumerate(rows, start_row + 1):
            alt = (ri - start_row) % 2 == 0
            for ci, val in enumerate(row, 1):
                cell = ws.cell(row=ri, column=ci, value=val)
                _style_body(cell, alt)
        ws.freeze_panes = ws.cell(row=start_row + 1, column=1)
        return start_row + len(rows) + 1

    wb_xl = _Workbook()
    wb_xl.remove(wb_xl.active)   # remove default sheet

    s = analysis['summary']
    name = analysis['workbook_name']

    # ──────────────────────────────────────────────────────────────────────────
    # Sheet 1 — Summary
    # ──────────────────────────────────────────────────────────────────────────
    ws1 = wb_xl.create_sheet('Summary')
    ws1.sheet_view.showGridLines = False
    ws1.column_dimensions['A'].width = 36
    ws1.column_dimensions['B'].width = 42

    # Title block
    ws1.row_dimensions[1].height = 36
    c = ws1.cell(row=1, column=1, value=f'Tableau Workbook Analysis Report')
    c.font  = _Font(name='Calibri', bold=True, size=16, color=C_WHITE)
    c.fill  = _hfill(C_BLUE)
    c.alignment = _Align(horizontal='left', vertical='center', indent=1)
    ws1.merge_cells('A1:B1')

    # Workbook metadata
    meta = [
        ('Workbook Name',    name),
        ('File Name',        analysis['file_name']),
        ('File Path',        analysis['file_path']),
        ('File Size',        f"{analysis['file_size_kb']} KB"),
        ('Source Platform',  analysis['source_platform']),
        ('Source Build',     analysis['source_build']),
        ('Analyzed At',      analysis['analyzed_at']),
    ]
    for ri, (k, v) in enumerate(meta, 2):
        kc = ws1.cell(row=ri, column=1, value=k)
        kc.font      = _Font(name='Calibri', bold=True, size=10, color=C_DKTEXT)
        kc.fill      = _hfill(C_LBLUE)
        kc.alignment = _left()
        kc.border    = _border()
        vc = ws1.cell(row=ri, column=2, value=v)
        vc.font      = _bfont()
        vc.alignment = _left()
        vc.border    = _border()

    # Summary counts
    blank_row = len(meta) + 3
    ws1.cell(row=blank_row, column=1, value='Key Metrics').font = _Font(
        name='Calibri', bold=True, size=12, color=C_BLUE)
    ws1.merge_cells(f'A{blank_row}:B{blank_row}')

    metrics = [
        ('Total Worksheets / Pages',    s['total_worksheets']),
        ('Total Dashboards',            s['total_dashboards']),
        ('Total Data Sources',          s['total_datasources']),
        ('Total Calculated Fields',     s['total_calculations']),
        ('Total Aggregation Uses',      s['total_aggregations']),
        ('Connection Types Used',       ', '.join(s['connection_types']) or 'N/A'),
    ]
    for ri, (k, v) in enumerate(metrics, blank_row + 1):
        alt = ri % 2 == 0
        kc = ws1.cell(row=ri, column=1, value=k)
        kc.font      = _Font(name='Calibri', bold=True, size=10, color=C_DKTEXT)
        kc.fill      = _alt_fill() if alt else _Fill('solid', fgColor=C_WHITE)
        kc.alignment = _left()
        kc.border    = _border()
        vc = ws1.cell(row=ri, column=2, value=v)
        vc.font      = _bfont()
        vc.fill      = _alt_fill() if alt else _Fill('solid', fgColor=C_WHITE)
        vc.alignment = _left()
        vc.border    = _border()

    # Visualization type breakdown
    viz_start = blank_row + len(metrics) + 2
    ws1.cell(row=viz_start, column=1, value='Visualization Types Used').font = _Font(
        name='Calibri', bold=True, size=12, color=C_BLUE)
    ws1.merge_cells(f'A{viz_start}:B{viz_start}')

    VIZ_LABELS = {
        'clusteredColumnChart':             'Clustered Column Chart',
        'columnChart':               'Stacked Column Chart',
        'hundredPercentStackedColumnChart': '100% Stacked Column Chart',
        'clusteredBarChart':                'Clustered Bar Chart',
        'barChart':                   'Stacked Bar Chart',
        'hundredPercentStackedBarChart':    '100% Stacked Bar Chart',
        'lineChart':                        'Line Chart',
        'areaChart':                        'Area Chart',
        'scatterChart':                     'Scatter Chart',
        'pieChart':                         'Pie Chart',
        'donutChart':                       'Donut Chart',
        'tableEx':                          'Table / Crosstab',
        'card':                             'KPI Card',
        'lineClusteredColumnComboChart':    'Combo Chart (Line + Column)',
    }
    for ri, (vtype, cnt) in enumerate(s['viz_type_counts'].items(), viz_start + 1):
        alt = ri % 2 == 0
        lbl = VIZ_LABELS.get(vtype, vtype)
        kc = ws1.cell(row=ri, column=1, value=lbl)
        kc.font = _Font(name='Calibri', size=10, color=C_DKTEXT)
        kc.fill = _alt_fill() if alt else _Fill('solid', fgColor=C_WHITE)
        kc.alignment = _left(); kc.border = _border()
        vc = ws1.cell(row=ri, column=2, value=cnt)
        vc.font = _Font(name='Calibri', bold=True, size=10, color=C_BLUE)
        vc.fill = _alt_fill() if alt else _Fill('solid', fgColor=C_WHITE)
        vc.alignment = _center(); vc.border = _border()

    # ──────────────────────────────────────────────────────────────────────────
    # Sheet 2 — Worksheets & Pages
    # ──────────────────────────────────────────────────────────────────────────
    ws2 = wb_xl.create_sheet('Worksheets & Pages')
    ws2.sheet_view.showGridLines = False
    headers2 = ['Sheet Name', 'Chart Type (PBI)', 'Mark Class (Tableau)',
                 'Data Sources', 'Row / Category Fields', 'Column / X-Axis Fields',
                 'Color / Series Fields', 'Text / Measure Fields',
                 'Filter Fields', 'Pane Count']
    rows2 = []
    for w in analysis['worksheets']:
        rows2.append([
            w['name'], VIZ_LABELS.get(w['chart_type'], w['chart_type']),
            w['mark_classes'], w['datasources'], w['row_fields'],
            w['col_fields'], w['color_fields'], w['text_fields'],
            w['filter_fields'], w['pane_count'],
        ])
    _write_table(ws2, headers2, rows2, header_color=C_BLUE)
    _autofit(ws2)

    # ──────────────────────────────────────────────────────────────────────────
    # Sheet 3 — Data Sources & Connections
    # ──────────────────────────────────────────────────────────────────────────
    ws3 = wb_xl.create_sheet('Data Sources & Connections')
    ws3.sheet_view.showGridLines = False
    headers3 = ['Datasource Caption', 'Connection Type', 'Server / Host',
                 'Database / Catalog', 'Schema', 'Table', 'HTTP Path',
                 'Username', 'File Name', 'Has Custom SQL',
                 'Total Columns', 'Dimension Cols', 'Measure Cols',
                 'All Column Names']
    rows3 = []
    for d in analysis['datasources']:
        rows3.append([
            d['caption'], d['conn_class'], d['server'], d['database'],
            d['schema'], d['table'], d['http_path'], d['username'],
            d['filename'], 'Yes' if d['custom_sql'] else 'No',
            d['total_cols'], d['dim_cols'], d['msr_cols'],
            ', '.join(d['col_names']),
        ])
    _write_table(ws3, headers3, rows3, header_color=C_GOLD, font_color=C_DKTEXT)
    _autofit(ws3)

    # ──────────────────────────────────────────────────────────────────────────
    # Sheet 4 — Dashboards
    # ──────────────────────────────────────────────────────────────────────────
    ws4 = wb_xl.create_sheet('Dashboards')
    ws4.sheet_view.showGridLines = False
    headers4 = ['Dashboard Name', 'Sheets / Zones Included']
    rows4 = [[d['name'], d['sheets']] for d in analysis['dashboards']]
    if not rows4:
        rows4 = [['(No dashboards found)', '']]
    _write_table(ws4, headers4, rows4, header_color=C_BLUE)
    _autofit(ws4)

    # ──────────────────────────────────────────────────────────────────────────
    # Sheet 5 — Calculations & Expressions
    # ──────────────────────────────────────────────────────────────────────────
    ws5 = wb_xl.create_sheet('Calculations & Expressions')
    ws5.sheet_view.showGridLines = False
    headers5 = ['Field / Calc Name', 'Formula / Expression',
                 'Data Type', 'Role', 'Datasource', 'First Used In']
    rows5 = []
    for c in analysis['calculations']:
        rows5.append([
            c['field_name'], c['formula'],
            c['datatype'], c['role'], c['datasource'], c['worksheet'],
        ])
    if not rows5:
        rows5 = [['(No calculations found)', '', '', '', '', '']]
    _write_table(ws5, headers5, rows5, header_color=C_BLUE)
    # Make formula column wider
    ws5.column_dimensions['B'].width = 60
    _autofit(ws5, min_w=10, max_w=40)
    ws5.column_dimensions['B'].width = 60

    # ──────────────────────────────────────────────────────────────────────────
    # Sheet 6 — Aggregations
    # ──────────────────────────────────────────────────────────────────────────
    ws6 = wb_xl.create_sheet('Aggregations')
    ws6.sheet_view.showGridLines = False
    headers6 = ['Aggregation Type', 'Field Name', 'Used In Worksheet']
    rows6 = [[a['agg_type'], a['field'], a['worksheet']] for a in analysis['aggregations']]
    if not rows6:
        rows6 = [['(No explicit aggregations found)', '', '']]
    _write_table(ws6, headers6, rows6, header_color=C_GOLD, font_color=C_DKTEXT)
    _autofit(ws6)

    # ──────────────────────────────────────────────────────────────────────────
    # Sheet 7 — All Columns per Datasource
    # ──────────────────────────────────────────────────────────────────────────
    ws7 = wb_xl.create_sheet('Column Reference')
    ws7.sheet_view.showGridLines = False
    headers7 = ['Datasource', 'Column Name', 'Calculated Formula']
    rows7 = []
    for d in analysis['datasources']:
        for col in d['col_names']:
            rows7.append([d['caption'], col, ''])
        for calc in d['calculations']:
            rows7.append([d['caption'], calc['name'], calc['formula']])
    if not rows7:
        rows7 = [['(No columns found)', '', '']]
    _write_table(ws7, headers7, rows7, header_color=C_BLUE)
    _autofit(ws7)

    # ── Tab colors ─────────────────────────────────────────────────────────────
    for ws, color in [(ws1, C_BLUE), (ws2, C_BLUE), (ws3, C_GOLD),
                      (ws4, C_BLUE), (ws5, C_GOLD), (ws6, C_GOLD), (ws7, C_BLUE)]:
        ws.sheet_properties.tabColor = color

    wb_xl.save(output_path)


# ─────────────────────────────────────────────────────────────────────────────
# Conversion worker
# ─────────────────────────────────────────────────────────────────────────────

def _update_job(filename: str, status: str, message: str):
    now = datetime.now().strftime("%H:%M:%S")
    if filename not in conversion_state["jobs"]:
        conversion_state["jobs"][filename] = {"started": now}
    job = conversion_state["jobs"][filename]
    job["status"] = status
    job["message"] = message
    if status in ("done", "error"):
        job["finished"] = now
    broadcast("job_update", {"filename": filename, "status": status,
                              "message": message, "ts": now})


def analyze_file(twb_path: Path, target_dir: Path):
    """
    Analyze a Tableau workbook and write the Excel analysis report.

    Output is always placed in:  target_dir / "analysis" / <stem>_analysis.xlsx
    The subfolder is created automatically if it does not exist.
    """
    filename  = twb_path.name
    # All analysis Excel files go into a dedicated "analysis" subfolder
    # so they are cleanly separated from the generated .pbit files.
    analysis_dir = target_dir / "analysis"
    out_name     = twb_path.stem + "_analysis.xlsx"
    out_path     = analysis_dir / out_name

    try:
        _update_job(filename, "running", "Analyzing Tableau workbook…")
        log("info", f"Analyzing {filename}", filename)

        analysis = analyze_workbook(twb_path)
        s = analysis['summary']
        _update_job(filename, "running",
                    f"Extracted: {s['total_worksheets']} sheets, "
                    f"{s['total_datasources']} datasources, "
                    f"{s['total_calculations']} calculations")

        _update_job(filename, "running", f"Writing {out_name}…")
        # Create target and analysis sub-directory if they don't exist
        analysis_dir.mkdir(parents=True, exist_ok=True)
        write_analysis_excel(analysis, out_path)

        size_kb = out_path.stat().st_size // 1024
        _update_job(filename, "done",
                    f"✓ Analysis saved → analysis/{out_name} ({size_kb} KB)")
        log("info",
            f"Analysis written → {out_path} ({size_kb} KB)", filename)

    except Exception as exc:
        print(f"[DEBUG except] line ~11788: {exc}")
        tb = traceback.format_exc()
        _update_job(filename, "error", f"✗ Analysis failed: {exc}")
        log("error", f"Analysis failed: {exc}", filename)
        log("error", tb, filename)


def convert_file(twb_path: Path, target_dir: Path, embed_sample_data: bool = False):
    filename = twb_path.name
    out_name = twb_path.stem + ".pbit"
    out_path = target_dir / out_name

    try:
        _update_job(filename, "running", "Parsing Tableau workbook…")
        log("info", f"Parsing {filename}", filename)

        workbook = parse_tableau_workbook(twb_path)

        _update_job(filename, "running",
                    f"Parsed: {len(workbook['datasources'])} data source(s), "
                    f"{len(workbook['dashboards'])} dashboard(s)")
        log("info",
            f"  → {len(workbook['datasources'])} datasource(s), "
            f"{len(workbook['worksheets'])} worksheet(s)", filename)

        mode_label = " [sample data]" if embed_sample_data else ""
        _update_job(filename, "running", "Building Power BI data model…")
        _update_job(filename, "running", "Building report layout…")
        _update_job(filename, "running", f"Writing {out_name}{mode_label}…")

        target_dir.mkdir(parents=True, exist_ok=True)
        write_pbit(workbook, out_path, embed_sample_data=embed_sample_data,
                   extracted_data=workbook.get('extracted_data', {}))

        size_kb = out_path.stat().st_size // 1024
        _update_job(filename, "done", f"✓ Created {out_name}{mode_label} ({size_kb} KB)")
        log("info", f"Written {out_path} ({size_kb} KB)", filename)

    except Exception as exc:
        print(f"[DEBUG except] line ~11826: {exc}")
        tb = traceback.format_exc()
        _update_job(filename, "error", f"✗ {exc}")
        log("error", f"Conversion failed: {exc}", filename)
        log("error", tb, filename)


def process_file(twb_path: Path, target_dir: Path,
                 embed_sample_data: bool = False, mode: str = 'migrate',
                 pbix_params: dict = None):
    """
    Route a Tableau file through the selected processing mode, then
    optionally convert the resulting PBIT to PBIX.

    mode options:
      'migrate'          – Convert to PBIT only
      'analyze'          – Excel analysis report only
      'analyze_migrate'  – Both analysis report AND PBIT

    pbix_params: if supplied and has key 'method' in ('desktop','api'),
      the PBIT is passed to the appropriate converter after creation.
    """
    if mode == 'analyze':
        analyze_file(twb_path, target_dir)
        return   # no PBIT produced, nothing to convert

    if mode == 'analyze_migrate':
        analyze_file(twb_path, target_dir)

    # Generate the PBIT
    convert_file(twb_path, target_dir, embed_sample_data)

    # Optionally convert PBIT → PBIX immediately after
    if pbix_params and pbix_params.get('method') not in (None, '', 'none'):
        pbit_path = target_dir / (twb_path.stem + ".pbit")
        method = pbix_params['method']
        if pbit_path.exists():
            if method == 'desktop':
                _pbix_via_desktop(
                    pbit_path, target_dir,
                    pbi_exe  = pbix_params.get('pbi_exe', ''),
                    timeout  = int(pbix_params.get('timeout', 90)),
                )
            elif method == 'api':
                _pbix_via_api(
                    pbit_path, target_dir,
                    tenant_id     = pbix_params.get('tenant_id', ''),
                    client_id     = pbix_params.get('client_id', ''),
                    client_secret = pbix_params.get('client_secret', ''),
                    workspace_id  = pbix_params.get('workspace_id', ''),
                )
        else:
            log("warn", f"PBIX conversion skipped — PBIT not found: {pbit_path.name}",
                twb_path.name)


def conversion_worker(source_dir: str, target_dir: str,
                      embed_sample_data: bool = False, mode: str = 'migrate',
                      pbix_params: dict = None):
    src = Path(source_dir).resolve()  # Convert to absolute path
    tgt = Path(target_dir).resolve()  # Convert to absolute path
    seen: set[str] = set()

    log("info", f"Watching {src}  →  {tgt}  [mode: {mode}]")
    broadcast("status", {"running": True, "source": str(src), "target": str(tgt)})

    while conversion_state["running"]:
        try:
            twb_files = list(src.glob("*.twb")) + list(src.glob("*.twbx"))
            for twb in twb_files:
                key = f"{twb.name}:{twb.stat().st_mtime}"
                if key not in seen:
                    seen.add(key)
                    threading.Thread(
                        target=process_file,
                        args=(twb, tgt, embed_sample_data, mode, pbix_params),
                        daemon=True
                    ).start()
        except Exception as e:
            log("error", f"Watcher error: {e}")
        time.sleep(2)

    broadcast("status", {"running": False})
    log("info", "Watcher stopped.")


# ─────────────────────────────────────────────────────────────────────────────
# PBIT → PBIX conversion helpers
# ─────────────────────────────────────────────────────────────────────────────

# Common job-key pattern for pbix conversions: "<stem>.pbit::pbix"
def _pbix_job_key(pbit_path: Path) -> str:
    return f"{pbit_path.name}::pbix"


def _pbix_via_desktop(pbit_path: Path, output_dir: Path,
                      pbi_exe: str = '', timeout: int = 90):
    """
    Convert a .pbit -> .pbix using three strategies in order:

    Strategy A (no PBI needed): A .pbit is a ZIP archive. A .pbix is the
    same ZIP with the extension changed. When the template has no bound
    parameters this is a 100% valid .pbix that PBI Desktop opens directly.
    We always try this first because it is instant and needs no UI automation.

    Strategy B (pywinauto UI automation): Opens PBI Desktop, waits for the
    report to load, triggers File -> Save As via F12, waits for the native
    Windows Save-As dialog (#32770) to appear, pastes the absolute output
    path via the clipboard, and confirms with a single Enter.

    Strategy C (blind win32api keystrokes): Fallback when pywinauto is
    unavailable. Uses raw win32api keybd_event calls with timed delays.

    Requires (for B/C only):
      - Windows OS
      - Power BI Desktop (installer edition, not Store)
    """
    job_key  = _pbix_job_key(pbit_path)
    out_pbix = output_dir / (pbit_path.stem + ".pbix")
    proc     = None   # always defined so finally-block is safe

    def _upd(status, msg):
        _update_job(job_key, status, msg)

    def _success(pbix: Path):
        size_kb = pbix.stat().st_size // 1024
        _upd("done", f"✓ {pbix.name} ({size_kb} KB)")
        log("info", f"[Desktop] ✓ Success -> {pbix.name} ({size_kb} KB)", job_key)

    def _find_any_pbix():
        hits = list(output_dir.glob("*.pbix"))
        return hits[0] if hits else None

    def _install_pkg(pkg_name, import_name):
        try:
            __import__(import_name)
            return None
        except ImportError:
            print(f"[DEBUG except] line ~11963: exception caught")
            pass
        log("info", f"[Desktop] Installing {pkg_name}...", job_key)
        import subprocess as _sp
        r = _sp.run([sys.executable, "-m", "pip", "install", pkg_name, "--quiet"],
                    capture_output=True, text=True)
        if r.returncode != 0:
            return (f"{pkg_name} install failed: {r.stderr.strip() or r.stdout.strip()}\n"
                    f"Run: pip install {pkg_name}")
        try:
            __import__(import_name)
            return None
        except ImportError as e:
            print(f"[DEBUG except] line ~11975: {e}")
            return f"{pkg_name} installed but unimportable: {e}"

    def _clip_paste(text):
        import subprocess as _sp
        p = _sp.Popen(["clip"], stdin=_sp.PIPE, stderr=_sp.PIPE)
        p.communicate(input=text.encode("utf-8"))
        p.wait(timeout=3)

    try:
        log("info", f"[Desktop] Converting {pbit_path.name} -> .pbix", job_key)
        output_dir.mkdir(parents=True, exist_ok=True)
        abs_pbix = out_pbix.resolve()
        path_str = str(abs_pbix)

        # ================================================================
        # STRATEGY A — Pure-Python ZIP copy (no PBI Desktop required)
        # ================================================================
        # A .pbit and a .pbix are both ZIP archives with identical internal
        # structure. The only practical difference is that .pbix may contain
        # a 'SecurityBindings' entry. Copying the ZIP and adding that entry
        # produces a fully valid .pbix that PBI Desktop opens without issues.
        # ================================================================
        _upd("running", "Strategy A: ZIP-copy .pbit -> .pbix...")
        log("info", "[Desktop][A] Attempting ZIP-copy strategy", job_key)

        import zipfile

        pbit_is_zip = False
        try:
            with zipfile.ZipFile(pbit_path, "r") as z:
                names = z.namelist()
                pbit_is_zip = True
                log("info", f"[Desktop][A] PBIT ZIP entries: {names}", job_key)
        except Exception as ze:
            log("warn", f"[Desktop][A] PBIT is not a valid ZIP: {ze}", job_key)

        if pbit_is_zip:
            try:
                tmp_pbix = abs_pbix.with_suffix(".pbix.tmp")
                with zipfile.ZipFile(pbit_path, "r") as src, \
                     zipfile.ZipFile(tmp_pbix, "w",
                                     compression=zipfile.ZIP_DEFLATED) as dst:
                    for item in src.infolist():
                        dst.writestr(item, src.read(item.filename))
                    # Add SecurityBindings if absent (required by PBI spec)
                    if "SecurityBindings" not in src.namelist():
                        dst.writestr("SecurityBindings", b"")
                tmp_pbix.replace(abs_pbix)
                log("info", "[Desktop][A] ZIP-copy succeeded", job_key)
                _success(abs_pbix)
                return   # done — no PBI Desktop needed
            except Exception as copy_err:
                log("warn",
                    f"[Desktop][A] ZIP-copy failed: {copy_err} — trying UI automation",
                    job_key)
                try:
                    abs_pbix.unlink(missing_ok=True)
                except Exception:
                    print(f"[DEBUG except] line ~12033: exception caught")
                    pass

        # ================================================================
        # STRATEGY B — pywinauto UI automation (Save As dialog)
        # ================================================================
        _upd("running", "Strategy B: UI automation via pywinauto...")
        log("info", "[Desktop][B] Installing dependencies...", job_key)

        _skip_b = False
        err = _install_pkg("pywin32", "win32api")
        if err:
            log("warn", f"[Desktop][B] pywin32 unavailable: {err}", job_key)
            _skip_b = True

        if not _skip_b:
            err = _install_pkg("pywinauto", "pywinauto")
            if err:
                log("warn", f"[Desktop][B] pywinauto unavailable: {err}", job_key)
                _skip_b = True

        if not _skip_b:
            log("info", "[Desktop][B] pywin32 + pywinauto OK", job_key)

            from pywinauto.application import Application
            from pywinauto.keyboard import send_keys

            # Locate PBI Desktop exe
            if not pbi_exe:
                for c in [
                    r"C:\Program Files\Microsoft Power BI Desktop\bin\PBIDesktop.exe",
                    r"C:\Program Files (x86)\Microsoft Power BI Desktop\bin\PBIDesktop.exe",
                ]:
                    if Path(c).exists():
                        pbi_exe = c
                        break
            if not pbi_exe or not Path(pbi_exe).exists():
                raise FileNotFoundError(
                    "Power BI Desktop not found. Enter the path to PBIDesktop.exe "
                    "in the 'PBI Desktop Path' field."
                )

            # Launch
            _upd("running", "Launching Power BI Desktop...")
            log("info", f"[Desktop][B] Launching: {pbi_exe}", job_key)
            import subprocess
            proc = subprocess.Popen([pbi_exe, str(pbit_path)])

            # Connect pywinauto
            app = Application(backend="uia")
            deadline = time.time() + timeout
            while time.time() < deadline:
                try:
                    app.connect(process=proc.pid)
                    break
                except Exception:
                    print(f"[DEBUG except] line ~12088: exception caught")
                    time.sleep(2)
            else:
                raise TimeoutError(f"PBI Desktop did not start within {timeout}s.")

            # Dismiss startup dialogs
            _upd("running", "Dismissing startup dialogs...")
            time.sleep(5)
            for _ in range(6):
                try:
                    send_keys("{ESC}")
                except Exception:
                    print(f"[DEBUG except] line ~12099: exception caught")
                    pass
                time.sleep(0.4)

            # Wait for title bar to lose "Loading"
            _upd("running", "Waiting for report to load...")
            main_win   = None
            load_dl    = time.time() + timeout
            while time.time() < load_dl:
                try:
                    for w in app.windows():
                        t = w.window_text()
                        if "Power BI Desktop" in t and "Loading" not in t:
                            main_win = w
                            break
                    if main_win:
                        break
                except Exception:
                    print(f"[DEBUG except] line ~12116: exception caught")
                    pass
                time.sleep(2)

            if main_win is None:
                try:
                    main_win = app.top_window()
                except Exception:
                    print(f"[DEBUG except] line ~12123: exception caught")
                    pass

            time.sleep(3)

            # Open Save As — try F12 first, then Alt+F->A
            # CRITICAL: send ONE shortcut, wait for dialog, then stop.
            # Firing both shortcuts unconditionally opens the dialog with
            # the first, then the second sends keys INTO the open dialog
            # and corrupts or closes it — so the file is never written.
            _upd("running", "Opening Save As dialog...")
            save_dlg = None

            for shortcut_label, keys_seq in [
                ("F12",          ["{F12}"]),
                ("Alt+F then A", ["%f", "a"]),
            ]:
                try:
                    if main_win:
                        main_win.set_focus()
                    time.sleep(0.4)
                    send_keys(keys_seq[0])
                    if len(keys_seq) > 1:
                        time.sleep(0.7)
                        send_keys(keys_seq[1])
                    log("info", f"[Desktop][B] Sent {shortcut_label}", job_key)
                except Exception as ke:
                    log("warn",
                        f"[Desktop][B] Key error ({shortcut_label}): {ke}", job_key)

                # Poll up to 5 s for native Win32 dialog class #32770
                dl = time.time() + 5
                while time.time() < dl:
                    try:
                        dlg = app.window(class_name="#32770")
                        if dlg.exists(timeout=0.5):
                            save_dlg = dlg
                            log("info",
                                f"[Desktop][B] Save As dialog confirmed ({shortcut_label})",
                                job_key)
                            break
                    except Exception:
                        print(f"[DEBUG except] line ~12164: exception caught")
                        pass
                    time.sleep(0.4)

                if save_dlg:
                    break
                log("warn",
                    f"[Desktop][B] Dialog not seen after {shortcut_label}", job_key)

            if save_dlg is None:
                log("warn",
                    "[Desktop][B] Could not confirm Save As dialog; typing blind",
                    job_key)

            time.sleep(0.8)

            # Enter path and save
            _upd("running", "Entering save path...")
            log("info", f"[Desktop][B] Target: {abs_pbix}", job_key)

            try:
                # Focus the filename Edit control if we have the dialog
                if save_dlg:
                    try:
                        fn_edit = save_dlg.child_window(control_type="Edit")
                        fn_edit.set_focus()
                        time.sleep(0.2)
                    except Exception:
                        print(f"[DEBUG except] line ~12191: exception caught")
                        pass

                send_keys("^a")
                time.sleep(0.2)
                send_keys("{DELETE}")
                time.sleep(0.2)

                # Clipboard paste — much more reliable than typing char-by-char
                # for paths with backslashes, spaces, and special characters.
                try:
                    _clip_paste(path_str)
                    time.sleep(0.4)
                    send_keys("^v")
                    time.sleep(0.6)
                    log("info", "[Desktop][B] Path pasted from clipboard", job_key)
                except Exception as ce:
                    log("warn",
                        f"[Desktop][B] Clipboard failed ({ce}), typing path",
                        job_key)
                    send_keys(path_str, with_spaces=True)
                    time.sleep(1.5)

                # Single Enter confirms the filename.
                # DO NOT send Tab before Enter — Tab moves focus to the
                # "Save as type" dropdown, so Enter then changes the format
                # instead of saving the file.
                send_keys("{ENTER}")
                log("info", "[Desktop][B] Enter sent — waiting for file...", job_key)

            except Exception as ke:
                log("warn",
                    f"[Desktop][B] Key error: {ke} — sending blind Enter", job_key)
                try:
                    send_keys("{ENTER}")
                except Exception:
                    print(f"[DEBUG except] line ~12226: exception caught")
                    pass

            # Poll for output file up to 30 s
            _upd("running", "Waiting for .pbix to be written...")
            for i in range(30):
                if abs_pbix.exists() and abs_pbix.stat().st_size > 1024:
                    _success(abs_pbix)
                    return
                log("info", f"[Desktop][B] Waiting ({i+1}/30)...", job_key)
                time.sleep(1)

            hit = _find_any_pbix()
            if hit:
                _success(hit)
                return

            log("warn",
                "[Desktop][B] File not found after 30 s — trying Strategy C",
                job_key)

        # ================================================================
        # STRATEGY C — Blind win32api keystrokes (no dialog detection)
        # ================================================================
        _upd("running", "Strategy C: blind keyboard Save As...")
        log("info", "[Desktop][C] Starting blind-keyboard save", job_key)

        # If proc is not set yet (Strategy B was skipped), launch PBI now
        if proc is None:
            if not pbi_exe:
                for c in [
                    r"C:\Program Files\Microsoft Power BI Desktop\bin\PBIDesktop.exe",
                    r"C:\Program Files (x86)\Microsoft Power BI Desktop\bin\PBIDesktop.exe",
                ]:
                    if Path(c).exists():
                        pbi_exe = c
                        break
            if not pbi_exe or not Path(pbi_exe).exists():
                raise FileNotFoundError(
                    "Power BI Desktop not found. Enter the path to PBIDesktop.exe."
                )
            import subprocess
            _upd("running", "Launching Power BI Desktop (Strategy C)...")
            proc = subprocess.Popen([pbi_exe, str(pbit_path)])
            time.sleep(timeout // 3)   # wait a generous fraction of timeout

        try:
            import win32api, win32con, win32gui  # type: ignore

            def _vk(key):
                win32api.keybd_event(key, 0, 0, 0)
                time.sleep(0.06)
                win32api.keybd_event(key, 0, win32con.KEYEVENTF_KEYUP, 0)
                time.sleep(0.12)

            # Bring PBI window to foreground
            if proc:
                hwnd_target = None
                def _enum_cb(h, _):
                    nonlocal hwnd_target
                    try:
                        import win32process
                        _, pid = win32process.GetWindowThreadProcessId(h)
                        if pid == proc.pid and win32gui.IsWindowVisible(h):
                            hwnd_target = h
                    except Exception:
                        print(f"[DEBUG except] line ~12291: exception caught")
                        pass
                win32gui.EnumWindows(_enum_cb, None)
                if hwnd_target:
                    win32gui.SetForegroundWindow(hwnd_target)
                    time.sleep(0.6)

            # F12 -> Save As
            _vk(win32con.VK_F12)
            time.sleep(3)   # wait for Save As dialog to appear

            # Paste path via clipboard
            _clip_paste(path_str)
            time.sleep(0.4)

            # Ctrl+A, Delete, Ctrl+V to enter path
            win32api.keybd_event(win32con.VK_CONTROL, 0, 0, 0)
            _vk(ord('A'))
            win32api.keybd_event(win32con.VK_CONTROL, 0, win32con.KEYEVENTF_KEYUP, 0)
            time.sleep(0.2)
            _vk(win32con.VK_DELETE)
            time.sleep(0.1)
            win32api.keybd_event(win32con.VK_CONTROL, 0, 0, 0)
            _vk(ord('V'))
            win32api.keybd_event(win32con.VK_CONTROL, 0, win32con.KEYEVENTF_KEYUP, 0)
            time.sleep(0.8)
            _vk(win32con.VK_RETURN)
            log("info", "[Desktop][C] Keys sent; waiting for file...", job_key)
            time.sleep(10)

        except Exception as c_err:
            log("warn", f"[Desktop][C] win32api failed: {c_err}", job_key)

        # Final poll
        for i in range(20):
            if abs_pbix.exists() and abs_pbix.stat().st_size > 1024:
                _success(abs_pbix)
                return
            time.sleep(1)

        hit = _find_any_pbix()
        if hit:
            _success(hit)
            return

        # All three strategies exhausted
        try:
            items = [f.name for f in output_dir.iterdir()]
        except Exception:
            print(f"[DEBUG except] line ~12339: exception caught")
            items = []
        raise RuntimeError(
            f"PBIX was not created after trying all three strategies.\n"
            f"Output folder contents: {items}\n"
            f"Verify PBI Desktop opened the PBIT without errors and that "
            f"the output path is writable:\n{abs_pbix}"
        )

    except Exception as exc:
        print(f"[DEBUG except] line ~12348: {exc}")
        tb = traceback.format_exc()
        _update_job(job_key, "error", f"✗ {exc}")
        log("error", f"[Desktop] Failed: {exc}", job_key)
        log("error", tb, job_key)
    finally:
        if proc is not None:
            try:
                if proc.poll() is None:
                    proc.terminate()
                    time.sleep(1)
                if proc.poll() is None:
                    proc.kill()
                log("info", "[Desktop] PBI Desktop process closed", job_key)
            except Exception as fe:
                log("warn", f"[Desktop] Error closing PBI Desktop: {fe}", job_key)


def _pbix_via_api(pbit_path: Path, output_dir: Path,
                  tenant_id: str, client_id: str,
                  client_secret: str, workspace_id: str):
    """
    Option 2 — Power BI REST API.

    Uploads the .pbit to a Power BI Service workspace, waits for the import
    to complete, then exports the instantiated report back as a .pbix.

    Requires:
      - Power BI Pro licence (or Premium capacity workspace)
      - Azure AD app registration with:
          API permissions: Report.ReadWrite.All, Dataset.ReadWrite.All
          Grant type: client_credentials (service principal)
    """
    job_key = _pbix_job_key(pbit_path)
    out_pbix = output_dir / (pbit_path.stem + ".pbix")

    def _upd(status, msg):
        _update_job(job_key, status, msg)

    try:
        import urllib.request as _urlreq
        import urllib.parse  as _urlparse

        _upd("running", "Authenticating with Azure AD…")
        log("info", f"[API] Converting {pbit_path.name} → .pbix via REST API", job_key)

        # ── Step 1: Get OAuth2 access token (client-credentials flow) ─────────
        token_url  = f"https://login.microsoftonline.com/{tenant_id}/oauth2/v2.0/token"
        token_body = _urlparse.urlencode({
            "grant_type":    "client_credentials",
            "client_id":     client_id,
            "client_secret": client_secret,
            "scope":         "https://analysis.windows.net/powerbi/api/.default",
        }).encode()

        req = _urlreq.Request(token_url, data=token_body,
                              headers={"Content-Type": "application/x-www-form-urlencoded"})
        with _urlreq.urlopen(req, timeout=30) as resp:
            token_data = json.loads(resp.read())

        if "access_token" not in token_data:
            err = token_data.get("error_description", token_data.get("error", "Unknown auth error"))
            raise RuntimeError(f"Authentication failed: {err}")

        token   = token_data["access_token"]
        headers = {"Authorization": f"Bearer {token}"}
        BASE    = "https://api.powerbi.com/v1.0/myorg"

        log("info", "[API] Token obtained", job_key)

        # ── Step 2: Upload PBIT to the workspace ──────────────────────────────
        _upd("running", f"Uploading {pbit_path.name} to Power BI Service…")
        log("info", f"[API] Uploading to workspace {workspace_id}", job_key)

        import_url = (
            f"{BASE}/groups/{workspace_id}/imports"
            f"?datasetDisplayName={_urlparse.quote(pbit_path.stem)}"
            f"&nameConflict=CreateOrOverwrite"
        )

        # Build a minimal multipart/form-data body manually (no extra deps)
        boundary = "PBIToolBoundary1234567890"
        pbit_bytes = pbit_path.read_bytes()
        body_parts = (
            f"--{boundary}\r\n"
            f'Content-Disposition: form-data; name="file"; filename="{pbit_path.name}"\r\n'
            f"Content-Type: application/octet-stream\r\n\r\n"
        ).encode() + pbit_bytes + f"\r\n--{boundary}--\r\n".encode()

        upload_headers = {
            **headers,
            "Content-Type": f"multipart/form-data; boundary={boundary}",
            "Content-Length": str(len(body_parts)),
        }

        req2 = _urlreq.Request(import_url, data=body_parts,
                               headers=upload_headers, method="POST")
        with _urlreq.urlopen(req2, timeout=120) as resp:
            import_resp = json.loads(resp.read())

        import_id = import_resp.get("id", "")
        if not import_id:
            raise RuntimeError(f"Upload failed — no import ID returned: {import_resp}")

        log("info", f"[API] Upload started, import ID: {import_id}", job_key)

        # ── Step 3: Poll until import completes ───────────────────────────────
        _upd("running", "Waiting for Power BI Service to process the report…")
        poll_url = f"{BASE}/groups/{workspace_id}/imports/{import_id}"
        deadline = time.time() + 300   # 5-minute timeout
        report_id = None

        while time.time() < deadline:
            req3 = _urlreq.Request(poll_url, headers=headers)
            with _urlreq.urlopen(req3, timeout=30) as resp:
                status_data = json.loads(resp.read())

            state = status_data.get("importState", "")
            log("info", f"[API] Import state: {state}", job_key)

            if state == "Succeeded":
                reports = status_data.get("reports", [])
                if reports:
                    report_id = reports[0]["id"]
                break
            elif state in ("Failed", "Cancelled"):
                raise RuntimeError(
                    f"Power BI Service import {state.lower()}. "
                    "Check that the workspace exists and your app has permission."
                )
            time.sleep(5)
        else:
            raise TimeoutError("Import did not complete within 5 minutes")

        if not report_id:
            raise RuntimeError(
                "Import succeeded but no report ID was returned. "
                "The PBIT may have been imported as a dataset without a report."
            )

        log("info", f"[API] Report created, ID: {report_id}", job_key)

        # ── Step 4: Export the report as PBIX ────────────────────────────────
        _upd("running", "Downloading .pbix from Power BI Service…")
        export_url = f"{BASE}/groups/{workspace_id}/reports/{report_id}/Export"
        req4 = _urlreq.Request(export_url, headers=headers)

        with _urlreq.urlopen(req4, timeout=120) as resp:
            pbix_bytes = resp.read()

        if len(pbix_bytes) < 1024:
            raise RuntimeError(
                f"Export returned too few bytes ({len(pbix_bytes)}). "
                "The report may not be exportable — check workspace licence tier."
            )

        output_dir.mkdir(parents=True, exist_ok=True)
        out_pbix.write_bytes(pbix_bytes)
        size_kb = len(pbix_bytes) // 1024

        _upd("done", f"✓ Downloaded {out_pbix.name} ({size_kb} KB)")
        log("info", f"[API] Done → {out_pbix} ({size_kb} KB)", job_key)

        # ── Step 5: (optional) delete the temporary report from the service ───
        try:
            del_url = f"{BASE}/groups/{workspace_id}/reports/{report_id}"
            del_req = _urlreq.Request(del_url, headers=headers, method="DELETE")
            _urlreq.urlopen(del_req, timeout=15)
            log("info", f"[API] Temporary report deleted from workspace", job_key)
        except Exception:
            log("warn", "[API] Could not delete temporary report from workspace", job_key)

    except Exception as exc:
        print(f"[DEBUG except] line ~12520: {exc}")
        tb = traceback.format_exc()
        _update_job(job_key, "error", f"✗ {exc}")
        log("error", f"[API] Failed: {exc}", job_key)
        log("error", tb, job_key)


def _extract_pbix_params(payload: dict) -> dict:
    """
    Pull PBIX-conversion fields out of any POST payload.

    Returns a dict with 'method' and the relevant credential/path keys,
    or an empty dict if no pbix_method was specified (or it is 'none').
    """
    method = payload.get("pbix_method", "").strip().lower()
    if not method or method == "none":
        return {}
    params = {"method": method}
    if method == "desktop":
        params["pbi_exe"] = payload.get("pbi_exe", "").strip()
        params["timeout"] = int(payload.get("timeout", 90))
    elif method == "api":
        params["tenant_id"]     = payload.get("tenant_id", "").strip()
        params["client_id"]     = payload.get("client_id", "").strip()
        params["client_secret"] = payload.get("client_secret", "").strip()
        params["workspace_id"]  = payload.get("workspace_id", "").strip()
    return params


# ─────────────────────────────────────────────────────────────────────────────
# HTTP server
# ─────────────────────────────────────────────────────────────────────────────

LOGIN_FILE = Path(__file__).parent / "Landing.html"
APP_FILE = Path(__file__).parent / "Index.html"

# Simple in-memory session store (reset on server restart)
_sessions = {}  # session_id -> {'authenticated': True, 'timestamp': ...}


class Handler(BaseHTTPRequestHandler):
    def log_message(self, fmt, *args):
        pass  # suppress default access log; we use our own

    def handle(self):
        # Override BaseHTTPRequestHandler.handle() so that connection-abort
        # errors (WinError 10053 on Windows, BrokenPipeError on Linux/macOS)
        # are silently swallowed here — before they propagate to the server's
        # handle_error() and print a full traceback.  This happens routinely
        # when a browser tab is closed while an SSE stream is open.
        try:
            super().handle()
        except (ConnectionAbortedError, ConnectionResetError,
                BrokenPipeError, OSError):
            pass

    def do_OPTIONS(self):
        self._cors()
        self.send_response(200)
        self.end_headers()

    def _cors(self):
        self.send_header("Access-Control-Allow-Origin", "*")
        self.send_header("Access-Control-Allow-Methods", "GET, POST, OPTIONS")
        self.send_header("Access-Control-Allow-Headers", "Content-Type")

    # ── GET ───────────────────────────────────────────────────────────────────
    def do_GET(self):
        parsed = urlparse(self.path)
        path = parsed.path.rstrip('/')
        print(f"\n[DEBUG] GET request: path='{path}'")

        if path in ('', '/'):
            print(f"[DEBUG] Routing to LOGIN page")
            self._serve_login()
        elif path == '/app':
            print(f"[DEBUG] Routing to APP page")
            self._serve_app()
        elif path == '/api/session':
            self._check_session()
        elif path == '/engines':
            self._json({'tableau': True, 'crystal': False, 'crystal_sdk': False, 'crystal_sdk_mode': ''})
        elif path == '/events':
            self._serve_sse()
        elif path == '/state':
            self._json(conversion_state)
        elif path.startswith('/'):
            # Try to serve static files
            self._serve_static(path)
        else:
            self.send_error(404)

    def _serve_login(self):
        print(f"\n[DEBUG] Serving LOGIN page: {LOGIN_FILE}")
        if LOGIN_FILE.exists():
            body = LOGIN_FILE.read_bytes()
            print(f"[DEBUG] Login file size: {len(body)} bytes")
        else:
            print(f"[DEBUG] Login file NOT FOUND: {LOGIN_FILE}")
            body = b'<h1>Login page not found</h1><p>Place Landing.html next to the server.</p>'
        self.send_response(200)
        self.send_header("Content-Type", "text/html; charset=utf-8")
        self.send_header("Content-Length", str(len(body)))
        self._cors()
        self.end_headers()
        self.wfile.write(body)
    
    def _serve_app(self):
        if APP_FILE.exists():
            body = APP_FILE.read_bytes()
        else:
            body = b'<h1>App file not found</h1><p>Place index.html next to the server.</p>'
        self.send_response(200)
        self.send_header("Content-Type", "text/html; charset=utf-8")
        self.send_header("Content-Length", str(len(body)))
        self._cors()
        self.end_headers()
        self.wfile.write(body)
    
    def _check_session(self):
        """Check if user has a valid session cookie"""
        cookies = self.headers.get('Cookie', '')
        session_id = None
        
        # Parse session_id from cookies
        for cookie in cookies.split(';'):
            cookie = cookie.strip()
            if cookie.startswith('session_id='):
                session_id = cookie.split('=', 1)[1]
                break
        
        if session_id and session_id in _sessions:
            self._json({'authenticated': True})
        else:
            self._json({'authenticated': False})

    def _serve_static(self, path):
        """Serve static files (images, SVGs, etc.)"""
        # Sanitize path to prevent directory traversal
        clean_path = path.lstrip('/')
        if '..' in clean_path:
            self.send_error(403)
            return
        
        file_path = Path(__file__).parent / clean_path
        
        if not file_path.exists() or file_path.is_dir():
            self.send_error(404)
            return
        
        # Serve the file
        try:
            body = file_path.read_bytes()
            # Guess content type based on extension
            ext = file_path.suffix.lower()
            content_types = {
                '.svg': 'image/svg+xml',
                '.png': 'image/png',
                '.jpg': 'image/jpeg',
                '.jpeg': 'image/jpeg',
                '.gif': 'image/gif',
                '.css': 'text/css',
                '.js': 'application/javascript',
                '.json': 'application/json',
            }
            content_type = content_types.get(ext, 'application/octet-stream')
            
            self.send_response(200)
            self.send_header("Content-Type", content_type)
            self.send_header("Content-Length", str(len(body)))
            self._cors()
            self.end_headers()
            self.wfile.write(body)
        except Exception as e:
            self.send_error(500)

    def _serve_sse(self):
        self.send_response(200)
        self.send_header("Content-Type", "text/event-stream")
        self.send_header("Cache-Control", "no-cache")
        self.send_header("Connection", "keep-alive")
        self._cors()
        self.end_headers()

        q: queue.Queue = queue.Queue(maxsize=200)
        with _clients_lock:
            _clients.append(q)

        # Send current state immediately on connect
        try:
            init = f"event: state\ndata: {json.dumps(conversion_state)}\n\n"
            self.wfile.write(init.encode('utf-8'))
            self.wfile.flush()
        except Exception:
            print(f"[DEBUG except] line ~12625: exception caught")
            pass

        try:
            while True:
                try:
                    payload = q.get(timeout=25)
                    self.wfile.write(payload.encode('utf-8'))
                    self.wfile.flush()
                except queue.Empty:
                    print(f"[DEBUG except] line ~12634: exception caught")
                    # Heartbeat to keep connection alive
                    self.wfile.write(b": heartbeat\n\n")
                    self.wfile.flush()
        except (BrokenPipeError, ConnectionResetError,
                ConnectionAbortedError, OSError):
            # Client disconnected (tab closed/refreshed) — normal, not an error
            pass
        finally:
            with _clients_lock:
                if q in _clients:
                    _clients.remove(q)

    def _json(self, data):
        body = json.dumps(data).encode('utf-8')
        self.send_response(200)
        self.send_header("Content-Type", "application/json")
        self.send_header("Content-Length", str(len(body)))
        self._cors()
        self.end_headers()
        self.wfile.write(body)

    # ── POST ──────────────────────────────────────────────────────────────────
    def do_POST(self):
        parsed = urlparse(self.path)
        path = parsed.path.rstrip('/')
        length = int(self.headers.get("Content-Length", 0))
        body = self.rfile.read(length) if length else b'{}'
        try:
            payload = json.loads(body)
        except Exception:
            print(f"[DEBUG except] line ~12664: exception caught")
            payload = {}

        if path == '/api/login':
            self._handle_login(payload)
        elif path == '/start':
            self._handle_start(payload)
        elif path == '/stop':
            self._handle_stop()
        elif path == '/convert_one':
            self._handle_convert_one(payload)
        elif path == '/clear':
            conversion_state["jobs"].clear()
            broadcast("state", conversion_state)
            self._json({"ok": True})
        elif path == '/convert_to_pbix':
            self._handle_convert_to_pbix(payload)
        else:
            self.send_error(404)

    def _handle_login(self, payload):
        """Simple login endpoint - accepts any username/password for now"""
        username = payload.get("username", "").strip()
        password = payload.get("password", "").strip()
        
        if not username or not password:
            self._json({"ok": False, "error": "Username and password required"})
            return
        
        # Simple validation: accept if both provided
        # In production, you would hash/validate against a database
        session_id = str(uuid.uuid4())
        _sessions[session_id] = {
            'authenticated': True,
            'username': username,
            'timestamp': time.time()
        }
        
        # Set session cookie
        self.send_response(200)
        self.send_header("Content-Type", "application/json")
        self.send_header("Set-Cookie", f"session_id={session_id}; Path=/; HttpOnly")
        self._cors()
        response = json.dumps({"ok": True, "redirect": "/app"}).encode('utf-8')
        self.send_header("Content-Length", str(len(response)))
        self.end_headers()
        self.wfile.write(response)

    def _handle_start(self, payload):
        if conversion_state["running"]:
            self._json({"ok": False, "error": "Already running"})
            return
        src = payload.get("source", "").strip()
        tgt = payload.get("target", "").strip()
        if not src or not tgt:
            self._json({"ok": False, "error": "source and target are required"})
            return
        if not Path(src).is_dir():
            self._json({"ok": False, "error": f"Source folder not found: {src}"})
            return
        sample      = bool(payload.get("embed_sample_data", False))
        mode        = payload.get("mode", "migrate")
        pbix_params = _extract_pbix_params(payload)
        conversion_state["running"] = True
        conversion_state["source"]  = src
        conversion_state["target"]  = tgt
        conversion_state["jobs"]    = {}
        threading.Thread(
            target=conversion_worker,
            args=(src, tgt, sample, mode, pbix_params), daemon=True
        ).start()
        self._json({"ok": True})

    def _handle_stop(self):
        conversion_state["running"] = False
        self._json({"ok": True})

    def _handle_convert_one(self, payload):
        filepath = payload.get("file", "").strip()
        target   = (payload.get("target", "") or "").strip()
        if not target:
            target = conversion_state.get("target", "").strip()
        if not filepath:
            self._json({"ok": False, "error": "No file path provided"}); return
        if not target:
            self._json({"ok": False, "error": "No target folder set. Enter one in the Target Folder field."}); return
        p = Path(filepath)
        if not p.exists():
            self._json({"ok": False, "error": f"File not found: {filepath}"}); return
        if p.suffix.lower() not in ('.twb', '.twbx'):
            self._json({"ok": False, "error": f"Not a Tableau file (.twb/.twbx): {p.name}"}); return
        sample      = bool(payload.get("embed_sample_data", False))
        mode        = payload.get("mode", "migrate")
        pbix_params = _extract_pbix_params(payload)
        threading.Thread(
            target=process_file,
            args=(p, Path(target), sample, mode, pbix_params), daemon=True
        ).start()
        self._json({"ok": True, "queued": p.name})

    def _handle_convert_to_pbix(self, payload):
        """Handle POST /convert_to_pbix — convert a .pbit to .pbix."""
        pbit_path  = payload.get("pbit_path", "").strip()
        output_dir = payload.get("output_dir", "").strip()
        method     = payload.get("method", "desktop")   # 'desktop' or 'api'

        if not pbit_path:
            self._json({"ok": False, "error": "No PBIT file path provided"}); return
        if not output_dir:
            self._json({"ok": False, "error": "No output folder provided"}); return

        p = Path(pbit_path)
        if not p.exists():
            self._json({"ok": False, "error": f"File not found: {pbit_path}"}); return
        if p.suffix.lower() != '.pbit':
            self._json({"ok": False, "error": f"Not a .pbit file: {p.name}"}); return

        if method == 'desktop':
            pbi_exe  = payload.get("pbi_exe", "").strip()
            timeout  = int(payload.get("timeout", 90))
            threading.Thread(
                target=_pbix_via_desktop,
                args=(p, Path(output_dir), pbi_exe, timeout),
                daemon=True
            ).start()
        elif method == 'api':
            tenant_id     = payload.get("tenant_id", "").strip()
            client_id     = payload.get("client_id", "").strip()
            client_secret = payload.get("client_secret", "").strip()
            workspace_id  = payload.get("workspace_id", "").strip()
            if not all([tenant_id, client_id, client_secret, workspace_id]):
                self._json({"ok": False, "error": "Tenant ID, Client ID, Client Secret and Workspace ID are all required"}); return
            threading.Thread(
                target=_pbix_via_api,
                args=(p, Path(output_dir), tenant_id, client_id, client_secret, workspace_id),
                daemon=True
            ).start()
        else:
            self._json({"ok": False, "error": f"Unknown method: {method}"}); return

        self._json({"ok": True, "queued": p.name})


class _QuietServer(ThreadingHTTPServer):
    """ThreadingHTTPServer that silently drops client-disconnect errors."""
    def handle_error(self, request, client_address):
        import sys
        exc = sys.exc_info()[1]
        if isinstance(exc, (ConnectionAbortedError, ConnectionResetError,
                            BrokenPipeError, OSError)):
            return   # browser closed the tab — not actionable
        super().handle_error(request, client_address)


# ─────────────────────────────────────────────────────────────────────────────
# Entry point
# ─────────────────────────────────────────────────────────────────────────────


# ── Offline-safe CDN bundler ──────────────────────────────────────────────────
# On first run, downloads React/ReactDOM/Babel from the first reachable CDN
# and saves them next to the server. Subsequent runs serve from disk.
# Multiple CDNs are tried — corporate proxies often block unpkg but allow others.
_JS_DEPS = [
    # React and ReactDOM are now INLINED in the HTML files (offline-safe).
    # Only Babel standalone needs downloading for JSX transformation.
    ('babel.min.js', [
        'https://registry.npmjs.org/@babel/standalone/-/standalone-7.23.5.tgz',
        'https://unpkg.com/@babel/standalone/babel.min.js',
        'https://cdnjs.cloudflare.com/ajax/libs/babel-standalone/7.23.5/babel.min.js',
        'https://cdn.jsdelivr.net/npm/@babel/standalone/babel.min.js',
    ]),
]
def _ensure_js_deps():
    """Download JS dependencies if not already present locally."""
    import urllib.request
    server_dir = Path(__file__).parent

    _MIN_SIZES = {
        'react.development.js':     100_000,
        'react-dom.development.js': 100_000,
        'babel.min.js':             500_000,
    }

    def _is_valid_js(path, fname):
        try:
            sz = path.stat().st_size
            if sz < _MIN_SIZES.get(fname, 50_000):
                return False
            with open(path, 'rb') as fh:
                head = fh.read(64).lstrip()
            return not head.startswith(b'<') and len(head) > 10
        except Exception:
            return False

    missing = [
        (fname, urls)
        for fname, urls in _JS_DEPS
        if not _is_valid_js(server_dir / fname, fname)
    ]
    if not missing:
        return
    print(f"  [SETUP] Downloading {len(missing)} JS dependency file(s)...")
    for fname, urls in missing:
        dest = server_dir / fname
        downloaded = False
        for url in urls:
            try:
                cdn = url.split('/')[2]
                print(f"  [SETUP]   {fname} from {cdn} ... ", end='', flush=True)
                if url.endswith('.tgz'):
                    # npm registry tarball — extract babel.min.js from it
                    import tarfile, io as _io
                    tgz_data = urllib.request.urlopen(url).read()
                    with tarfile.open(fileobj=_io.BytesIO(tgz_data), mode='r:gz') as tf:
                        _members = [m for m in tf.getmembers()
                                    if m.name.endswith('babel.min.js') and 'test' not in m.name]
                        if _members:
                            _extracted = tf.extractfile(_members[0]).read()
                            with open(dest, 'wb') as _fh:
                                _fh.write(_extracted)
                        else:
                            raise ValueError('babel.min.js not found in tarball')
                else:
                    urllib.request.urlretrieve(url, dest)
                if _is_valid_js(dest, fname):
                    size_kb = dest.stat().st_size // 1024
                    print(f"OK ({size_kb} KB)")
                    downloaded = True
                    break
                else:
                    size_kb = dest.stat().st_size // 1024
                    print(f"blocked ({size_kb} KB), trying next...")
                    try: dest.unlink()
                    except: pass
            except Exception as e:
                print(f"failed, trying next...")
        if not downloaded:
            print(f"  [SETUP]   WARNING: {fname} could not be downloaded.")
            print(f"  [SETUP]   Manually copy it to: {server_dir}")
    print()


def main():
    _ensure_js_deps()
    parser = argparse.ArgumentParser(description="Tableau → Power BI Migration Server")
    parser.add_argument("--port", type=int, default=8765)
    parser.add_argument("--source", default="./source",
                        help="Default source folder to watch")
    parser.add_argument("--target", default="./target",
                        help="Default target folder for .pbit output")
    parser.add_argument("--autostart", action="store_true",
                        help="Start watching immediately on launch")
    args = parser.parse_args()

    server = _QuietServer(("0.0.0.0", args.port), Handler)
    print(f"╔══════════════════════════════════════════════════╗")
    print(f"║  Tableau → Power BI Migration Server             ║")
    print(f"║  http://localhost:{args.port:<5}                           ║")
    print(f"╚══════════════════════════════════════════════════╝")
    print(f"  Source default : {args.source}")
    print(f"  Target default : {args.target}")
    print(f"  Press Ctrl+C to stop")
    print()

    if args.autostart:
        src = args.source
        tgt = args.target
        if Path(src).is_dir():
            conversion_state["running"] = True
            conversion_state["source"] = src
            conversion_state["target"] = tgt
            threading.Thread(target=conversion_worker, args=(src, tgt, False), daemon=True).start()
        else:
            print(f"  [WARN] --autostart: source folder '{src}' not found, skipping.")

    try:
        server.serve_forever()
    except KeyboardInterrupt:
        print(f"[DEBUG except] line ~12826: exception caught")
        conversion_state["running"] = False
        print("\n  Server stopped.")


if __name__ == "__main__":
    main()